window.FOURFORASP_LEARNING_DATA={"akl2":{"id":"akl2","title":"Akuntansi Keuangan Lanjutan II","short":"AKL II","konsen":["gabungan"],"quiz":[{"number":1,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Laba pascaakuisisi","learningOutcome":"Menghitung laba anak yang masuk periode konsolidasi","difficulty":"Mudah","type":"Definisi","question":"P membeli 80% saham S pada 1 April. Laba bersih S selama satu tahun adalah Rp120 juta dan diasumsikan terjadi merata. Berapa laba S yang menjadi basis konsolidasi sejak tanggal akuisisi?","options":["Rp30 juta","Rp90 juta","Rp96 juta","Rp120 juta"],"correct":"B","concept":"Batas periode konsolidasi","explanation":"Jawaban yang benar adalah B. Akuisisi terjadi pada 1 April, sehingga periode pascaakuisisi mencakup sembilan bulan, yaitu April–Desember. Laba yang masuk basis konsolidasi = 9/12 × Rp120 juta = Rp90 juta. Laba Januari–Maret sebesar Rp30 juta merupakan laba praakuisisi dan menjadi bagian dari aset neto yang diperoleh, bukan laba kelompok usaha tahun berjalan. Kesalahan yang sering terjadi adalah mengalikan laba setahun penuh dengan persentase kepemilikan tanpa terlebih dahulu memotong periode sebelum kendali diperoleh.","whyOthersWrong":"A hanya menunjukkan laba tiga bulan praakuisisi. C adalah 80% dari laba setahun penuh sehingga salah periode. D memasukkan seluruh laba S sebelum dan sesudah akuisisi.","tip":"Buat garis waktu tanggal akuisisi. Hitung dahulu laba pascaakuisisi, baru alokasikan kepada induk dan KNP.","reference":"TM 1 – Akuisisi Tahun Berjalan dan Akuisisi Bertahap","keywords":"interim acquisition; laba pascaakuisisi"},{"number":2,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Pembelian tambahan tanpa kehilangan kendali","learningOutcome":"Mengidentifikasi klasifikasi transaksi setelah kendali diperoleh","difficulty":"Mudah","type":"Definisi","question":"P telah memiliki 75% saham S dan kemudian membeli tambahan 10% dari KNP. P tetap mengendalikan S. Transaksi tersebut diklasifikasikan sebagai apa pada laporan keuangan konsolidasian?","options":["Transaksi ekuitas","Kombinasi bisnis baru","Pelepasan sebagian dengan laba rugi","Penurunan nilai goodwill"],"correct":"A","concept":"Perubahan kepemilikan tanpa kehilangan kendali","explanation":"Jawaban yang benar adalah A. Setelah kendali telah diperoleh, pembelian tambahan saham dari kepentingan nonpengendali tidak diperlakukan sebagai kombinasi bisnis baru. Kelompok usaha telah mengendalikan seluruh aset dan liabilitas anak sebelum transaksi. Karena kendali tetap ada, transaksi diperlakukan sebagai transaksi ekuitas antara pemilik induk dan KNP. Nilai tercatat KNP dikurangi, sedangkan selisih antara harga yang dibayar dan pengurangan KNP dicatat langsung pada ekuitas pemilik induk. Tidak timbul goodwill baru dan tidak ada laba atau rugi pada laporan laba rugi.","whyOthersWrong":"B salah karena kendali tidak diperoleh untuk pertama kali. C salah karena tidak ada kehilangan kendali. D tidak otomatis terjadi hanya karena persentase meningkat.","tip":"Tanyakan satu hal terlebih dahulu: apakah kendali hilang? Jika tidak, arahkan selisih ke ekuitas, bukan laba rugi.","reference":"TM 2 – Perubahan Kepemilikan pada Entitas Anak","keywords":"transaksi ekuitas; KNP; kendali"},{"number":3,"topic":"Indirect Holding","subtopic":"Kepemilikan efektif","learningOutcome":"Menghitung kepemilikan ekonomi induk atas entitas cucu","difficulty":"Mudah","type":"Definisi","question":"P memiliki 80% saham S, sedangkan S memiliki 70% saham T. Berapa kepemilikan efektif ekonomi P atas T?","options":["30%","70%","80%","56%"],"correct":"D","concept":"Perkalian jalur kepemilikan","explanation":"Jawaban yang benar adalah D. Kepemilikan efektif P atas T dihitung dengan mengalikan persentase kepemilikan pada setiap jalur: 80% × 70% = 56%. Angka ini menggambarkan bagian ekonomi pemilik induk atas laba dan ekuitas T melalui S. Namun, T tetap dikonsolidasikan penuh apabila S mengendalikan T dan P mengendalikan S. Karena itu, 56% bukan persentase aset dan liabilitas T yang dimasukkan ke laporan konsolidasian; aset dan liabilitas T tetap masuk 100%, kemudian bagian KNP disajikan terpisah.","whyOthersWrong":"A adalah bagian yang tidak dimiliki S. B hanya persentase S pada T. C hanya persentase P pada S.","tip":"Untuk jalur searah, kalikan setiap persentase. Bedakan kepemilikan ekonomi dari dasar konsolidasi penuh.","reference":"TM 3 – Indirect Holding: Struktur Induk–Anak–Cucu","keywords":"kepemilikan efektif; induk-anak-cucu"},{"number":4,"topic":"Transaksi Mata Uang Asing","subtopic":"Pengakuan awal","learningOutcome":"Menghitung nilai awal utang valuta asing","difficulty":"Mudah","type":"Definisi","question":"Entitas membeli persediaan senilai USD10.000 ketika kurs spot Rp15.200/USD. Berapa nilai persediaan dan utang usaha pada pengakuan awal?","options":["Rp150.000.000","Rp155.000.000","Rp152.000.000","Rp157.000.000"],"correct":"C","concept":"Pengukuran transaksi tanggal transaksi","explanation":"Jawaban yang benar adalah C. Transaksi valuta asing pada pengakuan awal diukur menggunakan kurs spot pada tanggal transaksi. Nilai rupiah = USD10.000 × Rp15.200 = Rp152.000.000. Persediaan dan utang dicatat pada jumlah yang sama agar jurnal seimbang. Kurs penutup baru digunakan untuk mengukur kembali pos moneter pada tanggal pelaporan jika utang belum diselesaikan. Kurs rata-rata hanya dapat menjadi pendekatan untuk transaksi berulang dan merata ketika fluktuasi tidak signifikan, bukan menggantikan kurs spot untuk satu transaksi tertentu.","whyOthersWrong":"A dan B menggunakan kurs yang tidak diberikan. D juga tidak berasal dari data transaksi.","tip":"Pada pengakuan awal, selalu cari kurs spot tanggal transaksi sebelum memikirkan kurs akhir periode.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"kurs spot; pengakuan awal"},{"number":5,"topic":"Transaksi Mata Uang Asing","subtopic":"Piutang moneter akhir periode","learningOutcome":"Menghitung keuntungan selisih kurs piutang","difficulty":"Mudah","type":"Definisi","question":"Piutang USD8.000 awalnya dicatat pada kurs Rp15.000/USD. Pada akhir periode kurs penutup menjadi Rp15.400/USD. Berapa keuntungan selisih kurs yang diakui?","options":["Rp3.200.000","Rugi Rp3.200.000","Rp123.200.000","Tidak ada penyesuaian"],"correct":"A","concept":"Pengukuran kembali pos moneter","explanation":"Jawaban yang benar adalah A. Nilai awal piutang = USD8.000 × Rp15.000 = Rp120.000.000. Nilai pada kurs penutup = USD8.000 × Rp15.400 = Rp123.200.000. Karena piutang dalam valuta asing bertambah nilainya dalam rupiah, entitas mengakui keuntungan selisih kurs sebesar Rp3.200.000. Jumlah Rp123.200.000 adalah nilai tercatat akhir piutang, bukan besarnya keuntungan. Pos moneter seperti piutang dan utang diukur kembali pada kurs penutup, sedangkan pos nonmoneter historis umumnya tidak diukur kembali.","whyOthersWrong":"B membalik arah dampak piutang. C adalah saldo akhir, bukan gain. D mengabaikan kewajiban remeasurement pos moneter.","tip":"Untuk piutang, kenaikan kurs valuta asing menghasilkan gain; untuk utang, kenaikan kurs menghasilkan loss.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"piutang moneter; kurs penutup; gain"},{"number":6,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Alokasi laba kepada KNP","learningOutcome":"Menghitung beban KNP atas laba pascaakuisisi","difficulty":"Sedang","type":"Konseptual","question":"P memperoleh 90% saham S pada 1 Juli. Laba S setahun Rp240 juta dan terjadi merata. Berapa bagian laba KNP yang diakui dalam laba konsolidasian tahun tersebut?","options":["Rp6 juta","Rp24 juta","Rp21,6 juta","Rp12 juta"],"correct":"D","concept":"Alokasi laba setelah tanggal kendali","explanation":"Jawaban yang benar adalah D. Akuisisi pada 1 Juli berarti hanya laba enam bulan Juli–Desember yang dikonsolidasikan. Laba pascaakuisisi = 6/12 × Rp240 juta = Rp120 juta. KNP memiliki 10%, sehingga bagian laba KNP = 10% × Rp120 juta = Rp12 juta. Persentase KNP tidak diterapkan pada laba setahun penuh karena laba Januari–Juni terjadi sebelum kendali diperoleh. Langkah yang benar adalah memotong periode terlebih dahulu, kemudian mengalokasikan laba pascaakuisisi kepada pemilik induk dan KNP.","whyOthersWrong":"A terlalu kecil karena hanya 5% dari laba pascaakuisisi. B memakai 10% laba setahun penuh. C memakai 9% laba setahun penuh.","tip":"Urutannya: periode pascaakuisisi → laba yang dikonsolidasi → persentase KNP.","reference":"TM 1 – Akuisisi Tahun Berjalan dan Akuisisi Bertahap","keywords":"KNP; laba pascaakuisisi"},{"number":7,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Roll-forward KNP","learningOutcome":"Menghitung saldo akhir kepentingan nonpengendali","difficulty":"Sedang","type":"Konseptual","question":"Saldo KNP pada tanggal akuisisi Rp180 juta. Setelah itu KNP memperoleh bagian laba Rp50 juta, menerima dividen Rp10 juta, dan menanggung rugi OCI Rp6 juta. Berapa saldo akhir KNP?","options":["Rp206 juta","Rp214 juta","Rp226 juta","Rp240 juta"],"correct":"B","concept":"Rekonsiliasi KNP","explanation":"Jawaban yang benar adalah B. Saldo akhir KNP dihitung dengan roll-forward: saldo awal Rp180 juta + bagian laba Rp50 juta − dividen Rp10 juta − rugi OCI Rp6 juta = Rp214 juta. Bagian laba meningkatkan kepentingan KNP, sedangkan dividen dan rugi OCI menguranginya. Saldo KNP harus diperbarui sampai tanggal transaksi sebelum digunakan dalam perhitungan pembelian tambahan atau penjualan sebagian. Menggunakan saldo akuisisi tanpa memasukkan laba, dividen, dan OCI akan menghasilkan penyesuaian ekuitas yang salah.","whyOthersWrong":"A mengurangi komponen secara berlebihan. C tidak mengurangkan rugi OCI dengan benar. D mengabaikan dividen dan OCI.","tip":"Gunakan pola: saldo awal + laba − dividen ± OCI ± penyesuaian lain.","reference":"TM 2 – Perubahan Kepemilikan pada Entitas Anak","keywords":"roll-forward KNP; laba; dividen; OCI"},{"number":8,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Pembelian saham dari KNP","learningOutcome":"Menentukan dampak selisih harga terhadap ekuitas induk","difficulty":"Mudah","type":"Konseptual","question":"P membeli tambahan saham S dari KNP seharga Rp145 juta. Nilai tercatat bagian KNP yang dipindahkan adalah Rp120 juta dan kendali tetap ada. Apa dampak konsolidasian?","options":["Goodwill bertambah Rp25 juta","Laba bertambah Rp25 juta","Ekuitas pemilik induk berkurang Rp25 juta","Ekuitas pemilik induk bertambah Rp25 juta"],"correct":"C","concept":"Harga beli versus nilai tercatat KNP","explanation":"Jawaban yang benar adalah C. Karena kendali tetap dipertahankan, pembelian tambahan diperlakukan sebagai transaksi ekuitas. KNP berkurang sebesar nilai tercatat bagian yang dibeli, yaitu Rp120 juta. Kas yang dibayar Rp145 juta. Selisih Rp25 juta merupakan jumlah yang mengurangi ekuitas pemilik induk. Tidak ada goodwill baru karena kendali atas aset dan liabilitas S sudah ada sebelum transaksi, dan tidak ada laba rugi karena kelompok tidak bertransaksi dengan pihak eksternal dalam kapasitas menghasilkan pendapatan.","whyOthersWrong":"A salah karena tidak ada goodwill baru. B salah karena selisih tidak masuk laba rugi. D membalik arah selisih.","tip":"Jika harga dibayar lebih besar daripada KNP yang dihentikan, ekuitas induk turun.","reference":"TM 2 – Perubahan Kepemilikan pada Entitas Anak","keywords":"pembelian tambahan; selisih ekuitas"},{"number":9,"topic":"Connecting Affiliates","subtopic":"Kepemilikan langsung dan tidak langsung","learningOutcome":"Menghitung bagian ekonomi induk melalui dua jalur","difficulty":"Sedang","type":"Konseptual","question":"P memiliki langsung 55% saham T. P juga memiliki 80% saham S, dan S memiliki 25% saham T. Berapa kepemilikan ekonomi P atas T?","options":["75%","60%","80%","100%"],"correct":"A","concept":"Penjumlahan kepemilikan langsung dan tidak langsung","explanation":"Jawaban yang benar adalah A. Bagian langsung P atas T adalah 55%. Bagian tidak langsung melalui S = 80% × 25% = 20%. Total kepemilikan ekonomi P atas T = 55% + 20% = 75%. Total saham T yang dikuasai kelompok adalah 55% + 25% = 80%, tetapi bagian ekonomi pemilik P hanya 75% karena 20% kepemilikan S dimiliki oleh KNP S. Inilah alasan connecting affiliates harus dianalisis per jalur, bukan hanya menjumlahkan saham kelompok.","whyOthersWrong":"B hanya salah satu kombinasi parsial. C adalah kepemilikan kelompok, bukan bagian ekonomi P. D menganggap seluruh T dimiliki P.","tip":"Hitung setiap jalur secara terpisah: langsung + (P pada S × S pada T).","reference":"TM 4 – Indirect Holding: Connecting Affiliates","keywords":"connecting affiliates; dua jalur"},{"number":10,"topic":"Transaksi Mata Uang Asing","subtopic":"Uang muka nonmoneter","learningOutcome":"Membedakan remeasurement pos moneter dan nonmoneter","difficulty":"Sedang","type":"Konseptual","question":"Entitas membayar uang muka tidak dapat dikembalikan sebesar USD20.000 untuk menerima persediaan. Kurs pembayaran Rp15.000/USD dan kurs akhir tahun Rp15.500/USD. Barang belum diterima. Berapa nilai uang muka pada akhir tahun?","options":["Rp310 juta dan rugi kurs Rp10 juta","Rp300 juta tanpa selisih kurs","Rp310 juta dan keuntungan kurs Rp10 juta","Rp300 juta dengan rugi kurs Rp10 juta"],"correct":"B","concept":"Substansi penyelesaian pos","explanation":"Jawaban yang benar adalah B. Uang muka yang akan diselesaikan dengan penerimaan barang, bukan dengan penerimaan sejumlah mata uang tetap, merupakan pos nonmoneter. Karena dicatat berdasarkan biaya historis, nilainya tetap USD20.000 × Rp15.000 = Rp300 juta. Perubahan kurs menjadi Rp15.500 tidak menghasilkan keuntungan atau kerugian selisih kurs atas uang muka tersebut. Nama akun bukan penentu utama; yang diperhatikan adalah bentuk penyelesaian. Deposit yang dapat dikembalikan dalam jumlah valuta asing tetap dapat berbeda perlakuannya karena bersifat moneter.","whyOthersWrong":"A dan C memperlakukan uang muka sebagai pos moneter. D mempertahankan saldo tetapi tetap mengakui rugi yang tidak semestinya.","tip":"Tanyakan: akan diterima kas tetap atau barang/jasa? Barang/jasa biasanya menunjukkan pos nonmoneter.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"uang muka; nonmoneter; kurs historis"},{"number":11,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Goodwill tanggal kendali","learningOutcome":"Menghitung goodwill pada akuisisi bertahap","difficulty":"Sedang","type":"Penerapan","question":"P sebelumnya memiliki 30% S yang bernilai wajar Rp360 juta. P membayar Rp640 juta untuk membeli tambahan 50% dan memperoleh kendali. Nilai wajar KNP Rp260 juta, sedangkan nilai wajar aset neto teridentifikasi S Rp1.100 juta. Berapa goodwill?","options":["Rp60 juta","Rp100 juta","Rp140 juta","Rp160 juta"],"correct":"D","concept":"Goodwill pada tanggal kendali","explanation":"Jawaban yang benar adalah D. Goodwill pada akuisisi bertahap dihitung: nilai wajar kepentingan lama Rp360 juta + imbalan baru Rp640 juta + nilai wajar KNP Rp260 juta − nilai wajar aset neto teridentifikasi Rp1.100 juta = Rp160 juta. Kepentingan lama digunakan pada nilai wajar tanggal kendali, bukan nilai tercatat historis. Selisih antara nilai wajar dan nilai tercatat kepentingan lama diakui sebagai gain atau loss remeasurement secara terpisah dari goodwill.","whyOthersWrong":"A, B, dan C menghilangkan salah satu komponen atau menggunakan basis yang tidak lengkap.","tip":"Gunakan formula empat komponen: old interest FV + new consideration + NCI FV − identifiable net assets FV.","reference":"TM 1 – Akuisisi Tahun Berjalan dan Akuisisi Bertahap","keywords":"step acquisition; goodwill; remeasurement"},{"number":12,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Penjualan sebagian tanpa kehilangan kendali","learningOutcome":"Menghitung penyesuaian ekuitas dari perubahan KNP","difficulty":"Sedang","type":"Penerapan","question":"P memiliki 80% S lalu menjual 10% saham S kepada pihak luar seharga Rp150 juta dan tetap mengendalikan S. Saldo KNP sebelum transaksi Rp240 juta untuk kepemilikan 20%. Berapa dampak pada ekuitas induk?","options":["Laba pelepasan Rp30 juta","Goodwill bertambah Rp30 juta","Ekuitas induk bertambah Rp30 juta","Ekuitas induk berkurang Rp30 juta"],"correct":"C","concept":"Perubahan nilai tercatat KNP","explanation":"Jawaban yang benar adalah C. Saldo KNP Rp240 juta mewakili 20%, sehingga nilai tercatat untuk tambahan 10% KNP adalah Rp120 juta. Kas yang diterima Rp150 juta. Karena kendali tetap ada, selisih Rp150 juta − Rp120 juta = Rp30 juta diakui langsung sebagai penambahan ekuitas pemilik induk. Tidak ada laba pelepasan pada laba rugi dan goodwill tidak dihitung ulang. Perhitungan menggunakan nilai tercatat KNP yang mutakhir, bukan nilai tercatat investasi pada laporan tersendiri induk.","whyOthersWrong":"A salah lokasi pengakuan. B salah karena tidak ada goodwill baru. D membalik arah selisih.","tip":"Penjualan tanpa kehilangan kendali: kas diterima − kenaikan KNP = penyesuaian ekuitas induk.","reference":"TM 2 – Perubahan Kepemilikan pada Entitas Anak","keywords":"partial disposal; KNP; ekuitas"},{"number":13,"topic":"Indirect Holding","subtopic":"Adjusted income entitas cucu","learningOutcome":"Menghitung bagian laba induk melalui rantai kepemilikan","difficulty":"Sedang","type":"Penerapan","question":"T melaporkan laba Rp200 juta. Amortisasi excess value T Rp20 juta dan laba persediaan upstream yang belum terealisasi Rp30 juta. S memiliki 70% T dan P memiliki 80% S. Berapa bagian laba T yang secara ekonomi menjadi hak P?","options":["Rp72 juta","Rp84 juta","Rp105 juta","Rp120 juta"],"correct":"B","concept":"Alokasi laba bottom-up","explanation":"Jawaban yang benar adalah B. Laba T harus disesuaikan terlebih dahulu: Rp200 juta − Rp20 juta amortisasi excess − Rp30 juta laba belum terealisasi = Rp150 juta. Bagian S = 70% × Rp150 juta = Rp105 juta. Bagian ekonomi P melalui S = 80% × Rp105 juta = Rp84 juta. Kesalahan umum adalah mengalikan persentase sebelum menyesuaikan laba T atau mengabaikan bahwa penyesuaian upstream mengurangi laba entitas penjual sebelum dialokasikan kepada seluruh pemegang sahamnya.","whyOthersWrong":"A menggunakan basis laba yang salah. C adalah bagian S, belum dialokasikan ke P. D mengabaikan sebagian penyesuaian.","tip":"Urutan wajib: sesuaikan laba entitas terbawah → alokasikan ke investor langsung → alokasikan lagi ke induk.","reference":"TM 3 – Indirect Holding: Struktur Induk–Anak–Cucu","keywords":"adjusted income; upstream; kepemilikan berjenjang"},{"number":14,"topic":"Transaksi Mata Uang Asing","subtopic":"Utang usaha akhir periode","learningOutcome":"Menghitung kerugian selisih kurs utang","difficulty":"Sedang","type":"Penerapan","question":"Entitas mengimpor barang senilai USD50.000 pada kurs Rp15.100/USD. Pada akhir periode utang belum dibayar dan kurs penutup Rp15.350/USD. Berapa selisih kurs yang diakui?","options":["Rugi Rp12.500.000","Untung Rp12.500.000","Rugi Rp767.500.000","Tidak ada selisih kurs"],"correct":"A","concept":"Kenaikan nilai kewajiban valuta asing","explanation":"Jawaban yang benar adalah A. Nilai awal utang = USD50.000 × Rp15.100 = Rp755.000.000. Nilai akhir = USD50.000 × Rp15.350 = Rp767.500.000. Utang meningkat Rp12.500.000, sehingga entitas mengakui kerugian selisih kurs sebesar Rp12.500.000. Untuk utang valuta asing, kenaikan kurs valuta asing terhadap rupiah meningkatkan jumlah rupiah yang harus dibayar. Persediaan historis tidak ikut diubah hanya karena utang diukur kembali.","whyOthersWrong":"B membalik arah dampak utang. C adalah saldo akhir utang, bukan kerugian. D mengabaikan remeasurement pos moneter.","tip":"Utang: kurs naik = rugi. Piutang: kurs naik = untung.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"utang moneter; exchange loss"},{"number":15,"topic":"Translasi Laporan Keuangan","subtopic":"Perubahan CTA","learningOutcome":"Menghitung selisih translasi dari rekonsiliasi aset neto","difficulty":"Sedang","type":"Penerapan","question":"Aset neto awal operasi asing FC1.000 diterjemahkan dengan kurs historis Rp14.000. Laba FC200 memakai kurs rata-rata Rp14.500, dividen FC50 memakai Rp14.500, dan aset neto akhir FC1.150 memakai kurs penutup Rp15.000. Berapa kenaikan CTA?","options":["Rp350 juta","Rp725 juta","Rp1.075 juta","Rp1.450 juta"],"correct":"C","concept":"Rekonsiliasi aset neto terjemahan","explanation":"Jawaban yang benar adalah C. Aset neto akhir terjemahan = FC1.150 × Rp15.000 = Rp17.250 juta. Komponen ekuitas tanpa CTA = aset neto awal Rp14.000 juta + laba Rp2.900 juta − dividen Rp725 juta = Rp16.175 juta. Selisih Rp17.250 juta − Rp16.175 juta = Rp1.075 juta merupakan kenaikan CTA. CTA muncul karena komponen aset neto diterjemahkan dengan kurs berbeda, bukan karena trial balance lokal tidak seimbang.","whyOthersWrong":"A dan B hanya mengambil sebagian perubahan kurs. D sama dengan selisih kurs per unit dikali seluruh aset neto awal tanpa mempertimbangkan laba dan dividen.","tip":"Bandingkan aset neto akhir pada closing rate dengan roll-forward ekuitas terjemahan.","reference":"TM 6 – Laporan Keuangan dalam Mata Uang Asing","keywords":"CTA; kurs historis; kurs rata-rata; kurs penutup"},{"number":16,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Excess depreciation dan KNP","learningOutcome":"Menganalisis laba KNP setelah penyesuaian nilai wajar","difficulty":"Sulit","type":"Mini Kasus","question":"P memperoleh 80% S pada 1 April. Laba S setahun Rp180 juta dan terjadi merata. Pada tanggal akuisisi terdapat kenaikan nilai wajar peralatan Rp120 juta dengan sisa umur 5 tahun. Berapa bagian laba KNP tahun berjalan setelah penyesuaian depresiasi excess?","options":["Rp18 juta","Rp27 juta","Rp21,6 juta","Rp23,4 juta"],"correct":"D","concept":"Laba pascaakuisisi setelah amortisasi excess","explanation":"Jawaban yang benar adalah D. Laba pascaakuisisi selama sembilan bulan = 9/12 × Rp180 juta = Rp135 juta. Tambahan depresiasi akibat excess value = Rp120 juta ÷ 5 tahun × 9/12 = Rp18 juta. Laba S yang telah disesuaikan = Rp135 juta − Rp18 juta = Rp117 juta. Bagian KNP 20% × Rp117 juta = Rp23,4 juta. Penyesuaian excess hanya dihitung sejak tanggal akuisisi, bukan setahun penuh.","whyOthersWrong":"A hanya tambahan depresiasi. B adalah 20% dari laba pascaakuisisi sebelum penyesuaian. C menggunakan basis penyesuaian yang tidak tepat.","tip":"Potong periode laba dan amortisasi pada tanggal yang sama, lalu alokasikan laba bersih yang telah disesuaikan.","reference":"TM 1 – Akuisisi Tahun Berjalan dan Akuisisi Bertahap","keywords":"interim acquisition; excess depreciation; KNP"},{"number":17,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Kehilangan kendali","learningOutcome":"Menghitung laba pelepasan ketika kendali hilang","difficulty":"Sulit","type":"Mini Kasus","question":"Pada tanggal kehilangan kendali, nilai tercatat aset neto S termasuk goodwill adalah Rp1.000 juta dan KNP Rp200 juta. P menerima kas Rp700 juta dan mempertahankan 20% saham yang bernilai wajar Rp250 juta. Berapa laba pelepasan konsolidasian?","options":["Rp150 juta","Rugi Rp50 juta","Rp350 juta","Rp950 juta"],"correct":"A","concept":"Penghentian konsolidasi secara penuh","explanation":"Jawaban yang benar adalah A. Laba pelepasan = kas diterima Rp700 juta + nilai wajar kepentingan tersisa Rp250 juta + penghentian KNP Rp200 juta − nilai tercatat aset neto dan goodwill Rp1.000 juta = Rp150 juta. Saat kendali hilang, seluruh anak didekonsolidasi, bukan hanya persentase saham yang dijual. Kepentingan yang masih dimiliki diukur pada nilai wajar dan menjadi dasar pengakuan investasi baru sesuai status setelah transaksi.","whyOthersWrong":"B mengabaikan KNP atau retained interest. C menghitung hanya sebagian komponen. D menjumlahkan komponen tanpa menghentikan aset neto.","tip":"Gunakan rumus lengkap: consideration + FV retained interest + NCI − carrying amount net assets and goodwill.","reference":"TM 2 – Perubahan Kepemilikan pada Entitas Anak","keywords":"loss of control; retained interest; gain"},{"number":18,"topic":"Connecting Affiliates","subtopic":"Alokasi laba T kepada KNP","learningOutcome":"Menganalisis KNP langsung dan KNP tidak langsung","difficulty":"Sulit","type":"Mini Kasus","question":"P memiliki 75% S dan langsung memiliki 40% T. S memiliki 30% T, sehingga kelompok mengendalikan T sebesar 70%. Jika laba T yang telah disesuaikan Rp100 juta, berapa total bagian laba T yang diatribusikan kepada KNP dalam konsolidasi?","options":["Rp30 juta","Rp32,5 juta","Rp37,5 juta","Rp40 juta"],"correct":"C","concept":"KNP berlapis","explanation":"Jawaban yang benar adalah C. KNP eksternal T memiliki 30% langsung, sehingga memperoleh Rp30 juta. Bagian laba T yang masuk melalui S adalah 30% × Rp100 juta = Rp30 juta. Karena KNP S memiliki 25% S, KNP S menikmati 25% × Rp30 juta = Rp7,5 juta. Total laba T yang diatribusikan kepada KNP = Rp30 juta + Rp7,5 juta = Rp37,5 juta. Bagian pemilik induk adalah 40% langsung ditambah 75% × 30% = 62,5%.","whyOthersWrong":"A hanya KNP langsung T. B menggunakan persentase ekonomi yang tidak lengkap. D mengabaikan struktur kepemilikan S.","tip":"Pisahkan KNP pada T dan bagian KNP S atas pendapatan investasi S dari T.","reference":"TM 4 – Indirect Holding: Connecting Affiliates","keywords":"KNP T; KNP S; connecting affiliates"},{"number":19,"topic":"Transaksi Mata Uang Asing","subtopic":"Transaksi lintas periode","learningOutcome":"Memisahkan selisih kurs antarperiode","difficulty":"Sulit","type":"Mini Kasus","question":"Piutang USD40.000 timbul 1 Desember pada kurs Rp15.000/USD. Kurs 31 Desember Rp15.300/USD dan piutang dilunasi 31 Januari pada kurs Rp15.200/USD. Berapa selisih kurs pada tahun pertama dan tahun kedua?","options":["Tahun 1 untung Rp8 juta; tahun 2 nihil","Tahun 1 untung Rp12 juta; tahun 2 rugi Rp4 juta","Tahun 1 untung Rp12 juta; tahun 2 untung Rp4 juta","Tahun 1 rugi Rp12 juta; tahun 2 untung Rp4 juta"],"correct":"B","concept":"Pemisahan gain/loss berdasarkan periode","explanation":"Jawaban yang benar adalah B. Tahun pertama: nilai piutang naik dari Rp600 juta menjadi Rp612 juta, sehingga terdapat keuntungan Rp12 juta. Tahun kedua: saldo awal Rp612 juta diselesaikan dengan kas Rp608 juta, sehingga timbul rugi Rp4 juta. Perubahan kurs tidak boleh seluruhnya dicatat pada tahun penyelesaian. Tanggal transaksi, tanggal pelaporan, dan tanggal penyelesaian membentuk tiga titik pengukuran yang memisahkan dampak ke laba rugi masing-masing periode.","whyOthersWrong":"A salah menghitung perubahan tahun pertama. C salah karena penurunan kurs setelah pelaporan menimbulkan rugi pada piutang. D membalik kedua arah.","tip":"Buat timeline tiga tanggal dan bandingkan nilai tercatat hanya dengan tanggal sebelumnya.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"cut-off; kurs pelaporan; settlement"},{"number":20,"topic":"Translasi Laporan Keuangan","subtopic":"Balancing figure CTA","learningOutcome":"Menentukan saldo CTA dari laporan posisi keuangan terjemahan","difficulty":"Sedang","type":"Mini Kasus","question":"Setelah translasi, total aset Rp9.800 juta. Liabilitas Rp4.100 juta, modal saham Rp2.000 juta, saldo laba terjemahan Rp3.200 juta, dan KNP Rp300 juta. Berapa CTA agar laporan posisi keuangan seimbang?","options":["Debit Rp200 juta","Kredit Rp500 juta","Debit Rp500 juta","Kredit Rp200 juta"],"correct":"D","concept":"Selisih translasi sebagai komponen ekuitas","explanation":"Jawaban yang benar adalah D. Ekuitas dan liabilitas tanpa CTA = Rp4.100 juta + Rp2.000 juta + Rp3.200 juta + Rp300 juta = Rp9.600 juta. Agar sama dengan aset Rp9.800 juta, diperlukan CTA kredit Rp200 juta sebagai tambahan komponen ekuitas/OCI. CTA boleh menjadi balancing figure hanya setelah semua akun telah diterjemahkan dengan kurs yang tepat. Angka tersebut bukan tempat untuk menyembunyikan kesalahan klasifikasi kurs atau kesalahan roll-forward saldo laba.","whyOthersWrong":"A memiliki arah yang berlawanan. B dan C menggunakan selisih Rp500 juta yang tidak sesuai rekonsiliasi.","tip":"Gunakan persamaan aset = liabilitas + modal + saldo laba + KNP + CTA.","reference":"TM 6 – Laporan Keuangan dalam Mata Uang Asing","keywords":"CTA; keseimbangan laporan posisi keuangan"},{"number":21,"topic":"Transaksi Mata Uang Asing","subtopic":"Remeasurement versus translation","learningOutcome":"Membedakan lokasi pengakuan dampak perubahan kurs","difficulty":"Mudah","type":"Perbandingan","question":"Utang USD10.000 tercatat pada Rp15.000/USD dan kurs penutup Rp15.400/USD. Pada saat yang sama, aset neto operasi asing FC10.000 berubah dengan selisih kurs ekuivalen Rp4 juta. Pernyataan yang PALING TEPAT adalah…","options":["Keduanya masuk laba rugi","Keduanya masuk OCI","Utang menghasilkan rugi Rp4 juta di laba rugi, sedangkan selisih translasi aset neto masuk OCI","Utang masuk OCI, sedangkan translasi masuk laba rugi"],"correct":"C","concept":"Perbedaan tujuan dan lokasi pengakuan","explanation":"Jawaban yang benar adalah C. Pengukuran kembali utang moneter dalam mata uang fungsional menghasilkan rugi selisih kurs Rp4 juta pada laba rugi karena kewajiban rupiah meningkat. Sebaliknya, translasi laporan keuangan operasi asing ke mata uang penyajian menghasilkan selisih translasi yang umumnya dicatat pada OCI sebagai CTA. Kedua proses sama-sama menggunakan kurs, tetapi tujuan dan lokasi pengakuannya berbeda. Remeasurement mengukur transaksi atau saldo dalam mata uang fungsional; translation mengubah laporan dari mata uang fungsional ke mata uang penyajian.","whyOthersWrong":"A dan B menyamakan dua proses yang berbeda. D membalik lokasi pengakuan.","tip":"Ingat: transaksi moneter → laba rugi; laporan operasi asing → OCI/CTA.","reference":"TM 5 dan TM 6 – Valas serta Translasi","keywords":"remeasurement; translation; P&L; OCI"},{"number":22,"topic":"Transaksi Mata Uang Asing","subtopic":"Direct dan indirect quotation","learningOutcome":"Membandingkan dua bentuk kuotasi kurs","difficulty":"Sedang","type":"Perbandingan","question":"Jika kurs langsung adalah Rp15.500/USD, berapa kurs tidak langsung dan nilai rupiah untuk USD2.000?","options":["USD0,000065/Rp dan Rp30.000.000","USD0,000064516/Rp dan Rp31.000.000","USD0,000064516/Rp dan Rp30.000.000","USD0,000065/Rp dan Rp31.500.000"],"correct":"B","concept":"Hubungan resiprokal antar-kuotasi","explanation":"Jawaban yang benar adalah B. Kurs tidak langsung adalah kebalikan kurs langsung: 1 ÷ 15.500 = sekitar USD0,000064516 per rupiah. Nilai rupiah USD2.000 = 2.000 × Rp15.500 = Rp31.000.000. Kuotasi langsung menyatakan jumlah rupiah untuk satu unit valuta asing, sedangkan kuotasi tidak langsung menyatakan jumlah valuta asing untuk satu rupiah. Keduanya menggambarkan nilai yang sama dan harus menghasilkan hasil konversi yang konsisten.","whyOthersWrong":"A salah pada hasil rupiah. C salah pada hasil rupiah. D memakai pembulatan dan nilai konversi yang tidak konsisten.","tip":"Indirect quote = 1/direct quote. Untuk mengubah USD ke rupiah dengan direct quote, kalikan.","reference":"TM 5 – Transaksi dalam Mata Uang Asing","keywords":"direct quotation; reciprocal rate"},{"number":23,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Perolehan kendali versus transaksi ekuitas","learningOutcome":"Membedakan remeasurement dan penyesuaian ekuitas","difficulty":"Sulit","type":"Perbandingan","question":"P memiliki 40% S dengan nilai tercatat Rp420 juta dan nilai wajar Rp500 juta. P membeli 30% lagi dan memperoleh kendali. Setelah itu P membeli tambahan 10% dari KNP seharga Rp150 juta saat nilai tercatat KNP yang dipindahkan Rp120 juta. Kombinasi dampak yang benar adalah…","options":["Gain remeasurement Rp30 juta dan goodwill baru Rp30 juta","Gain remeasurement Rp80 juta dan laba transaksi KNP Rp30 juta","Tidak ada gain remeasurement dan ekuitas bertambah Rp30 juta","Gain remeasurement Rp80 juta dan ekuitas induk berkurang Rp30 juta"],"correct":"D","concept":"Perubahan model akuntansi berdasarkan kendali","explanation":"Jawaban yang benar adalah D. Pada saat kendali pertama kali diperoleh, kepentingan lama diukur kembali dari Rp420 juta menjadi Rp500 juta sehingga timbul gain Rp80 juta pada laba rugi. Pembelian tambahan setelah kendali dipertahankan adalah transaksi ekuitas. Karena kas dibayar Rp150 juta melebihi nilai tercatat KNP Rp120 juta, ekuitas induk berkurang Rp30 juta. Tidak ada goodwill baru dan tidak ada laba rugi untuk pembelian pascakendali.","whyOthersWrong":"A salah menghitung gain dan menciptakan goodwill baru. B salah menempatkan selisih KNP ke laba. C mengabaikan remeasurement.","tip":"Tandai apakah transaksi menciptakan kendali atau terjadi setelah kendali. Perlakuannya berubah total.","reference":"TM 1 dan TM 2 – Akuisisi Bertahap serta Perubahan Kepemilikan","keywords":"step acquisition; post-control acquisition"},{"number":24,"topic":"Indirect Holding","subtopic":"Alokasi laba dan CTA berjenjang","learningOutcome":"Menganalisis bagian induk atas laba dan OCI operasi asing tidak langsung","difficulty":"Sulit","type":"Analisis","question":"P memiliki 80% S dan S memiliki 75% T, sebuah operasi asing. Laba T yang telah disesuaikan adalah FC200 ribu dan kurs rata-rata Rp15.000/FC. Rugi CTA T dalam rupiah Rp120 juta. Berapa bagian P atas laba T dan rugi CTA T?","options":["Laba Rp1.800 juta dan rugi CTA Rp72 juta","Laba Rp2.250 juta dan rugi CTA Rp90 juta","Laba Rp3.000 juta dan rugi CTA Rp120 juta","Laba Rp1.800 juta dan rugi CTA Rp120 juta"],"correct":"A","concept":"Alokasi berjenjang laba dan OCI","explanation":"Jawaban yang benar adalah A. Kepemilikan efektif P atas T = 80% × 75% = 60%. Laba T dalam rupiah = FC200 ribu × Rp15.000 = Rp3.000 juta. Bagian P = 60% × Rp3.000 juta = Rp1.800 juta. Rugi CTA juga dialokasikan berdasarkan kepentingan ekonomi yang relevan: 60% × Rp120 juta = Rp72 juta. Laba dan OCI harus dijaga terpisah selama alokasi bottom-up karena keduanya masuk komponen laporan yang berbeda.","whyOthersWrong":"B menggunakan 75% saja. C mengatribusikan seluruh laba dan CTA kepada P. D tidak membagi CTA kepada KNP.","tip":"Hitung persentase efektif, translasi laba dengan average rate, lalu alokasikan laba dan CTA secara terpisah.","reference":"TM 3, TM 4, dan TM 6 – Indirect Holding serta Translasi","keywords":"indirect holding; translation; OCI"},{"number":25,"topic":"Translasi Laporan Keuangan","subtopic":"Akuisisi operasi asing tengah tahun","learningOutcome":"Menganalisis laba pascaakuisisi, excess, translasi, dan atribusi","difficulty":"Sulit","type":"Analisis","question":"P memperoleh 80% S, operasi asing, pada 1 Juli. Laba S setahun FC240 ribu dan terjadi merata. Tambahan depresiasi excess adalah FC24 ribu per tahun sejak akuisisi. Kurs rata-rata Juli–Desember Rp15.000/FC. Berapa bagian laba terjemahan yang diatribusikan kepada P?","options":["Rp1.296 juta","Rp1.440 juta","Rp2.592 juta","Rp324 juta"],"correct":"A","concept":"Integrasi timeline akuisisi dan timeline kurs","explanation":"Jawaban yang benar adalah A. Laba pascaakuisisi enam bulan = FC240 ribu × 6/12 = FC120 ribu. Tambahan depresiasi excess enam bulan = FC24 ribu × 6/12 = FC12 ribu. Laba yang telah disesuaikan = FC108 ribu. Bagian P = 80% × FC108 ribu = FC86,4 ribu. Diterjemahkan pada kurs rata-rata pascaakuisisi: FC86,4 ribu × Rp15.000 = Rp1.296 juta. Bagian KNP adalah Rp324 juta.","whyOthersWrong":"B tidak mengurangi depresiasi excess. C memakai laba setahun penuh. D adalah bagian KNP, bukan bagian P.","tip":"Susun dua timeline berdampingan: tanggal kendali untuk laba dan periode kurs untuk translasi.","reference":"TM 1 dan TM 6 – Akuisisi Tengah Tahun serta Translasi","keywords":"interim acquisition; foreign operation; excess depreciation"}],"flashcards":[{"number":1,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Interim acquisition","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud interim acquisition?","shortAnswer":"Perolehan kendali atas entitas anak di tengah periode pelaporan.","explanation":"Pada interim acquisition, laporan laba rugi anak harus dipisahkan antara periode sebelum dan sesudah tanggal kendali. Hanya pendapatan dan beban setelah tanggal akuisisi yang masuk laba rugi konsolidasian. Aset dan liabilitas anak tetap dikonsolidasikan pada tanggal pelaporan karena kendali sudah ada pada akhir periode.","example":"P memperoleh S pada 1 April. Jika laba setahun Rp120 juta merata, laba pascaakuisisi adalah 9/12 × Rp120 juta = Rp90 juta.","keywords":"tanggal kendali; laba pascaakuisisi; cut-off","comparison":"Akuisisi awal tahun: tidak memerlukan pemotongan laba praakuisisi dalam periode berjalan.","mnemonic":"INGAT 'TANGGAL DULU, LABA KEMUDIAN'."},{"number":2,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Piecemeal acquisition","difficulty":"Mudah","type":"Definisi","question":"Apa inti perlakuan akuisisi bertahap saat kendali diperoleh?","shortAnswer":"Kepentingan lama diukur kembali pada nilai wajar tanggal kendali.","explanation":"Ketika pembelian tambahan mengubah investor menjadi pengendali, kepentingan yang telah dimiliki tidak lagi dipertahankan pada nilai tercatat historis. Selisih nilai wajar dan nilai tercatat diakui sebagai gain atau loss remeasurement. Nilai wajar kepentingan lama kemudian menjadi salah satu komponen perhitungan goodwill.","example":"Nilai tercatat 30% saham Rp420 juta dan nilai wajarnya Rp500 juta. Gain remeasurement = Rp80 juta.","keywords":"remeasurement; nilai wajar; tanggal kendali","comparison":"Pembelian tambahan setelah kendali: transaksi ekuitas dan tidak memakai remeasurement.","mnemonic":"STEP = Saham Terdahulu Evaluasi pada Pasar."},{"number":3,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Transaksi ekuitas","difficulty":"Mudah","type":"Definisi","question":"Kapan perubahan kepemilikan anak disebut transaksi ekuitas?","shortAnswer":"Saat persentase berubah tetapi induk tetap mempertahankan kendali.","explanation":"Perubahan kepemilikan tanpa kehilangan kendali dipandang sebagai transaksi antara pemilik induk dan KNP. Nilai tercatat KNP disesuaikan, sedangkan selisih dengan imbalan dicatat langsung pada ekuitas induk. Tidak ada laba rugi pelepasan dan tidak timbul goodwill baru.","example":"Harga beli tambahan Rp145 juta dan KNP yang dihentikan Rp120 juta. Ekuitas induk berkurang Rp25 juta.","keywords":"kendali tetap; KNP; ekuitas induk","comparison":"Kehilangan kendali: dekonsolidasi dan laba/rugi pelepasan.","mnemonic":"KENDALI TETAP = KE EKUITAS."},{"number":4,"topic":"Indirect Holding","subtopic":"Kepemilikan efektif","difficulty":"Mudah","type":"Definisi","question":"Bagaimana menghitung kepemilikan efektif dalam struktur P–S–T?","shortAnswer":"Kalikan persentase pada setiap jalur kepemilikan.","explanation":"Kepemilikan efektif menunjukkan bagian ekonomi pemilik induk atas entitas cucu. Rumus jalur sederhana adalah persentase P pada S dikali persentase S pada T. Hasilnya digunakan untuk alokasi ekonomi, bukan untuk menentukan persentase aset dan liabilitas yang dikonsolidasikan.","example":"P memiliki 80% S dan S memiliki 70% T. Kepemilikan efektif P atas T = 56%.","keywords":"jalur kepemilikan; bagian ekonomi; kontrol","comparison":"Kepemilikan kelompok dapat berbeda dari kepemilikan ekonomi pemilik induk.","mnemonic":"JALUR SEARAH = KALI."},{"number":5,"topic":"Transaksi Mata Uang Asing","subtopic":"Pos moneter","difficulty":"Sedang","type":"Definisi","question":"Apa ciri utama pos moneter valuta asing?","shortAnswer":"Hak menerima atau kewajiban menyerahkan jumlah unit mata uang yang tetap atau dapat ditentukan.","explanation":"Piutang, utang, dan kas valuta asing merupakan pos moneter karena penyelesaiannya berupa sejumlah mata uang tertentu. Pada tanggal pelaporan, pos moneter diukur kembali menggunakan kurs penutup. Selisih dari nilai tercatat sebelumnya umumnya diakui pada laba rugi.","example":"Utang USD50.000 naik dari kurs Rp15.100 menjadi Rp15.350. Kerugian kurs = USD50.000 × Rp250 = Rp12,5 juta.","keywords":"kurs penutup; piutang; utang; remeasurement","comparison":"Uang muka barang nonrefundable biasanya nonmoneter karena diselesaikan dengan barang.","mnemonic":"MONETER = MENERIMA/MENYERAHKAN MATA UANG."},{"number":6,"topic":"Translasi Laporan Keuangan","subtopic":"CTA","difficulty":"Sedang","type":"Definisi","question":"Apa itu cumulative translation adjustment (CTA)?","shortAnswer":"Selisih translasi yang timbul karena akun laporan keuangan dijabarkan dengan kurs berbeda.","explanation":"Aset dan liabilitas biasanya memakai kurs penutup, pendapatan dan beban memakai kurs transaksi atau rata-rata, sedangkan modal menggunakan kurs historis. Perbedaan kurs ini menimbulkan CTA yang disajikan dalam OCI dan terakumulasi dalam ekuitas. CTA bukan selisih kurs transaksi moneter biasa.","example":"Aset neto akhir terjemahan Rp17.250 juta dan roll-forward ekuitas tanpa CTA Rp16.175 juta. CTA = Rp1.075 juta.","keywords":"OCI; kurs penutup; kurs historis; kurs rata-rata","comparison":"Exchange gain/loss transaksi moneter biasanya masuk laba rugi.","mnemonic":"CTA = Cerminan Tiga kurs Akun."},{"number":7,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"KNP","difficulty":"Mudah","type":"Istilah","question":"Apa fungsi roll-forward KNP?","shortAnswer":"Menjelaskan perubahan saldo KNP dari awal sampai akhir periode.","explanation":"Roll-forward KNP memasukkan saldo awal, bagian laba, dividen, OCI, amortisasi excess, dan transaksi perubahan kepemilikan. Jadwal ini memastikan nilai KNP yang dipakai untuk pembelian tambahan atau penjualan sebagian sudah mutakhir pada tanggal transaksi.","example":"Rp180 juta + laba Rp50 juta − dividen Rp10 juta − rugi OCI Rp6 juta = Rp214 juta.","keywords":"saldo awal; laba; dividen; OCI","comparison":"Saldo KNP tanggal akuisisi belum tentu sama dengan saldo KNP pada tanggal transaksi berikutnya.","mnemonic":"KNP = Kini + Net profit − Pembagian ± OCI."},{"number":8,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Excess value","difficulty":"Mudah","type":"Istilah","question":"Apa yang dimaksud excess value dalam konsolidasi?","shortAnswer":"Selisih nilai wajar aset neto teridentifikasi terhadap nilai bukunya pada tanggal akuisisi.","explanation":"Excess value dialokasikan ke aset atau liabilitas tertentu dan memengaruhi beban setelah akuisisi melalui depresiasi atau amortisasi tambahan. Dalam struktur berlapis, excess P–S dan S–T dibuat dalam schedule terpisah karena memiliki tanggal dan masa manfaat berbeda.","example":"Kenaikan nilai peralatan Rp120 juta dengan umur 5 tahun menghasilkan tambahan depresiasi Rp24 juta per tahun.","keywords":"fair value adjustment; amortisasi; tanggal akuisisi","comparison":"Goodwill adalah residual setelah aset neto teridentifikasi diukur pada nilai wajar.","mnemonic":"EXCESS menempel pada ASET; GOODWILL adalah SISA."},{"number":9,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Deemed disposal","difficulty":"Mudah","type":"Istilah","question":"Apa yang dimaksud deemed disposal?","shortAnswer":"Penurunan persentase kepemilikan tanpa induk menjual saham secara langsung.","explanation":"Deemed disposal dapat terjadi ketika anak menerbitkan saham baru kepada pihak lain atau instrumen dilutif dieksekusi. Dampaknya tetap bergantung pada keberadaan kendali. Jika kendali tetap, selisih dicatat pada ekuitas. Jika kendali hilang, anak didekonsolidasi.","example":"S menerbitkan saham baru seluruhnya kepada pihak luar sehingga kepemilikan P turun dari 80% menjadi 65%.","keywords":"dilusi; penerbitan saham; kendali","comparison":"Partial disposal terjadi karena induk benar-benar menjual sebagian saham.","mnemonic":"DEEMED = DIANGGAP melepas, meski tidak menjual."},{"number":10,"topic":"Transaksi Mata Uang Asing","subtopic":"Direct quotation","difficulty":"Mudah","type":"Istilah","question":"Apa arti kurs langsung Rp15.500/USD?","shortAnswer":"Satu dolar AS setara dengan Rp15.500.","explanation":"Kurs langsung menyatakan jumlah mata uang domestik untuk satu unit valuta asing. Untuk mengubah dolar menjadi rupiah, jumlah dolar dikalikan kurs langsung. Kurs tidak langsung merupakan kebalikannya, yaitu jumlah valuta asing untuk satu unit mata uang domestik.","example":"USD2.000 × Rp15.500 = Rp31.000.000.","keywords":"domestic per foreign; konversi; reciprocal","comparison":"Kurs tidak langsung = 1 ÷ kurs langsung.","mnemonic":"DIRECT: DOMESTIK per satu unit asing."},{"number":11,"topic":"Translasi Laporan Keuangan","subtopic":"Kurs rata-rata","difficulty":"Sedang","type":"Istilah","question":"Kapan kurs rata-rata boleh digunakan dalam translasi laba rugi?","shortAnswer":"Saat transaksi terjadi merata dan kurs rata-rata mendekati kurs aktual.","explanation":"Kurs rata-rata merupakan pendekatan praktis untuk banyak transaksi pendapatan dan beban selama periode. Namun, pendekatan ini tidak tepat jika kurs sangat berfluktuasi atau terdapat transaksi besar pada tanggal tertentu. Dalam kasus tersebut, kurs tanggal transaksi lebih representatif.","example":"Penjualan rutin bulanan dapat memakai kurs rata-rata tahunan; penjualan besar sekali pada akhir tahun sebaiknya memakai kurs tanggal transaksi.","keywords":"average rate; pendekatan; volatilitas","comparison":"Aset dan liabilitas akhir umumnya memakai kurs penutup, bukan kurs rata-rata.","mnemonic":"RATA-RATA hanya saat transaksi RATA."},{"number":12,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Urutan penyelesaian","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan aman menyelesaikan akuisisi tengah tahun?","shortAnswer":"Tanggal kendali → potong laba → hitung excess/goodwill → alokasikan laba → eliminasi.","explanation":"Urutan dimulai dengan memastikan tanggal kendali, kemudian memisahkan laba dan dividen pra serta pascaakuisisi. Setelah itu, ukur aset neto dan excess value, hitung goodwill serta KNP, alokasikan laba pascaakuisisi yang telah disesuaikan, lalu susun eliminasi dan rekonsiliasi investasi.","example":"Akuisisi 1 April berarti laba dan amortisasi excess hanya dihitung untuk sembilan bulan.","keywords":"timeline; goodwill; KNP; eliminasi","comparison":"Akuisisi awal tahun tidak membutuhkan pemotongan laba praakuisisi tahun berjalan.","mnemonic":"TAHAP: Tanggal–Alokasi waktu–Harga/excess–Atribusi–Posting."},{"number":13,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Loss of control","difficulty":"Sedang","type":"Tahapan","question":"Apa tahapan menghitung laba rugi saat kendali hilang?","shortAnswer":"Ukur imbalan dan retained interest, hentikan aset neto/goodwill/KNP, lalu hitung selisih.","explanation":"Pertama perbarui seluruh saldo sampai tanggal pelepasan. Kedua ukur kas atau imbalan yang diterima dan nilai wajar kepentingan tersisa. Ketiga hentikan aset, liabilitas, goodwill, KNP, dan komponen ekuitas terkait. Selisih bersih diakui sebagai laba atau rugi pelepasan.","example":"Kas Rp700 + retained interest Rp250 + KNP Rp200 − aset neto dan goodwill Rp1.000 = gain Rp150 juta.","keywords":"deconsolidation; retained interest; KNP","comparison":"Jika kendali tetap, tidak ada deconsolidation dan selisih masuk ekuitas.","mnemonic":"TERIMA + TERSISA + KNP − NETO."},{"number":14,"topic":"Indirect Holding","subtopic":"Alokasi bottom-up","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan alokasi laba pada struktur P–S–T?","shortAnswer":"Sesuaikan laba T → alokasikan ke S/KNP T → sesuaikan laba S → alokasikan ke P/KNP S.","explanation":"Perhitungan dimulai dari entitas terbawah. Laba T dikurangi amortisasi excess dan laba belum terealisasi, kemudian dibagi kepada S dan KNP T. Bagian S atas T menjadi komponen laba S. Setelah laba S disesuaikan, barulah dialokasikan kepada P dan KNP S.","example":"Laba T Rp150 juta × 70% = Rp105 juta untuk S; kemudian × 80% = Rp84 juta untuk P.","keywords":"bottom-up; adjusted income; KNP berlapis","comparison":"Top-down berisiko mengalokasikan laba sebelum penyesuaian entitas terbawah selesai.","mnemonic":"MULAI DARI CUCU, NAIK KE INDUK."},{"number":15,"topic":"Translasi Laporan Keuangan","subtopic":"Roll-forward saldo laba dan CTA","difficulty":"Sulit","type":"Tahapan","question":"Apa urutan membentuk saldo laba terjemahan dan CTA?","shortAnswer":"Saldo laba awal terjemahan + laba terjemahan − dividen terjemahan, lalu rekonsiliasi terhadap aset neto akhir.","explanation":"Saldo laba tidak diterjemahkan langsung dengan kurs penutup. Saldo tersebut dibentuk melalui roll-forward memakai saldo awal historis, laba periode yang diterjemahkan dengan kurs transaksi atau rata-rata, serta dividen dengan kurs tanggal deklarasi atau kurs yang ditentukan soal. CTA kemudian menjadi selisih rekonsiliasi ekuitas terhadap aset neto akhir pada kurs penutup.","example":"Rp14.000 + Rp2.900 − Rp725 = Rp16.175; aset neto akhir Rp17.250, sehingga CTA Rp1.075 juta.","keywords":"retained earnings; historical rate; CTA","comparison":"Aset dan liabilitas akhir umumnya langsung memakai closing rate.","mnemonic":"RE dibangun, CTA direkonsiliasi."},{"number":16,"topic":"Indirect Holding","subtopic":"Kontrol vs kepemilikan ekonomi","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan kontrol dan kepemilikan efektif?","shortAnswer":"Kontrol menentukan konsolidasi; kepemilikan efektif menentukan bagian ekonomi.","explanation":"Entitas cucu dapat dikonsolidasikan penuh meskipun kepemilikan efektif induk kurang dari 50%, selama rantai kendali tetap ada. Persentase efektif dipakai untuk mengalokasikan laba, OCI, dan ekuitas kepada pemilik induk serta KNP.","example":"P 80% S dan S 60% T: P efektif 48% T, tetapi T tetap dikonsolidasikan 100%.","keywords":"control; economic interest; full consolidation","comparison":"Persentase saham langsung tidak selalu sama dengan bagian ekonomi akhir.","mnemonic":"KONTROL menjawab 'masuk atau tidak'; EFEKTIF menjawab 'bagian siapa'."},{"number":17,"topic":"Transaksi Mata Uang Asing","subtopic":"Remeasurement vs translation","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda utama remeasurement dan translation?","shortAnswer":"Remeasurement menghasilkan angka dalam mata uang fungsional; translation mengubahnya ke mata uang penyajian.","explanation":"Remeasurement digunakan untuk transaksi atau saldo yang bukan dalam mata uang fungsional dan selisihnya umumnya masuk laba rugi. Translation dilakukan terhadap laporan operasi asing dari mata uang fungsional ke mata uang penyajian, dengan selisih umumnya masuk OCI sebagai CTA.","example":"Utang USD pada entitas rupiah diukur kembali ke rupiah; laporan anak berfungsi USD diterjemahkan ke rupiah.","keywords":"functional currency; presentation currency; P&L; OCI","comparison":"Keduanya memakai kurs, tetapi tujuan dan lokasi selisih berbeda.","mnemonic":"REMEASURE = fungsi; TRANSLATE = penyajian."},{"number":18,"topic":"Transaksi Mata Uang Asing","subtopic":"Moneter vs nonmoneter","difficulty":"Sulit","type":"Perbandingan","question":"Bagaimana membedakan pos moneter dan nonmoneter secara cepat?","shortAnswer":"Lihat bentuk penyelesaian: unit mata uang tetap atau barang/jasa/aset.","explanation":"Pos moneter diselesaikan dengan jumlah mata uang tetap atau dapat ditentukan dan diukur kembali memakai kurs penutup. Pos nonmoneter historis tidak diukur kembali hanya karena kurs berubah. Penentuan didasarkan pada substansi hak atau kewajiban, bukan nama akun.","example":"Deposit refundable USD adalah moneter; uang muka pembelian barang nonrefundable biasanya nonmoneter.","keywords":"settlement; closing rate; historical cost","comparison":"Piutang barang berbeda dari piutang kas; fokus pada apa yang akan diterima.","mnemonic":"KAS TETAP = MONETER; BARANG/JASA = NONMONETER."},{"number":19,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Tanggal kendali vs pascakendali","difficulty":"Sulit","type":"Perbandingan","question":"Apa beda akuntansi pembelian yang menciptakan kendali dan pembelian setelah kendali?","shortAnswer":"Perolehan kendali memakai remeasurement dan goodwill; pembelian pascakendali masuk ekuitas.","explanation":"Saat kendali diperoleh, kombinasi bisnis diukur pada tanggal kendali, kepentingan lama dinilai kembali, dan goodwill dihitung. Setelah kendali ada, pembelian dari KNP hanya mengubah pembagian ekuitas antara induk dan KNP. Tidak ada remeasurement kepentingan lama dan tidak ada goodwill tambahan.","example":"Gain remeasurement Rp80 juta saat kendali diperoleh; kemudian harga tambahan Rp150 versus KNP Rp120 mengurangi ekuitas Rp30 juta.","keywords":"control date; goodwill; equity transaction","comparison":"Kehilangan kendali justru menyebabkan deconsolidation dan gain/loss pelepasan.","mnemonic":"DAPAT KENDALI = GOODWILL; TETAP KENDALI = EKUITAS."},{"number":20,"topic":"Akuisisi Tahun Berjalan & Bertahap","subtopic":"Perhitungan goodwill","difficulty":"Sedang","type":"Penerapan","question":"Bagaimana menghitung goodwill pada step acquisition?","shortAnswer":"FV kepentingan lama + imbalan baru + FV KNP − FV aset neto teridentifikasi.","explanation":"Semua komponen diukur pada tanggal kendali. Kepentingan lama harus menggunakan nilai wajar, bukan nilai tercatat. Jika hasil perhitungan negatif setelah penilaian ulang, kemungkinan terdapat gain pembelian murah, bukan goodwill negatif.","example":"Rp360 + Rp640 + Rp260 − Rp1.100 = goodwill Rp160 juta.","keywords":"old interest FV; consideration; NCI; net assets","comparison":"Goodwill pada pembelian tambahan pascakendali tidak dihitung ulang.","mnemonic":"LAMA + BARU + KNP − NETO."},{"number":21,"topic":"Transaksi Mata Uang Asing","subtopic":"Selisih kurs utang","difficulty":"Sedang","type":"Penerapan","question":"Bagaimana menghitung rugi kurs utang saat kurs naik?","shortAnswer":"Nominal valuta asing × (kurs penutup − kurs awal).","explanation":"Utang valuta asing adalah pos moneter. Ketika valuta asing menguat terhadap rupiah, jumlah rupiah yang harus dibayar meningkat dan selisih tersebut menjadi rugi kurs. Perhitungan harus membandingkan nilai tercatat baru dengan nilai pada tanggal pengukuran sebelumnya.","example":"USD50.000 × (Rp15.350 − Rp15.100) = rugi Rp12.500.000.","keywords":"payable; closing rate; exchange loss","comparison":"Untuk piutang, kenaikan kurs justru menghasilkan keuntungan.","mnemonic":"UTANG + KURS NAIK = BEBAN NAIK."},{"number":22,"topic":"Connecting Affiliates","subtopic":"Alokasi KNP berlapis","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menghitung total KNP atas laba T pada struktur P–S–T dengan kepemilikan langsung P dan S?","shortAnswer":"Jumlahkan KNP langsung T dan bagian KNP S atas pendapatan S dari T.","explanation":"Connecting affiliates menciptakan dua sumber KNP. Pertama, saham T yang tidak dimiliki kelompok. Kedua, bagian pemegang KNP S atas laba investasi S di T. Keduanya harus dihitung terpisah agar laba pemilik induk tidak terlalu tinggi.","example":"P 75% S, P 40% T, S 30% T, laba T Rp100 juta: KNP T Rp30 juta + KNP S Rp7,5 juta = Rp37,5 juta.","keywords":"KNP T; KNP S; direct and indirect path","comparison":"Menjumlahkan 30% KNP T saja mengabaikan hak KNP S.","mnemonic":"KNP LUAR T + KNP DALAM S."},{"number":23,"topic":"Perubahan Kepemilikan Entitas Anak","subtopic":"Saham treasuri anak","difficulty":"Sulit","type":"Mini Kasus","question":"S membeli 400 sahamnya dari KNP. Apa yang harus diperiksa sebelum menentukan dampak pada P?","shortAnswer":"Jumlah saham beredar baru, persentase efektif P, dan harga beli dibanding nilai buku per saham.","explanation":"Pembelian saham treasuri oleh anak menurunkan denominator saham beredar sehingga persentase efektif induk dapat meningkat tanpa membeli saham. Dampak pada bagian ekuitas induk bergantung pada harga pembelian saham treasuri relatif terhadap nilai buku per saham. Selama kendali tetap, dampak diperlakukan sebagai transaksi ekuitas.","example":"P memiliki 8.000 dari 10.000 saham. Setelah S membeli 400 saham KNP, persentase P menjadi 8.000/9.600 = 83,33%.","keywords":"treasury shares; shares outstanding; effective ownership","comparison":"Penerbitan saham baru anak memperbesar denominator dan dapat menurunkan persentase P.","mnemonic":"TREASURI TURUN denominator, PERSENTASE NAIK."},{"number":24,"topic":"Transaksi Mata Uang Asing","subtopic":"Transaksi lintas tahun","difficulty":"Sulit","type":"Mini Kasus","question":"Piutang USD40.000: kurs transaksi 15.000, akhir tahun 15.300, penyelesaian 15.200. Apa dampaknya per periode?","shortAnswer":"Tahun pertama untung Rp12 juta; tahun kedua rugi Rp4 juta.","explanation":"Nilai piutang naik Rp300 per USD sampai akhir tahun, sehingga gain = USD40.000 × Rp300 = Rp12 juta. Pada tahun berikutnya kurs turun Rp100 dari nilai tercatat akhir tahun, sehingga rugi = USD40.000 × Rp100 = Rp4 juta. Setiap periode hanya mengakui perubahan sejak titik pengukuran sebelumnya.","example":"Saldo: Rp600 juta → Rp612 juta → kas Rp608 juta.","keywords":"timeline; cut-off; settlement","comparison":"Mengakui net gain Rp8 juta seluruhnya pada tahun kedua melanggar cut-off.","mnemonic":"T–P–S: Transaksi, Pelaporan, Settlement."},{"number":25,"topic":"Indirect Holding","subtopic":"Operasi asing tidak langsung","difficulty":"Sulit","type":"Mini Kasus","question":"P 80% S dan S 75% T. T laba FC200 ribu pada kurs rata-rata Rp15.000. Berapa bagian laba P?","shortAnswer":"Rp1.800 juta.","explanation":"Kepemilikan efektif P = 80% × 75% = 60%. Laba T diterjemahkan lebih dahulu: FC200 ribu × Rp15.000 = Rp3.000 juta. Bagian ekonomi P = 60% × Rp3.000 juta = Rp1.800 juta. Jika T juga memiliki CTA, OCI tersebut dialokasikan terpisah menggunakan jalur kepemilikan yang sama.","example":"CTA rugi Rp120 juta menghasilkan bagian rugi P sebesar 60% × Rp120 juta = Rp72 juta.","keywords":"effective ownership; average rate; CTA allocation","comparison":"Total kepemilikan kelompok atas T adalah 75%, tetapi bagian ekonomi P hanya 60%.","mnemonic":"TRANSLASI DULU, ALOKASI KEMUDIAN."}]},"akuntansi-kontemporer":{"id":"akuntansi-kontemporer","title":"Akuntansi Kontemporer","short":"Akuntansi Kontemporer","konsen":["audit"],"quiz":[{"number":1,"topic":"Perkembangan SAK","subtopic":"Pilar SAK Indonesia","learningOutcome":"Mengidentifikasi pilar standar yang tepat","difficulty":"Mudah","type":"Definisi","question":"Dalam Kerangka Standar Pelaporan Keuangan Indonesia (KSPKI), standar yang menggantikan SAK ETAP sebagai Pilar 3 adalah ...","options":["SAK Indonesia untuk EMKM","SAK Indonesia untuk Entitas Privat","SAK Internasional","SAK Indonesia (Umum)"],"correct":"B","concept":"Pilar SAK Indonesia","explanation":"Jawaban B benar karena KSPKI menempatkan SAK Indonesia untuk Entitas Privat sebagai Pilar 3 dan standar tersebut menggantikan SAK ETAP. SAK Internasional berada pada Pilar 1, SAK Indonesia atau SAK Umum berada pada Pilar 2, sedangkan SAK Indonesia untuk EMKM berada pada Pilar 4. Pemilihan pilar tidak hanya melihat ukuran usaha, tetapi juga akuntabilitas publik, ketentuan regulator, dan riwayat kerangka pelaporan yang digunakan entitas.","whyOthersWrong":"A adalah Pilar 4 untuk entitas mikro, kecil, dan menengah. C adalah Pilar 1. D adalah Pilar 2 dan memiliki persyaratan pelaporan yang lebih kompleks.","tip":"Ingat urutan pilar: Internasional–Umum–Entitas Privat–EMKM. Fokus pada frasa “menggantikan SAK ETAP”.","reference":"TM 1 — KSPKI dan Pilar SAK; Buddy Brief dan Buddy Drill Akuntansi Kontemporer.","keywords":"KSPKI; Pilar 3; SAKEP"},{"number":2,"topic":"Kerangka Konseptual","subtopic":"Materialitas","learningOutcome":"Menjelaskan arti materialitas","difficulty":"Mudah","type":"Definisi","question":"Pernyataan yang PALING TEPAT mengenai materialitas dalam pelaporan keuangan adalah ...","options":["Seluruh kesalahan harus selalu mengubah keputusan pengguna","Materialitas hanya ditentukan oleh besarnya nilai rupiah","Informasi material jika penghilangan, salah saji, atau pengaburannya dapat memengaruhi keputusan pengguna utama","Pos yang tidak material wajib selalu dikapitalisasi"],"correct":"C","concept":"Materialitas sebagai aspek relevansi","explanation":"Jawaban C benar karena materialitas dinilai dari potensi pengaruh informasi terhadap keputusan pengguna utama laporan keuangan. Penilaian mempertimbangkan besar nilai, sifat transaksi, konteks, tren, kepatuhan, dan kemungkinan pengaburan informasi. Materialitas bukan ambang persentase universal yang berlaku untuk semua entitas. Dalam praktik, entitas dapat memakai parameter kuantitatif sebagai titik awal, tetapi tetap harus melakukan pertimbangan kualitatif dan mendokumentasikan alasan kesimpulannya.","whyOthersWrong":"A terlalu absolut. B mengabaikan sifat dan konteks. D keliru karena pos tidak material dapat diperlakukan secara praktis sepanjang tidak mengaburkan informasi material.","tip":"Cari hubungan dengan “keputusan pengguna”, bukan hanya nominal. Hindari pilihan yang memakai kata selalu atau hanya.","reference":"TM 2 — Karakteristik informasi keuangan dan materialitas; Kerangka Konseptual Pelaporan Keuangan.","keywords":"materialitas; keputusan pengguna"},{"number":3,"topic":"Good Corporate Governance","subtopic":"Teori Keagenan","learningOutcome":"Mengidentifikasi sumber konflik keagenan","difficulty":"Mudah","type":"Definisi","question":"Risiko utama yang dijelaskan teori keagenan ketika kepemilikan terpisah dari pengelolaan adalah ...","options":["Asimetri informasi dan konflik kepentingan","Keseragaman preferensi pemilik dan manajer","Hilangnya kebutuhan pengawasan","Tidak adanya biaya kontrak"],"correct":"A","concept":"Konflik principal–agent","explanation":"Jawaban A benar. Pemisahan pemilik sebagai principal dan manajemen sebagai agent menimbulkan risiko karena manajemen menguasai informasi operasional yang lebih banyak serta dapat memiliki insentif yang berbeda dari pemilik. Kondisi ini menciptakan asimetri informasi, moral hazard, dan biaya keagenan. Mekanisme tata kelola seperti dewan independen, komite audit, transparansi, pengendalian internal, serta insentif jangka panjang dirancang untuk menyelaraskan kepentingan dan meningkatkan akuntabilitas.","whyOthersWrong":"B justru berlawanan dengan asumsi dasar teori keagenan. C dan D mengabaikan kebutuhan monitoring, bonding, serta residual loss.","tip":"Hubungkan kata “pemisahan” dengan dua akibat: informasi tidak seimbang dan kepentingan tidak selalu sama.","reference":"TM 3 — Good Corporate Governance dan agency theory; PUGKI 2021.","keywords":"agency theory; asimetri informasi"},{"number":4,"topic":"Sustainability Accounting","subtopic":"Intensitas Karbon","learningOutcome":"Menjelaskan ukuran intensitas emisi","difficulty":"Mudah","type":"Definisi","question":"Rumus yang tepat untuk menghitung intensitas karbon per unit produksi adalah ...","options":["Jumlah produksi ÷ total emisi","Total biaya energi ÷ total emisi","Total emisi × jumlah produksi","Total emisi ÷ jumlah produksi"],"correct":"D","concept":"Intensitas emisi","explanation":"Jawaban D benar. Intensitas karbon menghubungkan emisi dengan penggerak aktivitas, misalnya unit produksi, pendapatan, luas area, atau ton produk. Rumus dasar per unit produksi adalah total emisi dibagi jumlah unit produksi. Ukuran intensitas membantu membandingkan efisiensi antarperiode ketika skala aktivitas berubah, tetapi tidak menggantikan informasi emisi absolut. Perusahaan yang intensitasnya menurun masih dapat mengalami kenaikan emisi total apabila volume produksi meningkat tajam.","whyOthersWrong":"A menghasilkan unit produksi per ton emisi, bukan intensitas emisi. B mengukur hubungan biaya dan emisi. C memperbesar angka tanpa makna rasio yang tepat.","tip":"Kata “per unit” berarti pembilang emisi dibagi penyebut aktivitas.","reference":"TM 4 — Akuntansi karbon; emisi Scope 1, Scope 2, Scope 3, dan intensitas.","keywords":"karbon; intensitas; emisi"},{"number":5,"topic":"PSAK 117","subtopic":"Contractual Service Margin","learningOutcome":"Menjelaskan fungsi CSM","difficulty":"Mudah","type":"Definisi","question":"Contractual Service Margin (CSM) dalam PSAK 117 merepresentasikan ...","options":["Klaim yang sudah terjadi tetapi belum dibayar","Laba belum diperoleh yang diakui seiring jasa asuransi diberikan","Seluruh premi kas yang diterima di muka","Penyesuaian risiko finansial atas investasi"],"correct":"B","concept":"Contractual Service Margin","explanation":"Jawaban B benar. CSM adalah komponen liabilitas kontrak asuransi yang menampung laba belum diperoleh dari kelompok kontrak. Pada pengakuan awal, CSM mencegah keuntungan hari pertama. Setelah itu, CSM disesuaikan sesuai ketentuan dan dilepas ke laba rugi berdasarkan jasa yang diberikan, umumnya menggunakan coverage units. Klaim yang sudah terjadi berkaitan dengan liability for incurred claims, sedangkan risk adjustment menggambarkan kompensasi atas ketidakpastian risiko nonkeuangan.","whyOthersWrong":"A menggambarkan LIC. C menyamakan kas dengan pendapatan. D keliru karena risk adjustment berfokus pada risiko nonkeuangan, bukan seluruh risiko investasi.","tip":"Ingat CSM = laba yang “disimpan” sampai jasa diberikan.","reference":"TM 6 — PSAK 117; GMM, FCF, risk adjustment, CSM, LRC, dan LIC.","keywords":"CSM; laba belum diperoleh"},{"number":6,"topic":"Perkembangan SAK","subtopic":"Kriteria SAK EMKM","learningOutcome":"Menentukan pilar berdasarkan data entitas","difficulty":"Mudah","type":"Konseptual","question":"Entitas tanpa akuntabilitas publik memiliki penjualan tahunan Rp250 juta selama dua tahun berturut-turut dan memenuhi kriteria usaha mikro yang digunakan dalam materi. Pilar yang PALING SESUAI adalah ...","options":["SAK Indonesia untuk EMKM","SAK Internasional","SAK Indonesia (Umum)","SAK Indonesia untuk Entitas Privat saja"],"correct":"A","concept":"Pemilihan pilar berdasarkan karakteristik entitas","explanation":"Jawaban A benar. Dalam materi, usaha mikro memiliki hasil penjualan tahunan paling banyak Rp300 juta. Entitas pada kasus memiliki penjualan Rp250 juta dan telah memenuhi kriteria selama dua tahun, sehingga SAK Indonesia untuk EMKM merupakan pilar yang paling sesuai dengan asumsi tidak ada ketentuan regulator lain. Angka tersebut dihitung dengan membandingkan Rp250 juta terhadap batas Rp300 juta. Pemilihan tetap harus mempertimbangkan ruang lingkup, akuntabilitas publik, dan izin otoritas.","whyOthersWrong":"B dan C terlalu kompleks untuk fakta kasus. D dapat digunakan oleh entitas privat tertentu, tetapi soal meminta pilar yang paling sesuai bagi entitas yang memenuhi kriteria EMKM.","tip":"Bandingkan angka kasus dengan batas omzet, lalu cek akuntabilitas publik dan periode pemenuhan.","reference":"TM 1 — SAK EMKM dan kriteria UMKM yang digunakan dalam materi (UU 20/2008).","keywords":"EMKM; omzet; pilar"},{"number":7,"topic":"Manajemen Laba","subtopic":"Total Accruals","learningOutcome":"Menghitung total akrual","difficulty":"Mudah","type":"Konseptual","question":"Laba bersih perusahaan Rp780 juta dan arus kas operasi Rp620 juta. Dengan pendekatan sederhana TA = laba bersih − arus kas operasi, total accruals adalah ...","options":["Rp80 juta","Rp140 juta","Rp160 juta","Rp1.400 juta"],"correct":"C","concept":"Total accruals sebagai selisih laba dan arus kas operasi","explanation":"Jawaban C benar. Total accruals dihitung: TA = laba bersih − arus kas operasi = Rp780 juta − Rp620 juta = Rp160 juta. Selisih ini menunjukkan bagian laba yang tidak direalisasikan sebagai arus kas operasi pada periode tersebut. Nilai total akrual belum otomatis menunjukkan manajemen laba karena masih mencakup akrual normal akibat pertumbuhan, modal kerja, depresiasi, dan karakter industri. Analisis lanjutan memisahkan nondiscretionary accruals dan discretionary accruals.","whyOthersWrong":"A dan B berasal dari pengurangan yang keliru. D merupakan penjumlahan laba bersih dan arus kas operasi, bukan total accruals.","tip":"Gunakan urutan NI minus CFO. Setelah memperoleh TA, jangan langsung menyimpulkan fraud.","reference":"TM 5 — Manajemen laba berbasis akrual; total accruals dan discretionary accruals.","keywords":"total accruals; laba; CFO"},{"number":8,"topic":"Sustainability Accounting","subtopic":"Intensitas Karbon","learningOutcome":"Menghitung intensitas emisi","difficulty":"Sedang","type":"Konseptual","question":"Pabrik menghasilkan 1.800 ton CO₂e dan memproduksi 90.000 unit. Intensitas karbon per unit adalah ...","options":["0,002 ton CO₂e","0,010 ton CO₂e","0,018 ton CO₂e","0,020 ton CO₂e"],"correct":"D","concept":"Perhitungan intensitas karbon","explanation":"Jawaban D benar. Intensitas karbon = total emisi ÷ jumlah produksi = 1.800 ton CO₂e ÷ 90.000 unit = 0,020 ton CO₂e per unit. Nilai tersebut setara dengan 20 kilogram CO₂e per unit karena 1 ton sama dengan 1.000 kilogram. Rasio ini berguna untuk memantau efisiensi emisi, membandingkan pabrik, dan menilai kemajuan target. Namun, pengguna tetap perlu melihat total emisi absolut dan perubahan batas pengukuran.","whyOthersWrong":"A, B, dan C muncul dari kesalahan pembagian atau salah menempatkan desimal. Selalu periksa satuan hasil.","tip":"Tulis satuan: ton ÷ unit. Konversikan ke kilogram untuk mengecek kewajaran.","reference":"TM 4 — Akuntansi karbon dan pengukuran data aktivitas × faktor emisi.","keywords":"emisi; intensitas; unit produksi"},{"number":9,"topic":"PSAK 117","subtopic":"Pelepasan CSM","learningOutcome":"Menghitung pelepasan CSM sederhana","difficulty":"Sedang","type":"Konseptual","question":"CSM awal Rp600 juta dilepas selama tiga tahun dengan coverage units yang sama. Pelepasan CSM pada tahun pertama adalah ...","options":["Rp200 juta","Rp300 juta","Rp400 juta","Rp600 juta"],"correct":"A","concept":"Alokasi CSM berdasarkan jasa","explanation":"Jawaban A benar. Karena coverage units sama selama tiga tahun, proporsi jasa tahun pertama adalah 1/3. Pelepasan CSM = Rp600 juta × 1/3 = Rp200 juta. Sisa CSM setelah pelepasan, dengan mengabaikan bunga dan perubahan estimasi, adalah Rp400 juta. Dalam praktik, perhitungan coverage units mempertimbangkan kuantitas manfaat dan periode pertanggungan. Karena itu, pelepasan tidak selalu garis lurus jika tingkat manfaat berbeda antarperiode.","whyOthersWrong":"B dan C menggunakan proporsi yang tidak sesuai. D mengakui seluruh laba pada tahun pertama dan bertentangan dengan prinsip jasa.","tip":"Tentukan proporsi coverage units tahun berjalan terhadap total coverage units.","reference":"TM 6 — PSAK 117; CSM dilepas berdasarkan jasa atau coverage units.","keywords":"CSM; coverage units; release"},{"number":10,"topic":"PSAK 118","subtopic":"Subtotal Wajib","learningOutcome":"Menghitung laba sebelum pendanaan dan pajak","difficulty":"Sedang","type":"Konseptual","question":"Laba operasi Rp1.700 juta dan penghasilan neto kategori investasi Rp200 juta. Subtotal laba sebelum pendanaan dan pajak penghasilan adalah ...","options":["Rp1.500 juta","Rp1.900 juta","Rp2.100 juta","Rp2.400 juta"],"correct":"B","concept":"Laba sebelum pendanaan dan pajak penghasilan","explanation":"Jawaban B benar. PSAK 118 menghubungkan subtotal laba sebelum pendanaan dan pajak penghasilan dengan laba operasi serta seluruh penghasilan dan beban dalam kategori investasi. Perhitungannya: Rp1.700 juta + Rp200 juta = Rp1.900 juta. Beban pendanaan dan pajak penghasilan belum dimasukkan pada subtotal ini. Struktur tersebut menciptakan anchor yang lebih konsisten untuk membandingkan kinerja operasi dan hasil investasi antarentitas.","whyOthersWrong":"A mengurangkan penghasilan investasi. C dan D memasukkan angka tambahan yang tidak diberikan, seperti pendanaan atau pajak.","tip":"Urutan PSAK 118: operasi, lalu investasi, baru pendanaan dan pajak.","reference":"TM 7 — PSAK 118; lima kategori dan subtotal wajib.","keywords":"PSAK 118; subtotal; investasi"},{"number":11,"topic":"Good Corporate Governance","subtopic":"Independensi Dewan","learningOutcome":"Menghitung proporsi dewan independen","difficulty":"Sedang","type":"Penerapan","question":"Dewan terdiri dari 5 anggota, termasuk 3 anggota independen. Persentase anggota independen adalah ...","options":["40%","50%","55%","60%"],"correct":"D","concept":"Independensi sebagai mekanisme monitoring","explanation":"Jawaban D benar. Persentase anggota independen = 3 ÷ 5 × 100% = 60%. Rasio ini memberikan gambaran kuantitatif mengenai komposisi dewan, tetapi efektivitas independensi tidak hanya ditentukan oleh jumlah. Kompetensi, keberanian bertanya, akses informasi, konflik kepentingan, masa jabatan, dan kualitas tindak lanjut juga penting. Karena itu, angka 60% perlu dibaca bersama bukti proses pengawasan dan kualitas keputusan dewan.","whyOthersWrong":"A memakai anggota nonindependen sebagai pembilang. B dan C merupakan pembulatan yang tidak sesuai dengan 3/5.","tip":"Pembilang = jumlah independen; penyebut = total anggota. Setelah menghitung, evaluasi substansi independensi.","reference":"TM 3 — GCG; independensi, akuntabilitas, dan fungsi pengawasan dewan.","keywords":"dewan; independen; rasio"},{"number":12,"topic":"Sustainability Accounting","subtopic":"Target Pengurangan Emisi","learningOutcome":"Menghitung target emisi","difficulty":"Sedang","type":"Penerapan","question":"Emisi Scope 1 dan Scope 2 masing-masing 3.200 dan 1.800 ton CO₂e. Target penurunan gabungan 8%. Target emisi maksimum berikutnya adalah ...","options":["4.200 ton CO₂e","4.400 ton CO₂e","4.600 ton CO₂e","4.800 ton CO₂e"],"correct":"C","concept":"Target pengurangan emisi absolut","explanation":"Jawaban C benar. Emisi dasar = 3.200 + 1.800 = 5.000 ton CO₂e. Pengurangan 8% = 5.000 × 8% = 400 ton. Target emisi maksimum = 5.000 − 400 = 4.600 ton CO₂e. Perusahaan perlu menjaga konsistensi boundary, metode, dan faktor emisi agar perbandingan target valid. Perubahan organisasi atau metodologi yang material dapat memerlukan restatement baseline.","whyOthersWrong":"A dan B menurunkan emisi terlalu besar. D hanya mengurangi 4% atau 200 ton dari baseline.","tip":"Jumlahkan scope yang diminta, hitung persentase pengurangan, lalu kurangi dari baseline.","reference":"TM 4 — Akuntansi karbon; target, baseline, boundary, dan faktor emisi.","keywords":"Scope 1; Scope 2; target"},{"number":13,"topic":"Manajemen Laba","subtopic":"Discretionary Accruals","learningOutcome":"Menghitung akrual diskresioner","difficulty":"Sedang","type":"Penerapan","question":"Total accruals Rp250 juta dan nondiscretionary accruals Rp180 juta. Discretionary accruals adalah ...","options":["Rp70 juta","Rp180 juta","Rp250 juta","Rp430 juta"],"correct":"A","concept":"Discretionary accruals sebagai residual","explanation":"Jawaban A benar. Discretionary accruals = total accruals − nondiscretionary accruals = Rp250 juta − Rp180 juta = Rp70 juta. Angka positif dapat menjadi sinyal income-increasing accruals, tetapi bukan bukti langsung manipulasi atau fraud. Model akrual dapat dipengaruhi pertumbuhan, industri, transaksi khusus, dan kesalahan spesifikasi. Oleh sebab itu, hasil harus ditriangulasi dengan jurnal akhir periode, estimasi, kontrak, arus kas, dan tata kelola.","whyOthersWrong":"B hanya mengambil NDA. C hanya mengambil TA. D menjumlahkan dua komponen yang seharusnya dikurangkan.","tip":"Gunakan identitas TA = NDA + DA, sehingga DA = TA − NDA.","reference":"TM 5 — Model deteksi manajemen laba; Jones dan Modified Jones.","keywords":"TA; NDA; DA"},{"number":14,"topic":"PSAK 117","subtopic":"Pengakuan Awal GMM","learningOutcome":"Menghitung CSM awal","difficulty":"Sedang","type":"Penerapan","question":"Pada pengakuan awal, nilai kini arus kas masuk Rp1.600 juta, nilai kini arus kas keluar Rp1.260 juta, dan risk adjustment Rp90 juta. CSM awal kelompok kontrak yang tidak onerous adalah ...","options":["Rp90 juta","Rp250 juta","Rp340 juta","Rp430 juta"],"correct":"B","concept":"CSM meniadakan keuntungan hari pertama","explanation":"Jawaban B benar. Fulfillment cash flows dengan konvensi liabilitas = arus kas keluar + risk adjustment − arus kas masuk = Rp1.260 + Rp90 − Rp1.600 = minus Rp250 juta. Nilai negatif menunjukkan net inflow atau keuntungan masa depan. Agar tidak ada keuntungan hari pertama, CSM dibentuk sebesar Rp250 juta sehingga jumlah FCF + CSM pada awal menjadi nol. Laba kemudian diakui ketika jasa asuransi diberikan.","whyOthersWrong":"A hanya mengambil risk adjustment. C adalah selisih arus kas sebelum RA. D menjumlahkan selisih arus kas dan RA secara keliru.","tip":"Hitung FCF terlebih dahulu. Jika FCF negatif pada kelompok menguntungkan, CSM biasanya mengimbangi nilai tersebut.","reference":"TM 6 — PSAK 117; pengakuan awal General Measurement Model.","keywords":"FCF; RA; CSM awal"},{"number":15,"topic":"PSAK 118","subtopic":"Laba Operasi","learningOutcome":"Menghitung subtotal laba operasi","difficulty":"Sedang","type":"Penerapan","question":"Pendapatan Rp8.000 juta, harga pokok penjualan Rp5.200 juta, dan beban operasi Rp1.100 juta. Penghasilan investasi Rp200 juta dan beban pendanaan Rp300 juta. Laba operasi adalah ...","options":["Rp1.400 juta","Rp1.500 juta","Rp1.600 juta","Rp1.700 juta"],"correct":"D","concept":"Kategori operasi sebagai residual","explanation":"Jawaban D benar. Laba operasi = pendapatan − harga pokok penjualan − beban operasi = Rp8.000 − Rp5.200 − Rp1.100 = Rp1.700 juta. Penghasilan investasi Rp200 juta dan beban pendanaan Rp300 juta tidak dimasukkan dalam subtotal laba operasi karena berada pada kategori berbeda. PSAK 118 menggunakan kategori operasi sebagai residual bagi penghasilan dan beban yang tidak diklasifikasikan ke kategori investasi, pendanaan, pajak, atau operasi dihentikan.","whyOthersWrong":"A memasukkan beban pendanaan. B dan C mencampurkan kategori investasi atau melakukan pengurangan yang tidak lengkap.","tip":"Pisahkan akun berdasarkan kategori sebelum menghitung. Jangan memasukkan investasi dan pendanaan ke laba operasi.","reference":"TM 7 — PSAK 118; kategori operasi, investasi, dan pendanaan.","keywords":"laba operasi; PSAK 118"},{"number":16,"topic":"Kerangka Konseptual","subtopic":"Materialitas Kuantitatif dan Kualitatif","learningOutcome":"Mengevaluasi salah saji terhadap ambang internal","difficulty":"Sedang","type":"Mini Kasus","question":"Kebijakan awal perusahaan menggunakan 1% total aset sebagai benchmark materialitas. Total aset Rp50 miliar dan salah saji Rp650 juta. Kesimpulan kuantitatif awal yang PALING TEPAT adalah ...","options":["Tidak material karena di bawah Rp1 miliar","Tidak material karena hanya memengaruhi satu akun","Material secara kuantitatif karena melebihi benchmark Rp500 juta","Material hanya jika terjadi dua tahun berturut-turut"],"correct":"C","concept":"Benchmark sebagai titik awal pertimbangan","explanation":"Jawaban C benar. Benchmark = 1% × Rp50 miliar = Rp500 juta. Salah saji Rp650 juta melebihi benchmark sebesar Rp150 juta, sehingga secara kuantitatif merupakan indikasi material. Kesimpulan akhir tetap mempertimbangkan sifat transaksi, dampak terhadap tren, covenant, kepatuhan, dan apakah informasi mengubah laba menjadi rugi. Benchmark pada soal adalah kebijakan kasus, bukan batas universal yang ditetapkan standar.","whyOthersWrong":"A memakai batas yang tidak diberikan. B mengabaikan besar dan sifat salah saji. D menambahkan syarat periode yang tidak ada.","tip":"Hitung benchmark dahulu, bandingkan nominal, lalu ingat bahwa faktor kualitatif tetap diperlukan.","reference":"TM 2 — Materialitas dan pertimbangan biaya–manfaat dalam pelaporan.","keywords":"materialitas; benchmark; salah saji"},{"number":17,"topic":"Sustainability Accounting","subtopic":"Intensitas Air","learningOutcome":"Menghitung persentase pengurangan intensitas","difficulty":"Sedang","type":"Mini Kasus","question":"Intensitas penggunaan air turun dari 4,5 m³ per unit menjadi 3,6 m³ per unit. Persentase penurunannya adalah ...","options":["20%","18%","16%","12%"],"correct":"A","concept":"Perubahan persentase intensitas air","explanation":"Jawaban A benar. Penurunan absolut = 4,5 − 3,6 = 0,9 m³ per unit. Persentase penurunan = 0,9 ÷ 4,5 × 100% = 20%. Hasil ini menunjukkan efisiensi penggunaan air per unit membaik. Namun, total konsumsi air dapat tetap naik jika volume produksi meningkat lebih dari peningkatan efisiensi. Karena itu, laporan keberlanjutan sebaiknya menyajikan indikator absolut dan intensitas secara bersamaan.","whyOthersWrong":"B, C, dan D berasal dari pembagian dengan penyebut yang tidak tepat atau pembulatan keliru.","tip":"Persentase perubahan selalu memakai nilai awal sebagai penyebut.","reference":"TM 4 — Akuntansi air; indikator absolut, intensitas, target, dan risiko kelangkaan.","keywords":"air; intensitas; penurunan"},{"number":18,"topic":"Manajemen Laba","subtopic":"Overproduction","learningOutcome":"Menghitung dampak produksi berlebih terhadap laba","difficulty":"Sedang","type":"Mini Kasus","question":"Biaya tetap produksi Rp600 juta. Produksi normal 100.000 unit, tetapi perusahaan memproduksi 150.000 unit dan menjual 100.000 unit. Dampak kenaikan laba saat ini dari alokasi biaya tetap per unit adalah ...","options":["Rp100 juta","Rp200 juta","Rp300 juta","Rp600 juta"],"correct":"B","concept":"Real earnings management melalui produksi berlebih","explanation":"Jawaban B benar. Pada produksi normal, biaya tetap per unit = Rp600 juta ÷ 100.000 = Rp6.000. Saat produksi 150.000 unit, biaya tetap per unit menjadi Rp4.000. Untuk 100.000 unit yang terjual, biaya tetap dalam HPP turun sebesar Rp2.000 × 100.000 = Rp200 juta. Selisih tersebut tertahan dalam persediaan dan menaikkan laba periode berjalan, meskipun dapat menambah biaya penyimpanan dan risiko usang.","whyOthersWrong":"A dan C tidak sesuai selisih biaya per unit. D menganggap seluruh biaya tetap menjadi kenaikan laba.","tip":"Bandingkan biaya tetap per unit normal dan aktual, lalu kalikan selisih dengan unit terjual.","reference":"TM 5 — Real earnings management; overproduction dan biaya produksi abnormal.","keywords":"overproduction; biaya tetap; COGS"},{"number":19,"topic":"PSAK 117","subtopic":"Kelompok Onerous","learningOutcome":"Menghitung kerugian pengakuan awal","difficulty":"Sulit","type":"Mini Kasus","question":"Nilai kini arus kas keluar Rp1.150 juta, arus kas masuk Rp1.000 juta, dan risk adjustment Rp80 juta. Kerugian kelompok onerous pada pengakuan awal adalah ...","options":["Rp80 juta","Rp150 juta","Rp180 juta","Rp230 juta"],"correct":"D","concept":"Kerugian kelompok kontrak merugi","explanation":"Jawaban D benar. Fulfillment cash flows = Rp1.150 + Rp80 − Rp1.000 = Rp230 juta, yaitu net liability tanpa margin keuntungan. Karena kelompok kontrak merugi pada pengakuan awal, CSM tidak dibentuk sebagai nilai negatif. Kerugian Rp230 juta diakui segera dalam laba rugi dan dilacak melalui loss component. Pengelompokan berdasarkan profitabilitas mencegah kontrak menguntungkan menutupi kerugian kelompok onerous.","whyOthersWrong":"A hanya mengambil risk adjustment. B hanya mengambil selisih arus kas. C menggabungkan angka secara tidak lengkap.","tip":"Untuk onerous: outflow + RA − inflow. Nilai positif diakui sebagai kerugian, bukan CSM negatif.","reference":"TM 6 — PSAK 117; tingkat agregasi, onerous group, dan loss component.","keywords":"onerous; FCF; loss component"},{"number":20,"topic":"PSAK 118","subtopic":"Rekonsiliasi UKTM","learningOutcome":"Merekonsiliasi ukuran manajemen ke subtotal standar","difficulty":"Sulit","type":"Mini Kasus","question":"Adjusted operating profit yang dipublikasikan Rp1.450 juta menambahkan kembali beban restrukturisasi Rp120 juta dan litigasi Rp50 juta. Laba operasi menurut subtotal PSAK terdekat adalah ...","options":["Rp1.620 juta","Rp1.500 juta","Rp1.280 juta","Rp1.170 juta"],"correct":"C","concept":"Rekonsiliasi UKTM ke subtotal PSAK","explanation":"Jawaban C benar. Adjusted operating profit diperoleh setelah manajemen menambahkan kembali dua beban. Untuk kembali ke laba operasi menurut PSAK, kedua add-back harus dikurangkan: Rp1.450 − Rp120 − Rp50 = Rp1.280 juta. PSAK 118 mensyaratkan UKTM dijelaskan dalam satu catatan, termasuk definisi, metode perhitungan, alasan kegunaan, perubahan, dan rekonsiliasi ke subtotal standar terdekat. UKTM tidak menggantikan subtotal wajib.","whyOthersWrong":"A menambahkan kembali beban untuk kedua kalinya. B dan D menggunakan hanya sebagian atau pengurangan berlebih.","tip":"Tentukan arah rekonsiliasi. Dari angka adjusted menuju PSAK, balikkan penyesuaian manajemen.","reference":"TM 7 — PSAK 118; Ukuran Kinerja Tetapan Manajemen dan rekonsiliasi.","keywords":"UKTM; rekonsiliasi; laba operasi"},{"number":21,"topic":"Manajemen Laba","subtopic":"Jones vs Modified Jones","learningOutcome":"Membedakan pengaruh piutang pada estimasi akrual normal","difficulty":"Sulit","type":"Perbandingan","question":"Aset awal Rp2.000 juta, Δpendapatan Rp600 juta, Δpiutang Rp120 juta, dan koefisien pendapatan 0,08. Komponen akrual normal model Modified Jones lebih rendah dari Jones sebesar ...","options":["Rp9,6 juta","Rp19,2 juta","Rp38,4 juta","Rp48,0 juta"],"correct":"A","concept":"Penyesuaian perubahan piutang dalam Modified Jones","explanation":"Jawaban A benar. Komponen Jones = 0,08 × (Rp600 ÷ Rp2.000) × Rp2.000 = Rp48 juta. Modified Jones menggunakan Δpendapatan − Δpiutang: 0,08 × ((Rp600 − Rp120) ÷ Rp2.000) × Rp2.000 = Rp38,4 juta. Selisihnya Rp48 − Rp38,4 = Rp9,6 juta. Pengurangan piutang dimaksudkan agar penjualan kredit yang berpotensi dikelola tidak seluruhnya dianggap akrual normal.","whyOthersWrong":"B dan C merupakan bagian nilai Modified Jones, bukan selisih. D adalah komponen Jones sebelum penyesuaian piutang.","tip":"Modified Jones mengurangi Δpiutang dari Δpendapatan. Bandingkan hasil kedua model, bukan hanya menghitung salah satunya.","reference":"TM 5 — Jones Model dan Modified Jones Model.","keywords":"Jones; Modified Jones; piutang"},{"number":22,"topic":"Sustainability Accounting","subtopic":"Emisi Absolut vs Intensitas","learningOutcome":"Membedakan perubahan absolut dan intensitas","difficulty":"Sulit","type":"Perbandingan","question":"Emisi turun dari 10.000 menjadi 9.500 ton CO₂e, sedangkan produksi turun dari 100.000 menjadi 90.000 unit. Pernyataan yang tepat adalah ...","options":["Emisi absolut turun 5% dan intensitas turun 5%","Emisi absolut turun 5%, tetapi intensitas naik sekitar 5,6%","Emisi absolut naik 5% dan intensitas turun 5,6%","Emisi absolut dan intensitas tidak berubah"],"correct":"B","concept":"Perbedaan indikator absolut dan relatif","explanation":"Jawaban B benar. Emisi absolut turun (500 ÷ 10.000) = 5%. Intensitas awal = 10.000 ÷ 100.000 = 0,10 ton per unit. Intensitas baru = 9.500 ÷ 90.000 = 0,10556 ton per unit. Kenaikan intensitas = (0,10556 − 0,10) ÷ 0,10 ≈ 5,6%. Artinya total emisi menurun karena skala produksi lebih kecil, tetapi efisiensi emisi per unit justru memburuk.","whyOthersWrong":"A menganggap arah kedua indikator selalu sama. C membalik perubahan absolut. D mengabaikan perubahan data.","tip":"Hitung emisi absolut dan rasio per unit secara terpisah. Jangan menyimpulkan efisiensi hanya dari total emisi.","reference":"TM 4 — Akuntansi karbon; indikator absolut dan intensitas.","keywords":"absolut; intensitas; emisi"},{"number":23,"topic":"PSAK 117","subtopic":"GMM vs PAA","learningOutcome":"Mengevaluasi kedekatan hasil PAA terhadap GMM","difficulty":"Sulit","type":"Perbandingan","question":"Untuk kontrak 12 bulan, estimasi liabilitas GMM Rp1.000 juta dan PAA Rp1.020 juta. Kebijakan uji internal kasus menganggap selisih ≤3% tidak material. Kesimpulan yang tepat adalah ...","options":["PAA pasti dilarang karena selalu lebih tinggi","GMM dan PAA identik tanpa perlu pengujian","PAA wajib untuk seluruh kontrak 12 bulan","Selisih 2% mendukung penggunaan PAA, dengan tetap memenuhi persyaratan lain"],"correct":"D","concept":"PAA sebagai penyederhanaan yang memenuhi syarat","explanation":"Jawaban D benar. Selisih = (Rp1.020 − Rp1.000) ÷ Rp1.000 × 100% = 2%. Berdasarkan kebijakan uji internal pada kasus, selisih tersebut berada di bawah 3%, sehingga hasil PAA dinilai mendekati GMM. Namun, kesimpulan penggunaan PAA tetap memerlukan pemenuhan kriteria standar, dokumentasi, dan evaluasi pola arus kas. Ambang 3% adalah asumsi kasus, bukan angka baku universal PSAK 117.","whyOthersWrong":"A terlalu absolut. B mengabaikan kebutuhan eligibility assessment. C salah karena kontrak satu tahun tidak membuat PAA otomatis wajib.","tip":"Hitung selisih relatif, bandingkan dengan kriteria kasus, lalu pertahankan syarat standar lainnya.","reference":"TM 6 — PSAK 117; Premium Allocation Approach dan uji kelayakan.","keywords":"PAA; GMM; eligibility"},{"number":24,"topic":"Manajemen Laba","subtopic":"Modified Jones Lengkap","learningOutcome":"Menganalisis discretionary accruals dengan model","difficulty":"Sulit","type":"Analisis","question":"TA Rp240 juta; aset awal Rp2.000 juta; Δpendapatan Rp600 juta; Δpiutang Rp100 juta; PPE Rp1.200 juta. NDA/A = 0,01 + 0,08[(ΔRev−ΔAR)/A] + 0,06(PPE/A). Discretionary accruals adalah ...","options":["Rp66 juta","Rp96 juta","Rp108 juta","Rp132 juta"],"correct":"C","concept":"Perhitungan residual akrual diskresioner","explanation":"Jawaban C benar. TA/A = Rp240 ÷ Rp2.000 = 0,12. NDA/A = 0,01 + 0,08[(600−100)/2.000] + 0,06(1.200/2.000) = 0,01 + 0,02 + 0,036 = 0,066. Maka DA/A = 0,12 − 0,066 = 0,054. Nilai DA = 0,054 × Rp2.000 juta = Rp108 juta. Nilai ini adalah sinyal statistik yang masih perlu investigasi bukti transaksi.","whyOthersWrong":"A adalah NDA ratio yang salah dibaca sebagai nominal. B dan D berasal dari substitusi atau pengurangan yang tidak lengkap.","tip":"Normalisasi seluruh variabel dengan aset awal, hitung NDA, lalu gunakan DA = TA − NDA dalam basis yang sama.","reference":"TM 5 — Modified Jones Model; residual sebagai proxy discretionary accruals.","keywords":"Modified Jones; NDA; DA"},{"number":25,"topic":"PSAK 117","subtopic":"Roll-forward CSM","learningOutcome":"Menganalisis perubahan CSM akhir periode","difficulty":"Sulit","type":"Analisis","question":"CSM awal Rp600 juta, akresi bunga Rp30 juta, perubahan estimasi jasa masa depan yang menguntungkan Rp90 juta. Coverage units tahun berjalan 40 dari total 160 setelah penyesuaian. CSM akhir adalah ...","options":["Rp540 juta","Rp570 juta","Rp600 juta","Rp720 juta"],"correct":"A","concept":"Roll-forward CSM dan pelepasan jasa","explanation":"Jawaban A benar. CSM sebelum pelepasan = Rp600 + Rp30 + Rp90 = Rp720 juta. Proporsi coverage units tahun berjalan = 40 ÷ 160 = 25%. Pelepasan ke laba rugi = Rp720 × 25% = Rp180 juta. CSM akhir = Rp720 − Rp180 = Rp540 juta. Perhitungan menunjukkan bahwa perubahan estimasi terkait jasa masa depan menyesuaikan CSM, sedangkan pelepasan periodik mencerminkan jasa yang telah diberikan.","whyOthersWrong":"B mengurangi nilai yang tidak sesuai coverage units. C mengabaikan seluruh perubahan. D adalah saldo sebelum pelepasan.","tip":"Urutkan roll-forward: saldo awal + bunga ± perubahan masa depan − release berdasarkan coverage units.","reference":"TM 6 — PSAK 117; perubahan CSM dan pengakuan jasa.","keywords":"CSM roll-forward; coverage units"}],"flashcards":[{"number":1,"topic":"Perkembangan SAK","subtopic":"KSPKI","difficulty":"Mudah","type":"Definisi","question":"Apa fungsi utama KSPKI?","shortAnswer":"Menjelaskan definisi SAK, empat pilar, pengguna tiap pilar, dan perpindahan antar pilar.","explanation":"KSPKI menjadi kerangka yang menata arsitektur standar pelaporan keuangan di Indonesia. Kerangka ini membantu entitas menentukan pilar yang sesuai berdasarkan akuntabilitas publik, karakteristik entitas, dan ketentuan regulator. KSPKI juga menjelaskan arah perpindahan pilar agar perubahan kerangka pelaporan tidak dilakukan secara bebas tanpa dasar.","example":"Entitas privat tanpa akuntabilitas publik menilai kelayakan menggunakan SAKEP, sedangkan emiten mengikuti pilar dengan persyaratan lebih tinggi.","keywords":"KSPKI; pilar; perpindahan","comparison":"KSPKI bukan PSAK transaksi; KSPKI mengatur kerangka pilar, sedangkan PSAK mengatur perlakuan akuntansi.","mnemonic":"K-P-P: Kerangka, Pilar, Perpindahan."},{"number":2,"topic":"Kerangka Konseptual","subtopic":"Materialitas","difficulty":"Mudah","type":"Definisi","question":"Kapan informasi disebut material?","shortAnswer":"Ketika penghilangan, salah saji, atau pengaburannya dapat memengaruhi keputusan pengguna utama.","explanation":"Materialitas merupakan aspek relevansi dan dinilai dalam konteks laporan keuangan entitas. Besarnya nilai penting, tetapi sifat transaksi, tren, covenant, kepatuhan, dan sensitivitas pengguna juga dapat membuat suatu informasi material. Tidak ada satu persentase yang otomatis berlaku untuk seluruh entitas dan kondisi.","example":"Salah saji kecil dapat material bila mengubah laba menjadi rugi atau menutupi pelanggaran perjanjian utang.","keywords":"materialitas; relevansi; keputusan","comparison":"Materialitas berbeda dari ketelitian absolut; laporan tidak harus bebas dari setiap selisih kecil.","mnemonic":"N-S-K: Nilai, Sifat, Konteks."},{"number":3,"topic":"Good Corporate Governance","subtopic":"Agency Theory","difficulty":"Mudah","type":"Definisi","question":"Apa inti masalah keagenan?","shortAnswer":"Perbedaan kepentingan dan informasi antara pemilik dan manajemen.","explanation":"Manajemen memiliki informasi lebih banyak dan dapat mengambil keputusan yang tidak sepenuhnya selaras dengan kepentingan pemilik atau pemangku kepentingan. Tata kelola mengurangi risiko tersebut melalui monitoring, transparansi, akuntabilitas, insentif jangka panjang, komite audit, dan dewan yang efektif.","example":"Manajer mempercepat laba agar bonus tercapai meskipun tindakan tersebut merugikan nilai jangka panjang.","keywords":"principal; agent; asimetri","comparison":"Agency theory berbeda dari stewardship theory yang lebih menekankan manajer sebagai pengelola yang dapat dipercaya.","mnemonic":"I-K-A: Informasi, Kepentingan, Akuntabilitas."},{"number":4,"topic":"Sustainability Accounting","subtopic":"Sustainability Accounting","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud sustainability accounting?","shortAnswer":"Pengukuran dan komunikasi informasi ekonomi, lingkungan, dan sosial untuk keputusan dan akuntabilitas.","explanation":"Sustainability accounting menghubungkan dampak dan ketergantungan lingkungan-sosial dengan strategi, risiko, biaya, aset, kewajiban, dan arus kas. Informasi tidak berhenti pada narasi, tetapi meliputi indikator, target, metode, baseline, serta pengendalian data yang dapat diuji.","example":"Perusahaan mengukur emisi, biaya energi, intensitas air, keselamatan kerja, dan dampaknya terhadap investasi.","keywords":"TBL; ESG; pengukuran","comparison":"Berbeda dari filantropi; sustainability accounting terintegrasi dengan keputusan bisnis dan pelaporan.","mnemonic":"3P: Profit, People, Planet."},{"number":5,"topic":"PSAK 117","subtopic":"CSM","difficulty":"Mudah","type":"Definisi","question":"Apa arti CSM?","shortAnswer":"Laba belum diperoleh dari kelompok kontrak asuransi yang diakui seiring jasa diberikan.","explanation":"CSM mencegah pengakuan keuntungan pada hari pertama. Pada periode berikutnya, CSM disesuaikan untuk bunga dan perubahan tertentu yang terkait jasa masa depan, kemudian dilepas ke laba rugi berdasarkan coverage units. Kelompok kontrak onerous tidak memiliki CSM negatif; kerugiannya diakui segera.","example":"CSM Rp600 juta dengan jasa sama tiga tahun dapat dilepas Rp200 juta per tahun jika tidak ada penyesuaian lain.","keywords":"CSM; laba; jasa","comparison":"CSM berbeda dari risk adjustment; CSM adalah laba belum diperoleh, RA adalah kompensasi risiko nonkeuangan.","mnemonic":"CSM = Cuan Saat Melayani."},{"number":6,"topic":"PSAK 118","subtopic":"UKTM","difficulty":"Mudah","type":"Definisi","question":"Apa itu Ukuran Kinerja Tetapan Manajemen (UKTM)?","shortAnswer":"Subtotal penghasilan dan beban yang digunakan dalam komunikasi publik manajemen dan memenuhi definisi PSAK 118.","explanation":"UKTM mencerminkan pandangan manajemen atas aspek kinerja, tetapi bukan subtotal yang secara khusus diwajibkan standar. Entitas harus menjelaskan definisi, metode, alasan kegunaan, perubahan, dan rekonsiliasi UKTM ke subtotal PSAK terdekat dalam satu catatan.","example":"Adjusted operating profit yang menambahkan kembali restrukturisasi dapat menjadi UKTM dan harus direkonsiliasi ke laba operasi.","keywords":"UKTM; subtotal; rekonsiliasi","comparison":"Tidak semua KPI adalah UKTM; rasio, volume, dan ukuran kas biasa tidak otomatis termasuk.","mnemonic":"U-K-T-M: Ukur, Keterangan, Telusur, Match."},{"number":7,"topic":"PSAK 117","subtopic":"Fulfillment Cash Flows","difficulty":"Mudah","type":"Istilah","question":"Komponen apa yang membentuk FCF?","shortAnswer":"Estimasi nilai kini arus kas masa depan ditambah risk adjustment risiko nonkeuangan.","explanation":"Fulfillment cash flows menggambarkan nilai kini pemenuhan kewajiban kontrak asuransi berdasarkan asumsi terkini. Arus kas harus eksplisit, tidak bias, probability-weighted, dan konsisten dengan batas kontrak. Risk adjustment ditambahkan untuk ketidakpastian jumlah dan waktu arus kas nonkeuangan.","example":"PV outflow Rp1.150 juta, PV inflow Rp1.000 juta, dan RA Rp80 juta menghasilkan FCF liabilitas Rp230 juta.","keywords":"FCF; PV; RA","comparison":"FCF tidak mencakup CSM; CSM ditambahkan terpisah dalam pengukuran liabilitas.","mnemonic":"FCF = Future Cash + Faktor risiko."},{"number":8,"topic":"Sustainability Accounting","subtopic":"Intensitas Karbon","difficulty":"Mudah","type":"Istilah","question":"Bagaimana menghitung intensitas karbon per unit?","shortAnswer":"Total emisi CO₂e dibagi jumlah unit produksi.","explanation":"Intensitas karbon menunjukkan efisiensi emisi relatif terhadap aktivitas. Rasio ini memudahkan perbandingan ketika skala usaha berubah, tetapi harus disertai emisi absolut agar pengguna tidak salah menilai. Boundary, faktor emisi, dan denominasi aktivitas harus konsisten.","example":"1.800 ton CO₂e ÷ 90.000 unit = 0,02 ton atau 20 kg CO₂e per unit.","keywords":"emisi; intensitas; aktivitas","comparison":"Emisi absolut mengukur total dampak; intensitas mengukur dampak per unit aktivitas.","mnemonic":"Emisi “per” produksi = Emisi ÷ Produksi."},{"number":9,"topic":"Manajemen Laba","subtopic":"Total Accruals","difficulty":"Sedang","type":"Istilah","question":"Apa rumus sederhana total accruals?","shortAnswer":"Total accruals = laba bersih − arus kas operasi.","explanation":"Total accruals mengukur selisih antara laba akuntansi dan kas operasi. Nilai ini mencakup akrual normal serta bagian yang mungkin dipengaruhi diskresi manajemen. Model seperti Jones memisahkan nondiscretionary accruals dan discretionary accruals menggunakan variabel ekonomi.","example":"Laba Rp780 juta dan CFO Rp620 juta menghasilkan total accruals Rp160 juta.","keywords":"TA; laba; CFO","comparison":"Total accruals bukan sama dengan discretionary accruals; DA hanya residual setelah akrual normal.","mnemonic":"TA = Tercatat laba – Arus kas."},{"number":10,"topic":"PSAK 117","subtopic":"Onerous Group","difficulty":"Sedang","type":"Istilah","question":"Apa konsekuensi kelompok kontrak onerous?","shortAnswer":"Kerugian neto diakui segera dalam laba rugi dan dilacak sebagai loss component.","explanation":"Kelompok onerous memiliki arus kas pemenuhan neto yang menunjukkan kerugian. Standar tidak memperbolehkan pembentukan CSM negatif untuk menunda kerugian. Pengelompokan kontrak berdasarkan profitabilitas memastikan kontrak menguntungkan tidak menutupi kontrak merugi.","example":"Outflow Rp1.150 juta + RA Rp80 juta − inflow Rp1.000 juta = kerugian Rp230 juta.","keywords":"onerous; loss component","comparison":"Kelompok profitable memiliki CSM positif; onerous mengakui loss segera.","mnemonic":"Onerous = Obral rugi sekarang."},{"number":11,"topic":"PSAK 118","subtopic":"Kategori Operasi","difficulty":"Sedang","type":"Istilah","question":"Mengapa kategori operasi disebut residual?","shortAnswer":"Karena mencakup penghasilan dan beban yang tidak masuk investasi, pendanaan, pajak, atau operasi dihentikan.","explanation":"Kategori operasi bukan sekadar transaksi rutin. Pos volatil, tidak berulang, atau tidak biasa tetap dapat berada dalam operasi bila tidak memenuhi definisi kategori lain. Aktivitas bisnis utama tertentu juga dapat mengubah klasifikasi bagi bank atau entitas investasi.","example":"Pendapatan bunga bank dapat menjadi operasi karena pemberian kredit merupakan aktivitas bisnis utama.","keywords":"operasi; residual; kategori","comparison":"“Tidak berulang” tidak sama dengan “nonoperasi”.","mnemonic":"O = Others setelah I-P-P-O dipisahkan."},{"number":12,"topic":"Perkembangan SAK","subtopic":"Pemilihan Pilar","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan memilih pilar SAK?","shortAnswer":"Cek akuntabilitas publik → karakter entitas → izin regulator → riwayat pilar → standar yang berlaku.","explanation":"Pemilihan pilar dimulai dari substansi entitas, bukan keinginan menyederhanakan pelaporan. Setelah menilai akuntabilitas publik dan ukuran, entitas memeriksa ketentuan regulator serta apakah sebelumnya telah menggunakan kerangka yang lebih kompleks. Kesimpulan dan perpindahan harus terdokumentasi.","example":"Entitas privat tidak otomatis boleh turun pilar bila sebelumnya telah memakai kerangka yang lebih tinggi.","keywords":"pilar; eligibility; regulator","comparison":"Naik pilar dan turun pilar memiliki konsekuensi serta persyaratan berbeda.","mnemonic":"A-K-I-R-S: Akuntabilitas, Karakter, Izin, Riwayat, Standar."},{"number":13,"topic":"Sustainability Accounting","subtopic":"Pengukuran Karbon","difficulty":"Sedang","type":"Tahapan","question":"Apa tahapan dasar menghitung emisi?","shortAnswer":"Tentukan boundary → kumpulkan data aktivitas → pilih faktor emisi → hitung CO₂e → validasi dan laporkan.","explanation":"Perhitungan emisi biasanya mengalikan data aktivitas dengan faktor emisi. Kualitas hasil sangat bergantung pada batas organisasi, kelengkapan data, versi faktor emisi, konversi gas ke CO₂e, dan kontrol perubahan metode. Hasil perlu direkonsiliasi serta ditinjau sebelum digunakan untuk target.","example":"Liter bahan bakar × faktor emisi menghasilkan Scope 1; listrik dibeli × faktor grid menghasilkan Scope 2.","keywords":"boundary; data; faktor emisi","comparison":"Pengurangan aktual berbeda dari offset; offset tidak mengubah emisi operasional yang dihitung.","mnemonic":"B-D-F-H-V: Batas, Data, Faktor, Hitung, Validasi."},{"number":14,"topic":"Manajemen Laba","subtopic":"Modified Jones","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan menghitung discretionary accruals?","shortAnswer":"Hitung TA → estimasi NDA → hitung DA = TA − NDA → analisis dan validasi bukti.","explanation":"Modified Jones mengestimasi akrual normal menggunakan perubahan pendapatan yang disesuaikan perubahan piutang serta PPE. Semua variabel umumnya dinormalisasi dengan aset awal. Residual menjadi proxy discretionary accruals, tetapi tidak boleh langsung dianggap fraud.","example":"TA/A 0,12 dan NDA/A 0,066 menghasilkan DA/A 0,054.","keywords":"TA; NDA; DA; residual","comparison":"Jones memakai Δpendapatan; Modified Jones mengurangi Δpiutang.","mnemonic":"T-N-D-B: Total, Normal, Diskresi, Bukti."},{"number":15,"topic":"PSAK 117","subtopic":"Pengukuran GMM","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan pengukuran awal GMM?","shortAnswer":"Estimasi arus kas → diskonto → risk adjustment → tentukan CSM atau kerugian onerous.","explanation":"Entitas mengestimasi arus kas dalam batas kontrak, mendiskontokan untuk nilai waktu uang dan risiko finansial yang relevan, lalu menambahkan risk adjustment risiko nonkeuangan. Jika net inflow menunjukkan laba masa depan, dibentuk CSM; jika net outflow menunjukkan rugi, kerugian diakui segera.","example":"Inflow 1.600, outflow 1.260, RA 90 menghasilkan net gain 250 dan CSM awal 250.","keywords":"cash flow; discount; RA; CSM","comparison":"CSM bukan bagian dari FCF; CSM ditentukan setelah FCF.","mnemonic":"A-D-R-M: Arus, Diskonto, Risiko, Margin."},{"number":16,"topic":"Kerangka Konseptual","subtopic":"Karakteristik Fundamental","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda relevansi dan representasi tepat?","shortAnswer":"Relevansi memengaruhi keputusan; representasi tepat menggambarkan substansi secara lengkap, netral, dan bebas salah material.","explanation":"Informasi berguna membutuhkan kedua karakteristik fundamental. Informasi yang sangat tepat tetapi tidak relevan tidak membantu keputusan. Informasi relevan tetapi bias atau tidak lengkap juga menyesatkan. Prudensi mendukung netralitas dalam kondisi ketidakpastian, bukan sengaja merendahkan aset atau laba.","example":"Nilai wajar dapat relevan, tetapi asumsi dan ketidakpastiannya harus diungkapkan agar representasinya tepat.","keywords":"relevansi; faithful representation","comparison":"Keterbandingan dan keterverifikasian adalah karakteristik peningkat, bukan fundamental.","mnemonic":"R-T: Relevan untuk keputusan, Tepat untuk substansi."},{"number":17,"topic":"Manajemen Laba","subtopic":"Akrual vs Riil","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda accrual-based dan real earnings management?","shortAnswer":"Akrual mengubah estimasi/jurnal; riil mengubah keputusan operasi dan arus kas.","explanation":"Manajemen laba berbasis akrual menggunakan ruang estimasi seperti provisi, depresiasi, atau cut-off. Manajemen laba riil mengubah aktivitas ekonomi, misalnya diskon agresif, produksi berlebih, atau pemotongan riset. Praktik riil sering lebih mahal bagi nilai jangka panjang karena memengaruhi operasi nyata.","example":"Memperpanjang umur aset adalah akrual; overproduction adalah riil.","keywords":"accrual; real; cash flow","comparison":"Keduanya dapat menaikkan laba saat ini, tetapi jalur dan bukti deteksinya berbeda.","mnemonic":"A = Akun; R = Real operation."},{"number":18,"topic":"PSAK 117","subtopic":"GMM vs PAA","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda utama GMM dan PAA?","shortAnswer":"GMM adalah model umum FCF+CSM; PAA menyederhanakan pengukuran liabilitas sisa pertanggungan untuk kontrak yang memenuhi syarat.","explanation":"PAA sering relevan untuk coverage pendek atau ketika hasilnya mendekati GMM secara wajar. PAA bukan metode otomatis bagi semua kontrak satu tahun dan tetap memerlukan penilaian onerous, akuisisi, serta pengukuran klaim yang terjadi. GMM lebih eksplisit dalam pembaruan asumsi dan CSM.","example":"Kontrak kesehatan 12 bulan dapat diuji PAA bila arus kas tidak sensitif terhadap asumsi jangka panjang.","keywords":"GMM; PAA; eligibility","comparison":"VFA digunakan untuk direct participation features, bukan sekadar coverage pendek.","mnemonic":"GMM = General lengkap; PAA = Praktis apabila eligible."},{"number":19,"topic":"Sustainability Accounting","subtopic":"GRI vs IFRS S1/S2","difficulty":"Sulit","type":"Perbandingan","question":"Apa beda fokus GRI dan IFRS S1/S2?","shortAnswer":"GRI berorientasi dampak pada ekonomi, lingkungan, manusia; IFRS S1/S2 berorientasi informasi material bagi penyedia modal.","explanation":"GRI mendukung pelaporan dampak entitas terhadap masyarakat dan lingkungan. IFRS S1 dan S2 menekankan risiko serta peluang keberlanjutan yang dapat memengaruhi prospek keuangan entitas. Kedua pendekatan dapat digunakan secara komplementer, tetapi materialitas, pengguna utama, dan batas informasinya perlu dibedakan.","example":"Dampak pencemaran pada komunitas relevan bagi GRI; konsekuensi biaya, litigasi, dan arus kas relevan bagi IFRS S1/S2.","keywords":"GRI; IFRS S1; IFRS S2","comparison":"Materialitas dampak tidak identik dengan materialitas finansial.","mnemonic":"GRI = Give impact; IFRS = Investor financial relevance."},{"number":20,"topic":"Good Corporate Governance","subtopic":"Rasio Independensi","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menerapkan rasio independensi dewan?","shortAnswer":"Jumlah anggota independen ÷ total anggota × 100%, lalu evaluasi kualitas independensinya.","explanation":"Rasio memberi indikator kuantitatif struktur monitoring. Namun, analisis tata kelola harus melampaui persentase: periksa kompetensi, konflik kepentingan, masa jabatan, akses informasi, kualitas diskusi, dan tindak lanjut. Rasio tinggi tanpa independensi substantif tidak menjamin pengawasan efektif.","example":"3 anggota independen dari 5 anggota menghasilkan rasio 60%.","keywords":"dewan; independensi; monitoring","comparison":"Independensi formal berbeda dari independensi dalam sikap dan keputusan.","mnemonic":"3T: Total independen ÷ Total dewan × 100."},{"number":21,"topic":"Sustainability Accounting","subtopic":"Target Emisi","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menghitung target emisi setelah penurunan?","shortAnswer":"Target = baseline × (1 − persentase penurunan).","explanation":"Gunakan baseline yang konsisten dan terdokumentasi. Perubahan boundary, akuisisi, divestasi, atau faktor emisi dapat membuat baseline perlu disajikan kembali. Target sebaiknya dilengkapi tahun dasar, cakupan scope, metode, serta indikator absolut dan intensitas.","example":"Baseline 5.000 ton dan target turun 8% menghasilkan target 4.600 ton CO₂e.","keywords":"baseline; target; reduction","comparison":"Target absolut berbeda dari target intensitas; hasilnya dapat bergerak ke arah berbeda.","mnemonic":"Sisa = Dasar × (100% − target)."},{"number":22,"topic":"PSAK 118","subtopic":"Subtotal Laba Rugi","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menghitung laba sebelum pendanaan dan pajak?","shortAnswer":"Laba operasi + hasil neto kategori investasi.","explanation":"Subtotal ini memisahkan hasil operasi dan investasi dari dampak pendanaan serta pajak. Sebelum menghitung, akun harus diklasifikasikan dengan benar berdasarkan aktivitas bisnis utama dan definisi kategori. Kesalahan mapping akun dapat merusak rekonsiliasi dan keterbandingan.","example":"Laba operasi 1.700 + hasil investasi 200 = 1.900 juta.","keywords":"operasi; investasi; subtotal","comparison":"Laba operasi belum mencakup kategori investasi; laba sebelum pendanaan dan pajak mencakup keduanya.","mnemonic":"O + I = sebelum P dan P."},{"number":23,"topic":"Kerangka Konseptual","subtopic":"Kasus Materialitas","difficulty":"Sulit","type":"Mini Kasus","question":"Salah saji Rp650 juta; benchmark internal 1% dari aset Rp50 miliar. Apa kesimpulan awal?","shortAnswer":"Benchmark Rp500 juta; salah saji melebihi Rp150 juta dan terindikasi material secara kuantitatif.","explanation":"Perhitungan hanya langkah awal. Evaluasi akhir harus melihat sifat salah saji, tren laba, covenant, kepatuhan, dan potensi pengaburan. Benchmark internal bukan pengganti pertimbangan profesional dan bukan angka universal standar.","example":"Salah saji yang mengubah laba menjadi rugi dapat material walau nilainya di bawah benchmark.","keywords":"benchmark; material; judgment","comparison":"Kuantitatif memberi titik awal; kualitatif menentukan konteks dan konsekuensi.","mnemonic":"H-B-K: Hitung, Bandingkan, Konteks."},{"number":24,"topic":"Manajemen Laba","subtopic":"Kasus Overproduction","difficulty":"Sulit","type":"Mini Kasus","question":"Mengapa overproduction dapat menaikkan laba saat ini?","shortAnswer":"Biaya tetap per unit turun dan sebagian biaya tertahan dalam persediaan, sehingga HPP unit terjual lebih rendah.","explanation":"Produksi melebihi permintaan dapat mengalihkan biaya tetap dari HPP periode berjalan ke persediaan. Laba naik sementara, tetapi perusahaan menghadapi risiko biaya penyimpanan, persediaan usang, diskon penjualan, dan arus kas yang memburuk. Analisis harus membandingkan produksi, penjualan, persediaan, dan biaya abnormal.","example":"Biaya tetap Rp600 juta: produksi 100 ribu = Rp6.000/unit; 150 ribu = Rp4.000/unit.","keywords":"overproduction; HPP; inventory","comparison":"Efisiensi produksi yang didukung permintaan berbeda dari produksi berlebih untuk mencapai target laba.","mnemonic":"Produksi Naik → Biaya/unit Turun → Persediaan Naik."},{"number":25,"topic":"PSAK 117","subtopic":"Kasus Onerous","difficulty":"Sulit","type":"Mini Kasus","question":"Outflow 1.150, inflow 1.000, RA 80. Apa perlakuannya?","shortAnswer":"FCF = 230 juta; kelompok onerous dan kerugian diakui segera.","explanation":"Perhitungan FCF liabilitas adalah 1.150 + 80 − 1.000 = 230 juta. Karena tidak ada laba masa depan untuk ditampung, tidak dibentuk CSM negatif. Kerugian diakui langsung dan dipantau melalui loss component agar pemulihan berikutnya tidak menghasilkan pengakuan laba yang salah.","example":"Kontrak merugi tidak boleh dicampur dengan kontrak menguntungkan dalam kelompok yang sama.","keywords":"onerous; FCF; loss","comparison":"Profitable group membentuk CSM; onerous group mengakui kerugian.","mnemonic":"O + RA − I = Onerous loss."}]},"dpsia":{"id":"dpsia","title":"Desain Pengendalian Sistem Informasi Akuntansi","short":"DPSIA","konsen":["sisfo"],"quiz":[{"number":1,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"SDLC","learningOutcome":"Menjelaskan definisi dan fungsi SDLC","difficulty":"Mudah","type":"Definisi","question":"Pernyataan yang PALING TEPAT menggambarkan System Development Life Cycle (SDLC) adalah ...","options":["Pendekatan sistematis dan berurutan untuk mengarahkan pengembangan sistem melalui tahapan yang saling berkaitan","Teknik untuk menguji keamanan aplikasi setelah sistem digunakan oleh seluruh pengguna","Metode untuk membeli perangkat keras tanpa melakukan analisis kebutuhan organisasi","Prosedur pemeliharaan yang hanya dilakukan ketika sistem mengalami kegagalan"],"correct":"A","concept":"SDLC sebagai metodologi pengembangan sistem","explanation":"Jawaban A benar karena SDLC merupakan pendekatan sistematis yang membagi pengembangan sistem ke dalam tahapan seperti perencanaan, analisis, desain, implementasi, serta tindak lanjut dan pemeliharaan. Setiap tahap menghasilkan keluaran yang menjadi dasar bagi tahap berikutnya. SDLC tidak terbatas pada pengujian keamanan atau pemeliharaan, dan juga bukan sekadar proses pembelian perangkat keras. Dalam konteks SIA pemerintah, penggunaan tahapan yang jelas membantu dokumentasi, akuntabilitas keputusan, pengendalian perubahan, dan keterlacakan kebutuhan pengguna.","whyOthersWrong":"B hanya menggambarkan sebagian aktivitas pengujian; C mengabaikan analisis dan tata kelola; D menyempitkan SDLC menjadi pemeliharaan reaktif.","tip":"Cari kata 'sistematis', 'tahapan', dan 'saling berkaitan'. Ketiganya merupakan ciri utama SDLC.","reference":"TM 1; RPS DPSIA 2514C3A5; Romney dkk. (2021); Simkin dkk. (2018)","keywords":"SDLC; tahapan; pengembangan sistem"},{"number":2,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Reasonable assurance","learningOutcome":"Menjelaskan tingkat keyakinan pengendalian internal","difficulty":"Mudah","type":"Definisi","question":"Istilah reasonable assurance dalam pengendalian internal berarti ...","options":["Jaminan mutlak bahwa seluruh risiko dan kesalahan dapat dihilangkan","Keyakinan memadai bahwa tujuan organisasi dapat dicapai dengan mempertimbangkan keterbatasan bawaan","Keyakinan yang hanya diberikan setelah auditor menyatakan laporan keuangan wajar","Jaminan bahwa seluruh aktivitas pengendalian harus dilakukan secara otomatis"],"correct":"B","concept":"Keyakinan memadai dalam sistem pengendalian internal","explanation":"Jawaban B benar. Pengendalian internal memberikan keyakinan memadai, bukan jaminan mutlak, karena terdapat keterbatasan seperti kesalahan manusia, kolusi, pengabaian oleh manajemen, perubahan kondisi, dan pertimbangan biaya-manfaat. Maknanya, organisasi merancang pengendalian agar risiko turun ke tingkat yang dapat diterima dan tujuan lebih mungkin tercapai. Reasonable assurance tidak bergantung pada opini auditor dan tidak mengharuskan seluruh pengendalian bersifat otomatis. Pengendalian manual yang dirancang dan dijalankan dengan baik tetap dapat menjadi bagian penting dari sistem.","whyOthersWrong":"A keliru karena pengendalian tidak menghapus seluruh risiko; C mencampur pengendalian internal dengan opini audit; D menganggap otomatisasi sebagai syarat mutlak.","tip":"Kata kuncinya adalah 'memadai', bukan 'mutlak'. Ingat pula keterbatasan bawaan pengendalian.","reference":"TM 2; PP Nomor 60 Tahun 2008 tentang SPIP; RPS DPSIA 2514C3A5","keywords":"reasonable assurance; keterbatasan bawaan; tujuan"},{"number":3,"topic":"TM3 IT General Control","subtopic":"Authentication","learningOutcome":"Membedakan autentikasi dan otorisasi","difficulty":"Mudah","type":"Definisi","question":"Proses untuk memastikan bahwa seseorang benar-benar merupakan pengguna yang diklaim disebut ...","options":["Authorization","Access provisioning","Authentication","Segregation of duties"],"correct":"C","concept":"Autentikasi sebagai verifikasi identitas pengguna","explanation":"Jawaban C benar karena authentication atau autentikasi adalah proses memverifikasi identitas pengguna, misalnya melalui kata sandi, token, biometrik, atau autentikasi multifaktor. Setelah identitas terbukti, barulah authorization menentukan tindakan atau data apa yang boleh diakses pengguna tersebut. Access provisioning merupakan proses pemberian dan pengelolaan hak akses, sedangkan segregation of duties memisahkan tanggung jawab yang tidak kompatibel. Urutan yang umum adalah: identitas diverifikasi terlebih dahulu, kemudian hak akses diterapkan sesuai peran.","whyOthersWrong":"A menentukan hak setelah identitas dikenali; B merupakan administrasi hak akses; D adalah prinsip pemisahan fungsi.","tip":"Authentication menjawab 'siapa kamu?', sedangkan authorization menjawab 'apa yang boleh kamu lakukan?'.","reference":"TM 3; materi IT General Control; Romney dkk. (2021)","keywords":"authentication; identitas; akses"},{"number":4,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Studi kelayakan","learningOutcome":"Menjelaskan fungsi feasibility study","difficulty":"Mudah","type":"Definisi","question":"Dokumen yang menilai apakah rencana pengembangan sistem layak dari sisi teknis, ekonomi, operasional, hukum, dan waktu adalah ...","options":["Data dictionary","Post-implementation review","Program specification","Feasibility study"],"correct":"D","concept":"Studi kelayakan dalam perencanaan pengembangan sistem","explanation":"Jawaban D benar. Feasibility study atau studi kelayakan digunakan untuk menilai apakah usulan sistem patut dilanjutkan dengan melihat kemampuan teknologi, biaya dan manfaat, kesiapan operasional, kepatuhan hukum atau regulasi, serta waktu pelaksanaan. Hasilnya mendukung keputusan melanjutkan, mengubah, menunda, atau menghentikan proyek. Data dictionary mendokumentasikan elemen data, program specification menjelaskan kebutuhan program, sedangkan post-implementation review dilakukan setelah sistem digunakan. Karena itu, studi kelayakan merupakan instrumen penting sebelum komitmen sumber daya yang besar dibuat.","whyOthersWrong":"A berkaitan dengan metadata; B dilakukan setelah implementasi; C berfokus pada rancangan atau logika program.","tip":"Jika soal menanyakan keputusan go/no-go sebelum proyek berjalan penuh, pilih studi kelayakan.","reference":"TM 4; RPS DPSIA 2514C3A5; materi perencanaan pengembangan sistem","keywords":"feasibility study; kelayakan; perencanaan"},{"number":5,"topic":"TM5 Analisis Sistem","subtopic":"Kebutuhan fungsional","learningOutcome":"Menjelaskan functional requirement","difficulty":"Mudah","type":"Definisi","question":"Kebutuhan yang menjelaskan fungsi yang harus dapat dilakukan oleh sistem disebut ...","options":["Kebutuhan fungsional","Kebutuhan nonfungsional","Kebutuhan infrastruktur","Kebutuhan dokumentasi"],"correct":"A","concept":"Kebutuhan fungsional sebagai layanan yang harus dilakukan sistem","explanation":"Jawaban A benar karena kebutuhan fungsional menjelaskan layanan, proses, perhitungan, validasi, transaksi, atau keluaran yang harus disediakan sistem. Contohnya, sistem harus dapat mencatat tagihan, memverifikasi pagu, dan menghasilkan laporan realisasi. Kebutuhan nonfungsional menjelaskan karakteristik kualitas seperti keamanan, kinerja, ketersediaan, dan kemudahan penggunaan. Infrastruktur dan dokumentasi dapat menjadi bagian pendukung, tetapi bukan istilah utama untuk menyatakan apa yang harus dilakukan sistem. Pemisahan ini penting agar desain dan pengujian memiliki kriteria yang jelas.","whyOthersWrong":"B berfokus pada kualitas atau batasan; C berfokus pada sarana teknis; D berfokus pada bukti dan petunjuk penggunaan.","tip":"Functional = fungsi yang dilakukan. Nonfunctional = kualitas atau cara sistem melaksanakan fungsi.","reference":"TM 5; RPS DPSIA 2514C3A5; materi analisis sistem","keywords":"functional requirement; fungsi; user requirement"},{"number":6,"topic":"TM6 Desain Output","subtopic":"Exception report","learningOutcome":"Menjelaskan jenis output berdasarkan penyimpangan","difficulty":"Mudah","type":"Konseptual","question":"Laporan yang hanya menampilkan transaksi atau kondisi yang menyimpang dari batas yang ditetapkan disebut ...","options":["Periodic report","Detail report","Exception report","External report"],"correct":"C","concept":"Laporan pengecualian sebagai alat fokus manajemen","explanation":"Jawaban C benar karena exception report dirancang untuk menyoroti penyimpangan, anomali, atau kondisi yang melewati batas tertentu. Contohnya, transaksi di atas kewenangan, keterlambatan melebihi batas waktu, atau realisasi anggaran yang terlalu rendah. Laporan ini membantu manajemen memusatkan perhatian pada kondisi yang memerlukan tindak lanjut, bukan membaca seluruh transaksi. Periodic report mengacu pada waktu penerbitan, detail report mengacu pada tingkat rincian, dan external report mengacu pada penerima di luar organisasi.","whyOthersWrong":"A diterbitkan secara berkala tanpa harus berisi penyimpangan; B memuat rincian; D dibedakan berdasarkan penerima.","tip":"Kata 'menyimpang', 'anomali', atau 'melewati batas' biasanya mengarah pada exception report.","reference":"TM 6; materi desain output; Romney dkk. (2021)","keywords":"exception report; penyimpangan; output"},{"number":7,"topic":"TM7 Desain File & Database","subtopic":"Foreign key","learningOutcome":"Menjelaskan fungsi foreign key","difficulty":"Mudah","type":"Konseptual","question":"Dalam database relasional, atribut yang menghubungkan suatu tabel dengan primary key pada tabel lain disebut ...","options":["Candidate key","Foreign key","Composite key","Domain key"],"correct":"B","concept":"Foreign key sebagai penghubung antartabel","explanation":"Jawaban B benar. Foreign key adalah atribut pada satu tabel yang merujuk primary key pada tabel lain untuk membentuk relasi. Sebagai contoh, kode unit pada tabel transaksi dapat merujuk kode unit pada tabel unit kerja. Hubungan tersebut mendukung integritas referensial, yaitu mencegah transaksi mengacu pada unit yang tidak ada. Candidate key adalah atribut yang berpotensi menjadi kunci utama, sedangkan composite key tersusun dari lebih dari satu atribut. Istilah domain key bukan konsep utama yang digunakan pada konteks ini.","whyOthersWrong":"A adalah calon kunci unik; C adalah kunci gabungan; D bukan jawaban yang tepat untuk atribut penghubung antartabel.","tip":"Foreign key 'tinggal' di tabel anak dan menunjuk primary key di tabel induk.","reference":"TM 7; materi desain file dan database; Simkin dkk. (2018)","keywords":"foreign key; relasi; integritas referensial"},{"number":8,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"Prototyping","learningOutcome":"Menentukan kondisi penggunaan prototyping","difficulty":"Sedang","type":"Konseptual","question":"Pendekatan prototyping PALING SESUAI digunakan ketika ...","options":["Seluruh kebutuhan telah stabil dan tidak memerlukan umpan balik pengguna","Organisasi hanya akan mengganti perangkat keras tanpa mengubah proses","Sistem telah beroperasi dan hanya memerlukan pencadangan data","Kebutuhan belum sepenuhnya jelas dan pengguna perlu melihat model awal untuk memberi umpan balik"],"correct":"D","concept":"Prototyping sebagai proses iteratif untuk memperjelas kebutuhan","explanation":"Jawaban D benar. Prototyping membuat model sederhana dari sistem yang diusulkan agar pengguna dapat mencoba, menilai, dan memberi umpan balik. Pendekatan ini bermanfaat ketika kebutuhan sulit dijelaskan hanya melalui dokumen atau masih berubah. Model kemudian diperbaiki secara iteratif sampai kebutuhan lebih dipahami. Jika kebutuhan sudah stabil dan proses sangat terstruktur, pendekatan lain dapat lebih efisien. Prototyping juga bukan teknik pencadangan dan tidak terbatas pada penggantian perangkat keras.","whyOthersWrong":"A lebih cocok dengan kebutuhan yang stabil; B terlalu sempit; C merupakan aktivitas operasi dan kontinuitas.","tip":"Cari kombinasi 'kebutuhan belum jelas', 'model awal', dan 'umpan balik berulang'.","reference":"TM 1; materi metodologi pengembangan sistem; Romney dkk. (2021)","keywords":"prototyping; kebutuhan; umpan balik"},{"number":9,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Tujuan-risiko-pengendalian","learningOutcome":"Menganalisis hubungan tujuan, risiko, dan pengendalian","difficulty":"Sedang","type":"Konseptual","question":"Hubungan tujuan, risiko, dan pengendalian yang PALING TEPAT adalah ...","options":["Tujuan menentukan hasil yang ingin dicapai, risiko menghambat pencapaiannya, dan pengendalian merespons risiko","Risiko baru dapat diidentifikasi setelah seluruh pengendalian dijalankan","Pengendalian menggantikan tujuan karena fokus utama organisasi adalah menghindari kesalahan","Setiap risiko harus dihilangkan tanpa mempertimbangkan biaya dan manfaat"],"correct":"A","concept":"Pengendalian sebagai respons terhadap risiko pencapaian tujuan","explanation":"Jawaban A benar. Organisasi terlebih dahulu menetapkan tujuan, lalu mengidentifikasi kejadian yang dapat menghambat tujuan tersebut. Pengendalian dirancang sebagai respons untuk mencegah, mendeteksi, atau mengoreksi dampak risiko. Pengendalian bukan tujuan itu sendiri dan tidak harus menghilangkan seluruh risiko. Pilihan respons juga mempertimbangkan tingkat risiko, biaya, manfaat, dan toleransi organisasi. Hubungan ini penting karena pengendalian yang tidak dikaitkan dengan tujuan dan risiko berpotensi menjadi prosedur administratif yang mahal tetapi tidak efektif.","whyOthersWrong":"B membalik urutan logis; C menjadikan pengendalian sebagai tujuan; D mengabaikan konsep risiko residual dan biaya-manfaat.","tip":"Urutan dasarnya: tujuan → risiko → respons/pengendalian → pemantauan.","reference":"TM 2; PP Nomor 60 Tahun 2008; materi kerangka pengendalian","keywords":"tujuan; risiko; pengendalian"},{"number":10,"topic":"TM3 IT General Control","subtopic":"Ketergantungan application control pada ITGC","learningOutcome":"Menjelaskan hubungan ITGC dan pengendalian aplikasi","difficulty":"Sedang","type":"Konseptual","question":"Mengapa kelemahan IT General Control dapat mengurangi keandalan pengendalian aplikasi?","options":["Karena pengendalian aplikasi hanya dapat dijalankan oleh auditor eksternal","Karena perubahan program, akses, dan operasi yang tidak terkendali dapat membuat logika aplikasi dimanipulasi atau tidak konsisten","Karena ITGC menggantikan seluruh validasi input dan rekonsiliasi output","Karena pengendalian aplikasi tidak memerlukan dokumentasi dan pengujian"],"correct":"B","concept":"Fondasi ITGC bagi konsistensi pengendalian aplikasi","explanation":"Jawaban B benar. Pengendalian aplikasi bergantung pada lingkungan TI yang terkendali. Jika pengembang dapat mengubah program tanpa persetujuan, pengguna memiliki akses berlebihan, atau operasi dan backup tidak dikelola, maka validasi dan perhitungan di aplikasi dapat diubah, dilewati, atau tidak tersedia saat dibutuhkan. ITGC tidak menggantikan pengendalian aplikasi, melainkan memberikan fondasi agar pengendalian aplikasi berjalan konsisten. Keduanya perlu didokumentasikan dan diuji sesuai risiko yang relevan.","whyOthersWrong":"A salah karena kontrol aplikasi dijalankan sistem dan organisasi; C menyamakan dua lapisan kontrol; D meniadakan kebutuhan bukti.","tip":"Bayangkan ITGC sebagai fondasi gedung dan pengendalian aplikasi sebagai ruangan di atasnya.","reference":"TM 3; materi IT General Control; Romney dkk. (2021)","keywords":"ITGC; application control; change management"},{"number":11,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Project charter","learningOutcome":"Menerapkan dokumen inisiasi proyek","difficulty":"Sedang","type":"Penerapan","question":"Sebuah instansi akan memulai proyek sistem persediaan. Dokumen PERTAMA yang paling tepat untuk menetapkan tujuan, ruang lingkup awal, sponsor, tim, dan kewenangan proyek adalah ...","options":["Data flow diagram","User acceptance test report","Project charter","Database schema"],"correct":"C","concept":"Project charter sebagai dokumen otorisasi awal proyek","explanation":"Jawaban C benar. Project charter mengesahkan proyek secara formal dan merangkum tujuan, ruang lingkup awal, sponsor, pemangku kepentingan, peran utama, sasaran, batasan, dan kewenangan manajer proyek. Dokumen ini memberi arah sebelum analisis dan desain rinci dilakukan. Data flow diagram digunakan untuk memodelkan aliran data, user acceptance test report disusun menjelang atau saat penerimaan sistem, sedangkan database schema merupakan hasil desain data. Tanpa charter, proyek mudah mengalami ketidakjelasan mandat dan perluasan ruang lingkup.","whyOthersWrong":"A dan D merupakan artefak analisis/desain; B merupakan artefak pengujian penerimaan, bukan inisiasi.","tip":"Jika yang diminta adalah otorisasi dan arah awal proyek, jawabannya biasanya project charter.","reference":"TM 4; materi perencanaan pengembangan sistem; RPS DPSIA 2514C3A5","keywords":"project charter; scope; sponsor"},{"number":12,"topic":"TM5 Analisis Sistem","subtopic":"Validasi kebutuhan","learningOutcome":"Menerapkan validasi user requirement","difficulty":"Sedang","type":"Penerapan","question":"Sebelum Software Requirements Specification disetujui, tindakan yang PALING TEPAT adalah ...","options":["Langsung memindahkan program ke lingkungan produksi","Menghapus kebutuhan yang sulit diuji tanpa berdiskusi dengan pengguna","Menentukan seluruh hak akses hanya berdasarkan keinginan pengembang","Memvalidasi kebutuhan bersama pengguna dan memastikan kebutuhan jelas, konsisten, dapat diuji, serta dapat ditelusuri"],"correct":"D","concept":"Validasi kebutuhan sebelum baseline spesifikasi","explanation":"Jawaban D benar. Sebelum SRS menjadi baseline, kebutuhan perlu ditinjau bersama pengguna dan pemangku kepentingan agar tidak ambigu, bertentangan, tidak lengkap, atau sulit diuji. Kebutuhan yang baik dapat ditelusuri ke tujuan bisnis dan nantinya ke desain serta skenario pengujian. Memindahkan program ke produksi terlalu dini, menghapus kebutuhan secara sepihak, atau menetapkan akses hanya dari sudut pandang pengembang meningkatkan risiko sistem tidak sesuai kebutuhan dan lemah dari sisi pengendalian.","whyOthersWrong":"A melompati desain dan pengujian; B mengabaikan pemilik kebutuhan; C mengabaikan proses bisnis dan prinsip least privilege.","tip":"Sebelum sign-off, cari tindakan yang meningkatkan kejelasan, konsistensi, keterujian, dan keterlacakan kebutuhan.","reference":"TM 5; materi analisis sistem; RPS DPSIA 2514C3A5","keywords":"SRS; validasi kebutuhan; traceability"},{"number":13,"topic":"TM6 Desain Output","subtopic":"Dashboard manajerial","learningOutcome":"Menentukan desain output sesuai pengguna","difficulty":"Sedang","type":"Penerapan","question":"Untuk pimpinan yang perlu memantau realisasi anggaran secara cepat, desain output yang PALING SESUAI adalah ...","options":["Dashboard ringkas dengan indikator utama, tren, filter, dan peringatan penyimpangan","Daftar seluruh jurnal transaksi tanpa pengelompokan","Dokumen sumber hasil pemindaian tanpa ringkasan","File log teknis aplikasi yang berisi seluruh aktivitas sistem"],"correct":"A","concept":"Desain output berbasis kebutuhan pengambil keputusan","explanation":"Jawaban A benar. Pimpinan membutuhkan informasi ringkas, relevan, tepat waktu, dan berorientasi keputusan. Dashboard yang menampilkan pagu, realisasi, sisa, tren, indikator kinerja, serta peringatan anomali membantu pemantauan tanpa menenggelamkan pengguna dalam rincian transaksi. Detail tetap dapat disediakan melalui drill-down. Daftar jurnal, hasil pemindaian, dan log teknis lebih cocok untuk kebutuhan operasional atau investigasi tertentu. Prinsip pentingnya adalah menyesuaikan isi, format, frekuensi, dan tingkat rincian dengan pengguna output.","whyOthersWrong":"B terlalu rinci; C tidak menyediakan informasi terolah; D berorientasi teknis dan bukan kebutuhan utama pimpinan.","tip":"Cocokkan tingkat rincian output dengan tingkat keputusan pengguna.","reference":"TM 6; materi desain output; Romney dkk. (2021)","keywords":"dashboard; ringkasan; exception"},{"number":14,"topic":"TM7 Desain File & Database","subtopic":"Relasi many-to-many","learningOutcome":"Menerapkan desain relasi database","difficulty":"Sedang","type":"Penerapan","question":"Satu tagihan dapat dibiayai oleh beberapa sumber dana dan satu sumber dana dapat membiayai banyak tagihan. Desain relasional yang tepat adalah ...","options":["Menyimpan seluruh sumber dana dalam satu field teks pada tabel tagihan","Membuat tabel penghubung yang berisi kunci tagihan dan kunci sumber dana","Menghapus primary key agar setiap baris dapat diulang","Menggabungkan semua data tagihan dan sumber dana dalam satu tabel tanpa pemisahan"],"correct":"B","concept":"Pemecahan relasi many-to-many melalui tabel penghubung","explanation":"Jawaban B benar. Relasi many-to-many tidak diterapkan langsung dalam database relasional, tetapi dipecah melalui junction table atau tabel penghubung. Tabel tersebut memuat foreign key tagihan dan foreign key sumber dana, serta dapat menyimpan atribut hubungan seperti nilai pembiayaan. Menaruh banyak nilai dalam satu field melanggar prinsip atomisitas, sedangkan menghapus primary key atau menggabungkan seluruh data meningkatkan duplikasi dan anomali. Desain tabel penghubung menjaga struktur relasi tetap jelas dan dapat dikendalikan.","whyOthersWrong":"A menghasilkan data tidak atomik; C menghilangkan identifikasi unik; D meningkatkan redundansi dan inkonsistensi.","tip":"Jika kedua sisi sama-sama 'banyak', pikirkan junction table.","reference":"TM 7; materi desain database relasional; Simkin dkk. (2018)","keywords":"many-to-many; junction table; foreign key"},{"number":15,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"Post-implementation review","learningOutcome":"Menerapkan evaluasi pascaimplementasi","difficulty":"Sedang","type":"Penerapan","question":"Enam bulan setelah aplikasi perjalanan dinas digunakan, organisasi ingin menilai apakah manfaat tercapai, pengguna puas, dan pengendalian berjalan efektif. Kegiatan yang tepat adalah ...","options":["Preliminary investigation","Program coding","Post-implementation review","Vendor selection"],"correct":"C","concept":"Evaluasi sistem setelah digunakan secara nyata","explanation":"Jawaban C benar. Post-implementation review dilakukan setelah sistem berjalan untuk membandingkan hasil aktual dengan tujuan, biaya, manfaat, kebutuhan pengguna, dan rancangan pengendalian. Kegiatan ini dapat menemukan masalah penggunaan, kelemahan prosedur, kebutuhan pelatihan, atau perbaikan sistem. Preliminary investigation dilakukan pada tahap awal, coding merupakan aktivitas pembangunan, dan vendor selection merupakan bagian pengadaan. Evaluasi pascaimplementasi penting agar organisasi tidak berhenti pada keberhasilan go-live, tetapi memastikan nilai dan akuntabilitas investasi.","whyOthersWrong":"A dilakukan sebelum pengembangan; B membangun program; D memilih pemasok sebelum implementasi.","tip":"Jika sistem sudah digunakan dan yang dinilai adalah manfaat aktual, jawabannya post-implementation review.","reference":"TM 1; materi SDLC; Romney dkk. (2021)","keywords":"post-implementation review; manfaat; evaluasi"},{"number":16,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Otorisasi transaksi","learningOutcome":"Menentukan pengendalian preventif pada proses pembayaran","difficulty":"Sedang","type":"Mini Kasus","question":"Aplikasi pembayaran baru memproses tagihan segera setelah operator menginput data, tanpa persetujuan pejabat berwenang. Pengendalian yang PALING TEPAT adalah ...","options":["Mencetak laporan bulanan setelah seluruh pembayaran selesai","Membuat salinan cadangan database setiap malam","Mengganti warna tampilan formulir agar lebih mudah dibaca","Mewajibkan otorisasi elektronik sesuai kewenangan sebelum transaksi diproses"],"correct":"D","concept":"Otorisasi sebagai pengendalian preventif atas transaksi","explanation":"Jawaban D benar. Risiko utama adalah pembayaran tidak sah karena operator dapat memproses transaksi tanpa persetujuan. Otorisasi elektronik sebelum pemrosesan merupakan pengendalian preventif yang memastikan transaksi disetujui oleh pejabat sesuai batas kewenangan. Laporan bulanan bersifat detektif dan terlambat untuk mencegah pembayaran; backup melindungi ketersediaan data, bukan keabsahan transaksi; perubahan warna hanya memperbaiki antarmuka. Pengendalian juga sebaiknya didukung audit trail dan pemisahan peran input, verifikasi, dan persetujuan.","whyOthersWrong":"A mendeteksi setelah kejadian; B menangani pemulihan data; C tidak menanggapi risiko otorisasi.","tip":"Perhatikan kata 'sebelum transaksi diproses'—ini menunjukkan kontrol preventif.","reference":"TM 2; PP Nomor 60 Tahun 2008; materi kegiatan pengendalian","keywords":"otorisasi; preventif; pembayaran"},{"number":17,"topic":"TM3 IT General Control","subtopic":"User access lifecycle","learningOutcome":"Menentukan respons atas akses pegawai yang tidak lagi berwenang","difficulty":"Sedang","type":"Mini Kasus","question":"Pegawai yang telah pindah unit masih dapat menyetujui transaksi pada aplikasi lama. Tindakan yang PALING TEPAT adalah ...","options":["Segera mencabut atau menyesuaikan akses, meninjau aktivitas sejak perpindahan, dan memperbaiki proses review akses berkala","Membiarkan akses tetap aktif sampai pegawai meminta penghapusan","Mengganti kata sandi pegawai tanpa mengubah peran dan hak akses","Menghapus seluruh log aktivitas agar akun tidak lagi terlihat"],"correct":"A","concept":"Pengelolaan siklus hidup akses dan peninjauan hak pengguna","explanation":"Jawaban A benar. Perpindahan tugas harus memicu perubahan atau pencabutan hak akses agar sesuai prinsip least privilege. Organisasi juga perlu meninjau log sejak tanggal perpindahan untuk mengetahui apakah akses digunakan secara tidak tepat dan memperbaiki integrasi proses kepegawaian dengan administrasi akses. Membiarkan akun aktif atau hanya mengganti kata sandi tidak menyelesaikan hak yang berlebihan. Menghapus log justru menghilangkan bukti audit dan dapat memperbesar risiko penyembunyian aktivitas.","whyOthersWrong":"B menunda respons risiko; C tidak mengoreksi otorisasi; D merusak audit trail.","tip":"Jawaban lengkap biasanya mencakup koreksi akses, pemeriksaan dampak, dan perbaikan proses.","reference":"TM 3; materi access control dan privileged access; Romney dkk. (2021)","keywords":"deprovisioning; access review; least privilege"},{"number":18,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Scope creep","learningOutcome":"Menentukan pengendalian atas perubahan ruang lingkup","difficulty":"Sedang","type":"Mini Kasus","question":"Proyek aplikasi persediaan terus terlambat karena unit pengguna berulang kali menambah fitur tanpa analisis dampak. Respons yang PALING TEPAT adalah ...","options":["Menerima seluruh permintaan agar pengguna selalu puas","Menetapkan baseline ruang lingkup dan menerapkan prosedur change control yang menilai dampak biaya, waktu, risiko, serta persetujuan","Menghapus jadwal proyek agar tim lebih fleksibel","Memindahkan sistem ke produksi meskipun fitur belum diuji"],"correct":"B","concept":"Pengendalian perubahan ruang lingkup proyek","explanation":"Jawaban B benar. Scope creep terjadi ketika ruang lingkup bertambah tanpa proses evaluasi dan persetujuan yang memadai. Baseline ruang lingkup memberi acuan, sedangkan change control mewajibkan setiap permintaan dianalisis terhadap manfaat, biaya, waktu, sumber daya, risiko, arsitektur, dan pengendalian. Permintaan dapat diterima, ditunda, atau ditolak secara terdokumentasi. Menerima seluruh permintaan, menghapus jadwal, atau melakukan go-live tanpa pengujian justru meningkatkan risiko keterlambatan, pembengkakan biaya, dan kegagalan sistem.","whyOthersWrong":"A mengabaikan batas proyek; C menghilangkan alat pemantauan; D mengorbankan kualitas dan pengendalian.","tip":"Jika masalahnya penambahan fitur tidak terkendali, cari baseline dan change control.","reference":"TM 4; materi scope, risk register, dan perencanaan proyek","keywords":"scope creep; change control; baseline"},{"number":19,"topic":"TM5 Analisis Sistem","subtopic":"Triangulasi pengumpulan data","learningOutcome":"Mengevaluasi bukti analisis sistem yang bertentangan","difficulty":"Sulit","type":"Mini Kasus","question":"Dalam wawancara, petugas menyatakan setiap tagihan diverifikasi. Namun sampel dokumen menunjukkan banyak bukti verifikasi kosong. Langkah analisis yang PALING TEPAT adalah ...","options":["Menggunakan hasil wawancara karena berasal langsung dari petugas","Mengabaikan dokumen karena tidak menggambarkan niat petugas","Melakukan triangulasi melalui observasi, penelusuran dokumen, dan klarifikasi untuk membedakan prosedur formal dengan praktik aktual","Langsung menyimpulkan terjadi kecurangan tanpa pengujian tambahan"],"correct":"C","concept":"Penggunaan beberapa teknik untuk memahami proses aktual","explanation":"Jawaban C benar. Ketika sumber informasi bertentangan, analis perlu menggabungkan wawancara, observasi, pemeriksaan dokumen, sampling, dan klarifikasi. Tujuannya membedakan prosedur yang seharusnya berlaku dengan praktik aktual dan menemukan penyebab ketidaksesuaian. Mengandalkan satu sumber dapat menghasilkan kebutuhan yang salah. Kekosongan bukti verifikasi menunjukkan indikasi kelemahan proses, tetapi belum cukup untuk langsung menyimpulkan kecurangan. Hasil triangulasi harus didokumentasikan dan digunakan untuk merumuskan risiko, kebutuhan, serta titik pengendalian.","whyOthersWrong":"A dan B bias pada satu sumber; D melompat ke kesimpulan tanpa dasar pengujian yang cukup.","tip":"Jika bukti saling bertentangan, pilih metode yang menggabungkan beberapa sumber dan memvalidasi fakta.","reference":"TM 5; materi teknik pengumpulan data dan analisis current system","keywords":"triangulasi; current system; bukti"},{"number":20,"topic":"TM6 Desain Output","subtopic":"Distribusi output","learningOutcome":"Menentukan pengendalian kerahasiaan laporan","difficulty":"Sulit","type":"Mini Kasus","question":"Laporan yang memuat data sensitif dikirim otomatis ke seluruh pegawai, padahal hanya pimpinan tertentu yang membutuhkan. Perbaikan PALING TEPAT adalah ...","options":["Menghapus nama laporan agar tidak menarik perhatian","Meningkatkan ukuran file agar sulit diteruskan","Mencetak laporan dalam jumlah lebih banyak untuk arsip","Menerapkan klasifikasi informasi, role-based access, daftar distribusi terotorisasi, enkripsi, dan pencatatan pengiriman"],"correct":"D","concept":"Pengendalian distribusi dan penggunaan output","explanation":"Jawaban D benar. Risiko berada pada kerahasiaan dan penggunaan laporan oleh pihak yang tidak berwenang. Pengendalian yang tepat harus dimulai dari klasifikasi informasi dan kebutuhan pengguna, kemudian menerapkan akses berbasis peran, distribusi terbatas, enkripsi saat pengiriman, serta log untuk keterlacakan. Mengubah nama, memperbesar ukuran file, atau mencetak lebih banyak salinan tidak mengurangi hak akses dan bahkan dapat memperbesar paparan. Desain output harus mencakup isi, format, media, penerima, jadwal, retensi, dan keamanan.","whyOthersWrong":"A hanya kosmetik; B tidak membatasi penerima; C menambah salinan dan risiko kebocoran.","tip":"Pada soal kerahasiaan output, cari kombinasi need-to-know, akses berbasis peran, proteksi transmisi, dan audit trail.","reference":"TM 6; materi pengendalian output dan keamanan informasi","keywords":"confidentiality; output distribution; role-based access"},{"number":21,"topic":"TM7 Desain File & Database","subtopic":"Primary key vs foreign key","learningOutcome":"Membedakan dua jenis kunci relasional","difficulty":"Sulit","type":"Perbandingan","question":"Perbedaan primary key dan foreign key yang PALING TEPAT adalah ...","options":["Primary key mengidentifikasi unik setiap baris, sedangkan foreign key merujuk kunci pada tabel lain untuk membentuk relasi","Primary key boleh selalu duplikat, sedangkan foreign key tidak boleh muncul lebih dari sekali","Primary key hanya digunakan untuk laporan, sedangkan foreign key hanya digunakan untuk backup","Primary key dan foreign key memiliki fungsi yang sama dan selalu berada pada tabel yang sama"],"correct":"A","concept":"Peran identifikasi dan penghubung dalam database relasional","explanation":"Jawaban A benar. Primary key memastikan setiap record pada sebuah tabel dapat diidentifikasi secara unik dan umumnya tidak boleh null. Foreign key digunakan untuk merujuk primary key atau kunci unik pada tabel lain sehingga hubungan antartabel terbentuk. Foreign key dapat berulang karena banyak transaksi dapat merujuk satu unit kerja. Keduanya berbeda fungsi tetapi bekerja bersama untuk menjaga struktur dan integritas referensial. Pilihan lain keliru karena membalik aturan keunikan atau memberi fungsi yang tidak berkaitan dengan kunci.","whyOthersWrong":"B membalik sifat keunikan; C mengaitkan kunci dengan laporan/backup; D menghilangkan perbedaan fungsi.","tip":"Primary = identitas utama baris. Foreign = penghubung ke tabel lain.","reference":"TM 7; materi desain database relasional","keywords":"primary key; foreign key; relasi"},{"number":22,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"Analisis vs desain","learningOutcome":"Membedakan tahap analisis dan desain","difficulty":"Sulit","type":"Perbandingan","question":"Pernyataan yang PALING TEPAT membedakan analisis sistem dan desain sistem adalah ...","options":["Analisis menentukan bahasa pemrograman, sedangkan desain hanya mewawancarai pengguna","Analisis menjelaskan apa yang dibutuhkan dan masalah yang harus diselesaikan, sedangkan desain menentukan bagaimana sistem memenuhi kebutuhan tersebut","Analisis dilakukan setelah implementasi, sedangkan desain dilakukan setelah pemeliharaan","Analisis dan desain merupakan istilah yang sama sehingga dapat dipertukarkan"],"correct":"B","concept":"Analisis sebagai apa dan desain sebagai bagaimana","explanation":"Jawaban B benar. Analisis berfokus pada pemahaman proses berjalan, masalah, risiko, kebutuhan pengguna, serta fungsi dan kualitas yang harus dipenuhi. Desain menerjemahkan kebutuhan itu menjadi rancangan proses, data, input, output, antarmuka, program, arsitektur, dan pengendalian. Meskipun dapat berlangsung iteratif, keduanya memiliki fokus berbeda. Bahasa pemrograman dapat dipertimbangkan pada desain teknis, sedangkan wawancara umumnya merupakan teknik analisis. Analisis dan desain tidak terjadi setelah pemeliharaan dan tidak boleh dipertukarkan tanpa konteks.","whyOthersWrong":"A membalik aktivitas; C salah urutan; D mengabaikan perbedaan tujuan dan keluaran.","tip":"Gunakan mnemonik: Analysis = WHAT, Design = HOW.","reference":"TM 1 dan TM 5; materi SDLC dan analisis sistem","keywords":"analysis; design; what vs how"},{"number":23,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Preventive vs detective control","learningOutcome":"Membedakan waktu dan tujuan pengendalian","difficulty":"Sulit","type":"Perbandingan","question":"Perbedaan pengendalian preventif dan detektif yang PALING TEPAT adalah ...","options":["Preventif selalu manual, sedangkan detektif selalu otomatis","Preventif hanya digunakan pada database, sedangkan detektif hanya digunakan pada laporan","Preventif dirancang mencegah kejadian sebelum atau saat proses, sedangkan detektif menemukan kejadian yang telah atau sedang terjadi","Preventif dan detektif tidak dapat digunakan bersamaan dalam satu proses"],"correct":"C","concept":"Perbedaan tujuan dan waktu pengendalian","explanation":"Jawaban C benar. Pengendalian preventif berupaya menghalangi kesalahan atau ketidakberesan sebelum menimbulkan dampak, misalnya otorisasi, pembatasan akses, dan validasi input. Pengendalian detektif mengidentifikasi kejadian yang telah atau sedang terjadi, misalnya rekonsiliasi, review laporan pengecualian, dan pemantauan log. Keduanya dapat manual atau otomatis dan sering digunakan bersama sebagai lapisan pertahanan. Efektivitasnya dinilai berdasarkan risiko, waktu respons, bukti pelaksanaan, serta tindak lanjut atas temuan.","whyOthersWrong":"A dan B membuat klasifikasi palsu; D keliru karena kontrol berlapis justru lazim digunakan.","tip":"Preventif = sebelum/menahan. Detektif = menemukan/menandai.","reference":"TM 2; PP Nomor 60 Tahun 2008; materi klasifikasi pengendalian","keywords":"preventive; detective; timing"},{"number":24,"topic":"TM3 IT General Control","subtopic":"Segregation of duties & change management","learningOutcome":"Mengevaluasi kelemahan ITGC berisiko tinggi","difficulty":"Sulit","type":"Analisis","question":"Seorang pengembang dapat mengubah program, memindahkan perubahan ke production, dan menghapus log tanpa review pihak lain. Paket pengendalian yang PALING TEPAT adalah ...","options":["Memberi pengembang hak administrator tambahan agar perubahan lebih cepat","Mengandalkan backup mingguan tanpa mengubah hak akses","Meminta pengembang menandatangani pernyataan integritas tanpa mengubah proses","Memisahkan pengembangan dan deployment, mewajibkan persetujuan serta pengujian independen, membatasi akses production, dan melindungi log dari perubahan"],"correct":"D","concept":"Pemisahan fungsi dan pengendalian perubahan berlapis","explanation":"Jawaban D benar. Kombinasi akses pengembangan, deployment, dan penghapusan log memberi satu orang kemampuan melakukan serta menyembunyikan perubahan tanpa deteksi. Respons harus berlapis: perubahan diminta dan disetujui, dikembangkan di lingkungan terpisah, diuji oleh pihak independen, dipindahkan ke production oleh fungsi yang berwenang, dan direkam dalam log yang dilindungi. Akses darurat juga perlu dibatasi dan ditinjau. Backup atau pernyataan integritas tidak menggantikan pemisahan fungsi dan bukti perubahan.","whyOthersWrong":"A memperbesar konflik akses; B hanya membantu pemulihan; C merupakan kontrol lemah tanpa pembatasan teknis dan review.","tip":"Pada risiko perubahan program, cari empat unsur: approval, testing, segregation, dan protected logging.","reference":"TM 3; materi change management dan privileged access; Romney dkk. (2021)","keywords":"segregation of duties; change management; immutable log"},{"number":25,"topic":"TM7 Desain File & Database","subtopic":"Normalisasi dan integritas data","learningOutcome":"Mengevaluasi desain tabel yang menimbulkan anomali","difficulty":"Sulit","type":"Analisis","question":"Satu tabel menyimpan data pegawai, unit, tagihan, dan pembayaran secara berulang. Perubahan nama unit harus dilakukan pada ratusan baris dan hasilnya sering tidak konsisten. Solusi PALING TEPAT adalah ...","options":["Memisahkan entitas ke tabel yang sesuai, menerapkan primary/foreign key, normalisasi, dan aturan integritas","Menambah kolom baru setiap kali terdapat perubahan nama unit","Mengizinkan pengguna menyalin baris lama agar data historis tetap terlihat","Menghapus seluruh validasi agar pembaruan dapat dilakukan lebih cepat"],"correct":"A","concept":"Normalisasi untuk mengurangi redundansi dan anomali","explanation":"Jawaban A benar. Gejala tersebut menunjukkan redundansi dan update anomaly: fakta yang sama disimpan berulang sehingga perubahan harus dilakukan pada banyak baris dan mudah menghasilkan inkonsistensi. Desain yang tepat memisahkan entitas pegawai, unit, tagihan, dan pembayaran, lalu menghubungkannya dengan primary key dan foreign key. Normalisasi serta aturan integritas membantu memastikan setiap fakta disimpan pada tempat yang benar. Menambah kolom, menyalin baris, atau menghapus validasi justru memperbesar masalah kualitas data.","whyOthersWrong":"B dan C menambah redundansi; D mengurangi kontrol dan memperbesar kesalahan.","tip":"Jika satu fakta diulang dan pembaruan menimbulkan inkonsistensi, pikirkan normalisasi dan integritas referensial.","reference":"TM 7; materi normalisasi, anomali, dan integritas data","keywords":"normalisasi; update anomaly; data integrity"}],"flashcards":[{"number":1,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"Sistem informasi akuntansi","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud Sistem Informasi Akuntansi (SIA)?","shortAnswer":"Sistem yang mengumpulkan, mencatat, menyimpan, dan mengolah data transaksi menjadi informasi untuk pengambilan keputusan dan pengendalian.","explanation":"SIA tidak hanya berupa aplikasi. SIA mencakup manusia, prosedur, data, perangkat lunak, infrastruktur, dan pengendalian. Tujuannya memastikan transaksi diproses secara lengkap, akurat, sah, tepat waktu, serta menghasilkan informasi yang relevan bagi pengguna.","example":"Aplikasi pembayaran yang terhubung dengan prosedur verifikasi, basis data tagihan, pengguna, dan laporan realisasi.","keywords":"SIA; data; informasi; pengendalian","comparison":"Sistem vs aplikasi: aplikasi hanya salah satu komponen sistem.","mnemonic":"Ingat 6P: People, Procedure, Platform, Program, Penyimpanan data, Pengendalian."},{"number":2,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"SDLC","difficulty":"Mudah","type":"Definisi","question":"Apa definisi singkat SDLC?","shortAnswer":"Pendekatan sistematis untuk mengembangkan sistem melalui tahapan perencanaan, analisis, desain, implementasi, dan pemeliharaan.","explanation":"Setiap tahap SDLC menghasilkan keluaran yang menjadi masukan bagi tahap berikutnya. Struktur ini membantu proyek memiliki tujuan, kebutuhan, rancangan, pengujian, dokumentasi, dan evaluasi yang dapat ditelusuri.","example":"Sebelum membuat aplikasi persediaan, tim merencanakan proyek, menganalisis kebutuhan, mendesain database, menguji, lalu mengimplementasikan.","keywords":"SDLC; lifecycle; tahapan","comparison":"Pengembangan vs pemeliharaan: pemeliharaan adalah salah satu bagian siklus.","mnemonic":"P-A-D-I-P: Plan, Analyze, Design, Implement, Preserve."},{"number":3,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Pengendalian internal","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud pengendalian internal?","shortAnswer":"Proses yang dirancang dan dijalankan untuk memberikan keyakinan memadai atas pencapaian tujuan organisasi.","explanation":"Pengendalian internal mencakup kebijakan, prosedur, perilaku, struktur, dan aktivitas yang menangani risiko. Tujuannya berkaitan dengan efektivitas dan efisiensi, keandalan pelaporan, pengamanan aset, serta kepatuhan.","example":"Pembayaran hanya dapat diproses setelah verifikasi dokumen dan otorisasi pejabat sesuai kewenangan.","keywords":"internal control; tujuan; risiko","comparison":"Pengendalian internal vs audit: audit mengevaluasi, pengendalian dijalankan dalam proses.","mnemonic":"Tujuan–Risiko–Kontrol: kontrol selalu harus terkait risiko terhadap tujuan."},{"number":4,"topic":"TM3 IT General Control","subtopic":"IT General Control","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud IT General Control (ITGC)?","shortAnswer":"Pengendalian umum yang menjaga lingkungan TI agar sistem dan pengendalian aplikasi dapat berjalan konsisten dan andal.","explanation":"ITGC biasanya mencakup tata kelola TI, pengelolaan akses, perubahan program, operasi TI, backup, pemulihan, keamanan fisik, dan pengelolaan insiden. Kelemahan ITGC dapat membuat kontrol aplikasi mudah diubah atau dilewati.","example":"Perubahan program hanya dapat dipindahkan ke production setelah persetujuan, pengujian, dan deployment oleh pihak berwenang.","keywords":"ITGC; access; change; operations","comparison":"ITGC vs application control: ITGC bersifat lintas sistem; application control melekat pada transaksi atau aplikasi tertentu.","mnemonic":"A-C-O: Access, Change, Operations."},{"number":5,"topic":"TM5 Analisis Sistem","subtopic":"User requirement","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud user requirement?","shortAnswer":"Kebutuhan pengguna terhadap fungsi, informasi, kualitas, dan batasan sistem yang akan dikembangkan.","explanation":"User requirement menggambarkan apa yang dibutuhkan pengguna dari perspektif proses bisnis. Kebutuhan kemudian dirinci menjadi kebutuhan fungsional, nonfungsional, data, keamanan, integrasi, dan pelaporan.","example":"Bendahara membutuhkan sistem yang dapat memeriksa pagu, mencatat pembayaran, dan menghasilkan laporan per unit.","keywords":"user requirement; kebutuhan; pengguna","comparison":"User requirement vs design specification: kebutuhan menjelaskan apa, desain menjelaskan bagaimana.","mnemonic":"UR = User Requests: apa yang pengguna perlukan."},{"number":6,"topic":"TM7 Desain File & Database","subtopic":"Normalisasi","difficulty":"Mudah","type":"Definisi","question":"Apa tujuan utama normalisasi database?","shortAnswer":"Mengorganisasi data untuk mengurangi redundansi dan mencegah anomali penyisipan, pembaruan, serta penghapusan.","explanation":"Normalisasi memisahkan fakta ke tabel yang tepat berdasarkan ketergantungan data. Hasilnya bukan sekadar lebih banyak tabel, tetapi struktur yang menjaga konsistensi dan memudahkan pemeliharaan.","example":"Data unit kerja disimpan sekali pada tabel Unit, bukan diulang pada setiap transaksi.","keywords":"normalization; redundancy; anomaly","comparison":"Redundansi vs duplikasi sah: redundansi yang tidak terkendali menimbulkan inkonsistensi.","mnemonic":"NORM = No Repeated Meaning."},{"number":7,"topic":"TM3 IT General Control","subtopic":"Authentication","difficulty":"Mudah","type":"Istilah","question":"Authentication menjawab pertanyaan apa?","shortAnswer":"Siapa kamu?","explanation":"Authentication memverifikasi identitas pengguna melalui kredensial, token, biometrik, atau faktor lain. Setelah identitas terbukti, sistem menerapkan authorization untuk menentukan hak pengguna.","example":"Pengguna memasukkan kata sandi dan kode OTP sebelum masuk aplikasi.","keywords":"authentication; identity; MFA","comparison":"Authentication vs authorization: identitas vs kewenangan.","mnemonic":"AuthN = Name; AuthZ = Zone of permission."},{"number":8,"topic":"TM3 IT General Control","subtopic":"Least privilege","difficulty":"Mudah","type":"Istilah","question":"Apa arti prinsip least privilege?","shortAnswer":"Pengguna hanya diberi hak akses minimum yang diperlukan untuk menjalankan tugasnya.","explanation":"Hak akses yang terlalu luas meningkatkan risiko transaksi tidak sah, perubahan data, dan konflik tugas. Least privilege diterapkan saat pemberian, perubahan, peninjauan, serta pencabutan akses.","example":"Operator boleh menginput tagihan tetapi tidak boleh menyetujui pembayarannya.","keywords":"least privilege; access; role","comparison":"Least privilege vs no access: akses tetap diberikan, tetapi dibatasi sesuai kebutuhan.","mnemonic":"Minimum needed, nothing more."},{"number":9,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Reasonable assurance","difficulty":"Sedang","type":"Istilah","question":"Mengapa pengendalian hanya memberi reasonable assurance?","shortAnswer":"Karena terdapat keterbatasan bawaan seperti human error, kolusi, management override, perubahan kondisi, dan biaya-manfaat.","explanation":"Pengendalian menurunkan risiko, tetapi tidak dapat menjamin seluruh kesalahan dan kecurangan hilang. Organisasi harus menentukan desain yang proporsional dengan risiko dan melakukan pemantauan.","example":"Dua persetujuan dapat mengurangi risiko, tetapi kolusi masih mungkin terjadi.","keywords":"reasonable assurance; inherent limitation","comparison":"Reasonable assurance vs absolute assurance.","mnemonic":"R = Realistic, bukan Risk-free."},{"number":10,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Project charter","difficulty":"Sedang","type":"Istilah","question":"Apa fungsi project charter?","shortAnswer":"Mengesahkan proyek dan menetapkan tujuan, ruang lingkup awal, sponsor, peran, kewenangan, serta sasaran utama.","explanation":"Charter memberi mandat formal dan arah awal sebelum analisis rinci. Ia membantu menyamakan ekspektasi dan menjadi dasar pengelolaan ruang lingkup serta perubahan.","example":"Charter proyek persediaan menetapkan sponsor, unit terlibat, batas waktu, dan hasil yang diharapkan.","keywords":"charter; sponsor; scope","comparison":"Project charter vs project plan: charter mengesahkan; plan merinci pelaksanaan.","mnemonic":"Charter = izin berlayar proyek."},{"number":11,"topic":"TM6 Desain Output","subtopic":"Exception report","difficulty":"Sedang","type":"Istilah","question":"Kapan exception report paling berguna?","shortAnswer":"Ketika pengguna perlu fokus pada transaksi atau kondisi yang menyimpang dari aturan atau batas.","explanation":"Laporan pengecualian mengurangi information overload dengan menampilkan item yang membutuhkan perhatian, misalnya transaksi melewati limit atau keterlambatan.","example":"Daftar pembayaran yang melebihi kewenangan pejabat.","keywords":"exception; anomaly; threshold","comparison":"Exception report vs periodic report: isi penyimpangan vs waktu penerbitan.","mnemonic":"Exception = yang keluar dari garis normal."},{"number":12,"topic":"TM1 Metodologi Pengembangan SIA","subtopic":"Tahapan SDLC","difficulty":"Sedang","type":"Tahapan","question":"Sebutkan urutan inti SDLC.","shortAnswer":"Perencanaan → Analisis → Desain/Pengadaan → Implementasi → Tindak lanjut dan pemeliharaan.","explanation":"Urutan dapat disesuaikan menurut metodologi, tetapi logikanya tetap: menetapkan alasan dan ruang lingkup, memahami kebutuhan, merancang solusi, menerapkan, lalu mengevaluasi dan memelihara.","example":"Aplikasi perjalanan dinas dimulai dari studi kebutuhan sebelum desain formulir dan database.","keywords":"planning; analysis; design; implementation","comparison":"Analisis vs desain: apa yang dibutuhkan vs bagaimana memenuhinya.","mnemonic":"PADI-P: Plan–Analyze–Design–Implement–Preserve."},{"number":13,"topic":"TM3 IT General Control","subtopic":"Change management","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan pengendalian perubahan program yang baik?","shortAnswer":"Permintaan → Analisis dampak → Persetujuan → Pengembangan → Pengujian → Deployment berwenang → Review.","explanation":"Setiap tahap harus terdokumentasi dan dipisahkan secara memadai. Tujuannya mencegah perubahan tidak sah, tidak diuji, atau sulit ditelusuri.","example":"Perubahan tarif diuji di test environment sebelum dipindahkan ke production oleh administrator rilis.","keywords":"change request; testing; deployment","comparison":"Development vs production: membangun/menguji vs operasi nyata.","mnemonic":"R-A-A-D-U-R: Request, Analyze, Approve, Develop, Uji, Release."},{"number":14,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Perencanaan proyek","difficulty":"Sedang","type":"Tahapan","question":"Apa alur ringkas perencanaan pengembangan sistem?","shortAnswer":"Identifikasi masalah → Tujuan dan scope → Alternatif → Studi kelayakan → Risiko/sumber daya → Persetujuan.","explanation":"Perencanaan mengubah gagasan menjadi keputusan proyek yang dapat dipertanggungjawabkan. Alternatif dibandingkan dan risiko dinilai sebelum organisasi mengalokasikan sumber daya.","example":"Instansi membandingkan membangun sendiri, membeli paket, atau memperbaiki sistem lama.","keywords":"problem; scope; feasibility; approval","comparison":"Perencanaan vs analisis rinci.","mnemonic":"Masalah–Maksud–Pilihan–Layak–Putuskan."},{"number":15,"topic":"TM5 Analisis Sistem","subtopic":"Analisis kebutuhan","difficulty":"Sedang","type":"Tahapan","question":"Apa alur analisis kebutuhan sistem?","shortAnswer":"Pahami proses berjalan → Kumpulkan data → Modelkan → Identifikasi risiko/kebutuhan → Validasi → Dokumentasikan dalam SRS.","explanation":"Analisis tidak cukup hanya bertanya kepada pengguna. Bukti harus dikumpulkan melalui beberapa teknik, dimodelkan, dan divalidasi agar kebutuhan konsisten serta dapat diuji.","example":"Wawancara bendahara dilengkapi observasi dan penelusuran sampel tagihan.","keywords":"current system; requirement; SRS","comparison":"Wawancara vs observasi: pernyataan pengguna vs praktik nyata.","mnemonic":"PA-MI-VA-DOK: Pahami, Ambil data, Modelkan, Identifikasi, Validasi, Dokumentasi."},{"number":16,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Preventif vs detektif","difficulty":"Sedang","type":"Perbandingan","question":"Apa pembeda utama pengendalian preventif dan detektif?","shortAnswer":"Preventif mencegah sebelum/saat kejadian; detektif menemukan kejadian yang telah atau sedang terjadi.","explanation":"Otorisasi dan validasi adalah contoh preventif. Rekonsiliasi dan review laporan pengecualian adalah contoh detektif. Keduanya dapat digunakan bersama.","example":"Limit transaksi mencegah; laporan transaksi melewati limit mendeteksi.","keywords":"preventive; detective; timing","comparison":"Jenis kontrol tidak ditentukan oleh manual atau otomatis.","mnemonic":"PRE = sebelum; DET = menemukan."},{"number":17,"topic":"TM3 IT General Control","subtopic":"Authentication vs authorization","difficulty":"Sedang","type":"Perbandingan","question":"Bedakan authentication dan authorization.","shortAnswer":"Authentication memverifikasi identitas; authorization menentukan hak setelah identitas terverifikasi.","explanation":"Keduanya berurutan dan saling melengkapi. Identitas yang benar tidak otomatis berarti pengguna boleh melakukan seluruh tindakan.","example":"Login dengan OTP adalah autentikasi; hak menyetujui transaksi adalah otorisasi.","keywords":"identity; permission","comparison":"Login bukan bukti bahwa semua menu boleh diakses.","mnemonic":"Who are you? → What may you do?"},{"number":18,"topic":"TM5 Analisis Sistem","subtopic":"Fungsional vs nonfungsional","difficulty":"Sedang","type":"Perbandingan","question":"Bedakan kebutuhan fungsional dan nonfungsional.","shortAnswer":"Fungsional menjelaskan apa yang sistem lakukan; nonfungsional menjelaskan kualitas, batasan, dan cara sistem melakukannya.","explanation":"Keduanya harus dapat diuji. Fungsi tanpa kualitas dapat menghasilkan sistem yang bekerja tetapi lambat, tidak aman, atau sulit digunakan.","example":"Menghitung realisasi = fungsional; respons maksimal tiga detik = nonfungsional.","keywords":"function; quality; constraint","comparison":"Nonfungsional bukan berarti tidak penting.","mnemonic":"WHAT vs HOW WELL."},{"number":19,"topic":"TM7 Desain File & Database","subtopic":"Primary vs foreign key","difficulty":"Sulit","type":"Perbandingan","question":"Bedakan primary key dan foreign key.","shortAnswer":"Primary key mengidentifikasi baris secara unik; foreign key menghubungkan tabel dengan merujuk kunci tabel lain.","explanation":"Primary key menjaga integritas entitas. Foreign key mendukung integritas referensial. Foreign key dapat berulang ketika banyak baris anak merujuk satu induk.","example":"KodeUnit adalah primary key di tabel Unit dan foreign key di tabel Transaksi.","keywords":"PK; FK; integrity","comparison":"Foreign key tidak harus unik.","mnemonic":"Primary = pribadi tabel; Foreign = menunjuk tetangga."},{"number":20,"topic":"TM6 Desain Output","subtopic":"Output manajerial","difficulty":"Sulit","type":"Penerapan","question":"Output apa yang cocok untuk pimpinan yang memantau realisasi anggaran?","shortAnswer":"Dashboard ringkas dengan KPI, tren, filter, dan exception alert, disertai drill-down bila diperlukan.","explanation":"Desain mengikuti kebutuhan keputusan, bukan sekadar menampilkan seluruh data. Pimpinan membutuhkan ringkasan tepat waktu, sementara detail tersedia untuk penelusuran.","example":"Pagu, realisasi, sisa, persentase, tren bulanan, dan unit yang menyimpang.","keywords":"dashboard; KPI; exception","comparison":"Ringkasan bukan berarti menghilangkan akses ke detail.","mnemonic":"Lihat cepat → sorot anomali → telusuri detail."},{"number":21,"topic":"TM7 Desain File & Database","subtopic":"Relasi many-to-many","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana merancang relasi many-to-many?","shortAnswer":"Gunakan tabel penghubung yang memuat foreign key dari kedua tabel.","explanation":"Tabel penghubung memecah relasi menjadi dua relasi one-to-many dan dapat menyimpan atribut hubungan.","example":"Tagihan–SumberDana dihubungkan tabel Alokasi(TagihanID, SumberDanaID, Nilai).","keywords":"junction table; many-to-many","comparison":"Jangan menyimpan beberapa nilai dalam satu field.","mnemonic":"Many–Many perlu meja perantara."},{"number":22,"topic":"TM4 Perencanaan Pengembangan SI","subtopic":"Scope creep","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana mengendalikan scope creep?","shortAnswer":"Tetapkan baseline scope dan proses change control dengan analisis dampak serta persetujuan.","explanation":"Perubahan tidak selalu ditolak, tetapi harus dinilai terhadap manfaat, biaya, waktu, risiko, sumber daya, dan pengendalian.","example":"Fitur baru ditunda ke fase berikutnya setelah dampak jadwal dinilai.","keywords":"scope; baseline; change control","comparison":"Fleksibel bukan berarti menerima semua perubahan.","mnemonic":"Perubahan boleh, perubahan liar tidak."},{"number":23,"topic":"TM2 Kerangka Pengendalian & SPIP","subtopic":"Otorisasi pembayaran","difficulty":"Sulit","type":"Mini Kasus","question":"Operator dapat menginput sekaligus menyetujui pembayaran. Apa risiko dan kontrol utama?","shortAnswer":"Risiko transaksi tidak sah; pisahkan input dan persetujuan serta gunakan otorisasi sesuai kewenangan.","explanation":"Konflik tugas memungkinkan satu orang membuat dan menyelesaikan transaksi tanpa pemeriksaan independen. Sistem harus membatasi peran dan merekam persetujuan.","example":"Operator input, verifikator memeriksa, pejabat berwenang menyetujui.","keywords":"segregation; authorization; payment","comparison":"Backup tidak menyelesaikan risiko transaksi tidak sah.","mnemonic":"Buat–Periksa–Setujui jangan di satu tangan."},{"number":24,"topic":"TM3 IT General Control","subtopic":"Akses pegawai pindah","difficulty":"Sulit","type":"Mini Kasus","question":"Pegawai yang pindah unit masih memiliki hak approve. Apa respons lengkap?","shortAnswer":"Cabut/ubah akses, tinjau log sejak perpindahan, dan perbaiki proses deprovisioning serta review akses berkala.","explanation":"Respons tidak berhenti pada menonaktifkan akun. Organisasi perlu menilai dampak penggunaan akses lama dan memperkuat hubungan antara data kepegawaian dan administrasi akses.","example":"Notifikasi mutasi otomatis memicu tiket perubahan hak akses.","keywords":"deprovisioning; review; log","comparison":"Mengganti password tidak menghapus kewenangan.","mnemonic":"Fix access, check impact, fix process."},{"number":25,"topic":"TM5 Analisis Sistem","subtopic":"Bukti analisis bertentangan","difficulty":"Sulit","type":"Mini Kasus","question":"Wawancara menyatakan kontrol selalu dijalankan, tetapi dokumen tidak menunjukkan bukti. Apa tindakan analis?","shortAnswer":"Lakukan triangulasi melalui observasi, pemeriksaan dokumen, sampling, dan klarifikasi.","explanation":"Analis harus membedakan prosedur formal dengan praktik aktual. Kesimpulan tidak boleh hanya bergantung pada satu sumber atau langsung menyatakan kecurangan tanpa bukti cukup.","example":"Amati proses pembayaran dan telusuri sampel dari awal sampai akhir.","keywords":"triangulation; evidence; current system","comparison":"Pernyataan pengguna bukan satu-satunya bukti.","mnemonic":"Tanya–Lihat–Cek–Konfirmasi."}]},"pbpn":{"id":"pbpn","title":"Proses Bisnis Penerimaan Negara","short":"PBPN","konsen":["pppn"],"quiz":[{"number":1,"topic":"Konsep Penerimaan Negara","subtopic":"TM 1","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Pernyataan yang paling tepat menggambarkan pendapatan negara adalah ...","options":["Seluruh uang yang masuk ke rekening pemerintah, termasuk titipan dan utang jangka pendek.","Hak pemerintah pusat yang diakui sebagai penambah nilai kekayaan bersih negara.","Seluruh aset tetap yang dimiliki kementerian dan lembaga.","Penerimaan yang hanya berasal dari pajak dalam negeri."],"correct":"B","concept":"Pendapatan negara = hak pemerintah pusat yang menambah kekayaan bersih.","explanation":"Pendapatan negara merupakan hak Pemerintah Pusat yang diakui sebagai penambah nilai kekayaan bersih. Cakupannya tidak hanya pajak dalam negeri, tetapi juga PNBP dan penerimaan lain sesuai struktur APBN. Pinjaman atau pembiayaan tidak otomatis diperlakukan sebagai pendapatan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 4 dan 14","keywords":"Pendapatan negara = hak pemerintah pusat yang menambah kekayaan bersih."},{"number":2,"topic":"Hierarki Proses Bisnis","subtopic":"TM 1","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Aktivitas manakah yang termasuk proses pendukung (support process) dalam penerimaan negara?","options":["Melakukan penagihan dan penegakan hukum kepada wajib pajak.","Menetapkan target penerimaan dan mengevaluasi kinerja fiskal.","Mengelola sistem teknologi informasi, SDM, sarana, dan logistik.","Menghitung potensi dan memungut penerimaan pajak."],"correct":"C","concept":"Core menghasilkan nilai; support menyediakan sumber daya; management mengarahkan dan mengevaluasi.","explanation":"Proses pendukung menyediakan sumber daya dan infrastruktur agar proses utama berjalan lancar. Pengelolaan TI, SDM, sarana, dan logistik merupakan contoh support process. Penagihan dan pemungutan termasuk proses utama, sedangkan penetapan target termasuk proses manajemen.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 5-6","keywords":"Core menghasilkan nilai; support menyediakan sumber daya; management mengarahkan dan mengevaluasi."},{"number":3,"topic":"Penyetoran Penerimaan","subtopic":"TM 1","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Manakah yang bukan termasuk Collecting Agent yang disebut dalam mekanisme penyetoran penerimaan negara?","options":["Bank Persepsi Valas.","Pos Persepsi.","Lembaga Persepsi Lainnya Valas.","Pos Persepsi Valas."],"correct":"D","concept":"Collecting Agent menerima setoran penerimaan negara melalui kanal resmi.","explanation":"Collecting Agent meliputi Bank Persepsi, Bank Persepsi Valas, Pos Persepsi, Lembaga Persepsi Lainnya, dan Lembaga Persepsi Lainnya Valas. Istilah Pos Persepsi Valas tidak termasuk daftar tersebut. Penyetoran dilakukan menggunakan Kode Billing melalui kanal yang tersedia.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 7; Proses Bisnis Penerimaan Negara (1).pdf, hlm. 2","keywords":"Collecting Agent menerima setoran penerimaan negara melalui kanal resmi."},{"number":4,"topic":"Pembagian Kewenangan","subtopic":"TM 1","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Unit yang mengelola penerimaan pajak perdagangan internasional dan cukai adalah ...","options":["Direktorat Jenderal Anggaran (DJA).","Direktorat Jenderal Pajak (DJP).","Direktorat Jenderal Bea dan Cukai (DJBC).","Direktorat Jenderal Perbendaharaan (DJPb)."],"correct":"C","concept":"Pajak perdagangan internasional dan cukai dikelola DJBC.","explanation":"DJBC berwenang mengelola penerimaan pajak perdagangan internasional dan cukai. DJP mengelola pajak dalam negeri selain cukai, DJA mengelola PNBP, sedangkan DJPb berperan dalam penatausahaan kas dan penerimaan nonanggaran tertentu.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 6","keywords":"Pajak perdagangan internasional dan cukai dikelola DJBC."},{"number":5,"topic":"Klasifikasi PPh Migas","subtopic":"TM 2","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Dalam struktur APBN, PPh Migas diklasifikasikan sebagai ...","options":["PNBP Sumber Daya Alam Migas.","Pendapatan Pajak Dalam Negeri.","Penerimaan Pembiayaan.","Pajak Perdagangan Internasional."],"correct":"B","concept":"PPh Migas adalah pajak; PNBP SDA Migas adalah bagian pemerintah atas pemanfaatan SDA.","explanation":"PPh Migas adalah pajak penghasilan atas kegiatan usaha hulu migas oleh Kontraktor KKS dan masuk kategori Pendapatan Pajak Dalam Negeri. PPh Migas berbeda akun dengan PNBP SDA Migas, walaupun keduanya sama-sama berasal dari sektor migas.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 15-16","keywords":"PPh Migas adalah pajak; PNBP SDA Migas adalah bagian pemerintah atas pemanfaatan SDA."},{"number":6,"topic":"PSC Gross Split","subtopic":"TM 2","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Dalam PSC Gross Split, bagaimana perlakuan biaya operasi yang dikeluarkan kontraktor?","options":["Seluruhnya dikembalikan pemerintah melalui cost recovery.","Dibayar kembali melalui reimbursement PPN.","Dapat diperhitungkan sebagai deductible expenses dalam menghitung penghasilan kena pajak.","Tidak boleh menjadi pengurang dalam bentuk apa pun."],"correct":"C","concept":"Gross Split = no cost recovery; biaya operasi menjadi deductible expenses.","explanation":"PSC Gross Split membagi produksi kotor tanpa mekanisme pengembalian biaya operasi oleh pemerintah. Biaya operasi tetap dapat diperlakukan sebagai pengurang penghasilan bruto sesuai ketentuan perpajakan. Karena itu, jawaban yang tepat adalah deductible expenses, bukan cost recovery atau reimbursement.","whyOthersWrong":"","tip":"","reference":"Proses Bisnis Penerimaan Negara (1).pdf, hlm. 5; PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 20-27","keywords":"Gross Split = no cost recovery; biaya operasi menjadi deductible expenses."},{"number":7,"topic":"Prinsip PSC Cost Recovery","subtopic":"TM 2","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Prinsip nail down dalam PSC Cost Recovery berarti ...","options":["Tarif dan ketentuan pajak mengikuti aturan yang berlaku saat kontrak ditandatangani.","Semua biaya operasi otomatis disetujui sebagai cost recovery.","Kontraktor bebas mengubah kewajiban pajak secara sepihak.","Bagian pemerintah selalu dihitung setelah seluruh pajak dibayar."],"correct":"A","concept":"Nail down mengunci rezim pajak pada saat kontrak ditandatangani.","explanation":"Nail down menjaga agar perlakuan pajak mengikuti aturan yang berlaku pada saat kontrak ditandatangani. Konsekuensinya, perubahan tarif setelah penandatanganan tidak serta-merta mengubah kontrak lama. Prinsip ini berbeda dari sanctity of contract yang menekankan penghormatan terhadap seluruh kesepakatan kontrak.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 21-22","keywords":"Nail down mengunci rezim pajak pada saat kontrak ditandatangani."},{"number":8,"topic":"PPN dan PPnBM","subtopic":"TM 3","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Pernyataan yang benar mengenai PPN dan PPnBM adalah ...","options":["PPN dan PPnBM sama-sama hanya dipungut satu kali.","PPN bersifat multi-stage, sedangkan PPnBM merupakan pajak tambahan yang umumnya dipungut satu kali atas barang mewah.","PPnBM dapat dikreditkan seperti Pajak Masukan.","PPN hanya dikenakan atas barang mewah."],"correct":"B","concept":"PPN multi-stage; PPnBM single-stage dan tambahan atas barang mewah.","explanation":"PPN adalah pajak tidak langsung yang dipungut pada berbagai mata rantai produksi dan distribusi melalui mekanisme kredit pajak. PPnBM merupakan pungutan tambahan atas Barang Kena Pajak tergolong mewah dan bersifat single stage. PPnBM bukan Pajak Masukan yang dapat dikreditkan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 31","keywords":"PPN multi-stage; PPnBM single-stage dan tambahan atas barang mewah."},{"number":9,"topic":"Penyerahan BKP","subtopic":"TM 3","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Transaksi yang tidak termasuk penyerahan BKP adalah ...","options":["Pemberian cuma-cuma barang produksi.","Pemakaian sendiri BKP untuk kepentingan pengusaha.","Penyerahan BKP sebagai jaminan utang-piutang.","Penjualan aktiva yang semula tidak untuk diperjualbelikan dan Pajak Masukannya dapat dikreditkan."],"correct":"C","concept":"Jaminan utang bukan penyerahan BKP.","explanation":"BKP yang diserahkan sebagai jaminan utang-piutang tidak diperlakukan sebagai penyerahan BKP. Pemberian cuma-cuma dan pemakaian sendiri pada prinsipnya termasuk penyerahan. Penjualan aktiva tertentu juga dapat menjadi penyerahan apabila Pajak Masukan saat perolehannya dapat dikreditkan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 33; Proses Bisnis Penerimaan Negara (1).pdf, hlm. 5-6","keywords":"Jaminan utang bukan penyerahan BKP."},{"number":10,"topic":"Mekanisme Kredit PPN","subtopic":"TM 3","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Apabila Pajak Keluaran lebih besar daripada Pajak Masukan pada suatu masa pajak, konsekuensinya adalah ...","options":["PKP harus menyetor selisih sebagai PPN kurang bayar.","PKP otomatis memperoleh restitusi.","Pajak Keluaran dihapuskan.","Selisihnya menjadi PPh Pasal 25."],"correct":"A","concept":"PK > PM = kurang bayar; PM > PK = lebih bayar.","explanation":"Mekanisme PPN menggunakan PK dikurangi PM. Jika PK lebih besar daripada PM, terdapat PPN kurang bayar yang harus disetor ke kas negara. Jika PM lebih besar, selisihnya dapat dikompensasikan atau dimintakan restitusi sesuai ketentuan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 32 dan 40-41","keywords":"PK > PM = kurang bayar; PM > PK = lebih bayar."},{"number":11,"topic":"Fasilitas PPN","subtopic":"TM 3","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Perbedaan utama PPN Dibebaskan dan PPN Tidak Dipungut terletak pada ...","options":["Tarif PPN ekspor yang digunakan.","Kewajiban membuat NPWP pembeli.","Status barang sebagai BKP atau bukan BKP.","Kemampuan mengkreditkan Pajak Masukan terkait transaksi."],"correct":"D","concept":"Dibebaskan: PM tidak dapat dikreditkan; Tidak Dipungut: PM tetap dapat dikreditkan.","explanation":"Pada PPN Dibebaskan, PPN tidak dipungut dan Pajak Masukan terkait tidak dapat dikreditkan sehingga menjadi beban biaya. Pada PPN Tidak Dipungut, Pajak Masukan tetap dapat dikreditkan, dikompensasikan, atau direstitusi. Inilah pembeda paling penting di antara kedua fasilitas.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 44-46","keywords":"Dibebaskan: PM tidak dapat dikreditkan; Tidak Dipungut: PM tetap dapat dikreditkan."},{"number":12,"topic":"Subjek Pajak PPh","subtopic":"TM 4","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Subjek pajak yang menggantikan kedudukan pewaris sejak pewaris meninggal sampai harta warisan selesai dibagikan adalah ...","options":["Bentuk Usaha Tetap.","Warisan yang Belum Terbagi.","Organisasi Internasional.","Persekutuan komanditer."],"correct":"B","concept":"WBT menjaga kewajiban pajak selama proses pembagian warisan.","explanation":"Warisan yang Belum Terbagi menjadi subjek pajak untuk menjaga kesinambungan kewajiban pajak setelah pewaris meninggal. Status ini dimulai saat pewaris meninggal dan berakhir ketika warisan selesai dibagikan. Pengurusannya diwakili oleh ahli waris atau pelaksana wasiat.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 50-51","keywords":"WBT menjaga kewajiban pajak selama proses pembagian warisan."},{"number":13,"topic":"Kompensasi Kerugian","subtopic":"TM 4","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Yang dimaksud kompensasi kerugian horizontal adalah ...","options":["Membawa kerugian ke lima tahun pajak berikutnya.","Mengurangkan kerugian luar negeri dari penghasilan final dalam negeri.","Mengurangkan kerugian suatu kegiatan dengan penghasilan lain pada tahun pajak yang sama.","Menghapus seluruh pajak terutang pada tahun rugi."],"correct":"C","concept":"Horizontal = tahun yang sama; vertikal = dibawa ke tahun berikutnya.","explanation":"Kompensasi horizontal dilakukan dalam tahun pajak yang sama dengan mengurangkan kerugian dari satu sumber terhadap penghasilan lain yang dapat digabungkan. Kompensasi vertikal adalah membawa sisa kerugian ke tahun berikutnya, maksimal lima tahun. Kerugian dari penghasilan final atau luar negeri tidak digunakan sembarangan dalam mekanisme ini.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 55","keywords":"Horizontal = tahun yang sama; vertikal = dibawa ke tahun berikutnya."},{"number":14,"topic":"PPh Final dan Nonfinal","subtopic":"TM 4","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Ciri yang tepat dari penghasilan yang dikenai PPh Final adalah ...","options":["Tidak digabung dengan penghasilan tarif umum dan pajaknya tidak dapat dikreditkan terhadap PPh umum.","Selalu dihitung berdasarkan laba fiskal tahunan.","Biaya terkait selalu dapat dikurangkan dari penghasilan bruto.","Tidak terutang apabila usaha mengalami rugi."],"correct":"A","concept":"PPh Final berdiri sendiri dari penghitungan PPh umum.","explanation":"PPh Final dikenakan dengan tarif khusus atas jenis transaksi tertentu dan tidak digabung dalam penghitungan PPh tarif umum. Pajak final tidak dapat menjadi kredit pajak terhadap PPh umum. Biaya terkait umumnya tidak dikurangkan dan pajak dapat tetap terutang walaupun secara keseluruhan usaha rugi.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 52","keywords":"PPh Final berdiri sendiri dari penghitungan PPh umum."},{"number":15,"topic":"Penyusutan dan Amortisasi","subtopic":"TM 4","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Pasangan konsep yang benar adalah ...","options":["Penyusutan untuk goodwill; amortisasi untuk bangunan.","Penyusutan untuk tanah; amortisasi untuk persediaan.","Penyusutan untuk harta berwujud; amortisasi untuk harta tidak berwujud.","Penyusutan dan amortisasi hanya berlaku bagi wajib pajak orang pribadi."],"correct":"C","concept":"Penyusutan = tangible; amortisasi = intangible.","explanation":"Penyusutan mengalokasikan biaya harta berwujud selama masa manfaat, sedangkan amortisasi mengalokasikan biaya harta tidak berwujud seperti goodwill atau hak tertentu. Tanah dengan hak tertentu pada umumnya tidak disusutkan. Kedua mekanisme dapat digunakan oleh wajib pajak yang memenuhi ketentuan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 57","keywords":"Penyusutan = tangible; amortisasi = intangible."},{"number":16,"topic":"PPh Pasal 23","subtopic":"TM 4","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Objek yang pada umumnya dipotong PPh Pasal 23 sebesar 2% dari jumlah bruto adalah ...","options":["Dividen dan royalti.","Sewa penggunaan harta selain tanah/bangunan serta jasa teknik atau manajemen.","Gaji pegawai tetap.","Bunga deposito yang dikenai PPh Final."],"correct":"B","concept":"PPh 23: 15% untuk dividen/bunga/royalti; 2% untuk sewa harta dan jasa tertentu.","explanation":"PPh Pasal 23 sebesar 2% dari jumlah bruto berlaku antara lain atas sewa dan penggunaan harta selain yang diatur PPh Final serta jasa teknik, manajemen, konsultan, dan jasa tertentu. Dividen, bunga, dan royalti pada umumnya berada pada kelompok tarif 15%. Gaji masuk PPh Pasal 21, sedangkan deposito memiliki rezim final tersendiri.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 69-70","keywords":"PPh 23: 15% untuk dividen/bunga/royalti; 2% untuk sewa harta dan jasa tertentu."},{"number":17,"topic":"Karakteristik PBB","subtopic":"TM 5","learningOutcome":"","difficulty":"Mudah","type":"Pilihan Ganda","question":"Mengapa PBB disebut pajak objektif?","options":["Karena pengenaannya terutama memperhatikan kondisi bumi dan/atau bangunan, bukan keadaan pribadi wajib pajak.","Karena PBB hanya dikenakan kepada badan hukum.","Karena tarifnya selalu sama di seluruh Indonesia.","Karena pembayaran PBB menjadi bukti kepemilikan tanah."],"correct":"A","concept":"PBB melihat objek, bukan kondisi personal subjek.","explanation":"PBB berfokus pada kondisi objek berupa bumi dan/atau bangunan. Keadaan pribadi wajib pajak bukan unsur utama dalam menentukan pajak terutang. Bukti pelunasan PBB juga bukan bukti kepemilikan hak atas tanah atau bangunan.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 76 dan 80","keywords":"PBB melihat objek, bukan kondisi personal subjek."},{"number":18,"topic":"Saat Terutang PBB-P2","subtopic":"TM 5","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Kondisi objek yang digunakan untuk menentukan PBB-P2 tahun berjalan adalah kondisi pada ...","options":["Tanggal SPPT dicetak.","1 Januari tahun pajak.","Tanggal pembayaran pajak.","31 Desember tahun pajak."],"correct":"B","concept":"PBB memakai snapshot objek pada 1 Januari.","explanation":"PBB-P2 ditentukan berdasarkan keadaan objek pada tanggal 1 Januari tahun pajak. Perubahan setelah tanggal tersebut pada prinsipnya tidak mengubah PBB tahun berjalan. Contohnya, bangunan yang rusak setelah 1 Januari masih diperhitungkan sesuai kondisi pada 1 Januari.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 80-82","keywords":"PBB memakai snapshot objek pada 1 Januari."},{"number":19,"topic":"NJOPTKP PBB-P2","subtopic":"TM 5","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Apabila seorang wajib pajak memiliki beberapa objek PBB-P2 dalam satu wilayah kabupaten/kota, NJOPTKP pada umumnya diberikan ...","options":["Untuk setiap objek tanpa batas.","Hanya untuk objek dengan NJOP terendah.","Hanya untuk satu objek, umumnya objek dengan NJOP tertinggi.","Hanya jika seluruh objek digunakan sebagai tempat tinggal."],"correct":"C","concept":"Satu WP, satu NJOPTKP PBB-P2 dalam satu wilayah per tahun.","explanation":"NJOPTKP PBB-P2 diberikan kepada satu objek untuk setiap wajib pajak dalam satu wilayah dan tahun pajak. Dalam materi, penerapannya umumnya diarahkan pada objek dengan NJOP tertinggi. Objek lain tetap dihitung tanpa pengurangan NJOPTKP.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 83","keywords":"Satu WP, satu NJOPTKP PBB-P2 dalam satu wilayah per tahun."},{"number":20,"topic":"Kepabeanan dan PDRI","subtopic":"TM 6","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Makna asas 'same time, same document' dalam impor adalah ...","options":["Semua barang impor harus tiba pada waktu yang sama.","Bea masuk dan bea keluar dikenakan dalam satu transaksi ekspor.","PIB hanya boleh memuat satu jenis barang.","DJBC memungut PDRI bersamaan dengan bea masuk dalam satu dokumen PIB, meskipun dasar hukumnya berbeda."],"correct":"D","concept":"Satu waktu dan satu dokumen untuk BM serta PDRI.","explanation":"PPN Impor, PPnBM Impor, dan PPh Pasal 22 Impor berlandaskan undang-undang perpajakan, tetapi dipungut oleh DJBC bersamaan dengan bea masuk. Seluruh pungutan dicantumkan dalam PIB dan diselesaikan melalui mekanisme pembayaran yang terintegrasi.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 101-102","keywords":"Satu waktu dan satu dokumen untuk BM serta PDRI."},{"number":21,"topic":"Bea Masuk Tambahan","subtopic":"TM 6","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Bea Masuk Tambahan yang dikenakan untuk mengimbangi subsidi dari pemerintah negara pengekspor adalah ...","options":["BMAD (Bea Masuk Anti-Dumping).","BMI (Bea Masuk Imbalan/Countervailing Duty).","BMTP (Bea Masuk Tindakan Pengamanan).","BMP (Bea Masuk Pembalasan)."],"correct":"B","concept":"Subsidi = BMI; dumping = BMAD; lonjakan = BMTP; diskriminasi = BMP.","explanation":"BMI atau countervailing duty dikenakan ketika barang impor memperoleh subsidi dari negara pengekspor dan subsidi tersebut merugikan industri dalam negeri. BMAD menanggulangi dumping, BMTP menanggulangi lonjakan impor, sedangkan BMP merupakan tindakan pembalasan atas perlakuan diskriminatif.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 99-100 dan 120-121","keywords":"Subsidi = BMI; dumping = BMAD; lonjakan = BMTP; diskriminasi = BMP."},{"number":22,"topic":"Impor Sementara","subtopic":"TM 6","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Tiga elemen utama dalam tata cara impor sementara adalah ...","options":["Izin, jaminan, dan kewajiban re-ekspor tepat waktu.","Promosi, penjualan, dan distribusi domestik.","Pembebasan seluruh pajak, tanpa jaminan dan tanpa batas waktu.","Pendaftaran merek, diskon tarif, dan pengalihan kepemilikan."],"correct":"A","concept":"Impor sementara = izin + jaminan + re-ekspor.","explanation":"Fasilitas impor sementara menekankan legalitas izin, penyerahan jaminan atas pungutan yang ditangguhkan, dan kewajiban mengekspor kembali barang sesuai jangka waktu. Kegagalan memenuhi kewajiban tersebut dapat menimbulkan pungutan dan sanksi administrasi.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 106-117","keywords":"Impor sementara = izin + jaminan + re-ekspor."},{"number":23,"topic":"Nilai Pabean dan Nilai Impor","subtopic":"TM 7","learningOutcome":"","difficulty":"Sedang","type":"Pilihan Ganda","question":"Formula yang tepat untuk menghitung Nilai Impor sebagai dasar PDRI adalah ...","options":["Nilai Impor = CIF - Bea Masuk.","Nilai Impor = Harga Jual + PPN.","Nilai Impor = Nilai Pabean + Bea Masuk + Bea Masuk Tambahan (jika ada).","Nilai Impor = Bea Masuk × tarif PPN."],"correct":"C","concept":"NP = CIF x kurs; NI = NP + BM + BMT.","explanation":"Nilai Pabean umumnya berasal dari CIF dikalikan kurs pajak. Nilai Impor kemudian dihitung dengan menambahkan Bea Masuk dan Bea Masuk Tambahan jika dikenakan. Nilai Impor menjadi dasar PPN Impor, PPnBM Impor, dan PPh Pasal 22 Impor.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 122-123","keywords":"NP = CIF x kurs; NI = NP + BM + BMT."},{"number":24,"topic":"Perhitungan Bea Masuk","subtopic":"TM 7","learningOutcome":"","difficulty":"Sulit","type":"Pilihan Ganda","question":"Suatu barang dikenai Bea Masuk umum 5% dan BMAD 10%. Berapa total tarif bea masuk yang diterapkan terhadap Nilai Pabean?","options":["5%.","15%.","50%.","10%."],"correct":"B","concept":"BMT ditambahkan ke BM umum.","explanation":"Bea Masuk Tambahan bersifat kumulatif terhadap Bea Masuk umum, bukan menggantikannya. Karena itu total tarif adalah 5% + 10% = 15% dari Nilai Pabean. Rumusnya: Total BM = (tarif BM umum + tarif BMT) x Nilai Pabean.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 121-122","keywords":"BMT ditambahkan ke BM umum."},{"number":25,"topic":"Sanksi Administrasi Kepabeanan","subtopic":"TM 7","learningOutcome":"","difficulty":"Sulit","type":"Pilihan Ganda","question":"Importir telah membayar Bea Masuk Rp1.000.000, tetapi Bea Masuk yang seharusnya dibayar Rp1.500.000. Jika kekurangan 50% dikenai denda 200% dari kekurangan bayar, berapa dendanya?","options":["Rp500.000.","Rp750.000.","Rp1.000.000.","Rp1.500.000."],"correct":"C","concept":"Denda dihitung dari persentase tertentu atas kekurangan pembayaran.","explanation":"Kekurangan bayar adalah Rp1.500.000 - Rp1.000.000 = Rp500.000. Persentase kekurangan terhadap yang telah dibayar adalah 50%, sehingga tingkat denda yang digunakan 200% dari kekurangan bayar. Denda = 200% x Rp500.000 = Rp1.000.000.","whyOthersWrong":"","tip":"","reference":"PROSES BISNIS PENERIMAAN NEGARA.pdf, hlm. 124-125","keywords":"Denda dihitung dari persentase tertentu atas kekurangan pembayaran."}],"flashcards":[{"number":1,"topic":"Konsep Dasar","subtopic":"TM 1","difficulty":"","type":"","question":"Apa yang dimaksud proses bisnis penerimaan negara?","shortAnswer":"Rangkaian kegiatan terintegrasi dari penghimpunan, pencatatan, pengelolaan, penyetoran, pengawasan, hingga pelaporan penerimaan negara.","explanation":"Proses bisnis menghubungkan input penerimaan dengan hasil berupa pembiayaan pembangunan, akuntabilitas, dan pelayanan publik.","example":"Pembayaran pajak dibuatkan billing, diterima Collecting Agent, masuk Kas Negara, lalu dicatat dan dilaporkan.","keywords":"","comparison":"Berbeda dari satu prosedur tunggal; proses bisnis mencakup keseluruhan rangkaian lintas unit.","mnemonic":"Ingat alur: HIMPUN-CATAT-KELOLA-LAPOR."},{"number":2,"topic":"Hierarki Proses","subtopic":"TM 1","difficulty":"","type":"","question":"Apa beda core process, support process, dan management process?","shortAnswer":"Core menghasilkan penerimaan/nilai; support menyediakan sumber daya; management mengarahkan, mengendalikan, dan mengevaluasi.","explanation":"Ketiganya saling bergantung. Core tanpa support akan tersendat, sedangkan tanpa management proses tidak terarah dan tidak terukur.","example":"Pemungutan pajak = core; sistem TI = support; penetapan target = management.","keywords":"","comparison":"Core bukan selalu kegiatan paling besar, tetapi yang langsung menghasilkan nilai utama.","mnemonic":"Co-Su-Man: Core, Support, Management."},{"number":3,"topic":"Penyetoran","subtopic":"TM 1","difficulty":"","type":"","question":"Siapa Collecting Agent dan apa fungsi Kode Billing?","shortAnswer":"Collecting Agent adalah lembaga penerima setoran negara; Kode Billing mengidentifikasi jenis dan akun pembayaran secara elektronik.","explanation":"Collecting Agent mencakup Bank Persepsi, Bank Persepsi Valas, Pos Persepsi, Lembaga Persepsi Lainnya, dan Lembaga Persepsi Lainnya Valas.","example":"Wajib bayar membuat Kode Billing lalu membayar melalui teller, ATM, mobile banking, atau kanal resmi lain.","keywords":"","comparison":"Collecting Agent menerima pembayaran; Biller membentuk informasi tagihan/billing.","mnemonic":"Billing = 'alamat tujuan' uang ke Kas Negara."},{"number":4,"topic":"Fungsi APBN","subtopic":"TM 1","difficulty":"","type":"","question":"Apa enam fungsi APBN?","shortAnswer":"Alokasi, Distribusi, Stabilisasi, Otorisasi, Perencanaan, dan Regulasi.","explanation":"Fungsi APBN menjelaskan bagaimana pendapatan dan belanja digunakan untuk pelayanan, pemerataan, stabilitas ekonomi, dasar pelaksanaan, target, dan pengaturan.","example":"Subsidi dapat mencerminkan fungsi distribusi dan stabilisasi sekaligus.","keywords":"","comparison":"Otorisasi memberi dasar hukum pelaksanaan; perencanaan memberi target dan arah.","mnemonic":"AlDiSta OPeR."},{"number":5,"topic":"PPh Migas","subtopic":"TM 2","difficulty":"","type":"","question":"Apa perbedaan PPh Migas dan PNBP SDA Migas?","shortAnswer":"PPh Migas adalah pajak penghasilan kontraktor hulu migas; PNBP SDA Migas adalah penerimaan nonpajak dari bagian pemerintah atas pemanfaatan SDA migas.","explanation":"Keduanya berasal dari sektor yang sama tetapi dicatat pada akun dan dasar pengenaan yang berbeda dalam APBN.","example":"PPh atas penghasilan KKKS masuk pajak dalam negeri; bagian pemerintah dari produksi masuk PNBP SDA.","keywords":"","comparison":"Jangan menyamakan sektor asal dengan klasifikasi akun APBN.","mnemonic":"PPh = pajak penghasilan; PNBP = bagian negara dari SDA."},{"number":6,"topic":"PSC Cost Recovery","subtopic":"TM 2","difficulty":"","type":"","question":"Apa inti PSC Cost Recovery?","shortAnswer":"Pemerintah dan kontraktor membagi hasil produksi, sementara biaya operasi yang memenuhi ketentuan dapat dikembalikan dari hasil produksi.","explanation":"Klaim biaya harus riil, wajar, dan sesuai kontrak. Rezim ini juga mengenal prinsip nail down, gross up, dan sanctity of contract.","example":"Biaya eksplorasi yang memenuhi syarat dapat masuk cost recovery sebelum pembagian tertentu.","keywords":"","comparison":"Berbeda dengan Gross Split yang tidak memakai pengembalian biaya oleh pemerintah.","mnemonic":"Cost Recovery = biaya 'kembali' dari produksi."},{"number":7,"topic":"PSC Gross Split","subtopic":"TM 2","difficulty":"","type":"","question":"Apa inti PSC Gross Split?","shortAnswer":"Produksi kotor dibagi sejak awal berdasarkan split tanpa mekanisme cost recovery.","explanation":"Kontraktor menanggung risiko biaya operasi, tetapi biaya yang memenuhi ketentuan dapat menjadi deductible expenses dalam penghitungan pajak.","example":"Biaya pengeboran tidak direimburse pemerintah, namun dapat mengurangi penghasilan bruto sesuai aturan.","keywords":"","comparison":"Cost Recovery mengembalikan biaya; Gross Split langsung membagi produksi.","mnemonic":"Gross Split = bagi kotor, biaya ditanggung kontraktor."},{"number":8,"topic":"PPN vs PPnBM","subtopic":"TM 3","difficulty":"","type":"","question":"Apa beda PPN dan PPnBM?","shortAnswer":"PPN adalah pajak konsumsi multi-stage dengan kredit Pajak Masukan; PPnBM adalah pungutan tambahan single-stage atas barang mewah.","explanation":"PPN dipungut di berbagai mata rantai dan netral melalui mekanisme PK-PM. PPnBM tidak dikreditkan.","example":"Mobil mewah dapat dikenai PPN dan tambahan PPnBM.","keywords":"","comparison":"PPN berlaku luas; PPnBM hanya pada BKP tergolong mewah.","mnemonic":"PPN = banyak tahap; PPnBM = mewah, sekali."},{"number":9,"topic":"Kredit PPN","subtopic":"TM 3","difficulty":"","type":"","question":"Bagaimana rumus sederhana PPN yang harus disetor?","shortAnswer":"PPN Kurang Bayar = Pajak Keluaran - Pajak Masukan yang dapat dikreditkan.","explanation":"PK timbul saat PKP melakukan penyerahan, sedangkan PM timbul saat PKP memperoleh BKP/JKP untuk kegiatan usaha yang memenuhi syarat.","example":"PK Rp15 juta dan PM Rp11 juta menghasilkan kurang bayar Rp4 juta.","keywords":"","comparison":"Jika PM lebih besar, terjadi lebih bayar yang dapat dikompensasi atau direstitusi.","mnemonic":"KELUAR dikurangi MASUK."},{"number":10,"topic":"Fasilitas PPN","subtopic":"TM 3","difficulty":"","type":"","question":"Apa beda PPN Dibebaskan dan PPN Tidak Dipungut?","shortAnswer":"Keduanya tidak memungut PPN keluaran, tetapi pada Dibebaskan PM tidak dapat dikreditkan, sedangkan pada Tidak Dipungut PM tetap dapat dikreditkan.","explanation":"Dibebaskan bersifat final dalam rantai dan PM menjadi biaya. Tidak Dipungut mempertahankan hak kredit PM.","example":"Mesin strategis tertentu dapat memperoleh fasilitas sesuai ketentuan; perlakuan PM mengikuti jenis fasilitasnya.","keywords":"","comparison":"Fokus pembeda bukan 'ada PPN atau tidak', melainkan hak kredit PM.","mnemonic":"BEBAS = PM BEBAN; TDP = PM TETAP."},{"number":11,"topic":"Faktur Pajak","subtopic":"TM 3","difficulty":"","type":"","question":"Kapan Faktur Pajak pada umumnya dibuat?","shortAnswer":"Pada saat yang lebih dahulu antara penyerahan BKP/JKP, penerimaan pembayaran, uang muka, atau termin sesuai peristiwa yang berlaku.","explanation":"Faktur Pajak menjadi bukti pungutan dan harus memuat identitas, barang/jasa, nilai transaksi, PPN/PPnBM, nomor seri, tanggal, dan otorisasi.","example":"Jika uang muka diterima sebelum barang diserahkan, faktur dibuat saat uang muka diterima.","keywords":"","comparison":"Faktur Pajak bukan sekadar kuitansi; ia memiliki unsur formal dan material pajak.","mnemonic":"Yang lebih dahulu terjadi, faktur mengikuti."},{"number":12,"topic":"Subjek PPh","subtopic":"TM 4","difficulty":"","type":"","question":"Apa empat kategori utama subjek PPh?","shortAnswer":"Orang Pribadi, Badan, Warisan yang Belum Terbagi, dan Bentuk Usaha Tetap.","explanation":"Kategori tersebut kemudian dibedakan menjadi Subjek Pajak Dalam Negeri dan Subjek Pajak Luar Negeri berdasarkan domisili, keberadaan, atau kegiatan.","example":"WBT menjadi subjek pajak sejak pewaris meninggal sampai warisan dibagi.","keywords":"","comparison":"Subjek pajak berbeda dari objek pajak; subjek menjawab 'siapa', objek menjawab 'penghasilan apa'.","mnemonic":"OP-Badan-WBT-BUT."},{"number":13,"topic":"PPh Final","subtopic":"TM 4","difficulty":"","type":"","question":"Apa ciri utama PPh Final?","shortAnswer":"Pajaknya dihitung secara khusus, tidak digabung dengan penghasilan tarif umum, dan tidak dapat dikreditkan terhadap PPh umum.","explanation":"PPh Final menyederhanakan pemungutan untuk transaksi tertentu, tetapi biaya terkait umumnya tidak dapat dikurangkan.","example":"PPh final atas sewa tanah/bangunan dihitung dari jumlah bruto sesuai tarif khusus.","keywords":"","comparison":"PPh nonfinal digabung dalam SPT Tahunan dan kredit pajaknya dapat diperhitungkan.","mnemonic":"FINAL = selesai pada transaksi."},{"number":14,"topic":"Kompensasi Rugi","subtopic":"TM 4","difficulty":"","type":"","question":"Apa beda kompensasi kerugian horizontal dan vertikal?","shortAnswer":"Horizontal mengurangi penghasilan lain pada tahun yang sama; vertikal membawa sisa rugi ke tahun berikutnya maksimal lima tahun.","explanation":"Kompensasi berlaku atas kerugian fiskal yang memenuhi ketentuan dan tidak mencakup penghasilan final atau kerugian luar negeri secara sembarangan.","example":"Laba usaha A Rp100 juta dan rugi usaha B Rp30 juta menghasilkan neto Rp70 juta pada tahun yang sama.","keywords":"","comparison":"Horizontal lintas sumber dalam satu tahun; vertikal lintas tahun.","mnemonic":"Hori = sekarang; Verti = ke depan."},{"number":15,"topic":"Penyusutan-Amortisasi","subtopic":"TM 4","difficulty":"","type":"","question":"Kapan menggunakan penyusutan dan kapan amortisasi?","shortAnswer":"Penyusutan untuk harta berwujud; amortisasi untuk harta tidak berwujud.","explanation":"Metode dan masa manfaat mengikuti kelompok aset serta ketentuan pajak. Bangunan umumnya menggunakan garis lurus.","example":"Mesin disusutkan; goodwill diamortisasi.","keywords":"","comparison":"Tanah pada umumnya tidak disusutkan seperti bangunan.","mnemonic":"Susut = benda terlihat; Amortisasi = hak/nilai tak terlihat."},{"number":16,"topic":"PPh Pasal 23","subtopic":"TM 4","difficulty":"","type":"","question":"Apa objek utama PPh Pasal 23?","shortAnswer":"Dividen, bunga, royalti, hadiah tertentu, sewa harta selain tanah/bangunan, dan jasa tertentu.","explanation":"Kelompok dividen/bunga/royalti umumnya 15% bruto; sewa harta dan jasa tertentu umumnya 2% bruto, dengan pengecualian sesuai aturan.","example":"Jasa manajemen oleh badan kepada perusahaan lain dapat dipotong PPh 23.","keywords":"","comparison":"Gaji pegawai termasuk PPh 21, bukan PPh 23.","mnemonic":"23: hasil modal dan jasa badan."},{"number":17,"topic":"PBB-P2 vs PBB-P5L","subtopic":"TM 5","difficulty":"","type":"","question":"Apa beda PBB-P2 dan PBB-P5L?","shortAnswer":"PBB-P2 dikelola pemerintah daerah untuk perdesaan/perkotaan; PBB-P5L dikelola pemerintah pusat/DJP untuk perkebunan, perhutanan, pertambangan, migas, panas bumi, dan sektor lainnya.","explanation":"Perbedaan kewenangan memengaruhi penerbitan SPPT, kanal pembayaran, formula, dan NJOPTKP.","example":"Rumah tinggal dikenai PBB-P2; wilayah kerja pertambangan migas masuk PBB-P5L.","keywords":"","comparison":"P2 = daerah; P5L = sektor khusus pusat.","mnemonic":"P2 'perdesaan-perkotaan'; P5L 'lima sektor lebih'."},{"number":18,"topic":"Saat Terutang PBB","subtopic":"TM 5","difficulty":"","type":"","question":"Mengapa tanggal 1 Januari penting dalam PBB?","shortAnswer":"PBB tahun berjalan ditentukan berdasarkan kondisi objek pada 1 Januari.","explanation":"Perubahan setelah 1 Januari pada prinsipnya baru memengaruhi tahun pajak berikutnya. Ini menciptakan titik potong administrasi yang jelas.","example":"Gudang terbakar 10 Januari tetap dihitung berdasarkan kondisi saat 1 Januari.","keywords":"","comparison":"Berbeda dari pajak transaksi yang terutang saat transaksi terjadi.","mnemonic":"PBB memotret objek di awal tahun."},{"number":19,"topic":"NJOP-NJOPTKP-NJKP","subtopic":"TM 5","difficulty":"","type":"","question":"Apa hubungan NJOP, NJOPTKP, dan NJKP?","shortAnswer":"NJOP adalah nilai jual objek; NJOPTKP adalah bagian yang tidak dikenai pajak; NJKP adalah persentase tertentu dari NJOP setelah pengurangan sesuai ketentuan.","explanation":"Ketiga unsur membentuk dasar penghitungan PBB sebelum dikalikan tarif.","example":"PBB-P5L umum: 0,5% x 40% x (NJOP - NJOPTKP).","keywords":"","comparison":"NJOP adalah nilai; NJOPTKP pengurang; NJKP basis kena pajak.","mnemonic":"Nilai - Tidak Kena = Kena."},{"number":20,"topic":"BM-BK-Cukai","subtopic":"TM 6","difficulty":"","type":"","question":"Apa beda Bea Masuk, Bea Keluar, dan Cukai?","shortAnswer":"Bea Masuk dikenakan atas impor; Bea Keluar atas ekspor komoditas tertentu; Cukai atas barang tertentu yang konsumsinya perlu dikendalikan atau diawasi.","explanation":"Ketiganya memiliki fungsi budgeter dan regulerend, tetapi objek dan tujuannya berbeda.","example":"Impor elektronik dapat kena BM; ekspor CPO tertentu dapat kena BK; rokok kena cukai.","keywords":"","comparison":"BM/BK mengikuti arus lintas batas; cukai mengikuti karakteristik barang.","mnemonic":"Masuk-impor, Keluar-ekspor, Cukai-konsumsi."},{"number":21,"topic":"Trade Remedies","subtopic":"TM 6","difficulty":"","type":"","question":"Apa empat jenis Bea Masuk Tambahan?","shortAnswer":"BMAD, BMI, BMTP, dan Bea Masuk Pembalasan.","explanation":"BMAD untuk dumping, BMI untuk subsidi, BMTP untuk lonjakan impor, dan pembalasan untuk perlakuan diskriminatif terhadap ekspor Indonesia.","example":"Produk impor bersubsidi yang merugikan industri domestik dapat dikenai BMI.","keywords":"","comparison":"BMT menambah BM umum dan tidak menggantikannya.","mnemonic":"Dump-Subsidi-Lonjakan-Balas."},{"number":22,"topic":"PIB vs PIBK","subtopic":"TM 6","difficulty":"","type":"","question":"Apa beda PIB dan PIBK?","shortAnswer":"PIB adalah pemberitahuan impor umum untuk barang impor; PIBK adalah pemberitahuan sederhana untuk barang kiriman/konsinyasi, terutama kiriman bernilai relatif kecil dan bervolume tinggi.","explanation":"PIBK menyesuaikan karakteristik e-commerce lintas batas dan jasa titipan, sedangkan PIB biasa memuat data impor yang lebih lengkap.","example":"Paket e-commerce lintas negara dapat menggunakan dokumen barang kiriman sesuai ketentuan.","keywords":"","comparison":"PIBK bukan singkatan impor untuk dipakai biasa; huruf K merujuk barang kiriman/konsinyasi.","mnemonic":"K pada PIBK = Kiriman."},{"number":23,"topic":"Impor Sementara","subtopic":"TM 6","difficulty":"","type":"","question":"Apa kewajiban pokok fasilitas impor sementara?","shortAnswer":"Memperoleh izin, menyerahkan jaminan, menggunakan barang sesuai tujuan, dan mengekspor kembali tepat waktu.","explanation":"Fasilitas dapat berupa pembebasan atau keringanan BM. Keterlambatan re-ekspor dapat menimbulkan BM yang seharusnya dibayar dan denda.","example":"Peralatan pameran masuk sementara lalu harus dikirim kembali setelah kegiatan.","keywords":"","comparison":"Impor untuk dipakai bersifat definitif; impor sementara wajib re-ekspor.","mnemonic":"Sementara berarti harus kembali."},{"number":24,"topic":"Nilai Pabean-Nilai Impor","subtopic":"TM 7","difficulty":"","type":"","question":"Apa beda Nilai Pabean dan Nilai Impor?","shortAnswer":"Nilai Pabean menjadi dasar Bea Masuk dan umumnya dihitung dari CIF x kurs; Nilai Impor menjadi dasar PDRI dan dihitung dari Nilai Pabean + BM + BMT.","explanation":"Pembedaan ini penting agar BM dan PDRI tidak menggunakan dasar yang keliru.","example":"NP Rp100 juta dan BM Rp10 juta menghasilkan NI Rp110 juta jika tidak ada BMT.","keywords":"","comparison":"NP untuk bea; NI untuk pajak impor.","mnemonic":"Pabean dulu, Impor setelah ditambah bea."},{"number":25,"topic":"PIB BC 2.0","subtopic":"TM 7","difficulty":"","type":"","question":"Apa fungsi utama PIB BC 2.0?","shortAnswer":"PIB adalah pemberitahuan pabean elektronik oleh importir/PPJK untuk impor dipakai, berisi data barang dan penghitungan sendiri BM, cukai, serta PDRI.","explanation":"PIB terintegrasi dengan CEISA/NLE dan dapat menjadi dokumen yang dipersamakan dengan Faktur Pajak jika identitas, bukti pembayaran, dan NTPN memenuhi syarat.","example":"Importir mencantumkan HS Code, nilai pabean, BM, PPN, dan PPh 22 per seri barang.","keywords":"","comparison":"PIB adalah dokumen deklarasi impor; SSPCP adalah bukti pembayaran pungutannya.","mnemonic":"PIB = Pemberitahuan, Identitas, Bea."}]},"ksp":{"id":"ksp","title":"Kepemimpinan Sektor Publik","short":"Kepemimpinan SP","konsen":["gabungan"],"quiz":[{"number":1,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Definisi kepemimpinan","learningOutcome":"Menjelaskan esensi kepemimpinan sebagai proses pengaruh","difficulty":"Mudah","type":"Definisi","question":"Pernyataan yang PALING TEPAT mendefinisikan kepemimpinan adalah …","options":["kewenangan formal untuk memerintah bawahan agar menaati seluruh instruksi","proses memengaruhi, memotivasi, dan memungkinkan orang lain berkontribusi menuju tujuan bersama","kemampuan menyusun struktur organisasi dan membagi pekerjaan secara administratif","jabatan tertinggi yang memberikan hak menentukan keputusan tanpa umpan balik"],"correct":"B","concept":"Kepemimpinan sebagai proses relasional","explanation":"Jawaban B benar karena kepemimpinan tidak berhenti pada jabatan atau kewenangan formal. Intinya adalah proses pengaruh yang melibatkan pemimpin, pengikut, tujuan bersama, dan situasi. Pengaruh tersebut tampak ketika orang memahami arah, termotivasi, serta mampu memberi kontribusi yang bermakna. Dalam organisasi sektor publik, kepemimpinan juga harus dijalankan secara sah, etis, dan dapat dipertanggungjawabkan. Kesalahan umum adalah menyamakan kepemimpinan dengan perintah satu arah, padahal efektivitasnya sangat bergantung pada kepercayaan, komunikasi, serta respons pengikut.","whyOthersWrong":"A dan D terlalu menekankan kewenangan dan kepatuhan sepihak. C menggambarkan fungsi manajerial, tetapi belum mencakup proses memengaruhi dan membangun komitmen.","tip":"Cari unsur pengaruh, pengikut, tujuan bersama, dan hubungan dua arah.","reference":"TM 1 — Konsep kepemimpinan dalam organisasi; Yukl & Gardner; Northouse.","keywords":"pengaruh; motivasi; tujuan bersama"},{"number":2,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Karakteristik organisasi","learningOutcome":"Mengidentifikasi pembeda organisasi dari kumpulan orang biasa","difficulty":"Mudah","type":"Definisi","question":"Suatu kumpulan orang dapat disebut organisasi apabila memiliki …","options":["anggota dalam jumlah besar dan pemimpin yang paling senior","lokasi kerja yang sama serta hubungan sosial yang akrab","tujuan, pembagian peran, struktur, koordinasi, dan mekanisme pertanggungjawaban","seragam, aturan tertulis, dan kegiatan yang dilakukan setiap hari"],"correct":"C","concept":"Organisasi sebagai kesatuan sosial terkoordinasi","explanation":"Jawaban C benar karena organisasi merupakan kesatuan sosial yang dikoordinasikan secara sadar untuk mencapai tujuan tertentu. Ciri utamanya bukan sekadar orang berkumpul, melainkan adanya tujuan, pembagian peran, struktur, komunikasi, koordinasi, serta pertanggungjawaban. Unsur tersebut membuat kontribusi individu terhubung menjadi pekerjaan kolektif. Dalam sektor publik, struktur dan pertanggungjawaban juga memastikan bahwa kewenangan digunakan sesuai mandat. Kesalahan umum adalah menganggap jumlah anggota, kedekatan sosial, atau rutinitas sebagai pembeda utama, padahal semua itu dapat muncul pada kelompok biasa.","whyOthersWrong":"A, B, dan D dapat ditemukan pada kelompok biasa dan tidak selalu menunjukkan adanya tujuan, pembagian tugas, serta akuntabilitas yang terstruktur.","tip":"Pilih opsi yang memuat tujuan, struktur, koordinasi, dan tanggung jawab.","reference":"TM 1 — Kepemimpinan dalam organisasi; karakteristik organisasi.","keywords":"tujuan; struktur; koordinasi; pertanggungjawaban"},{"number":3,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Teori situasional","learningOutcome":"Menjelaskan fokus teori kepemimpinan situasional","difficulty":"Mudah","type":"Definisi","question":"Teori kepemimpinan situasional menekankan bahwa …","options":["efektivitas gaya bergantung pada kesesuaian dengan tugas, pengikut, dan kondisi","pemimpin efektif selalu memiliki sifat bawaan yang sama","pemimpin cukup menggunakan imbalan dan hukuman untuk semua keadaan","gaya demokratis merupakan satu-satunya gaya yang efektif"],"correct":"A","concept":"Kepemimpinan situasional","explanation":"Jawaban A benar karena pendekatan situasional menolak gagasan bahwa satu gaya selalu terbaik. Pemimpin harus membaca sifat tugas, tingkat risiko, waktu, kesiapan pengikut, serta dinamika lingkungan sebelum menentukan kadar arahan dan dukungan. Gaya yang efektif pada pegawai baru belum tentu tepat bagi tenaga ahli yang matang. Dalam sektor publik, penyesuaian ini tetap dibatasi mandat, etika, dan akuntabilitas. Kesalahan umum adalah memahami fleksibilitas sebagai ketidakkonsistenan, padahal yang berubah adalah pendekatan, sedangkan nilai dan tujuan publik tetap dijaga.","whyOthersWrong":"B menggambarkan teori sifat. C mencerminkan pendekatan transaksional yang diterapkan secara kaku. D mengabaikan pentingnya konteks.","tip":"Kata kunci teori situasional ialah tidak ada satu gaya terbaik untuk semua kondisi.","reference":"TM 2 — Teori situasional/kontingensi; Hersey–Blanchard.","keywords":"situasi; kesiapan pengikut; kesesuaian gaya"},{"number":4,"topic":"TM 3 — Integritas","subtopic":"Definisi integritas","learningOutcome":"Menjelaskan makna integritas dalam perilaku pemimpin","difficulty":"Mudah","type":"Definisi","question":"Integritas pemimpin PALING TEPAT tercermin dalam …","options":["kepatuhan kepada atasan tanpa mempertimbangkan nilai dan aturan","kemampuan menjaga citra positif di depan pemangku kepentingan","keberanian mengambil risiko meskipun prosedur diabaikan","konsistensi nilai, ucapan, keputusan, dan tindakan meskipun terdapat tekanan"],"correct":"D","concept":"Integritas sebagai konsistensi moral","explanation":"Jawaban D benar karena integritas menuntut keselarasan antara nilai, ucapan, keputusan, dan tindakan, termasuk ketika tidak diawasi atau ketika pilihan yang benar menimbulkan konsekuensi pribadi. Integritas bukan sekadar citra atau kepatuhan kepada orang tertentu, melainkan ketaatan pada norma, etika, dan mandat organisasi. Dalam sektor publik, integritas menjaga kepercayaan serta mencegah penyalahgunaan kewenangan. Kesalahan umum adalah menganggap loyalitas kepada atasan sebagai integritas, padahal loyalitas tidak boleh mengalahkan hukum, etika, dan kepentingan publik.","whyOthersWrong":"A dapat mendorong kepatuhan buta. B hanya berfokus pada citra. C menempatkan keberanian di atas aturan dan akuntabilitas.","tip":"Uji apakah perilaku tetap konsisten saat ada tekanan atau tidak ada pengawasan.","reference":"TM 3 — Pengertian dan prinsip integritas; PermenPAN-RB Nomor 38 Tahun 2017.","keywords":"konsistensi; nilai; tekanan"},{"number":5,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Nilai publik","learningOutcome":"Menjelaskan orientasi utama kepemimpinan sektor publik","difficulty":"Mudah","type":"Definisi","question":"Nilai publik terutama merujuk pada …","options":["peningkatan popularitas pemimpin di mata masyarakat","manfaat kolektif yang sah, adil, akuntabel, dan dirasakan masyarakat","jumlah program yang berhasil diselesaikan dalam satu tahun","besarnya anggaran yang dikelola oleh organisasi pemerintah"],"correct":"B","concept":"Nilai publik","explanation":"Jawaban B benar karena nilai publik menggabungkan manfaat bagi masyarakat dengan legalitas, keadilan, legitimasi, akses, dan akuntabilitas. Banyaknya program atau besarnya anggaran belum otomatis menunjukkan nilai publik apabila hasilnya tidak relevan, tidak merata, atau tidak sah. Pemimpin sektor publik harus menyeimbangkan efektivitas dengan hak warga serta mandat hukum. Kesalahan umum adalah menyamakan nilai publik dengan popularitas atau output administratif, padahal ukuran akhirnya adalah manfaat yang bermakna dan dapat dipertanggungjawabkan kepada masyarakat.","whyOthersWrong":"A hanya mengukur popularitas. C mengukur output, bukan manfaat. D mengukur sumber daya, bukan nilai yang dihasilkan.","tip":"Pilih jawaban yang memadukan manfaat, proses yang sah, keadilan, dan akuntabilitas.","reference":"TM 4 — Kepemimpinan sektor publik dan nilai publik.","keywords":"manfaat kolektif; legalitas; keadilan; akuntabilitas"},{"number":6,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Kewenangan dan pengaruh","learningOutcome":"Membedakan kewenangan formal dari pengaruh kepemimpinan","difficulty":"Mudah","type":"Konseptual","question":"Perbedaan utama antara kewenangan formal dan pengaruh kepemimpinan adalah …","options":["kewenangan bersumber dari jabatan, sedangkan pengaruh tumbuh dari kredibilitas, relasi, dan kepercayaan","kewenangan selalu informal, sedangkan pengaruh selalu tertulis dalam struktur","kewenangan menghasilkan komitmen intrinsik, sedangkan pengaruh hanya menghasilkan kepatuhan","kewenangan dan pengaruh merupakan istilah yang sepenuhnya sama"],"correct":"A","concept":"Kewenangan formal versus pengaruh","explanation":"Jawaban A benar karena kewenangan formal melekat pada jabatan dan memberi hak membuat keputusan dalam batas tertentu. Pengaruh kepemimpinan lebih luas: ia tumbuh dari kompetensi, keteladanan, keadilan, komunikasi, dan kepercayaan. Kewenangan dapat menghasilkan kepatuhan minimal, tetapi komitmen yang bertahan memerlukan pengaruh yang dipercaya. Dalam sektor publik, keduanya harus dipakai secara sah dan proporsional. Kesalahan umum adalah beranggapan bahwa jabatan otomatis membuat seseorang efektif, padahal keputusan dapat ditaati secara formal tetapi tidak memperoleh dukungan nyata.","whyOthersWrong":"B membalik sumber kewenangan. C membalik dampak umum kewenangan dan pengaruh. D mengabaikan perbedaan sumber serta kualitas kepatuhan.","tip":"Tanyakan: apakah sumbernya jabatan atau kredibilitas hubungan?","reference":"TM 1 — Pemimpin formal dan informal; hubungan pengaruh.","keywords":"jabatan; kredibilitas; kepercayaan"},{"number":7,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Transaksional dan transformasional","learningOutcome":"Menghubungkan mekanisme kepemimpinan dengan jenis teorinya","difficulty":"Mudah","type":"Konseptual","question":"Hubungan konsep yang tepat antara kepemimpinan transaksional dan transformasional adalah …","options":["keduanya hanya berbeda pada tingkat jabatan pemimpin","transaksional berfokus pada visi, sedangkan transformasional pada hukuman","transaksional mengelola pertukaran dan standar, sedangkan transformasional membangun visi, makna, dan perubahan","transformasional tidak memerlukan target, kontrol, atau akuntabilitas"],"correct":"C","concept":"Transaksional dan transformasional","explanation":"Jawaban C benar karena kepemimpinan transaksional menggunakan kejelasan target, imbalan, koreksi, dan pertukaran untuk menjaga kinerja. Kepemimpinan transformasional menggerakkan pengikut melalui visi bersama, stimulasi intelektual, keteladanan, dan perhatian individual sehingga tercipta komitmen serta perubahan. Keduanya tidak selalu saling meniadakan; organisasi publik sering membutuhkan standar transaksional sekaligus energi transformasional. Kesalahan umum adalah menganggap transformasional berarti bebas dari kontrol, padahal perubahan tetap harus dilembagakan melalui tata kelola dan akuntabilitas.","whyOthersWrong":"A tidak menjelaskan mekanisme. B membalik ciri kedua teori. D meniadakan pentingnya standar dan pengendalian.","tip":"Imbalan bersyarat menunjuk transaksional; visi dan perubahan menunjuk transformasional.","reference":"TM 2 — Teori kontemporer: transaksional dan transformasional.","keywords":"pertukaran; visi; perubahan"},{"number":8,"topic":"TM 3 — Integritas","subtopic":"Budaya integritas","learningOutcome":"Menganalisis hubungan keteladanan dan sistem pengendalian","difficulty":"Sedang","type":"Konseptual","question":"Budaya integritas paling kuat terbentuk ketika organisasi …","options":["hanya menyampaikan slogan etika secara berkala","menyerahkan seluruh tanggung jawab etika kepada unit kepatuhan","mengandalkan karakter baik pemimpin tanpa memperbaiki sistem","memadukan keteladanan, aturan jelas, kanal pelaporan, konsistensi sanksi, dan perlindungan pelapor"],"correct":"D","concept":"Budaya integritas berbasis teladan dan sistem","explanation":"Jawaban D benar karena budaya integritas lahir dari interaksi antara teladan pemimpin dan sistem organisasi. Keteladanan memberi sinyal nilai, sedangkan aturan, pengendalian, kanal pelaporan, perlindungan pelapor, serta sanksi yang konsisten membuat perilaku etis dapat dipertahankan. Slogan tanpa praktik mudah menjadi simbolik, dan karakter individu tanpa sistem akan rapuh ketika pemimpin berganti. Dalam sektor publik, kombinasi ini penting karena integritas harus berlangsung lintas jabatan dan waktu. Kesalahan umum adalah menganggap etika cukup dikelola oleh satu unit, padahal setiap pimpinan dan pegawai memiliki tanggung jawab.","whyOthersWrong":"A bersifat seremonial. B memindahkan tanggung jawab dari seluruh organisasi. C membuat integritas bergantung pada figur.","tip":"Jawaban kuat selalu menggabungkan role model, prosedur, pelaporan, perlindungan, dan konsekuensi.","reference":"TM 3 — Membangun budaya integritas; kompetensi integritas.","keywords":"keteladanan; sistem; kanal pelaporan; konsistensi"},{"number":9,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Kompetensi jabatan ASN","learningOutcome":"Menjelaskan hubungan kompetensi teknis, manajerial, dan sosial kultural","difficulty":"Sedang","type":"Konseptual","question":"Mengapa kompetensi teknis, manajerial, dan sosial kultural harus dipadukan dalam jabatan ASN?","options":["agar seluruh ASN dapat menjalankan pekerjaan yang sama","karena kinerja jabatan membutuhkan keahlian bidang, kemampuan mengelola, dan kepekaan melayani masyarakat majemuk","karena kompetensi manajerial dapat menggantikan pengetahuan teknis","agar masa kerja menjadi satu-satunya dasar promosi"],"correct":"B","concept":"Standar kompetensi jabatan ASN","explanation":"Jawaban B benar karena jabatan ASN tidak hanya menuntut pengetahuan bidang. Kompetensi teknis memastikan pekerjaan dilakukan dengan benar, kompetensi manajerial memungkinkan pemimpin mengelola orang dan unit, sedangkan kompetensi sosial kultural membantu pelayanan yang inklusif dalam masyarakat majemuk. Ketiganya harus sesuai tuntutan jabatan dan tidak dapat saling menggantikan. Dalam sistem merit, kombinasi kompetensi, kualifikasi, dan kinerja menjadi dasar objektif pengelolaan karier. Kesalahan umum adalah menilai kelayakan jabatan hanya dari senioritas, gelar, atau satu jenis kompetensi.","whyOthersWrong":"A mengabaikan spesifikasi jabatan. C salah karena kompetensi manajerial tidak menggantikan keahlian bidang. D bertentangan dengan sistem merit.","tip":"Ingat TMS: Teknis–Manajerial–Sosial kultural.","reference":"TM 4 — PermenPAN-RB Nomor 38 Tahun 2017; kompetensi jabatan ASN.","keywords":"teknis; manajerial; sosial kultural"},{"number":10,"topic":"TM 5 — Kerja Sama","subtopic":"Kelompok dan tim","learningOutcome":"Membedakan kelompok kerja dari tim efektif","difficulty":"Sedang","type":"Konseptual","question":"Ciri yang paling membedakan tim efektif dari kelompok kerja biasa adalah …","options":["semua anggota mempunyai jabatan dan keahlian yang sama","anggota selalu sepakat dan tidak pernah mengalami konflik","terdapat tujuan bersama, ketergantungan pekerjaan, peran saling melengkapi, dan akuntabilitas kolektif","seluruh keputusan dibuat pemimpin agar proses berlangsung cepat"],"correct":"C","concept":"Tim efektif","explanation":"Jawaban C benar karena tim terbentuk ketika kontribusi anggota saling bergantung untuk mencapai outcome bersama. Peran dapat berbeda, tetapi harus saling melengkapi dan dihubungkan oleh tujuan, norma, komunikasi, serta akuntabilitas kolektif. Konflik tugas yang dikelola secara profesional justru dapat memperbaiki keputusan; ketiadaan konflik tidak selalu menandakan tim sehat. Dalam organisasi sektor publik, tim lintas unit memerlukan mekanisme integrasi agar pekerjaan tidak berhenti sebagai daftar tugas terpisah. Kesalahan umum adalah menyebut setiap kelompok sebagai tim tanpa memeriksa dependensi dan hasil bersama.","whyOthersWrong":"A tidak diperlukan dalam tim. B mengabaikan konflik produktif. D dapat melemahkan partisipasi dan tanggung jawab bersama.","tip":"Cari tujuan bersama, dependensi, peran pelengkap, dan akuntabilitas bersama.","reference":"TM 5 — Kelompok, tim, koordinasi, dan kolaborasi.","keywords":"tujuan bersama; ketergantungan; akuntabilitas kolektif"},{"number":11,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Penerapan kepemimpinan situasional","learningOutcome":"Menerapkan gaya berdasarkan kesiapan pengikut","difficulty":"Sedang","type":"Penerapan","question":"Seorang kepala unit memberi instruksi rinci kepada pegawai baru, tetapi memberikan otonomi berbasis target kepada analis senior. Pendekatan tersebut paling sesuai dengan …","options":["kepemimpinan situasional","kepemimpinan otoriter permanen","teori sifat","laissez-faire tanpa pengawasan"],"correct":"A","concept":"Penyesuaian gaya terhadap kesiapan","explanation":"Jawaban A benar karena pemimpin menyesuaikan kadar arahan dan otonomi dengan kesiapan pengikut pada tugas tertentu. Pegawai baru membutuhkan struktur dan umpan balik lebih rinci, sedangkan analis senior dapat diberi ruang memilih metode selama outcome, batas kewenangan, dan akuntabilitas jelas. Ini bukan perlakuan tidak adil, melainkan dukungan yang relevan dengan kebutuhan. Kesalahan umum adalah menyamakan delegasi dengan laissez-faire. Delegasi tetap menetapkan tujuan, standar, tenggat, serta mekanisme pemantauan, sedangkan laissez-faire cenderung pasif dan minim arah.","whyOthersWrong":"B tidak menjelaskan perbedaan perlakuan berdasarkan kesiapan. C berfokus pada karakter pemimpin. D mengabaikan target dan pengawasan.","tip":"Perhatikan apakah gaya berubah sesuai kompetensi dan komitmen pengikut.","reference":"TM 2 — Kepemimpinan situasional; tipe liberal dan laissez-faire.","keywords":"kesiapan pengikut; arahan; dukungan"},{"number":12,"topic":"TM 3 — Integritas","subtopic":"Konflik kepentingan","learningOutcome":"Menentukan tindakan awal untuk menjaga integritas","difficulty":"Sedang","type":"Penerapan","question":"Seorang pejabat menerima tawaran hadiah dari vendor yang sedang mengikuti proses pengadaan. Tindakan PERTAMA yang paling tepat adalah …","options":["menerima hadiah karena keputusan belum dibuat","menyimpan hadiah dan melaporkannya setelah kontrak selesai","meminta bawahan menerima hadiah agar tidak terkait langsung","menolak atau mengungkapkan tawaran melalui mekanisme resmi serta menjaga jarak dari konflik kepentingan"],"correct":"D","concept":"Pencegahan konflik kepentingan","explanation":"Jawaban D benar karena tawaran hadiah dari pihak yang berkepentingan dapat menimbulkan konflik kepentingan aktual maupun persepsian. Tindakan awal adalah menolak atau mengungkapkan tawaran melalui mekanisme resmi, mendokumentasikan kejadian, dan memastikan proses keputusan tetap objektif. Integritas tidak hanya menilai apakah keputusan benar-benar dipengaruhi, tetapi juga apakah publik dapat mempercayai independensi proses. Kesalahan umum adalah menunda pelaporan atau memindahkan penerimaan kepada orang lain; keduanya tidak menghilangkan risiko dan justru memperburuk akuntabilitas.","whyOthersWrong":"A mengabaikan konflik kepentingan. B menunda pengendalian hingga terlambat. C memindahkan, bukan menghilangkan, risiko integritas.","tip":"Pada hadiah/vendor, pikirkan penolakan, pengungkapan, dokumentasi, dan independensi proses.","reference":"TM 3 — Integritas, konflik kepentingan, dan budaya etis.","keywords":"konflik kepentingan; hadiah; pengungkapan"},{"number":13,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Relasi pemimpin politik dan ASN karier","learningOutcome":"Menerapkan profesionalisme ASN terhadap mandat politik yang sah","difficulty":"Sedang","type":"Penerapan","question":"Pemimpin politik menetapkan program prioritas baru. Sikap ASN karier yang PALING TEPAT adalah …","options":["menolak program karena seluruh kebijakan politik bersifat partisan","mendukung program tanpa analisis agar dianggap loyal","memberikan analisis profesional, menjelaskan risiko, dan melaksanakan mandat yang sah sesuai aturan","mengubah data agar program terlihat berhasil"],"correct":"C","concept":"Mandat politik dan profesionalisme birokrasi","explanation":"Jawaban C benar karena pemimpin politik membawa mandat demokratis untuk menentukan arah kebijakan, sedangkan ASN karier memberi keahlian, kesinambungan, analisis, serta pelaksanaan profesional. Netralitas tidak berarti menolak kebijakan politik, melainkan tidak menyalahgunakan jabatan untuk kepentingan partisan dan tetap bekerja berdasarkan hukum serta bukti. ASN perlu menyampaikan risiko secara jujur, menawarkan alternatif yang sah, lalu melaksanakan keputusan yang berada dalam kewenangan. Kesalahan umum adalah menyamakan loyalitas dengan kepatuhan tanpa analisis atau, sebaliknya, menganggap semua agenda politik tidak profesional.","whyOthersWrong":"A meniadakan mandat demokratis. B menghilangkan fungsi analisis profesional. D melanggar integritas dan akuntabilitas.","tip":"Bedakan mandat kebijakan dengan pelaksanaan profesional berbasis merit dan hukum.","reference":"TM 4 — Kepemimpinan jalur politik, jalur karier, dan netralitas ASN.","keywords":"netralitas; profesionalisme; mandat sah"},{"number":14,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Komunikasi kebijakan kompleks","learningOutcome":"Menerapkan komunikasi multi-kanal dan umpan balik","difficulty":"Sedang","type":"Penerapan","question":"Untuk menjelaskan perubahan prosedur yang kompleks kepada pegawai lintas unit, strategi komunikasi yang paling tepat adalah …","options":["mengirim satu surat edaran dan menganggap seluruh pegawai telah memahami","menggabungkan penjelasan formal, forum dialog, contoh penerapan, teach-back, dan tindak lanjut tertulis","menyampaikan pesan hanya melalui percakapan informal agar lebih cepat","menunda komunikasi sampai semua pihak sepakat sepenuhnya"],"correct":"B","concept":"Komunikasi efektif dan pemeriksaan pemahaman","explanation":"Jawaban B benar karena pesan kompleks membutuhkan saluran yang sesuai, contoh konkret, kesempatan bertanya, serta pemeriksaan pemahaman. Teach-back meminta penerima menjelaskan kembali makna atau tindakan sehingga pemimpin dapat mendeteksi kesenjangan sebelum implementasi. Kanal formal menjaga akuntabilitas, sedangkan dialog membantu klarifikasi dan penerimaan. Kesalahan umum adalah menyamakan pengiriman pesan dengan keberhasilan komunikasi. Komunikasi baru efektif ketika penerima memahami makna, melakukan tindakan yang tepat, dan tersedia umpan balik untuk memperbaiki pesan.","whyOthersWrong":"A hanya membuktikan pesan dikirim. C tidak cukup untuk keputusan yang menimbulkan kewajiban. D membuat ketidakpastian berlarut-larut.","tip":"Cari kombinasi kejelasan, kanal tepat, feedback, dan dokumentasi.","reference":"TM 6 — Level komunikasi; komunikasi formal dan informal; teach-back.","keywords":"multi-kanal; teach-back; feedback"},{"number":15,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Perbaikan kinerja","learningOutcome":"Menerapkan pengukuran berbasis baseline, proses, dan outcome","difficulty":"Sedang","type":"Penerapan","question":"Langkah paling tepat untuk meningkatkan hasil layanan publik adalah …","options":["menetapkan baseline, memilih indikator proses dan outcome, menguji metode alternatif, lalu meninjau dampaknya","menaikkan target output tanpa memeriksa kapasitas dan mutu","menilai kinerja hanya dari jumlah kegiatan yang dilaksanakan","mengganti indikator setiap kali hasil belum tercapai"],"correct":"A","concept":"Siklus perbaikan kinerja berorientasi hasil","explanation":"Jawaban A benar karena perbaikan kinerja memerlukan titik awal, ukuran yang relevan, percobaan metode, dan evaluasi dampak. Baseline membantu menilai kemajuan secara adil; indikator proses memberi sinyal dini, sedangkan outcome menunjukkan perubahan yang dialami penerima manfaat. Pemimpin kemudian menyesuaikan metode berdasarkan bukti, bukan sekadar menaikkan target. Kesalahan umum adalah mengukur keberhasilan hanya dari aktivitas atau output, padahal jumlah kegiatan dapat meningkat tanpa memperbaiki kualitas layanan. Orientasi hasil juga harus menjaga etika, kapasitas, mutu, dan keberlanjutan sistem.","whyOthersWrong":"B dapat mendorong tekanan dan penurunan mutu. C berhenti pada aktivitas. D merusak konsistensi pengukuran.","tip":"Urutkan: baseline → indikator → tindakan → monitoring → evaluasi outcome.","reference":"TM 7 — Orientasi pada hasil; output, outcome, baseline, dan perbaikan.","keywords":"baseline; indikator; outcome; perbaikan"},{"number":16,"topic":"TM 5 — Kerja Sama","subtopic":"Psychological safety","learningOutcome":"Menganalisis intervensi untuk tim yang takut berbicara","difficulty":"Sulit","type":"Mini Kasus","question":"Dalam rapat, anggota tim selalu setuju, tetapi kesalahan baru diketahui setelah layanan gagal. Tindakan pemimpin yang PALING TEPAT adalah …","options":["memperketat larangan kritik agar rapat lebih tertib","mengganti seluruh anggota yang pernah melakukan kesalahan","membangun keamanan psikologis, meminta dissent berbasis data, dan menindaklanjuti masalah tanpa mempermalukan individu","menghapus evaluasi agar anggota tidak takut"],"correct":"C","concept":"Keamanan psikologis dan konflik tugas","explanation":"Jawaban C benar karena pola selalu setuju dapat menandakan rendahnya keamanan psikologis, bukan kekompakan. Pemimpin perlu membuka ruang bertanya, mengakui ketidakpastian, meminta pandangan berbeda, dan memisahkan kritik terhadap ide dari serangan personal. Kesalahan tetap harus ditangani secara akuntabel, tetapi fokus awalnya adalah memahami sistem dan mencegah pengulangan. Dengan demikian, konflik tugas menjadi sumber pembelajaran. Kesalahan umum adalah menghapus kritik atau evaluasi, karena hal itu justru memperkuat budaya diam dan membuat risiko baru terlambat terdeteksi.","whyOthersWrong":"A memperkuat ketakutan. B mendorong blame culture dan menghilangkan pembelajaran. D menghapus mekanisme koreksi.","tip":"Ketiadaan konflik bukan selalu sehat; cari ruang aman, data, dan tindak lanjut sistemik.","reference":"TM 5 — Psychological safety, konflik tugas, dan pembelajaran tim.","keywords":"psychological safety; dissent; pembelajaran"},{"number":17,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Komunikasi krisis","learningOutcome":"Menganalisis respons komunikasi pada informasi yang belum lengkap","difficulty":"Sulit","type":"Mini Kasus","question":"Terjadi gangguan layanan digital dan informasi penyebabnya belum lengkap. Respons komunikasi pemimpin yang paling tepat adalah …","options":["menunggu seluruh fakta lengkap sebelum memberi informasi apa pun","menyalahkan unit teknis agar publik mengetahui pihak yang bertanggung jawab","memberi perkiraan yang pasti agar masyarakat segera tenang","menjelaskan yang diketahui dan belum diketahui, tindakan yang sedang dilakukan, kanal bantuan, serta waktu pembaruan berikutnya"],"correct":"D","concept":"Komunikasi krisis yang cepat dan akurat","explanation":"Jawaban D benar karena komunikasi krisis harus cepat, akurat, empatik, dan terus diperbarui. Pemimpin tidak perlu menunggu seluruh fakta, tetapi harus membedakan informasi yang telah terverifikasi dari hal yang belum diketahui. Masyarakat juga membutuhkan tindakan yang sedang dilakukan, alternatif layanan, kanal bantuan, dan waktu pembaruan berikutnya. Kesalahan umum adalah memberi kepastian palsu atau mencari kambing hitam, karena keduanya dapat merusak kepercayaan. Transparansi proporsional berarti terbuka mengenai fakta relevan tanpa menyebarkan spekulasi atau informasi yang belum teruji.","whyOthersWrong":"A menciptakan ruang rumor. B mendorong blame culture. C berisiko menyebarkan informasi yang keliru.","tip":"Dalam krisis: diketahui, belum diketahui, dilakukan, bantuan, dan waktu update.","reference":"TM 6 — Komunikasi krisis dan sistem komunikasi terbuka.","keywords":"krisis; transparansi proporsional; pembaruan"},{"number":18,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Distorsi indikator","learningOutcome":"Menganalisis risiko cream-skimming dan Goodhart's law","difficulty":"Sulit","type":"Mini Kasus","question":"Unit pelayanan hanya memilih kasus termudah agar target jumlah penyelesaian tercapai, sementara kasus kelompok rentan tertunda. Analisis yang paling tepat adalah …","options":["strategi tersebut efisien karena output meningkat","terjadi cream-skimming dan distorsi indikator; ukuran harus memasukkan kompleksitas, mutu, dan pemerataan","masalah hanya terletak pada kurangnya sosialisasi target","target jumlah penyelesaian harus dinaikkan lagi"],"correct":"B","concept":"Risiko indikator sempit","explanation":"Jawaban B benar karena unit memilih kasus mudah untuk mempercantik angka, bukan untuk memaksimalkan nilai publik. Perilaku ini disebut cream-skimming dan menunjukkan risiko Goodhart's law: ketika ukuran sempit dijadikan target, perilaku dapat terdistorsi. Perbaikannya adalah menyeimbangkan jumlah penyelesaian dengan kompleksitas kasus, mutu, ketepatan waktu, pemerataan, dan outcome penerima manfaat. Kesalahan umum adalah menyebutnya efisiensi, padahal kelompok yang paling membutuhkan justru terabaikan. Orientasi hasil harus menilai dampak dan keadilan, bukan angka output semata.","whyOthersWrong":"A mengabaikan mutu dan keadilan. C tidak menyentuh desain indikator. D dapat memperkuat distorsi.","tip":"Saat angka tampak baik tetapi kebutuhan sulit dihindari, curigai cream-skimming dan Goodhart.","reference":"TM 7 — Goodhart's law, cream-skimming, output, outcome, dan keadilan.","keywords":"cream-skimming; Goodhart; pemerataan"},{"number":19,"topic":"TM 3 — Integritas","subtopic":"Tekanan untuk memanipulasi data","learningOutcome":"Mengevaluasi respons terhadap perintah yang tidak etis","difficulty":"Sulit","type":"Mini Kasus","question":"Atasan meminta tanggal laporan diubah agar unit terlihat patuh terhadap tenggat. Tindakan yang paling tepat adalah …","options":["menolak perubahan yang tidak benar, menjelaskan risikonya, menjaga bukti, dan menggunakan kanal eskalasi yang sah","mengubah tanggal karena loyalitas kepada atasan adalah prioritas","menghapus seluruh laporan agar tidak ada bukti keterlambatan","menunda keputusan sampai audit menemukan masalah"],"correct":"A","concept":"Integritas di bawah tekanan","explanation":"Jawaban A benar karena perubahan tanggal yang tidak sesuai fakta merupakan manipulasi dan merusak akuntabilitas. Integritas menuntut pegawai menolak tindakan yang salah, menjelaskan dampak hukum dan reputasi, menjaga dokumentasi, serta menggunakan jalur konsultasi atau eskalasi yang sah. Cara penyampaian tetap profesional dan berfokus pada fakta. Kesalahan umum adalah menyamakan loyalitas dengan mengikuti semua instruksi. Loyalitas yang benar diarahkan pada mandat, hukum, dan kepentingan organisasi jangka panjang, bukan pada perlindungan citra sementara.","whyOthersWrong":"B adalah kepatuhan buta. C memperbesar pelanggaran dengan menghilangkan bukti. D membiarkan informasi salah terus digunakan.","tip":"Pada perintah tidak etis: tolak secara profesional, dokumentasikan, jelaskan risiko, dan eskalasi secara sah.","reference":"TM 3 — Integritas, konsistensi tindakan, dan keberanian moral.","keywords":"manipulasi; keberanian moral; eskalasi"},{"number":20,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Mandat kebijakan dan legalitas","learningOutcome":"Menganalisis pilihan ASN ketika prioritas politik bermasalah","difficulty":"Sulit","type":"Mini Kasus","question":"Program prioritas pimpinan politik berpotensi melanggar aturan dan tidak didukung bukti kebutuhan. Respons ASN senior yang PALING TEPAT adalah …","options":["langsung mengumumkan penolakan kepada media","melaksanakan seluruh instruksi karena berasal dari pejabat terpilih","menyampaikan analisis hukum dan dampak, menawarkan alternatif yang sah, serta mendokumentasikan proses keputusan","mengurangi kualitas data agar program terlihat layak"],"correct":"C","concept":"Profesionalisme birokrasi dalam dilema kebijakan","explanation":"Jawaban C benar karena ASN harus menghormati mandat demokratis sekaligus menjaga legalitas, profesionalisme, dan kepentingan publik. Tugasnya adalah menjelaskan dasar hukum, bukti kebutuhan, risiko, dampak terhadap kelompok terdampak, serta alternatif yang dapat mencapai tujuan secara sah. Proses perlu didokumentasikan agar keputusan dapat dipertanggungjawabkan. Kesalahan umum adalah memilih antara kepatuhan total dan perlawanan terbuka. Pendekatan profesional menempatkan dialog berbasis bukti dan batas kewenangan sebagai langkah utama, kemudian menggunakan eskalasi resmi bila risiko tidak terselesaikan.","whyOthersWrong":"A mengabaikan jalur internal dan dapat memperkeruh masalah. B meniadakan tanggung jawab profesional. D melanggar integritas.","tip":"Seimbangkan mandat politik dengan hukum, bukti, alternatif, dan dokumentasi.","reference":"TM 4 — Jalur politik, ASN karier, sistem merit, dan nilai publik.","keywords":"legalitas; bukti; alternatif; dokumentasi"},{"number":21,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Liberal dan laissez-faire","learningOutcome":"Membedakan kebebasan terarah dari kepasifan pemimpin","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan paling tepat antara gaya liberal dan laissez-faire adalah …","options":["liberal selalu otoriter, sedangkan laissez-faire demokratis","liberal digunakan untuk pegawai baru, sedangkan laissez-faire untuk keadaan darurat","keduanya identik karena sama-sama memberi kebebasan","liberal memberi otonomi dalam batas tujuan dan kontrol, sedangkan laissez-faire cenderung pasif dan minim arahan"],"correct":"D","concept":"Liberal versus laissez-faire","explanation":"Jawaban D benar karena gaya liberal memberikan ruang berkreasi dan memilih metode, tetapi tetap mempertahankan tujuan, batas kewenangan, dukungan, serta evaluasi hasil. Laissez-faire lebih dekat pada sikap pasif atau lepas tangan, sehingga arah dan akuntabilitas dapat kabur. Pada tim profesional matang, otonomi dapat efektif bila outcome dan milestone jelas. Kesalahan umum adalah menyamakan semua kebebasan dengan delegasi yang baik. Delegasi tetap menuntut penetapan hasil, sumber daya, monitoring, dan dukungan ketika hambatan muncul.","whyOthersWrong":"A dan B tidak sesuai ciri kedua gaya. C mengabaikan perbedaan arah, dukungan, dan pengawasan.","tip":"Delegasi bukan pengabaian: lihat apakah tujuan, batas, dan evaluasi masih ada.","reference":"TM 2 — Tipe liberal dan laissez-faire.","keywords":"otonomi; batas; kepasifan"},{"number":22,"topic":"TM 5 — Kerja Sama","subtopic":"Koordinasi dan kolaborasi","learningOutcome":"Membedakan penyelarasan kerja dari penciptaan solusi bersama","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan utama antara koordinasi dan kolaborasi adalah …","options":["koordinasi hanya terjadi di sektor privat, sedangkan kolaborasi di sektor publik","koordinasi menyelaraskan pekerjaan yang tetap terpisah, sedangkan kolaborasi membagi kewenangan dan menciptakan solusi bersama","koordinasi membutuhkan kepercayaan, sedangkan kolaborasi tidak","kolaborasi selalu lebih cepat dan tidak memerlukan tata kelola"],"correct":"B","concept":"Koordinasi versus kolaborasi","explanation":"Jawaban B benar karena koordinasi terutama mengatur jadwal, informasi, urutan, dan antarmuka agar pekerjaan terpisah tidak bertabrakan. Kolaborasi melangkah lebih jauh: para pihak berbagi pengetahuan, sumber daya, risiko, bahkan sebagian kewenangan untuk membentuk solusi bersama. Keduanya memerlukan kepercayaan dan tata kelola, terutama di sektor publik yang melibatkan banyak mandat. Kesalahan umum adalah menganggap kolaborasi otomatis lebih baik. Kolaborasi hanya tepat ketika masalah memang saling bergantung dan manfaat integrasi lebih besar daripada biaya koordinasinya.","whyOthersWrong":"A salah secara konteks. C meniadakan kepercayaan dalam kolaborasi. D mengabaikan kebutuhan governance dan potensi biaya.","tip":"Koordinasi = selaras; kolaborasi = bersama-sama menciptakan keputusan/solusi.","reference":"TM 5 — Kelompok, tim, koordinasi, dan kolaborasi.","keywords":"penyelarasan; solusi bersama; kewenangan"},{"number":23,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Output dan outcome","learningOutcome":"Membedakan produk layanan dari perubahan bagi penerima manfaat","difficulty":"Sedang","type":"Perbandingan","question":"Manakah pasangan yang tepat untuk membedakan output dan outcome?","options":["output adalah sumber daya; outcome adalah kegiatan","output adalah dampak jangka panjang; outcome adalah jumlah dokumen","output adalah produk langsung layanan; outcome adalah perubahan yang dialami penerima manfaat","output dan outcome selalu identik selama target tercapai"],"correct":"C","concept":"Output versus outcome","explanation":"Jawaban C benar karena output merupakan produk langsung dari aktivitas, seperti izin terbit, peserta dilatih, atau laporan selesai. Outcome menunjukkan perubahan yang terjadi pada penerima manfaat, misalnya waktu layanan berkurang, kepatuhan meningkat, atau akses kelompok rentan membaik. Pemimpin berorientasi hasil tidak berhenti pada banyaknya output, tetapi menguji apakah produk tersebut benar-benar menghasilkan perubahan yang dimaksud. Kesalahan umum adalah menganggap output sebagai hasil akhir, sehingga organisasi sibuk menyelesaikan kegiatan tanpa memeriksa manfaatnya.","whyOthersWrong":"A dan B menukar unsur rantai hasil. D menghapus perbedaan penting antara produk dan perubahan.","tip":"Tanyakan: apa yang dihasilkan organisasi, lalu apa yang berubah bagi masyarakat?","reference":"TM 7 — Rantai hasil: input, aktivitas, output, outcome, impact.","keywords":"output; outcome; penerima manfaat"},{"number":24,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Pemilihan gaya kepemimpinan","learningOutcome":"Mengevaluasi pendekatan kepemimpinan yang kontekstual","difficulty":"Sulit","type":"Analisis","question":"Pernyataan analitis yang PALING KUAT mengenai gaya kepemimpinan efektif di sektor publik adalah …","options":["pemimpin perlu memadukan nilai yang konsisten dengan gaya yang disesuaikan pada tugas, risiko, kesiapan pengikut, dan tujuan publik","gaya transformasional selalu paling baik karena tidak membutuhkan kontrol formal","gaya demokratis harus digunakan pada semua keputusan agar partisipatif","gaya otoriter paling tepat karena birokrasi membutuhkan kepatuhan"],"correct":"A","concept":"Integrasi nilai dan kepemimpinan situasional","explanation":"Jawaban A benar karena efektivitas kepemimpinan sektor publik tidak dapat ditentukan oleh satu label gaya. Pemimpin harus menjaga nilai, legalitas, dan tujuan publik secara konsisten, lalu menyesuaikan perilaku dengan jenis tugas, risiko, waktu, kompetensi pengikut, dan kebutuhan partisipasi. Keadaan darurat mungkin membutuhkan arahan tegas, sedangkan inovasi lintas unit membutuhkan dialog dan kolaborasi. Kesalahan umum adalah menjadikan satu gaya sebagai resep universal. Bahkan gaya transformasional memerlukan standar, pengendalian, dan institusionalisasi agar perubahan tetap sah serta berkelanjutan.","whyOthersWrong":"B meniadakan kontrol. C mengabaikan keputusan yang membutuhkan kecepatan atau kewenangan jelas. D menyederhanakan birokrasi menjadi kepatuhan semata.","tip":"Jawaban tingkat lanjut harus menyebut konteks, pengikut, risiko, nilai, dan hasil publik.","reference":"TM 1–2 — Kepemimpinan sebagai proses; teori situasional dan kontemporer.","keywords":"konteks; nilai konsisten; adaptasi gaya"},{"number":25,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Sistem komunikasi kinerja","learningOutcome":"Mengevaluasi rancangan komunikasi yang mencegah distorsi target","difficulty":"Sulit","type":"Analisis","question":"Sistem komunikasi kinerja yang PALING TEPAT untuk mencegah perilaku mengejar angka semata adalah …","options":["menyampaikan satu target output tanpa indikator lain agar fokus","merahasiakan metode penilaian supaya pegawai tidak memanipulasi","mengubah target setiap bulan tanpa menjelaskan alasan","menjelaskan rantai hasil, menyeimbangkan indikator mutu dan pemerataan, membuka feedback, serta meninjau dampak yang tidak diinginkan"],"correct":"D","concept":"Komunikasi kinerja dan pengendalian distorsi indikator","explanation":"Jawaban D benar karena target harus dipahami dalam hubungan antara aktivitas, output, outcome, mutu, pemerataan, dan dampak. Pemimpin perlu menjelaskan alasan indikator, membuka ruang pertanyaan, serta meninjau konsekuensi yang tidak diinginkan seperti cream-skimming atau penurunan mutu. Transparansi ini membuat pegawai memahami tujuan, bukan sekadar angka. Kesalahan umum adalah menganggap kerahasiaan atau target tunggal mencegah manipulasi. Sebaliknya, desain sempit dan komunikasi satu arah dapat memperbesar gaming karena anggota tidak melihat keseluruhan nilai publik yang hendak dicapai.","whyOthersWrong":"A mendorong tunnel vision. B mengurangi kejelasan dan kepercayaan. C merusak konsistensi serta kemampuan belajar.","tip":"Pilih sistem yang menghubungkan tujuan, indikator seimbang, feedback, dan evaluasi dampak.","reference":"TM 6–7 — Sistem komunikasi terbuka; orientasi hasil; Goodhart's law.","keywords":"rantai hasil; balanced indicator; feedback; dampak"}],"flashcards":[{"number":1,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Esensi kepemimpinan","difficulty":"Mudah","type":"Definisi","question":"Apa definisi ringkas kepemimpinan?","shortAnswer":"Proses memengaruhi, memotivasi, dan memungkinkan orang lain berkontribusi untuk mencapai tujuan bersama.","explanation":"Kepemimpinan bersifat relasional, bukan hanya atribut jabatan. Pemimpin, pengikut, tujuan, dan situasi saling memengaruhi. Efektivitas terlihat dari perubahan pemahaman, komitmen, dan tindakan, bukan sekadar kepatuhan sesaat.","example":"Kepala unit menjelaskan alasan perubahan prosedur, menerima pertanyaan, lalu menyesuaikan dukungan agar pegawai mampu menerapkannya.","keywords":"pengaruh; motivasi; tujuan bersama","comparison":"Manajemen — lebih menekankan perencanaan, pengorganisasian, dan pengendalian pekerjaan.","mnemonic":"PPT: Pengaruh–Pengikut–Tujuan."},{"number":2,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Organisasi","difficulty":"Mudah","type":"Definisi","question":"Kapan kumpulan orang disebut organisasi?","shortAnswer":"Ketika memiliki tujuan, pembagian peran, struktur, koordinasi, komunikasi, dan pertanggungjawaban.","explanation":"Organisasi berbeda dari kerumunan karena pekerjaan anggota dihubungkan secara sadar untuk mencapai sasaran tertentu. Struktur dan koordinasi membuat kontribusi individu saling terkait, sedangkan pertanggungjawaban menjelaskan siapa melakukan apa dan kepada siapa hasil dilaporkan.","example":"Unit pelayanan memiliki target, pembagian front office–verifikator–penanggung jawab, alur koordinasi, dan laporan kinerja.","keywords":"tujuan; struktur; koordinasi; akuntabilitas","comparison":"Kelompok sosial — dapat berkumpul tanpa pembagian kerja dan tanggung jawab formal.","mnemonic":"TuSKoK: Tujuan–Struktur–Koordinasi/Komunikasi–Kepemimpinan."},{"number":3,"topic":"TM 3 — Integritas","subtopic":"Makna integritas","difficulty":"Mudah","type":"Definisi","question":"Apa inti integritas pemimpin?","shortAnswer":"Konsistensi antara nilai, ucapan, keputusan, dan tindakan, termasuk ketika ada tekanan atau tidak diawasi.","explanation":"Integritas menghubungkan prinsip moral dengan perilaku nyata. Pemimpin berintegritas tidak mengubah standar hanya karena kepentingan pribadi, tekanan atasan, atau risiko reputasi. Konsistensi tersebut menjadi dasar kepercayaan dan legitimasi.","example":"Pejabat menolak mengubah tanggal laporan meskipun perubahan itu dapat membuat unit terlihat patuh.","keywords":"konsistensi; nilai; tekanan; kejujuran","comparison":"Loyalitas — loyalitas kepada atasan tidak boleh mengalahkan hukum, etika, dan mandat publik.","mnemonic":"NUKT: Nilai–Ucapan–Keputusan–Tindakan."},{"number":4,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Definisi kepemimpinan sektor publik","difficulty":"Mudah","type":"Definisi","question":"Apa yang membedakan kepemimpinan sektor publik?","shortAnswer":"Tujuannya menghasilkan nilai publik melalui proses yang sah, adil, inklusif, akuntabel, dan berorientasi pelayanan.","explanation":"Pemimpin sektor publik tidak hanya mengejar efisiensi atau output. Ia harus mempertimbangkan legalitas, hak warga, pemerataan, legitimasi, serta dampak jangka panjang. Keputusan yang cepat tetapi tidak sah atau tidak adil belum menghasilkan nilai publik.","example":"Anggaran diarahkan ke layanan kelompok rentan meskipun manfaat finansial langsungnya kecil.","keywords":"nilai publik; legalitas; keadilan; akuntabilitas","comparison":"Kepemimpinan privat — lebih leluasa memprioritaskan profitabilitas dan daya saing.","mnemonic":"SAIL: Sah–Adil–Inklusif–Layanan."},{"number":5,"topic":"TM 5 — Kerja Sama","subtopic":"Definisi kerja sama","difficulty":"Mudah","type":"Definisi","question":"Apa makna kerja sama dalam kompetensi manajerial?","shortAnswer":"Kemampuan membangun hubungan kerja efektif, saling membantu, berbagi sumber daya, dan bertanggung jawab atas hasil bersama.","explanation":"Kerja sama bukan sekadar hadir dalam kelompok. Anggota harus memahami tujuan, dependensi, peran, dan cara mengintegrasikan kontribusi. Pemimpin menjaga komunikasi, kepercayaan, dan akuntabilitas agar hasil kolektif lebih besar daripada pekerjaan terpisah.","example":"Unit hukum, teknologi, dan layanan berbagi data serta menyepakati outcome bersama untuk memperbaiki layanan digital.","keywords":"hubungan; bantuan; sumber daya; hasil bersama","comparison":"Koordinasi — menyelaraskan pekerjaan, tetapi belum tentu menciptakan solusi bersama.","mnemonic":"4B: Bangun relasi–Berbagi–Bantu–Bertanggung jawab."},{"number":6,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Definisi komunikasi efektif","difficulty":"Sedang","type":"Definisi","question":"Kapan komunikasi dapat disebut efektif?","shortAnswer":"Ketika makna dipahami, tindakan yang tepat terjadi, dan umpan balik digunakan untuk memperbaiki pesan.","explanation":"Pengiriman pesan belum menjamin keberhasilan komunikasi. Pemimpin perlu memilih kanal, bahasa, waktu, dan bentuk pesan yang sesuai, lalu memastikan pemahaman melalui pertanyaan, teach-back, atau tindak lanjut. Efektivitas dinilai dari keselarasan makna dan tindakan.","example":"Setelah sosialisasi prosedur, pegawai diminta menjelaskan kembali langkah penting sebelum implementasi.","keywords":"makna; tindakan; feedback; kanal","comparison":"Informasi terkirim — hanya membuktikan pesan telah disampaikan, bukan dipahami.","mnemonic":"MTA: Makna–Tindakan–Umpan balik."},{"number":7,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Nilai publik","difficulty":"Mudah","type":"Istilah","question":"Apa yang dimaksud nilai publik?","shortAnswer":"Manfaat kolektif yang sah, adil, akuntabel, dan bermakna bagi masyarakat.","explanation":"Nilai publik menilai manfaat sekaligus proses pencapaiannya. Program yang populer atau menghasilkan banyak output belum tentu bernilai publik apabila melanggar hak, tidak merata, atau tidak menjawab kebutuhan. Legitimasi dan kepercayaan juga menjadi bagian hasil.","example":"Layanan keliling meningkatkan akses warga terpencil, bukan hanya menambah jumlah loket.","keywords":"manfaat; legalitas; keadilan; legitimasi","comparison":"Popularitas — dukungan sesaat tidak selalu menunjukkan manfaat publik yang sah.","mnemonic":"MaLaK: Manfaat–Legalitas–Keadilan."},{"number":8,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Sistem merit","difficulty":"Mudah","type":"Istilah","question":"Apa inti sistem merit dalam pengelolaan ASN?","shortAnswer":"Keputusan kepegawaian didasarkan secara objektif pada kualifikasi, kompetensi, dan kinerja.","explanation":"Sistem merit mengurangi dominasi kedekatan pribadi, politik, atau senioritas mutlak. Penempatan dan pengembangan ASN harus sesuai tuntutan jabatan, dilakukan dengan bukti, serta dapat dipertanggungjawabkan. Merit tidak berarti mengabaikan pengalaman, tetapi menilainya bersama kompetensi dan hasil kerja.","example":"Promosi kepala unit menggunakan asesmen kompetensi dan rekam kinerja, bukan hubungan personal.","keywords":"kualifikasi; kompetensi; kinerja; objektif","comparison":"Senioritas — masa kerja dapat dipertimbangkan, tetapi bukan satu-satunya dasar.","mnemonic":"3K Merit: Kualifikasi–Kompetensi–Kinerja."},{"number":9,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Kelompok kompetensi ASN","difficulty":"Mudah","type":"Istilah","question":"Apa tiga kelompok kompetensi jabatan ASN?","shortAnswer":"Kompetensi teknis, manajerial, dan sosial kultural.","explanation":"Kompetensi teknis memastikan penguasaan bidang, kompetensi manajerial mendukung pengelolaan unit dan orang, sedangkan sosial kultural menjaga pelayanan inklusif dalam masyarakat majemuk. Ketiganya harus sesuai dengan tuntutan jabatan.","example":"Pemimpin layanan digital perlu memahami teknologi, memimpin tim, dan peka terhadap hambatan akses kelompok berbeda.","keywords":"teknis; manajerial; sosial kultural","comparison":"Kualifikasi pendidikan — gelar adalah salah satu bukti, bukan keseluruhan kompetensi.","mnemonic":"TMS: Teknis–Manajerial–Sosial kultural."},{"number":10,"topic":"TM 5 — Kerja Sama","subtopic":"Psychological safety","difficulty":"Sedang","type":"Istilah","question":"Apa arti psychological safety dalam tim?","shortAnswer":"Keyakinan bersama bahwa anggota aman bertanya, mengakui kesalahan, dan berbeda pendapat secara profesional.","explanation":"Keamanan psikologis tidak berarti bebas dari target atau kritik. Anggota tetap bertanggung jawab, tetapi tidak dipermalukan ketika menyampaikan risiko atau kekeliruan dengan itikad baik. Kondisi ini mempercepat deteksi masalah dan pembelajaran.","example":"Pegawai junior berani menunjukkan kelemahan rancangan sebelum layanan diluncurkan.","keywords":"aman berbicara; kesalahan; dissent; pembelajaran","comparison":"Kenyamanan — tim dapat mengalami diskusi keras tetapi tetap aman secara interpersonal.","mnemonic":"3B: Bertanya–Berbeda–Belajar."},{"number":11,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Orientasi hasil","difficulty":"Sedang","type":"Istilah","question":"Apa makna orientasi pada hasil?","shortAnswer":"Fokus pada pencapaian standar dan perbaikan hasil yang nyata, bukan sekadar menyelesaikan aktivitas.","explanation":"Pemimpin berorientasi hasil menghubungkan sumber daya, aktivitas, output, outcome, dan dampak. Ia menggunakan baseline, indikator, monitoring, evaluasi, serta metode alternatif untuk meningkatkan kinerja tanpa mengorbankan etika, mutu, atau keberlanjutan.","example":"Keberhasilan pelatihan dinilai dari perubahan kemampuan peserta, bukan hanya jumlah kelas.","keywords":"standar; outcome; perbaikan; akuntabilitas","comparison":"Orientasi aktivitas — berfokus pada banyaknya kegiatan, bukan perubahan yang dihasilkan.","mnemonic":"HASIL: Hasil nyata–Akurasi ukuran–Standar–Inovasi–Lanjut."},{"number":12,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Diagnosis kepemimpinan","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan singkat menerapkan kepemimpinan secara kontekstual?","shortAnswer":"Tetapkan tujuan → pahami pengikut dan situasi → pilih kadar arahan/dukungan → komunikasikan → pantau dan sesuaikan.","explanation":"Urutan ini mencegah pemimpin memakai gaya secara otomatis. Tujuan dan batas mandat ditetapkan lebih dahulu, lalu pemimpin membaca kesiapan orang, risiko, dan waktu. Setelah tindakan dilakukan, feedback digunakan untuk menyesuaikan dukungan.","example":"Pegawai baru diberi prosedur rinci; analis senior diberi target dan ruang metode; keduanya dievaluasi melalui hasil.","keywords":"tujuan; pengikut; gaya; feedback","comparison":"Improvisasi tanpa diagnosis — fleksibilitas tetap membutuhkan tujuan dan alasan.","mnemonic":"Tu-Pe-Ga-Ko-Ev: Tujuan–Pengikut–Gaya–Komunikasi–Evaluasi."},{"number":13,"topic":"TM 5 — Kerja Sama","subtopic":"Tahap perkembangan tim","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan tahap perkembangan tim?","shortAnswer":"Forming → Storming → Norming → Performing → Adjourning.","explanation":"Forming adalah orientasi awal, storming menampilkan perbedaan dan perebutan pengaruh, norming membentuk aturan kerja, performing mencapai kinerja matang, dan adjourning menutup tugas serta memindahkan pembelajaran. Peran pemimpin berubah pada setiap tahap.","example":"Tim proyek mulai saling mengenal, berdebat tentang metode, menyepakati aturan, bekerja efektif, lalu melakukan evaluasi akhir.","keywords":"forming; storming; norming; performing; adjourning","comparison":"Urutan linier mutlak — tim dapat mundur tahap ketika anggota atau tugas berubah.","mnemonic":"FSNPA."},{"number":14,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Struktur pesan","difficulty":"Sedang","type":"Tahapan","question":"Apa struktur cepat untuk menyusun pesan kerja yang jelas?","shortAnswer":"Siapa → Apa → Mengapa → Kapan → Bagaimana → Bantuan.","explanation":"Struktur ini memastikan penerima mengetahui penanggung jawab, tindakan, alasan, waktu, cara pelaksanaan, dan dukungan yang tersedia. Untuk pesan sensitif, pemimpin juga perlu memilih kanal, memastikan pemahaman, dan menyediakan ruang umpan balik.","example":"“Tim verifikasi memperbarui data sebelum Jumat melalui aplikasi; panduan dan helpdesk tersedia.”","keywords":"siapa; apa; mengapa; kapan; bagaimana; bantuan","comparison":"Pesan panjang — kelengkapan bukan berarti memasukkan semua detail tanpa prioritas.","mnemonic":"SAMKBB: Siapa–Apa–Mengapa–Kapan–Bagaimana–Bantuan."},{"number":15,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Rantai hasil","difficulty":"Sulit","type":"Tahapan","question":"Apa urutan rantai hasil program publik?","shortAnswer":"Input → Aktivitas → Output → Outcome → Impact.","explanation":"Input adalah sumber daya, aktivitas adalah pekerjaan, output merupakan produk langsung, outcome adalah perubahan pada penerima manfaat, dan impact menunjukkan dampak jangka panjang. Pemimpin harus menguji asumsi hubungan antarlevel, karena output tinggi belum menjamin outcome.","example":"Anggaran → pelatihan → peserta lulus → kompetensi meningkat → kualitas layanan publik membaik.","keywords":"input; aktivitas; output; outcome; impact","comparison":"Output dan outcome — output adalah produk; outcome adalah perubahan.","mnemonic":"IAOOI: Input–Aktivitas–Output–Outcome–Impact."},{"number":16,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Kepemimpinan dan manajemen","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan kepemimpinan dan manajemen?","shortAnswer":"Kepemimpinan membangun arah dan komitmen; manajemen menata rencana, sumber daya, proses, dan pengendalian.","explanation":"Keduanya saling melengkapi. Kepemimpinan tanpa manajemen dapat menghasilkan visi tanpa pelaksanaan, sedangkan manajemen tanpa kepemimpinan dapat membuat organisasi tertib tetapi kehilangan makna dan adaptasi. Pemimpin sektor publik membutuhkan keduanya.","example":"Pemimpin menjelaskan visi layanan inklusif; manajemen menerjemahkannya menjadi jadwal, anggaran, SOP, dan indikator.","keywords":"arah; komitmen; proses; pengendalian","comparison":"Kewenangan — jabatan dapat memberi kewenangan, tetapi belum otomatis memberi kepemimpinan.","mnemonic":"Lead = arah; Manage = tata."},{"number":17,"topic":"TM 1 — Konsep Kepemimpinan","subtopic":"Kewenangan dan pengaruh","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan kewenangan formal dan pengaruh?","shortAnswer":"Kewenangan berasal dari jabatan; pengaruh tumbuh dari kredibilitas, keteladanan, kompetensi, dan relasi.","explanation":"Kewenangan memungkinkan keputusan resmi, sedangkan pengaruh membuat orang bersedia memberi komitmen lebih dari kepatuhan minimum. Pemimpin efektif menggunakan kewenangan sesuai batas dan memperkuatnya dengan kepercayaan serta keadilan.","example":"Staf menaati surat tugas karena kewenangan, tetapi mendukung perubahan karena percaya pada alasan dan integritas pemimpin.","keywords":"jabatan; kredibilitas; kepercayaan","comparison":"Pemimpin informal — dapat memiliki pengaruh tinggi tanpa jabatan formal.","mnemonic":"W = Wewenang dari posisi; P = Pengaruh dari pribadi dan relasi."},{"number":18,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Transaksional dan transformasional","difficulty":"Sulit","type":"Perbandingan","question":"Bagaimana membedakan kepemimpinan transaksional dan transformasional?","shortAnswer":"Transaksional menjaga pertukaran, target, dan standar; transformasional membangun visi, makna, komitmen, dan perubahan.","explanation":"Transaksional efektif untuk kejelasan tugas dan koreksi, sedangkan transformasional menggerakkan motivasi intrinsik melalui visi, stimulasi intelektual, dan perhatian individual. Organisasi publik sering memerlukan kombinasi keduanya agar inovasi tetap terukur dan akuntabel.","example":"Target layanan dan evaluasi kinerja bersifat transaksional; ajakan membangun pelayanan inklusif bersifat transformasional.","keywords":"imbalan; standar; visi; perubahan","comparison":"Transformasional bukan tanpa kontrol; perubahan tetap memerlukan tata kelola.","mnemonic":"Transaksi = tukar; Transformasi = ubah."},{"number":19,"topic":"TM 2 — Teori Kepemimpinan","subtopic":"Liberal dan laissez-faire","difficulty":"Sulit","type":"Perbandingan","question":"Apa perbedaan gaya liberal dan laissez-faire?","shortAnswer":"Liberal memberi otonomi terarah dengan tujuan dan kontrol; laissez-faire cenderung pasif dan minim arahan.","explanation":"Kebebasan pada gaya liberal tetap disertai batas kewenangan, milestone, dukungan, dan evaluasi. Laissez-faire berisiko membuat tanggung jawab kabur karena pemimpin terlalu lepas tangan. Delegasi yang baik bukan pengabaian.","example":"Analis senior bebas memilih metode tetapi wajib memenuhi standar dan tenggat; itu liberal, bukan laissez-faire.","keywords":"otonomi; batas; dukungan; pengawasan","comparison":"Delegasi — delegasi tetap menetapkan outcome dan akuntabilitas.","mnemonic":"Liberal = leluasa dengan lintasan; laissez-faire = lepas."},{"number":20,"topic":"TM 4 — Kepemimpinan Sektor Publik","subtopic":"Asas Ki Hajar Dewantara","difficulty":"Sedang","type":"Penerapan","question":"Bagaimana menerapkan tiga asas Ki Hajar Dewantara dalam kepemimpinan ASN?","shortAnswer":"Di depan memberi teladan, di tengah membangun semangat, dan dari belakang memberi dukungan.","explanation":"Pemimpin tidak selalu berada pada posisi yang sama. Ia tampil di depan saat nilai dan arah perlu dicontohkan, bekerja di tengah untuk menghubungkan serta memotivasi, lalu memberi ruang dari belakang ketika tim telah mampu bertindak mandiri.","example":"Pemimpin mematuhi disiplin, membantu tim saat perubahan, lalu mendelegasikan proyek kepada pegawai yang siap.","keywords":"teladan; semangat; dukungan","comparison":"Otoriter — memberi teladan tidak berarti mendominasi semua keputusan.","mnemonic":"Depan–Tengah–Belakang = Teladan–Semangat–Dukungan."},{"number":21,"topic":"TM 6 — Komunikasi Efektif","subtopic":"Active listening dan teach-back","difficulty":"Sedang","type":"Penerapan","question":"Bagaimana pemimpin memastikan pesan benar-benar dipahami?","shortAnswer":"Mendengarkan aktif, bertanya klarifikasi, lalu menggunakan teach-back atau meminta penerima menjelaskan kembali.","explanation":"Active listening membantu menangkap konteks dan kekhawatiran, sedangkan teach-back menguji kesamaan makna. Pemimpin sebaiknya memperbaiki pesan bila penerima belum tepat, bukan menyalahkan penerima. Cara ini penting untuk prosedur rumit atau informasi sensitif.","example":"Setelah pengarahan, pegawai menjelaskan ulang langkah eskalasi dan tenggat.","keywords":"mendengar; klarifikasi; teach-back; feedback","comparison":"Mengulang pesan — pengulangan belum tentu menguji pemahaman.","mnemonic":"Dengar–Tanya–Ulangkan."},{"number":22,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Pengukuran perbaikan","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana merancang pengukuran kinerja yang tidak berhenti pada output?","shortAnswer":"Tetapkan baseline, gunakan indikator proses dan outcome, tambahkan mutu serta pemerataan, lalu evaluasi dampak tidak diinginkan.","explanation":"Pengukuran seimbang menghubungkan kemajuan awal, sinyal proses, hasil bagi penerima manfaat, kualitas, dan keadilan. Pemimpin perlu mewaspadai Goodhart's law, gaming, serta cream-skimming ketika angka sempit dijadikan target utama.","example":"Selain jumlah izin, ukur waktu, akurasi, keluhan, akses kelompok rentan, dan perubahan kepatuhan.","keywords":"baseline; outcome; mutu; pemerataan; Goodhart","comparison":"Efisiensi — hemat sumber daya tidak selalu berarti tujuan publik tercapai.","mnemonic":"BOMPA: Baseline–Outcome–Mutu–Pemerataan–Akibat samping."},{"number":23,"topic":"TM 3 — Integritas","subtopic":"Mini kasus hadiah vendor","difficulty":"Sulit","type":"Mini Kasus","question":"Vendor peserta pengadaan menawarkan hadiah. Konsep dan tindakan apa yang tepat?","shortAnswer":"Konflik kepentingan; tolak atau ungkapkan tawaran melalui mekanisme resmi, dokumentasikan, dan jaga independensi.","explanation":"Risiko tidak hanya berasal dari pengaruh nyata, tetapi juga dari persepsi bahwa keputusan tidak netral. Pengungkapan dan pengendalian sejak awal menjaga kepercayaan serta melindungi proses pengadaan. Memindahkan hadiah kepada bawahan tidak menghapus konflik.","example":"Pejabat menolak hadiah, melapor kepada unit berwenang, dan memastikan keputusan dilakukan oleh proses yang objektif.","keywords":"hadiah; vendor; konflik kepentingan; pengungkapan","comparison":"Gratifikasi biasa — konteks kepentingan vendor membuat risikonya sangat tinggi.","mnemonic":"TUD: Tolak–Ungkap–Dokumentasikan."},{"number":24,"topic":"TM 5 — Kerja Sama","subtopic":"Mini kasus budaya diam","difficulty":"Sulit","type":"Mini Kasus","question":"Tim selalu setuju, tetapi kesalahan sering terlambat diketahui. Apa masalah utamanya?","shortAnswer":"Psychological safety rendah; pemimpin perlu membuka dissent berbasis data dan fokus pada pembelajaran sistem.","explanation":"Ketiadaan perbedaan pendapat dapat berarti anggota takut mengambil risiko interpersonal. Pemimpin perlu mengundang kritik, tidak mempermalukan orang yang mengakui kesalahan, serta menetapkan tindak lanjut yang jelas. Akuntabilitas tetap dijaga tanpa blame culture.","example":"Rapat selalu menyertakan sesi “risiko yang belum kita lihat” dan penanggung jawab aksi.","keywords":"budaya diam; dissent; psychological safety","comparison":"Kekompakan — tim kompak tetap dapat berdebat secara profesional.","mnemonic":"Diam bukan damai."},{"number":25,"topic":"TM 7 — Orientasi pada Hasil","subtopic":"Mini kasus cream-skimming","difficulty":"Sulit","type":"Mini Kasus","question":"Unit memilih kasus termudah agar target jumlah selesai tercapai. Apa analisisnya?","shortAnswer":"Cream-skimming dan distorsi indikator; ukuran perlu memasukkan kompleksitas, mutu, pemerataan, dan outcome.","explanation":"Ketika angka target terlalu sempit, pegawai dapat mengoptimalkan indikator sambil mengorbankan kebutuhan publik. Ini sejalan dengan Goodhart's law. Pemimpin harus memperbaiki desain ukuran dan meninjau siapa yang tertinggal.","example":"Kasus sederhana selesai cepat, tetapi permohonan warga rentan menumpuk karena memerlukan bantuan tambahan.","keywords":"cream-skimming; Goodhart; pemerataan; outcome","comparison":"Efisiensi — peningkatan angka tidak efisien bila kebutuhan penting ditinggalkan.","mnemonic":"Angka naik, jangan biarkan nilai publik turun."}]},"komneg":{"id":"komneg","title":"Komunikasi dan Negosiasi","short":"Komunikasi & Negosiasi","konsen":["gabungan"],"quiz":[{"number":1,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Definisi komunikasi","learningOutcome":"Menjelaskan konsep dasar komunikasi","difficulty":"Mudah","type":"Definisi","question":"Definisi komunikasi yang PALING TEPAT adalah ...","options":["Proses pengiriman, penerimaan, dan pembentukan makna melalui pesan dalam konteks tertentu","Kegiatan menyampaikan informasi secara satu arah tanpa membutuhkan respons","Pemindahan data tertulis dari satu media ke media lain secara administratif","Kemampuan berbicara lancar agar pendengar selalu menyetujui pembicara"],"correct":"A","concept":"Komunikasi sebagai proses transaksional","explanation":"Jawaban A benar karena komunikasi tidak sekadar memindahkan informasi, melainkan melibatkan pengiriman, penerimaan, dan pembentukan makna. Proses berlangsung dalam konteks tertentu, dapat dipengaruhi gangguan, menimbulkan efek, dan memungkinkan umpan balik. Dalam praktik pelayanan publik, pesan yang sudah dikirim belum tentu dipahami; komunikator perlu memeriksa respons penerima dan menyesuaikan cara penyampaian. Kesalahan umum adalah menganggap komunikasi berhasil hanya karena pembicara telah berbicara atau dokumen telah dikirim.","whyOthersWrong":"B terlalu satu arah; C hanya menggambarkan pemindahan data; D menyamakan kelancaran berbicara dengan persetujuan penerima.","tip":"Cari definisi yang memuat proses, makna, konteks, serta kemungkinan umpan balik.","reference":"TM 1 – Definisi dan prinsip komunikasi; DeVito.","keywords":"proses; makna; konteks"},{"number":2,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Komponen komunikasi","learningOutcome":"Mengidentifikasi fungsi feedforward","difficulty":"Mudah","type":"Definisi","question":"Komponen yang memberikan orientasi SEBELUM pesan utama disampaikan disebut ...","options":["Feedback","Feedforward","Channel","Noise"],"correct":"B","concept":"Feedforward","explanation":"Feedforward adalah informasi pendahuluan yang diberikan sebelum pesan utama. Fungsinya memberi orientasi, konteks, atau gambaran struktur agar penerima siap mengikuti isi. Contohnya, “Saya akan menjelaskan tiga tahap utama.” Feedback berbeda karena muncul selama atau setelah pesan untuk menilai respons dan pemahaman. Dalam presentasi maupun pelayanan, feedforward membantu mengurangi ketidakpastian, sedangkan feedback membantu mendeteksi apakah pesan sudah dipahami.","whyOthersWrong":"A merupakan respons setelah/selama pesan; C adalah media penyampaian; D adalah gangguan yang mendistorsi pesan.","tip":"Perhatikan kata SEBELUM. Orientasi awal = feedforward; respons penerima = feedback.","reference":"TM 1 – Delapan komponen komunikasi.","keywords":"feedforward; orientasi awal"},{"number":3,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Komunikasi nonverbal","learningOutcome":"Menjelaskan komunikasi nonverbal","difficulty":"Mudah","type":"Definisi","question":"Komunikasi nonverbal adalah ...","options":["Komunikasi yang hanya terjadi melalui dokumen resmi","Komunikasi yang tidak memiliki makna linguistik sama sekali","Penyampaian makna tanpa menggunakan kata-kata sebagai unsur utamanya","Penggunaan istilah teknis agar pesan terdengar profesional"],"correct":"C","concept":"Komunikasi nonverbal","explanation":"Komunikasi nonverbal menyampaikan makna tanpa menjadikan kata-kata sebagai unsur utama. Bentuknya meliputi ekspresi wajah, gestur, postur, kontak mata, jarak, sentuhan, penggunaan waktu, penampilan, dan parabahasa seperti volume atau kecepatan bicara. Nonverbal dapat mengulang, menggantikan, melengkapi, menentang, menekankan, atau mengatur pesan verbal. Karena itu, komunikasi tanpa kata tetap dapat membawa makna yang kuat.","whyOthersWrong":"A terlalu sempit dan justru memakai dokumen verbal; B keliru karena isyarat nonverbal bermakna; D membahas pilihan istilah verbal.","tip":"Bedakan “tanpa kata sebagai unsur utama” dari “tanpa makna”.","reference":"TM 2 – Komunikasi nonverbal dan lambang nonverbal.","keywords":"nonverbal; isyarat"},{"number":4,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Mendengarkan aktif","learningOutcome":"Mengidentifikasi ciri mendengarkan aktif","difficulty":"Mudah","type":"Definisi","question":"Ciri UTAMA mendengarkan aktif adalah ...","options":["Menyiapkan bantahan sejak pembicara mulai berbicara","Mencatat setiap kata tanpa memeriksa maknanya","Memberikan nasihat secepat mungkin","Memusatkan perhatian, memparafrasekan, dan mengklarifikasi pesan"],"correct":"D","concept":"Mendengarkan aktif","explanation":"Mendengarkan aktif menuntut perhatian mental dan fisik, usaha memahami isi serta perasaan, dan respons yang menguji makna. Parafrase membantu menyatakan kembali inti pesan dengan kata sendiri, sedangkan klarifikasi memeriksa bagian yang belum jelas. Teknik ini mencegah asumsi dan membuat pembicara merasa didengar. Mendengar pasif atau sekadar mencatat kata tidak cukup karena tidak menjamin pemahaman.","whyOthersWrong":"A memusatkan perhatian pada bantahan; B menyalin tanpa menguji makna; C memberi solusi sebelum memahami kebutuhan.","tip":"Pilih tindakan yang menunjukkan fokus, parafrase, klarifikasi, dan respons relevan.","reference":"TM 3 – Mendengarkan aktif.","keywords":"mendengarkan aktif; klarifikasi"},{"number":5,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Definisi komunikasi organisasi","learningOutcome":"Menjelaskan komunikasi organisasi","difficulty":"Mudah","type":"Definisi","question":"Komunikasi organisasi merupakan ...","options":["Proses penciptaan dan pertukaran pesan untuk menyelaraskan tindakan serta mencapai tujuan bersama","Percakapan informal yang tidak berhubungan dengan struktur atau tujuan kerja","Penyampaian instruksi dari pimpinan tanpa arus informasi lain","Kegiatan publikasi eksternal yang selalu menggunakan media massa"],"correct":"A","concept":"Komunikasi organisasi","explanation":"Komunikasi organisasi adalah proses penciptaan dan pertukaran pesan di antara individu, unit, dan lingkungan organisasi untuk menyelaraskan tindakan dan mencapai tujuan bersama. Proses ini mencakup komunikasi formal dan informal, arus ke bawah, ke atas, horizontal, serta diagonal. Komunikasi organisasi tidak hanya berupa instruksi pimpinan; laporan, koordinasi, umpan balik, budaya, dan jaringan informasi juga berperan.","whyOthersWrong":"B mengabaikan tujuan dan struktur; C membatasi komunikasi pada satu arah; D hanya menggambarkan sebagian komunikasi eksternal.","tip":"Cari definisi yang memuat pertukaran pesan, koordinasi, dan tujuan bersama.","reference":"TM 4 – Definisi komunikasi organisasi.","keywords":"organisasi; pertukaran pesan"},{"number":6,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Dimensi isi dan hubungan","learningOutcome":"Menganalisis dua dimensi pesan","difficulty":"Sedang","type":"Konseptual","question":"Mengapa kalimat yang sama dapat dipahami berbeda ketika diucapkan oleh atasan dan teman sebaya?","options":["Karena pesan tertulis selalu lebih jelas daripada pesan lisan","Karena komunikasi membawa dimensi isi sekaligus mencerminkan hubungan antarpihak","Karena penerima hanya memperhatikan pilihan kata dan mengabaikan konteks","Karena semua hubungan komplementer menghasilkan makna yang sama"],"correct":"B","concept":"Dimensi content dan relationship","explanation":"Setiap pesan memiliki dimensi isi dan hubungan. Isi menunjukkan informasi yang dinyatakan, sedangkan hubungan memberi petunjuk tentang bagaimana pesan perlu ditafsirkan berdasarkan peran, kedekatan, kekuasaan, dan suasana. Kalimat yang sama dapat terasa sebagai saran, perintah, atau candaan ketika disampaikan oleh pihak berbeda. Karena itu, analisis komunikasi tidak boleh hanya berhenti pada kata-kata; konteks hubungan turut menentukan makna.","whyOthersWrong":"A tidak menjelaskan perbedaan hubungan; C mengabaikan konteks; D menggeneralisasi hubungan komplementer.","tip":"Saat soal menyebut pihak yang berbeda tetapi kalimat sama, pikirkan dimensi hubungan.","reference":"TM 1 – Prinsip komunikasi: isi dan hubungan.","keywords":"content; relationship"},{"number":7,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Keselarasan verbal-nonverbal","learningOutcome":"Menganalisis diskordansi pesan","difficulty":"Sedang","type":"Konseptual","question":"Seseorang berkata “Saya senang membantu” tetapi menghindari kontak mata dan bernada kesal. Kondisi ini menunjukkan ...","options":["Redundansi yang memperkuat makna verbal","Substitusi karena isyarat menggantikan seluruh kata","Diskordansi karena pesan verbal dan nonverbal tidak selaras","Regulasi karena kontak mata mengatur giliran berbicara"],"correct":"C","concept":"Diskordansi verbal-nonverbal","explanation":"Diskordansi terjadi ketika pesan verbal dan nonverbal bertentangan. Ucapan “senang membantu” menunjukkan sikap positif, tetapi kontak mata yang dihindari dan nada kesal mengirimkan makna berbeda. Dalam kondisi demikian, penerima sering lebih mempercayai petunjuk nonverbal karena dianggap mencerminkan emosi sebenarnya. Komunikator perlu menyelaraskan kata, intonasi, ekspresi, dan perilaku agar pesan kredibel.","whyOthersWrong":"A memerlukan pengulangan makna yang selaras; B berarti isyarat menggantikan kata; D berkaitan dengan pengaturan giliran interaksi.","tip":"Cari pertentangan antara kata dan isyarat, bukan sekadar keberadaan unsur nonverbal.","reference":"TM 2 – Fungsi nonverbal dan diskordansi.","keywords":"diskordansi; keselarasan"},{"number":8,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Persepsi","learningOutcome":"Menjelaskan efek primasi","difficulty":"Sedang","type":"Konseptual","question":"Kesan pertama memengaruhi penilaian berikutnya secara berlebihan. Fenomena ini disebut ...","options":["Efek kontras","Efek halo","Proyeksi","Efek primasi"],"correct":"D","concept":"Efek primasi","explanation":"Efek primasi adalah kecenderungan memberi bobot besar pada informasi atau kesan yang diterima lebih awal. Kesan pertama kemudian memengaruhi penafsiran terhadap perilaku berikutnya, bahkan ketika tersedia informasi baru. Dalam komunikasi interpersonal, efek ini dapat menimbulkan penilaian yang tidak objektif. Pencegahannya adalah menunda kesimpulan, mencari bukti tambahan, dan memisahkan observasi dari interpretasi.","whyOthersWrong":"A membandingkan objek dengan rangsangan sebelumnya; B menyebarkan satu ciri ke seluruh penilaian; C memindahkan karakter diri kepada orang lain.","tip":"Kata “pertama” atau “informasi awal” biasanya mengarah pada efek primasi.","reference":"TM 3 – Persepsi dan kesalahan persepsi.","keywords":"primasi; persepsi"},{"number":9,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Kepemimpinan dan partisipasi","learningOutcome":"Menganalisis hubungan kendali dan partisipasi","difficulty":"Sedang","type":"Konseptual","question":"Dalam rapat, semakin tinggi kendali komunikator dan semakin sempit ruang tanggapan, partisipasi anggota cenderung ...","options":["Menurun karena anggota memiliki sedikit kesempatan memberi masukan","Meningkat karena instruksi yang kaku selalu memotivasi","Tetap karena partisipasi tidak dipengaruhi gaya komunikasi","Tidak dapat dinilai tanpa mengetahui jumlah peserta"],"correct":"A","concept":"Kendali komunikator dan partisipasi","explanation":"Kendali komunikator dan partisipasi audiens cenderung berbanding terbalik. Ketika pemimpin mendominasi percakapan, menentukan semua keputusan, dan membatasi tanggapan, anggota hanya memiliki sedikit ruang untuk bertanya atau memberi masukan. Gaya ini dapat berguna dalam situasi darurat, tetapi kurang tepat untuk pekerjaan yang membutuhkan komitmen dan kreativitas. Gaya demokratis memberi struktur sekaligus kesempatan berpartisipasi.","whyOthersWrong":"B menganggap kekakuan selalu memotivasi; C mengabaikan pengaruh gaya komunikasi; D tidak diperlukan untuk menarik hubungan konseptual.","tip":"Perhatikan arah hubungan: kendali naik, ruang partisipasi turun.","reference":"TM 4 – Gaya kepemimpinan dan partisipasi.","keywords":"kendali; partisipasi"},{"number":10,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Pendekatan penyampaian pesan","learningOutcome":"Menjelaskan pemilihan pendekatan pesan","difficulty":"Sedang","type":"Konseptual","question":"Pendekatan tidak langsung lebih tepat digunakan ketika ...","options":["Audiens sudah mendukung dan membutuhkan keputusan segera","Pesan berpotensi menimbulkan reaksi negatif sehingga alasan perlu diberikan sebelum inti","Isi pesan rutin, singkat, dan tidak sensitif","Penerima hanya membutuhkan satu fakta yang bersifat netral"],"correct":"B","concept":"Pendekatan langsung dan tidak langsung","explanation":"Pendekatan tidak langsung menempatkan fakta, alasan, atau buffer sebelum inti pesan. Struktur ini tepat ketika audiens diperkirakan menolak, kecewa, atau membutuhkan konteks agar keputusan dapat diterima secara adil. Pendekatan langsung lebih efisien untuk pesan rutin, positif, netral, atau ketika audiens sudah mendukung. Pemilihan pendekatan harus mempertimbangkan tujuan, respons audiens, urgensi, dan hubungan.","whyOthersWrong":"A, C, dan D menggambarkan situasi yang lebih cocok memakai pendekatan langsung.","tip":"Respons negatif yang diperkirakan = alasan dahulu, inti sesudah.","reference":"TM 5 – Pendekatan deduktif dan induktif.","keywords":"langsung; tidak langsung"},{"number":11,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Ambiguitas bahasa","learningOutcome":"Menerapkan prinsip kejelasan","difficulty":"Mudah","type":"Penerapan","question":"Perbaikan PALING TEPAT untuk pesan “Dokumen dikirim besok” adalah ...","options":["Dokumen akan segera dikirim jika tidak ada kendala","Dokumen mungkin dikirim dalam waktu dekat melalui media yang tersedia","Dokumen dikirim Senin, 21 Juli, pukul 10.00 WIB melalui email","Dokumen dikirim seperti biasanya kepada pihak terkait"],"correct":"C","concept":"Bahasa spesifik dan tidak ambigu","explanation":"Pilihan C menghilangkan ambiguitas karena menyebut hari, tanggal, waktu, dan media. Kata “besok” bergantung pada waktu pembacaan dan dapat menimbulkan penafsiran berbeda, terutama pada pesan digital yang dibaca terlambat. Komunikasi efektif menggunakan pelaku, tindakan, tenggat, saluran, dan hasil yang spesifik. Kejelasan ini mengurangi risiko keterlambatan dan kesalahan tindak lanjut.","whyOthersWrong":"A, B, dan D masih memakai waktu atau kondisi yang kabur dan tidak memberi kepastian media serta tenggat.","tip":"Pilih kalimat dengan unsur siapa/apa, kapan, dan melalui media apa.","reference":"TM 2 – Hambatan semantik dan ambiguitas.","keywords":"ambiguitas; spesifik"},{"number":12,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Empati dan pengungkapan diri","learningOutcome":"Menerapkan respons empatik","difficulty":"Sedang","type":"Penerapan","question":"Saat rekan kerja mengungkapkan pengalaman yang menyedihkan, respons awal yang PALING TEPAT adalah ...","options":["Membandingkan masalahnya dengan pengalaman pribadi yang lebih berat","Langsung menjelaskan kesalahan yang menyebabkan masalah tersebut","Mengalihkan topik agar suasana tidak menjadi emosional","Mendengarkan, merefleksikan perasaannya, lalu menanyakan dukungan yang dibutuhkan"],"correct":"D","concept":"Respons empatik","explanation":"Respons D menunjukkan empati karena pendengar hadir, mengenali perasaan, dan memberi ruang kepada pembicara untuk menentukan dukungan yang dibutuhkan. Refleksi perasaan bukan berarti menyetujui semua tindakan, melainkan memeriksa apakah emosi telah dipahami dengan tepat. Nasihat atau perbandingan yang terlalu cepat dapat membuat pembicara merasa dihakimi. Setelah emosi tervalidasi, barulah solusi dapat dibahas bila diminta.","whyOthersWrong":"A mengalihkan fokus ke diri sendiri; B menilai sebelum memahami; C menghindari kebutuhan emosional pembicara.","tip":"Urutan aman: dengarkan, refleksikan, klarifikasi kebutuhan, kemudian bantu.","reference":"TM 3 – Empati, mendengarkan, dan pengungkapan diri.","keywords":"empati; refleksi perasaan"},{"number":13,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Komunikasi ke atas","learningOutcome":"Menerapkan arus komunikasi organisasi","difficulty":"Sedang","type":"Penerapan","question":"Informasi yang PALING SESUAI disampaikan melalui komunikasi ke atas adalah ...","options":["Laporan kemajuan, kendala pelaksanaan, dan usulan perbaikan dari staf","Instruksi pembagian tugas dari pimpinan kepada bawahan","Koordinasi jadwal antara dua unit yang setara","Sosialisasi kebijakan organisasi kepada masyarakat"],"correct":"A","concept":"Komunikasi ke atas","explanation":"Komunikasi ke atas bergerak dari tingkat yang lebih rendah kepada pimpinan. Isinya lazim berupa laporan kemajuan, kendala, umpan balik, kebutuhan sumber daya, dan usulan. Arus ini penting agar pimpinan mengetahui kondisi nyata dan dapat mengambil keputusan. Agar efektif, informasi harus ringkas, terverifikasi, relevan, dan disertai dampak serta alternatif tindakan.","whyOthersWrong":"B merupakan komunikasi ke bawah; C merupakan komunikasi horizontal; D merupakan komunikasi eksternal/publik.","tip":"Identifikasi arah berdasarkan pengirim dan penerima, bukan hanya isi pesannya.","reference":"TM 4 – Arah komunikasi organisasi.","keywords":"komunikasi ke atas; laporan"},{"number":14,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Etika telepon resmi","learningOutcome":"Menerapkan pembukaan telepon resmi","difficulty":"Mudah","type":"Penerapan","question":"Urutan awal yang PALING TEPAT ketika petugas menerima telepon resmi adalah ...","options":["Menanyakan keperluan, meminta identitas, lalu menyebut instansi","Menyebut instansi, memberi salam, memperkenalkan diri, lalu menawarkan bantuan","Menjelaskan batas waktu telepon, menyebut nama, lalu meminta penelepon menunggu","Memperkenalkan riwayat pekerjaan, memberi salam, lalu mencatat nomor telepon"],"correct":"B","concept":"Pembukaan telepon resmi","explanation":"Pembukaan telepon resmi perlu memberi kepastian identitas, kesopanan, dan kesiapan membantu. Urutan yang wajar adalah menyebut instansi, memberi salam, memperkenalkan diri, kemudian menawarkan bantuan. Struktur ini membangun kepercayaan dan memudahkan penelepon menindaklanjuti percakapan. Setelah itu petugas mendengarkan, mencatat, mengklarifikasi, dan menutup dengan rangkuman.","whyOthersWrong":"A meminta informasi sebelum identitas petugas jelas; C berfokus pada batas waktu; D memuat informasi pribadi yang tidak relevan.","tip":"Ingat ISI-TUTUP: identitas, salam, inti; tindak lanjut, ulangi, tutup.","reference":"TM 5 – Komunikasi melalui telepon.","keywords":"telepon; salam; identitas"},{"number":15,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Evaluasi edukasi","learningOutcome":"Menerapkan fungsi pre-test","difficulty":"Sedang","type":"Penerapan","question":"Dalam kegiatan edukasi, pre-test terutama digunakan untuk ...","options":["Menentukan peringkat akhir peserta","Menggantikan seluruh evaluasi setelah kegiatan","Memetakan pengetahuan awal agar materi dan metode dapat disesuaikan","Membuktikan keberhasilan kegiatan sebelum pelaksanaan"],"correct":"C","concept":"Pre-test","explanation":"Pre-test dilakukan sebelum edukasi untuk memetakan pengetahuan, kesalahpahaman, atau kebutuhan awal peserta. Hasilnya membantu fasilitator menentukan tingkat kedalaman materi, contoh, metode, dan alokasi waktu. Pre-test tidak sama dengan post-test; post-test digunakan untuk melihat perubahan setelah kegiatan. Evaluasi yang baik dapat menilai aspek kognitif, sikap, dan kemampuan menerapkan prosedur.","whyOthersWrong":"A bukan tujuan utama; B keliru karena evaluasi akhir tetap diperlukan; D tidak mungkin membuktikan keberhasilan sebelum kegiatan.","tip":"Kata “awal” dan “sebelum” mengarah pada pemetaan kebutuhan, bukan hasil akhir.","reference":"TM 6 – Evaluasi kegiatan edukasi.","keywords":"pre-test; kebutuhan belajar"},{"number":16,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Manajemen konflik","learningOutcome":"Mengevaluasi pesan-saya","difficulty":"Sulit","type":"Mini Kasus","question":"Seorang staf sering terlambat mengirim data sehingga proses tim tertunda. Pernyataan yang PALING KONSTRUKTIF adalah ...","options":["Kamu memang tidak pernah dapat diandalkan dalam pekerjaan","Semua keterlambatan tim terjadi karena sikapmu","Mulai sekarang jangan memberi alasan apa pun","Saya kesulitan menyelesaikan rekonsiliasi ketika data diterima setelah tenggat; mari sepakati waktu pengiriman"],"correct":"D","concept":"Pesan-saya dalam konflik","explanation":"Pilihan D memakai pesan-saya yang deskriptif: menyebut situasi, dampak pada pekerjaan, dan ajakan menyusun solusi. Pesan ini berfokus pada perilaku yang dapat diubah, bukan menyerang karakter. Pendekatan konstruktif menjaga martabat pihak lain, mengurangi defensivitas, dan membuka negosiasi mengenai tenggat. Konflik menjadi produktif ketika fokus pada masalah, data, kebutuhan, serta tindakan berikutnya.","whyOthersWrong":"A dan B menyerang pribadi serta memakai generalisasi; C menutup dialog dan tidak menyelesaikan akar masalah.","tip":"Pilih kalimat yang memuat “ketika..., saya mengalami..., mari...”.","reference":"TM 3 – Manajemen konflik dan pesan-saya.","keywords":"pesan-saya; konflik"},{"number":17,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Komunikasi krisis","learningOutcome":"Mengevaluasi respons organisasi","difficulty":"Sulit","type":"Mini Kasus","question":"Rumor perubahan layanan menyebar cepat dan membuat masyarakat cemas, sedangkan data final masih diverifikasi. Tindakan awal yang PALING TEPAT adalah ...","options":["Memberi pembaruan resmi yang cepat, empatik, menyebut informasi terverifikasi, dan menjanjikan waktu pembaruan berikutnya","Membiarkan rumor sampai seluruh detail selesai agar tidak perlu mengoreksi pesan","Menyampaikan semua dugaan internal supaya publik merasa memperoleh informasi lengkap","Menyerahkan jawaban kepada setiap pegawai tanpa pesan inti yang seragam"],"correct":"A","concept":"Komunikasi krisis","explanation":"Dalam krisis, organisasi perlu merespons cepat tanpa mengorbankan akurasi. Pilihan A mengakui kecemasan, membedakan fakta terverifikasi dari informasi yang belum pasti, memakai satu pesan resmi, dan menetapkan waktu pembaruan. Langkah ini mengurangi ruang rumor sekaligus menjaga kredibilitas. Diam terlalu lama dapat memperbesar ketidakpastian, sedangkan spekulasi dan pesan tidak seragam menciptakan risiko koreksi serta hilangnya kepercayaan.","whyOthersWrong":"B memberi ruang rumor; C menyebarkan dugaan; D menghasilkan inkonsistensi antarpetugas.","tip":"Jawaban krisis terbaik biasanya cepat, empatik, terverifikasi, konsisten, dan memiliki jadwal update.","reference":"TM 4 – Pengelolaan informasi dan komunikasi krisis.","keywords":"krisis; verifikasi; konsistensi"},{"number":18,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Pesan negatif","learningOutcome":"Menentukan pendekatan pesan","difficulty":"Sedang","type":"Mini Kasus","question":"Unit kerja harus menolak permohonan kerja sama yang diajukan mitra lama. Mitra diperkirakan kecewa, tetapi hubungan perlu dijaga. Struktur pesan yang PALING TEPAT adalah ...","options":["Menyampaikan penolakan pada kalimat pertama tanpa alasan atau alternatif","Membuka secara netral, menjelaskan alasan objektif, menyampaikan penolakan dengan sopan, lalu menawarkan alternatif","Menghindari keputusan jelas dan hanya menyampaikan pujian kepada mitra","Menunda respons sampai mitra berhenti menanyakan hasil permohonan"],"correct":"B","concept":"Pesan negatif tidak langsung","explanation":"Pesan negatif kepada mitra lama perlu tetap jelas tetapi menjaga hubungan. Pembukaan netral atau buffer menyiapkan konteks, alasan objektif menunjukkan keputusan tidak sewenang-wenang, penolakan disampaikan secara sopan, dan alternatif memberi arah tindak lanjut. Buffer tidak boleh menyesatkan atau menyamarkan keputusan. Kejelasan akhir tetap diperlukan agar penerima tidak menunggu tanpa kepastian.","whyOthersWrong":"A terlalu keras dan tidak memberi konteks; C tidak menyampaikan keputusan; D tidak profesional dan merusak hubungan.","tip":"Untuk pesan negatif: buffer wajar, alasan objektif, keputusan jelas, alternatif atau goodwill.","reference":"TM 5 – Pesan bisnis negatif.","keywords":"pesan negatif; buffer; alternatif"},{"number":19,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Fasilitasi edukasi","learningOutcome":"Menentukan tindak lanjut yang akuntabel","difficulty":"Sedang","type":"Mini Kasus","question":"Dalam sesi edukasi, peserta menanyakan ketentuan teknis yang belum dikuasai fasilitator. Respons yang PALING TEPAT adalah ...","options":["Memberikan perkiraan agar sesi tidak terhenti","Mengalihkan pertanyaan dan tidak mencatatnya","Mengakui perlu verifikasi, mencatat pertanyaan, menyebut sumber resmi, dan memberi jadwal tindak lanjut","Meminta peserta mencari sendiri tanpa arahan sumber"],"correct":"C","concept":"Akuntabilitas fasilitator","explanation":"Fasilitator tidak boleh menebak jawaban karena informasi keliru dapat menimbulkan tindakan yang salah. Respons profesional adalah mengakui batas pengetahuan, mencatat pertanyaan, memeriksa sumber resmi, dan memberi waktu tindak lanjut yang dapat dilacak. Sikap ini tidak mengurangi kredibilitas; justru menunjukkan integritas dan akuntabilitas. Jawaban lanjutan perlu didokumentasikan agar konsisten bagi seluruh peserta.","whyOthersWrong":"A berisiko menyebarkan informasi salah; B menghilangkan kebutuhan peserta; D tidak memberi dukungan atau sumber yang jelas.","tip":"Ketika belum tahu: jangan menebak—catat, verifikasi, dan tindak lanjuti.","reference":"TM 6 – Pelaksanaan edukasi dan tindak lanjut.","keywords":"verifikasi; tindak lanjut"},{"number":20,"topic":"TM 7 Presentasi dan Slide Efektif","subtopic":"Desain slide","learningOutcome":"Mengevaluasi kualitas slide","difficulty":"Sulit","type":"Mini Kasus","question":"Satu slide berisi 14 baris teks, lima warna, tiga animasi, dan judul “Data”. Perbaikan yang PALING TEPAT adalah ...","options":["Memperkecil font agar semua teks tetap muat","Menambah ikon dekoratif agar slide tampak lebih ramai","Mempertahankan teks lalu mempercepat waktu penyampaian","Menetapkan satu pesan utama, meringkas isi, memakai hierarki visual, dan membuat judul yang menyatakan temuan"],"correct":"D","concept":"Signal-to-noise ratio dan hierarki visual","explanation":"Pilihan D memperbaiki akar masalah: terlalu banyak informasi dan dekorasi mengaburkan pesan utama. Slide efektif mendukung satu ide, memakai kata kunci atau visual relevan, hierarki yang jelas, kontras memadai, dan judul yang menyatakan kesimpulan. Judul “Data” tidak membantu audiens; judul informatif seharusnya menyebut temuan. Mengurangi noise lebih efektif daripada memperkecil font atau menambah ornamen.","whyOthersWrong":"A menurunkan keterbacaan; B menambah noise; C mempertahankan beban kognitif dan mengorbankan pemahaman.","tip":"Audit slide: satu ide, judul bermakna, visual relevan, whitespace, font terbaca.","reference":"TM 7 – Desain slide dan signal-to-noise ratio.","keywords":"slide; hierarki; signal-to-noise"},{"number":21,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Feedback dan feedforward","learningOutcome":"Membedakan dua komponen komunikasi","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan utama feedback dan feedforward adalah ...","options":["Feedback menilai respons setelah/selama pesan, sedangkan feedforward memberi orientasi sebelum pesan utama","Feedback selalu berbentuk tulisan, sedangkan feedforward selalu berbentuk lisan","Feedback digunakan dalam komunikasi formal, sedangkan feedforward hanya informal","Feedback memilih saluran, sedangkan feedforward menghilangkan gangguan"],"correct":"A","concept":"Feedback versus feedforward","explanation":"Feedback dan feedforward dibedakan terutama berdasarkan waktu dan fungsi. Feedback muncul selama atau setelah pesan diterima untuk mengetahui reaksi, koreksi, dan tingkat pemahaman. Feedforward diberikan sebelum pesan utama untuk menyiapkan penerima, menjelaskan konteks, atau menunjukkan struktur. Keduanya dapat berbentuk lisan maupun tulisan dan dapat digunakan dalam situasi formal maupun informal.","whyOthersWrong":"B dan C membuat pembatasan bentuk/konteks yang tidak benar; D mencampur fungsi saluran dan pengendalian noise.","tip":"Ingat: feed-FORWARD = menghadap ke depan; feed-BACK = melihat kembali respons.","reference":"TM 1 – Feedback dan feedforward.","keywords":"feedback; feedforward"},{"number":22,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Empati dan simpati","learningOutcome":"Membedakan empati dan simpati","difficulty":"Sulit","type":"Perbandingan","question":"Pernyataan yang PALING TEPAT membedakan empati dan simpati adalah ...","options":["Empati berarti menyetujui semua keputusan, sedangkan simpati berarti menolaknya","Empati berusaha memahami pengalaman dari sudut pandang orang lain; simpati menunjukkan rasa prihatin dari sudut pandang sendiri","Empati hanya digunakan dalam hubungan pribadi; simpati hanya digunakan di tempat kerja","Empati berfokus pada solusi teknis; simpati berfokus pada data faktual"],"correct":"B","concept":"Empati versus simpati","explanation":"Empati adalah usaha memahami pengalaman dan perasaan dari sudut pandang orang lain, kemudian memeriksa pemahaman tersebut. Simpati adalah rasa prihatin atau kepedulian yang tetap berangkat dari sudut pandang diri sendiri. Keduanya dapat bersifat positif, tetapi empati biasanya lebih membantu dalam mendengarkan karena tidak buru-buru menilai. Empati juga tidak berarti menyetujui semua tindakan atau mengabaikan batas profesional.","whyOthersWrong":"A menyamakan empati dengan persetujuan; C membatasi konteks secara salah; D menukar fokus kedua konsep.","tip":"Empati = masuk ke perspektif; simpati = melihat dan merasa prihatin dari luar.","reference":"TM 3 – Efektivitas komunikasi interpersonal.","keywords":"empati; simpati"},{"number":23,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Fakta, interpretasi, dan rekomendasi","learningOutcome":"Membedakan unsur laporan","difficulty":"Sulit","type":"Perbandingan","question":"Manakah pasangan yang menunjukkan perbedaan fakta dan interpretasi secara benar dalam laporan kegiatan?","options":["Fakta: kegiatan berhasil; Interpretasi: hadir 80 peserta","Fakta: peserta sangat antusias; Interpretasi: 70% menjawab benar","Fakta: 80 dari 100 peserta hadir; Interpretasi: tingkat kehadiran menunjukkan jangkauan kegiatan cukup baik","Fakta: metode paling efektif; Interpretasi: sesi berlangsung dua jam"],"correct":"C","concept":"Fakta versus interpretasi","explanation":"Fakta adalah data yang dapat diverifikasi, misalnya jumlah kehadiran 80 dari 100 peserta. Interpretasi adalah makna yang ditarik dari fakta, misalnya tingkat kehadiran tersebut menunjukkan jangkauan kegiatan cukup baik. Laporan yang akuntabel harus memisahkan keduanya dan menjelaskan dasar interpretasi. Klaim “berhasil”, “antusias”, atau “paling efektif” tidak boleh ditulis sebagai fakta tanpa indikator.","whyOthersWrong":"A dan B membalik fakta serta interpretasi; D menempatkan klaim evaluatif sebagai fakta dan durasi sebagai interpretasi.","tip":"Angka/kejadian terukur biasanya fakta; penilaian terhadap arti data adalah interpretasi.","reference":"TM 6 – Pelaporan, evaluasi, dan rekomendasi.","keywords":"fakta; interpretasi; laporan"},{"number":24,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Jaringan komunikasi","learningOutcome":"Menganalisis pemilihan jaringan","difficulty":"Sulit","type":"Analisis","question":"Tim lintas fungsi harus menghasilkan gagasan baru melalui pertukaran informasi yang intensif. Jaringan yang PALING SESUAI adalah ...","options":["Roda, karena seluruh informasi harus melewati satu pusat","Rantai, karena pesan bergerak linier sesuai hierarki","Jaringan Y, karena keputusan perlu terpusat pada dua jalur","Semua saluran, karena anggota dapat berkomunikasi langsung dan berpartisipasi luas"],"correct":"D","concept":"Jaringan semua saluran","explanation":"Jaringan semua saluran memungkinkan setiap anggota berkomunikasi langsung dengan anggota lain. Pola ini memiliki partisipasi dan kepuasan tinggi serta cocok untuk pemecahan masalah kompleks dan inovasi lintas fungsi. Kekurangannya adalah koordinasi dapat lebih lambat dan volume komunikasi tinggi, sehingga peran, dokumentasi, dan keputusan perlu diatur. Roda atau rantai lebih cepat untuk tugas sederhana dan terpusat, tetapi membatasi pertukaran gagasan.","whyOthersWrong":"A, B, dan C memiliki sentralisasi lebih tinggi dan kesempatan interaksi langsung yang lebih rendah.","tip":"Tugas kreatif dan kompleks membutuhkan jaringan partisipatif; instruksi rutin dapat lebih terpusat.","reference":"TM 4 – Lima jaringan komunikasi.","keywords":"jaringan; semua saluran; inovasi"},{"number":25,"topic":"TM 7 Presentasi dan Slide Efektif","subtopic":"Strategi presentasi terpadu","learningOutcome":"Menganalisis presentasi efektif","difficulty":"Sulit","type":"Analisis","question":"Presenter memiliki waktu 10 menit untuk menjelaskan kebijakan baru kepada audiens nonteknis. Strategi yang PALING TEPAT adalah ...","options":["Menentukan satu tesis, memilih struktur sederhana, memakai contoh relevan, berlatih dengan timer, dan menyiapkan slide visual","Memasukkan seluruh detail regulasi ke slide agar tidak ada informasi yang terlewat","Menghafal naskah kata demi kata dan menghindari pertanyaan agar waktu terkendali","Memusatkan perhatian pada animasi karena visual lebih penting daripada tujuan dan audiens"],"correct":"A","concept":"Strategi presentasi efektif","explanation":"Strategi A mengintegrasikan lima unsur penting: analisis audiens, tesis yang jelas, struktur yang mudah diikuti, contoh yang relevan, latihan waktu, dan slide pendukung. Audiens nonteknis membutuhkan penyederhanaan tanpa kehilangan inti kebijakan. Presenter harus memahami materi, bukan menghafal kata per kata, serta menyiapkan kemungkinan pertanyaan. Slide tidak menggantikan penjelasan; fungsinya memperjelas dan membantu ingatan.","whyOthersWrong":"B membebani slide dengan detail; C mengurangi keluwesan dan interaksi; D menempatkan dekorasi di atas tujuan.","tip":"Jawaban terbaik biasanya menyelaraskan audiens, tujuan, struktur, delivery, latihan, dan visual.","reference":"TM 7 – Persiapan, pengorganisasian, penyampaian, dan slide.","keywords":"tesis; audiens; latihan; visual"}],"flashcards":[{"number":1,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Konsep dasar","difficulty":"Mudah","type":"Definisi","question":"Apa inti definisi komunikasi?","shortAnswer":"Proses mengirim, menerima, dan membentuk makna melalui pesan dalam konteks tertentu.","explanation":"Komunikasi melibatkan sumber-penerima, pesan, saluran, konteks, gangguan, kompetensi, serta respons. Keberhasilan bukan diukur dari pesan yang terkirim, tetapi dari makna yang dipahami dan efek yang dihasilkan.","example":"Petugas menjelaskan prosedur, meminta penerima merangkum, lalu memperbaiki bagian yang salah.","keywords":"proses; pesan; makna; konteks","comparison":"Informasi: isi yang dipertukarkan; komunikasi: proses pembentukan makna.","mnemonic":"PESAN = Proses, Efek, Situasi, Arti, Noise."},{"number":2,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Komunikasi nonverbal","difficulty":"Mudah","type":"Definisi","question":"Apa itu komunikasi nonverbal?","shortAnswer":"Penyampaian makna tanpa menggunakan kata-kata sebagai unsur utama.","explanation":"Nonverbal mencakup ekspresi, gestur, kontak mata, postur, jarak, sentuhan, waktu, penampilan, dan parabahasa. Isyarat dapat melengkapi, mengganti, menekankan, atau bahkan menentang pesan verbal.","example":"Ucapan “silakan” diperkuat dengan gerakan tangan yang menunjukkan arah.","keywords":"isyarat; gestur; parabahasa","comparison":"Verbal memakai kata; nonverbal memakai isyarat dan cara penyampaian.","mnemonic":"NON = Nada, Otot/gerak, Netra."},{"number":3,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Hubungan antarpribadi","difficulty":"Mudah","type":"Definisi","question":"Apa itu komunikasi interpersonal?","shortAnswer":"Komunikasi antara dua orang atau lebih untuk membangun, memelihara, atau mengubah hubungan.","explanation":"Komunikasi interpersonal dapat dilihat dari komponen pesan, hubungan diadik, dan perkembangan dari impersonal menjadi lebih pribadi. Kualitasnya dipengaruhi empati, keterbukaan, dukungan, sikap positif, dan kesetaraan.","example":"Dua rekan kerja membahas kendala, saling mengklarifikasi, dan menyepakati solusi.","keywords":"diadik; hubungan; perkembangan","comparison":"Komunikasi intrapersonal terjadi dalam diri; interpersonal terjadi antarpihak.","mnemonic":"INTER = interaksi antarorang."},{"number":4,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Organisasi","difficulty":"Mudah","type":"Definisi","question":"Apa itu komunikasi organisasi?","shortAnswer":"Penciptaan dan pertukaran pesan untuk menyelaraskan tindakan dan mencapai tujuan organisasi.","explanation":"Komunikasi organisasi berlangsung melalui saluran formal dan informal, bergerak ke bawah, ke atas, horizontal, dan diagonal, serta dipengaruhi struktur, budaya, gaya kepemimpinan, dan jaringan.","example":"Staf mengirim laporan ke pimpinan, lalu dua unit berkoordinasi melaksanakan keputusan.","keywords":"tujuan; struktur; arus; jaringan","comparison":"Komunikasi bisnis berfokus pada pesan kerja; komunikasi organisasi mencakup sistem hubungan dan aliran informasi.","mnemonic":"ORGANISASI = Orang bergerak karena arus informasi."},{"number":5,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Pesan bisnis","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud pesan bisnis?","shortAnswer":"Pesan kerja yang dirancang untuk mencapai tujuan organisasi melalui isi dan media yang sesuai audiens.","explanation":"Pesan bisnis dimulai dari tujuan, analisis audiens, pengumpulan informasi, penyusunan kerangka, penulisan, revisi, dan pemilihan media. Kejelasan dan tindak lanjut lebih penting daripada bahasa yang terdengar rumit.","example":"Email meminta konfirmasi data dengan tenggat, format, dan kontak yang jelas.","keywords":"tujuan; audiens; media; revisi","comparison":"Pesan bisnis tidak selalu surat dinas; surat dinas adalah salah satu bentuk resmi.","mnemonic":"TARIK = Tujuan, Audiens, Rangka, Isi, Koreksi."},{"number":6,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Edukasi keuangan negara","difficulty":"Mudah","type":"Definisi","question":"Apa tujuan edukasi keuangan negara?","shortAnswer":"Mengubah atau meningkatkan pengetahuan, sikap, dan kemampuan menerapkan informasi keuangan negara.","explanation":"Edukasi bukan sekadar menyampaikan materi. Kegiatan perlu berbasis kebutuhan audiens, memiliki tujuan terukur, menggunakan metode yang sesuai, dievaluasi, dilaporkan, dan ditindaklanjuti.","example":"Peserta bukan hanya mengetahui prosedur, tetapi mampu mempraktikkannya setelah simulasi.","keywords":"edukasi; perubahan; penerapan","comparison":"Sosialisasi dapat berfokus memberi tahu; edukasi menargetkan pembelajaran dan penerapan.","mnemonic":"AUDIT = Audiens, Tujuan, Desain, Implementasi, Tindak lanjut."},{"number":7,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Feedforward","difficulty":"Mudah","type":"Istilah","question":"Apa fungsi feedforward?","shortAnswer":"Memberi orientasi atau konteks sebelum pesan utama.","explanation":"Feedforward menyiapkan penerima agar mengetahui tujuan, urutan, atau batas pembahasan. Hal ini mengurangi ketidakpastian dan membantu perhatian tertuju pada bagian penting.","example":"“Dalam lima menit saya akan membahas masalah, penyebab, dan solusi.”","keywords":"orientasi; sebelum; konteks","comparison":"Feedback muncul selama/setelah pesan untuk menilai respons.","mnemonic":"FORWARD = lihat ke depan sebelum pesan."},{"number":8,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Proxemics","difficulty":"Mudah","type":"Istilah","question":"Apa arti proxemics?","shortAnswer":"Penggunaan jarak dan ruang sebagai pesan nonverbal.","explanation":"Jarak dapat menunjukkan kedekatan, formalitas, kekuasaan, dan kenyamanan. Zona intim, personal, sosial, dan publik digunakan sesuai hubungan serta konteks budaya.","example":"Berbicara dengan orang baru biasanya memakai jarak sosial, bukan jarak intim.","keywords":"jarak; ruang; zona","comparison":"Haptics membahas sentuhan; proxemics membahas jarak.","mnemonic":"PROX = proximity atau kedekatan."},{"number":9,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Empati","difficulty":"Sedang","type":"Istilah","question":"Apa ciri empati dalam komunikasi?","shortAnswer":"Memahami pengalaman dari sudut pandang orang lain dan mengonfirmasi pemahaman tersebut.","explanation":"Empati ditunjukkan melalui perhatian, refleksi perasaan, pertanyaan terbuka, dan tidak terburu-buru memberi nasihat. Empati tidak sama dengan menyetujui seluruh tindakan.","example":"“Kedengarannya kamu kecewa karena hasilnya berbeda dari yang dijanjikan, benar?”","keywords":"perspektif; refleksi; konfirmasi","comparison":"Simpati adalah rasa prihatin dari perspektif diri sendiri.","mnemonic":"EM-PATI = masuk perspektif pihak lain."},{"number":10,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Komunikasi informal","difficulty":"Sedang","type":"Istilah","question":"Apa fungsi positif komunikasi informal?","shortAnswer":"Melengkapi saluran formal, membangun keakraban, dan mempercepat pertukaran informasi.","explanation":"Komunikasi informal dapat memperkuat kohesi dan membantu koordinasi. Namun, informasi penting tetap perlu diverifikasi dan didokumentasikan agar rumor tidak menggantikan saluran resmi.","example":"Diskusi singkat antarrekan membantu menemukan kendala, lalu hasilnya dicatat dalam kanal resmi.","keywords":"informal; kohesi; verifikasi","comparison":"Informal bukan berarti tidak profesional; formal bukan berarti selalu lebih efektif.","mnemonic":"Informal = dekat, tetapi fakta tetap dicek."},{"number":11,"topic":"TM 7 Presentasi dan Slide Efektif","subtopic":"Signal-to-noise ratio","difficulty":"Sedang","type":"Istilah","question":"Apa arti signal-to-noise ratio pada slide?","shortAnswer":"Perbandingan antara informasi utama yang berguna dan elemen tambahan yang mengganggu.","explanation":"Slide efektif membuat signal lebih menonjol melalui hierarki, kontras, whitespace, judul informatif, dan visual relevan. Dekorasi, teks berlebihan, dan animasi yang tidak mendukung pesan merupakan noise.","example":"Sorot angka penurunan waktu layanan; hapus ikon dan paragraf yang tidak membantu temuan.","keywords":"signal; noise; hierarki","comparison":"Konten lengkap belum tentu efektif; signal-to-noise menilai kejelasan fokus.","mnemonic":"SIGNAL terang, NOISE disingkirkan."},{"number":12,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Tahap hubungan","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan tahap hubungan interpersonal menurut DeVito?","shortAnswer":"Kontak → Keterlibatan → Keakraban → Perusakan → Pemutusan.","explanation":"Hubungan tidak selalu melewati semua tahap secara linier. Hubungan dapat berhenti, mundur, bertahan pada satu tahap, atau berakhir. Tahap keakraban ditandai kepercayaan dan komitmen lebih tinggi.","example":"Rekan baru berkenalan, sering bekerja bersama, menjadi dekat, lalu menjauh karena konflik.","keywords":"kontak; keterlibatan; keakraban","comparison":"Keluasan adalah banyaknya topik; kedalaman adalah tingkat pribadi suatu topik.","mnemonic":"KLIK-P = Kontak, Keterlibatan, Intim/Keakraban, Kerusakan, Pemutusan."},{"number":13,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Penyusunan pesan","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan TARIK untuk menyusun pesan bisnis?","shortAnswer":"Tujuan → Audiens → Rangka → Isi → Koreksi.","explanation":"Tujuan menetapkan hasil, audiens menentukan pendekatan dan detail, rangka mengatur alur, isi menyampaikan pesan, dan koreksi memastikan kejelasan, ketepatan, serta kelengkapan sebelum dikirim.","example":"Sebelum mengirim email permintaan data, tetapkan tenggat, pahami penerima, susun poin, tulis, lalu revisi.","keywords":"tujuan; audiens; rangka; revisi","comparison":"Menulis langsung tanpa analisis sering menghasilkan pesan melebar.","mnemonic":"TARIK pesan sebelum dikirim."},{"number":14,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Siklus edukasi","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan AUDIT dalam kegiatan edukasi?","shortAnswer":"Audiens → Tujuan → Desain → Implementasi → Tindak lanjut.","explanation":"Audiens dan kebutuhan dianalisis lebih dahulu. Tujuan dibuat terukur, desain memilih materi/metode/media, implementasi menjalankan kegiatan, dan tindak lanjut menggunakan evaluasi serta laporan untuk perbaikan.","example":"Pre-test memetakan kebutuhan, simulasi digunakan saat kegiatan, post-test dan laporan menjadi dasar tindak lanjut.","keywords":"audiens; tujuan; desain; evaluasi","comparison":"Pelaksanaan adalah satu tahap; manajemen edukasi mencakup seluruh siklus.","mnemonic":"AUDIT kegiatan, bukan hanya hadir dan selesai."},{"number":15,"topic":"TM 7 Presentasi dan Slide Efektif","subtopic":"Persiapan presentasi","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan praktis menyiapkan presentasi efektif?","shortAnswer":"Analisis audiens/tujuan → tesis dan struktur → slide → latihan → penyampaian dan evaluasi.","explanation":"Presentasi dimulai dari kebutuhan audiens, bukan dari template. Tesis menentukan satu pesan inti, struktur membantu alur, slide menjadi dukungan visual, latihan menguji waktu serta teknologi, dan evaluasi memperbaiki penampilan berikutnya.","example":"Latihan bersuara dengan timer dan simulasi proyektor sebelum presentasi 10 menit.","keywords":"audiens; tesis; struktur; rehearsal","comparison":"Slide adalah alat bantu, bukan titik awal dan bukan naskah lengkap.","mnemonic":"A-T-S-L-S = Audiens, Tesis, Struktur, Latihan, Sampaikan."},{"number":16,"topic":"TM 1 Pengantar Komunikasi","subtopic":"Feedback vs feedforward","difficulty":"Sedang","type":"Perbandingan","question":"Bedakan feedback dan feedforward.","shortAnswer":"Feedback menilai respons selama/setelah pesan; feedforward menyiapkan penerima sebelum pesan.","explanation":"Keduanya mengurangi kesalahpahaman pada waktu berbeda. Feedforward menjelaskan konteks atau agenda, sedangkan feedback memeriksa reaksi dan pemahaman untuk koreksi.","example":"Feedforward: “Ada tiga langkah.” Feedback: “Coba ulangi langkah yang dipahami.”","keywords":"waktu; orientasi; respons","comparison":"Channel adalah media; bukan respons atau orientasi.","mnemonic":"FORWARD sebelum, BACK sesudah."},{"number":17,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Empati vs simpati","difficulty":"Sedang","type":"Perbandingan","question":"Apa pembeda utama empati dan simpati?","shortAnswer":"Empati memahami dari perspektif orang lain; simpati merasa prihatin dari perspektif diri.","explanation":"Empati cenderung lebih eksploratif dan memeriksa perasaan, sedangkan simpati dapat berupa ungkapan kepedulian. Empati tidak harus berarti persetujuan.","example":"Empati: “Apa yang paling berat bagimu?” Simpati: “Saya ikut prihatin.”","keywords":"perspektif; perasaan","comparison":"Empati bukan persetujuan; simpati bukan sikap tidak peduli.","mnemonic":"Empati masuk, simpati melihat."},{"number":18,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Langsung vs tidak langsung","difficulty":"Sedang","type":"Perbandingan","question":"Kapan memakai pendekatan langsung dan tidak langsung?","shortAnswer":"Langsung untuk pesan rutin/positif; tidak langsung untuk pesan yang diperkirakan memicu respons negatif.","explanation":"Pendekatan langsung menyampaikan inti di awal. Pendekatan tidak langsung memberi buffer dan alasan sebelum keputusan, tetapi tetap harus jelas serta tidak manipulatif.","example":"Konfirmasi jadwal: langsung. Penolakan kerja sama sensitif: tidak langsung.","keywords":"deduktif; induktif; respons audiens","comparison":"Buffer bukan cara menyembunyikan keputusan.","mnemonic":"Positif: inti dulu; negatif: konteks dulu."},{"number":19,"topic":"TM 2 Verbal, Nonverbal, dan Intrapersonal","subtopic":"Monochronic vs polychronic","difficulty":"Sulit","type":"Perbandingan","question":"Bedakan orientasi waktu monochronic dan polychronic.","shortAnswer":"Monochronic menekankan satu tugas dan jadwal; polychronic lebih lentur serta menangani beberapa interaksi/tugas.","explanation":"Perbedaan orientasi waktu dapat menimbulkan konflik tentang ketepatan, prioritas, dan interupsi. Komunikator perlu menyepakati tenggat dan cara koordinasi, bukan menganggap satu budaya waktu selalu lebih benar.","example":"Monochronic menyelesaikan agenda satu per satu; polychronic menerima beberapa percakapan berjalan bersamaan.","keywords":"waktu; jadwal; budaya","comparison":"Chronemics adalah studi pesan melalui waktu; mono/poly adalah orientasi waktu.","mnemonic":"MONO satu; POLY banyak."},{"number":20,"topic":"TM 5 Pesan Bisnis dan Telepon","subtopic":"Telepon resmi","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana membuka dan mengelola telepon resmi?","shortAnswer":"Sebut instansi, salam, nama, tawarkan bantuan; lalu dengarkan, klarifikasi, rangkum, dan tutup sopan.","explanation":"Identitas memberi kepastian, klarifikasi mencegah salah catat, dan rangkuman memastikan tindak lanjut. Bila jawaban belum tersedia, catat dan sepakati waktu menghubungi kembali.","example":"“KPP X, selamat pagi, dengan Rina. Ada yang dapat dibantu?”","keywords":"identitas; salam; klarifikasi; tindak lanjut","comparison":"Telepon resmi bukan percakapan spontan tanpa pencatatan.","mnemonic":"ISI-TUTUP = Identitas, Salam, Inti; Tindak lanjut, Ulangi, Tutup."},{"number":21,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Mendengarkan aktif","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menerapkan mendengarkan aktif saat keluhan?","shortAnswer":"Fokus, beri respons nonverbal, parafrase, refleksikan perasaan, klarifikasi, lalu sepakati tindak lanjut.","explanation":"Urutan ini membedakan pemahaman dari penilaian. Solusi diberikan setelah kebutuhan dan fakta cukup jelas. Pendengar tidak memotong, tidak membuat asumsi, dan tidak mengalihkan fokus kepada dirinya.","example":"“Jadi dokumen tertunda dua hari dan Bapak khawatir tenggat terlewat, benar?”","keywords":"fokus; parafrase; refleksi","comparison":"Mendengar adalah proses fisiologis; mendengarkan adalah proses aktif memberi makna.","mnemonic":"DENGAR = Diam, Empati, Nyatakan ulang, Gali, Arahkan solusi, Ringkas."},{"number":22,"topic":"TM 7 Presentasi dan Slide Efektif","subtopic":"Judul slide","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana membuat judul slide yang informatif?","shortAnswer":"Tuliskan kesimpulan atau pesan utama, bukan label umum.","explanation":"Judul harus membantu audiens memahami apa yang perlu diperhatikan sebelum membaca grafik. “Waktu layanan turun 30%” lebih berguna daripada “Grafik 1” karena menyatakan temuan dan mengarahkan interpretasi.","example":"Ubah “Hasil Survei” menjadi “Kepuasan meningkat setelah penyederhanaan formulir”.","keywords":"judul; temuan; fokus","comparison":"Judul topik hanya menyebut area; judul pesan menyatakan kesimpulan.","mnemonic":"Judul = jawaban singkat slide."},{"number":23,"topic":"TM 3 Komunikasi Interpersonal","subtopic":"Keluhan emosional","difficulty":"Sulit","type":"Mini Kasus","question":"Wajib pajak marah karena layanan terlambat. Apa respons awal?","shortAnswer":"Validasi emosi, minta maaf atas ketidaknyamanan, klarifikasi fakta, dan arahkan pada solusi.","explanation":"Empati menurunkan ketegangan dan memungkinkan pembicaraan faktual. Permintaan maaf atas ketidaknyamanan tidak selalu berarti mengakui kesalahan hukum. Petugas tetap menjaga batas, aturan, dan keamanan.","example":"“Saya memahami Bapak kecewa. Mohon maaf atas ketidaknyamanannya. Mari saya cek statusnya.”","keywords":"validasi; tenang; solusi","comparison":"Empati bukan menyerah pada semua tuntutan.","mnemonic":"TENANG = Terima emosi, Empati, Nyatakan maaf, Analisis, Negosiasi solusi, Garis tindak lanjut."},{"number":24,"topic":"TM 4 Komunikasi Organisasi","subtopic":"Rumor organisasi","difficulty":"Sulit","type":"Mini Kasus","question":"Rumor kebijakan menyebar sebelum data final. Apa tindakan organisasi?","shortAnswer":"Keluarkan pembaruan resmi yang terverifikasi, konsisten, empatik, dan memiliki jadwal pembaruan berikutnya.","explanation":"Kecepatan penting, tetapi spekulasi merusak kredibilitas. Pesan perlu membedakan fakta, hal yang belum diketahui, tindakan sementara, dan kanal resmi. Juru bicara serta unit harus menggunakan pesan inti yang sama.","example":"“Informasi A telah terverifikasi; bagian B masih diperiksa. Pembaruan berikutnya pukul 15.00.”","keywords":"krisis; verifikasi; konsistensi","comparison":"Diam total berbeda dari kehati-hatian; kehati-hatian tetap dapat memberi update terbatas.","mnemonic":"CEPAT = Cek fakta, Empati, Pesan tunggal, Atur update, Tindak lanjut."},{"number":25,"topic":"TM 6 Edukasi Keuangan Negara","subtopic":"Pengungkapan dan data peserta","difficulty":"Sulit","type":"Mini Kasus","question":"Peserta mengungkap data pribadi sensitif di forum edukasi. Apa respons fasilitator?","shortAnswer":"Hentikan penyebutan detail, arahkan ke kanal privat, jelaskan kerahasiaan, dan catat hanya informasi yang diperlukan.","explanation":"Pengungkapan diri harus mempertimbangkan kepatutan, risiko, konteks, dan kebutuhan. Fasilitator melindungi peserta tanpa mempermalukan, tidak menggunakan informasi untuk tujuan lain, dan mengikuti batas kewenangan serta keamanan data.","example":"“Agar data Bapak tetap aman, detail ini kita lanjutkan melalui konsultasi privat.”","keywords":"privasi; kepatutan; risiko","comparison":"Keterbukaan membantu hubungan, tetapi bukan berarti semua informasi aman dibagikan di semua forum.","mnemonic":"PRIVAT = Pindahkan, Rahasiakan, Identifikasi kebutuhan, Verifikasi izin, Ambil seperlunya, Tindak lanjut."}]},"mpsia":{"id":"mpsia","title":"Manajemen Proyek SIA","short":"MPSIA","konsen":["sisfo"],"quiz":[{"number":1,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Definisi dan karakteristik proyek","learningOutcome":"Menjelaskan ciri utama proyek.","difficulty":"Mudah","type":"Definisi","question":"Pernyataan yang PALING TEPAT menggambarkan sebuah proyek adalah ...","options":["Upaya sementara dengan awal dan akhir jelas untuk menghasilkan produk, layanan, atau hasil yang unik.","Kegiatan rutin yang terus berlangsung selama organisasi masih membutuhkan layanan tersebut.","Serangkaian tugas operasional yang selalu menggunakan prosedur dan keluaran yang sama.","Pekerjaan tanpa batas waktu yang bertujuan menjaga stabilitas proses organisasi."],"correct":"A","concept":"Proyek bersifat sementara dan menghasilkan keluaran unik.","explanation":"Jawaban A benar karena proyek memiliki kondisi mulai dan selesai yang jelas serta diarahkan untuk menghasilkan produk, layanan, kemampuan, atau hasil yang unik. Sifat sementara melekat pada upayanya, bukan pada umur hasilnya; aplikasi yang dibangun melalui proyek dapat digunakan bertahun-tahun. Pilihan B, C, dan D lebih menggambarkan operasi, yaitu pekerjaan rutin dan berulang untuk mempertahankan layanan organisasi. Kesalahan yang sering terjadi adalah menganggap proyek harus singkat. Proyek tiga tahun tetap merupakan proyek selama memiliki tujuan dan kondisi akhir yang jelas.","whyOthersWrong":"B, C, dan D menekankan kegiatan rutin, berulang, atau tanpa akhir yang jelas sehingga lebih sesuai dengan karakter operasi.","tip":"Cari dua kata kunci: sementara dan hasil unik.","reference":"TM 1 — Dasar Proyek; RPS MPSIA ASP4130; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"temporary; unique result; tujuan"},{"number":2,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Proyek, program, dan portofolio","learningOutcome":"Membedakan program dari proyek dan portofolio.","difficulty":"Mudah","type":"Definisi","question":"Program dalam konteks manajemen proyek adalah ...","options":["Kumpulan seluruh investasi organisasi yang dipilih hanya berdasarkan biaya terendah.","Sekelompok proyek dan kegiatan terkait yang dikoordinasikan untuk memperoleh manfaat gabungan.","Satu upaya sementara yang menghasilkan satu deliverable unik dan berdiri sendiri.","Kegiatan operasional berulang yang menjaga agar produk tetap digunakan."],"correct":"B","concept":"Program mengoordinasikan proyek terkait untuk manfaat bersama.","explanation":"Jawaban B benar. Program mengelola beberapa proyek dan kegiatan yang saling terkait agar manfaat gabungan dapat dicapai secara lebih baik dibandingkan jika setiap proyek dikelola secara terpisah. Proyek berfokus pada keluaran tertentu, sedangkan portofolio memilih dan menyeimbangkan investasi agar selaras dengan strategi organisasi. Pilihan A lebih mendekati portofolio, tetapi salah karena portofolio tidak hanya mempertimbangkan biaya. Pilihan C adalah definisi proyek, dan pilihan D adalah operasi. Pembeda utama program adalah keterkaitan proyek dan orientasi pada manfaat bersama.","whyOthersWrong":"A mencampuradukkan portofolio dengan pemilihan biaya terendah; C adalah proyek; D adalah operasi.","tip":"Program = proyek terkait + manfaat bersama.","reference":"TM 1 — Proyek, Program, dan Portofolio; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"program; manfaat gabungan; koordinasi"},{"number":3,"topic":"System View, Organisasi, dan Daur Hidup","subtopic":"Systems approach dan three-sphere model","learningOutcome":"Menjelaskan pandangan sistem dalam proyek TI.","difficulty":"Mudah","type":"Definisi","question":"Systems approach pada proyek SIA menuntut tim untuk ...","options":["Memusatkan analisis hanya pada kemampuan aplikasi dan infrastruktur teknis.","Mengutamakan kebutuhan unit teknologi walaupun proses bisnis tidak berubah.","Menilai keterkaitan aspek bisnis, organisasi, dan teknologi sebagai satu kesatuan.","Memisahkan keputusan pengguna dari desain data agar proyek lebih cepat."],"correct":"C","concept":"Solusi TI harus selaras dengan bisnis, organisasi, dan teknologi.","explanation":"Jawaban C benar karena systems approach melihat proyek sebagai bagian dari sistem organisasi yang saling berhubungan. Keberhasilan SIA tidak hanya ditentukan oleh aplikasi, tetapi juga oleh manfaat bisnis, proses, struktur kewenangan, budaya, kemampuan pengguna, data, keamanan, dan infrastruktur. Pilihan A dan B terlalu teknosentris, sedangkan pilihan D justru memutus hubungan yang seharusnya dikelola. Kesalahan umum adalah menganggap proyek gagal hanya karena software error, padahal penyebabnya dapat berupa SOP yang tidak diperbarui, konflik antarunit, atau pengguna yang tidak siap.","whyOthersWrong":"A dan B mengabaikan dimensi bisnis/organisasi; D memisahkan unsur yang seharusnya terintegrasi.","tip":"Ingat tiga lingkaran: bisnis—organisasi—teknologi.","reference":"TM 2 — System View dan Three-Sphere Model; RPS MPSIA ASP4130; Schwalbe 9th Ed.","keywords":"system view; business; organization; technology"},{"number":4,"topic":"Process Groups dan Metodologi","subtopic":"Monitoring and Controlling Process Group","learningOutcome":"Mengidentifikasi tujuan Monitoring and Controlling.","difficulty":"Mudah","type":"Definisi","question":"Aktivitas yang PALING mencerminkan Monitoring and Controlling adalah ...","options":["Menetapkan sponsor dan memberi otorisasi formal kepada project manager.","Mengembangkan modul serta melaksanakan pengujian sesuai rencana.","Mengarsipkan dokumen, melepas sumber daya, dan menutup kontrak.","Membandingkan kinerja aktual dengan baseline serta mengelola penyimpangan dan perubahan."],"correct":"D","concept":"Monitoring and Controlling membandingkan aktual dengan rencana.","explanation":"Jawaban D benar karena Monitoring and Controlling berfungsi mengukur kondisi aktual, membandingkannya dengan baseline, menganalisis varians dan tren, memperbarui prakiraan, memantau risiko, serta memproses perubahan. Pilihan A adalah Initiating, pilihan B adalah Executing, dan pilihan C adalah Closing. Proses pengendalian tidak bertujuan sekadar memberi status merah atau mencari pihak yang salah. Informasi kinerja harus digunakan untuk menentukan penyebab, dampak, pilihan koreksi, dan kebutuhan perubahan sebelum masalah membesar.","whyOthersWrong":"A = Initiating; B = Executing; C = Closing. Hanya D memuat pengukuran terhadap baseline.","tip":"Kata kunci pengendalian: aktual, baseline, varians, forecast, perubahan.","reference":"TM 3 — Lima Process Groups; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"baseline; varians; perubahan"},{"number":5,"topic":"Manajemen Integrasi Proyek","subtopic":"Project charter","learningOutcome":"Menjelaskan fungsi project charter.","difficulty":"Mudah","type":"Definisi","question":"Fungsi UTAMA project charter adalah ...","options":["Memberi otorisasi formal kepada proyek dan project manager serta menetapkan arah tingkat tinggi.","Merinci seluruh aktivitas, durasi, dependensi, dan kebutuhan sumber daya proyek.","Menjadi daftar lengkap seluruh kebutuhan fungsional dan nonfungsional.","Mencatat seluruh risiko, issue, respons, dan pemilik tindakan proyek."],"correct":"A","concept":"Charter mengesahkan proyek dan kewenangan project manager.","explanation":"Jawaban A benar. Project charter menghubungkan proyek dengan tujuan organisasi, menetapkan sponsor, menunjuk project manager, serta memberikan otorisasi formal dan arah tingkat tinggi. Charter dapat memuat tujuan, high-level scope, milestone, anggaran awal, risiko utama, dan stakeholder kunci, tetapi bukan rencana proyek yang lengkap. Pilihan B lebih dekat dengan jadwal dan project management plan, pilihan C menggambarkan requirements documentation, sedangkan pilihan D menggambarkan risk register atau issue log. Jebakan umum adalah menganggap charter sudah memuat seluruh cara proyek akan dijalankan.","whyOthersWrong":"B adalah rincian perencanaan; C adalah dokumentasi kebutuhan; D adalah register risiko/issue.","tip":"Charter = izin resmi dan arah awal, bukan buku aturan rinci.","reference":"TM 4 — Project Charter; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"otorisasi; sponsor; high-level scope"},{"number":6,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Proyek dan operasi","learningOutcome":"Membedakan proyek dan operasi.","difficulty":"Sedang","type":"Konseptual","question":"Pasangan kegiatan yang menunjukkan hubungan proyek dan operasi secara tepat adalah ...","options":["Backup harian sebagai proyek, sedangkan pembangunan data center sebagai operasi.","Payroll bulanan sebagai proyek, sedangkan migrasi data sebagai operasi.","Implementasi modul rekonsiliasi sebagai proyek, kemudian rekonsiliasi bulanan sebagai operasi.","Pemeliharaan aplikasi sebagai proyek, kemudian pengembangan aplikasi baru sebagai operasi."],"correct":"C","concept":"Proyek menciptakan perubahan; operasi mempertahankan hasilnya.","explanation":"Jawaban C benar karena implementasi modul rekonsiliasi memiliki tujuan unik, tim, jadwal, dan kondisi selesai sehingga merupakan proyek. Setelah modul diserahkan, pelaksanaan rekonsiliasi bulanan menjadi kegiatan rutin dan berulang sehingga termasuk operasi. Pilihan lain membalik karakter proyek dan operasi. Keduanya sama-sama memerlukan orang, anggaran, perencanaan, dan pengendalian, tetapi arah pekerjaannya berbeda: proyek menciptakan kemampuan baru, sedangkan operasi menjaga kemampuan tersebut tetap menghasilkan manfaat.","whyOthersWrong":"A, B, dan D membalik klasifikasi kegiatan perubahan dan kegiatan rutin.","tip":"Tanyakan: apakah ada hasil unik dan garis akhir, atau kegiatan berulang?","reference":"TM 1 — Proyek dan Operasi; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"perubahan; rutin; serah terima"},{"number":7,"topic":"System View, Organisasi, dan Daur Hidup","subtopic":"Project life cycle dan process groups","learningOutcome":"Membedakan fase dengan kelompok proses.","difficulty":"Sedang","type":"Konseptual","question":"Pernyataan yang benar mengenai project life cycle dan process groups adalah ...","options":["Nama fase proyek harus selalu Initiating, Planning, Executing, Controlling, dan Closing.","Process groups dapat muncul berulang dalam berbagai fase, sedangkan fase membagi perjalanan proyek.","Planning hanya dilakukan satu kali sebelum fase pengembangan dimulai.","Closing hanya diperlukan jika proyek berhasil mencapai seluruh target awal."],"correct":"B","concept":"Fase dan process groups bukan hal yang sama.","explanation":"Jawaban B benar. Project life cycle membagi proyek ke dalam fase yang sesuai konteks, misalnya analisis, desain, pembangunan, pengujian, dan implementasi. Process groups menggambarkan tujuan proses manajemen—memulai, merencanakan, mengerjakan, memantau, dan menutup—yang dapat terjadi di berbagai fase. Pilihan A salah karena nama fase tidak wajib sama dengan process groups. Pilihan C salah karena perencanaan dapat diperbarui secara iteratif. Pilihan D salah karena proyek yang dihentikan pun harus ditutup secara formal.","whyOthersWrong":"A menyamakan fase dengan process groups; C menganggap planning satu kali; D mengabaikan formal closing.","tip":"Fase menjawab 'bagian perjalanan'; process groups menjawab 'tujuan pengelolaan'.","reference":"TM 2 — Daur Hidup Proyek; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"fase; process groups; berulang"},{"number":8,"topic":"Process Groups dan Metodologi","subtopic":"Hubungan antar-process group","learningOutcome":"Menghubungkan aktivitas dengan process group.","difficulty":"Sedang","type":"Konseptual","question":"Tim menyusun WBS, jadwal, estimasi biaya, rencana risiko, dan aturan perubahan. Aktivitas tersebut terutama berada pada ...","options":["Initiating, karena proyek sedang memperoleh otorisasi awal.","Executing, karena tim mulai menggunakan sumber daya proyek.","Closing, karena dokumen proyek sedang dilengkapi.","Planning, karena tim menyepakati cara mencapai tujuan dan mengendalikan pekerjaan."],"correct":"D","concept":"Planning menyusun cara kerja proyek secara terintegrasi.","explanation":"Jawaban D benar karena WBS, jadwal, estimasi biaya, rencana risiko, dan prosedur perubahan merupakan bagian dari perencanaan cara proyek akan dilaksanakan, dipantau, dan dikendalikan. Initiating hanya memberi otorisasi dan arah tingkat tinggi. Executing menghasilkan deliverable melalui pekerjaan yang telah direncanakan, sedangkan Closing menyelesaikan penerimaan dan administrasi. Perencanaan bukan pekerjaan project manager seorang diri; rencana yang realistis disusun bersama pihak yang mengerjakan dan memahami kebutuhan.","whyOthersWrong":"A terlalu awal dan tingkat tinggi; B berfokus menghasilkan deliverable; C berfokus penutupan.","tip":"Jika aktivitas menyusun 'bagaimana, kapan, siapa, berapa, dan bagaimana dikontrol', pilih Planning.","reference":"TM 3 — Planning Process Group; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"WBS; jadwal; rencana risiko"},{"number":9,"topic":"Manajemen Integrasi Proyek","subtopic":"Business case, benefits plan, dan charter","learningOutcome":"Menghubungkan fungsi tiga dokumen integrasi.","difficulty":"Sedang","type":"Konseptual","question":"Urutan fungsi dokumen yang PALING TEPAT adalah ...","options":["Business case menjelaskan kelayakan; benefits management plan mengatur realisasi manfaat; charter memberi otorisasi.","Business case memberi otorisasi; benefits management plan merinci aktivitas; charter mengukur manfaat.","Business case menjadi scope baseline; benefits management plan menjadi risk register; charter menjadi jadwal.","Business case mencatat issue; benefits management plan mengendalikan kontrak; charter menjadi WBS."],"correct":"A","concept":"Ketiga dokumen memiliki tujuan berbeda tetapi saling terkait.","explanation":"Jawaban A benar. Business case menjawab mengapa investasi layak dilakukan dengan membahas masalah, pilihan, biaya-manfaat, dan risiko. Benefits management plan menjelaskan manfaat yang ditargetkan, ukuran, waktu realisasi, asumsi, risiko, serta pemilik manfaat. Project charter kemudian mengesahkan proyek dan kewenangan project manager pada tingkat tinggi. Pilihan B, C, dan D mencampur fungsi dokumen dengan WBS, risk register, issue log, dan jadwal. Cara membedakannya: alasan investasi—pengelolaan manfaat—otorisasi proyek.","whyOthersWrong":"B, C, dan D menempatkan fungsi operasional atau dokumen lain pada ketiga dokumen tersebut.","tip":"Ingat urutan: layak → manfaat → resmi dimulai.","reference":"TM 4 — Business Case, Benefits Management Plan, Project Charter; PMBOK Guide 6th Ed.","keywords":"kelayakan; manfaat; otorisasi"},{"number":10,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Product scope dan project scope","learningOutcome":"Membedakan product scope dan project scope.","difficulty":"Sedang","type":"Konseptual","question":"Pernyataan yang tepat mengenai product scope dan project scope adalah ...","options":["Product scope menjelaskan pekerjaan proyek, sedangkan project scope menjelaskan fitur produk.","Product scope menjelaskan fungsi hasil, sedangkan project scope menjelaskan pekerjaan untuk menghasilkan fungsi itu.","Product scope hanya digunakan pada operasi, sedangkan project scope hanya digunakan pada program.","Keduanya sama karena setiap fitur selalu membutuhkan satu aktivitas saja."],"correct":"B","concept":"Product scope = kemampuan hasil; project scope = pekerjaan pembentuknya.","explanation":"Jawaban B benar. Product scope menjelaskan fitur dan fungsi produk, misalnya audit trail atau laporan otomatis. Project scope menjelaskan seluruh pekerjaan yang diperlukan untuk menghasilkan fitur tersebut, seperti analisis, desain, coding, integrasi, migrasi, pengujian, dokumentasi, dan pelatihan. Pilihan A membalik definisi, pilihan C tidak memiliki dasar, dan pilihan D mengabaikan bahwa satu fitur dapat memerlukan banyak pekerjaan. Pemahaman ini penting agar fitur yang tampak sederhana tidak diremehkan dampaknya terhadap jadwal dan biaya.","whyOthersWrong":"A membalik definisi; C salah konteks; D menganggap hubungan fitur-pekerjaan selalu satu banding satu.","tip":"Produk harus bisa apa? Proyek harus mengerjakan apa?","reference":"TM 5 — Product Scope dan Project Scope; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"fitur; pekerjaan; deliverable"},{"number":11,"topic":"Manajemen Jadwal Proyek","subtopic":"PERT dan three-point estimation","learningOutcome":"Menghitung expected duration PERT.","difficulty":"Sedang","type":"Penerapan","question":"Suatu aktivitas memiliki O = 4 hari, M = 7 hari, dan P = 16 hari. Expected duration PERT adalah ...","options":["6 hari","7 hari","8 hari","9 hari"],"correct":"C","concept":"TE = (O + 4M + P) / 6.","explanation":"Jawaban C benar. Rumus expected duration PERT adalah TE = (O + 4M + P) / 6. Substitusi: TE = (4 + 4×7 + 16) / 6 = (4 + 28 + 16) / 6 = 48 / 6 = 8 hari. Estimasi most likely mendapat bobot terbesar karena dianggap paling representatif. Angka delapan hari bukan jaminan penyelesaian, melainkan rata-rata tertimbang dari tiga skenario. Kesalahan umum adalah menghitung rata-rata sederhana sehingga mengabaikan bobot empat pada M.","whyOthersWrong":"A, B, dan D berasal dari pembulatan atau rata-rata yang tidak mengikuti bobot PERT.","tip":"Ingat pola 1–4–1, lalu bagi 6.","reference":"TM 6 — PERT; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"PERT; O; M; P"},{"number":12,"topic":"Manajemen Jadwal Proyek","subtopic":"Forward pass","learningOutcome":"Menentukan Early Start dari beberapa predecessor.","difficulty":"Sedang","type":"Penerapan","question":"Aktivitas E memiliki dua predecessor dengan EF masing-masing 8 dan 13. Tanpa lead atau lag, ES aktivitas E adalah ...","options":["13","8","10,5","21"],"correct":"A","concept":"Jika predecessor lebih dari satu, ES memakai EF terbesar.","explanation":"Jawaban A benar. Dalam forward pass, aktivitas dengan beberapa predecessor baru dapat dimulai setelah seluruh predecessor yang diwajibkan selesai. Karena itu, Early Start aktivitas E menggunakan Early Finish terbesar, yaitu max(8,13) = 13. Pilihan B hanya mempertimbangkan predecessor yang selesai lebih awal, pilihan C mengambil rata-rata yang tidak digunakan dalam network logic, dan pilihan D menjumlahkan EF secara keliru. Setelah ES diketahui, EF dihitung dengan EF = ES + durasi aktivitas.","whyOthersWrong":"B mengabaikan predecessor terlama; C memakai rata-rata; D menjumlahkan waktu yang tidak seharusnya dijumlahkan.","tip":"Forward pass bercabang masuk: ambil EF terbesar.","reference":"TM 6 — Forward Pass dan Network Diagram; PMBOK Guide 6th Ed.","keywords":"forward pass; ES; EF terbesar"},{"number":13,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Requirements yang dapat diuji","learningOutcome":"Menerapkan karakteristik kebutuhan yang baik.","difficulty":"Sedang","type":"Penerapan","question":"Rumusan kebutuhan yang PALING dapat diuji adalah ...","options":["Sistem harus memiliki tampilan yang modern dan nyaman.","Sistem harus bekerja cepat pada seluruh kondisi.","Laporan sebaiknya tersedia tanpa menunggu terlalu lama.","Sebanyak 95% laporan bulanan terbuka maksimal 5 detik untuk 500 pengguna aktif."],"correct":"D","concept":"Kebutuhan harus jelas, terukur, dan dapat diverifikasi.","explanation":"Jawaban D benar karena menyebut ukuran keberhasilan, waktu respons, persentase, dan beban pengguna sehingga dapat dibuat test case yang objektif. Pilihan A, B, dan C menggunakan istilah subjektif seperti modern, cepat, dan tidak terlalu lama tanpa batas terukur. Kebutuhan yang kabur membuka interpretasi berbeda antara pengguna, analis, pengembang, dan penguji. Dalam proyek SIA, kebutuhan fungsional maupun nonfungsional perlu memiliki sumber, prioritas, kriteria uji, dan keterlacakan agar penerimaan tidak bergantung pada persepsi.","whyOthersWrong":"A, B, dan C bersifat subjektif dan tidak menyediakan ambang pengujian.","tip":"Cari angka, kondisi uji, dan batas keberhasilan.","reference":"TM 5 — Collect Requirements; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"measurable; testable; acceptance criteria"},{"number":14,"topic":"Manajemen Integrasi Proyek","subtopic":"Integrated Change Control","learningOutcome":"Menerapkan prosedur perubahan terintegrasi.","difficulty":"Sedang","type":"Penerapan","question":"SETELAH change request disetujui, tindakan yang PALING tepat adalah ...","options":["Mengimplementasikan perubahan segera tanpa memperbarui dokumen agar tidak terlambat.","Memperbarui baseline, rencana, dokumen, dan komunikasi sebelum perubahan dilaksanakan.","Menghapus change log karena keputusan telah dibuat oleh pihak berwenang.","Menunda seluruh pekerjaan proyek sampai semua stakeholder kembali menyetujui charter."],"correct":"B","concept":"Perubahan disetujui harus diintegrasikan ke rencana dan baseline.","explanation":"Jawaban B benar. Persetujuan perubahan bukan akhir proses. Tim harus memperbarui baseline, subsidiary plan, dokumen, jadwal, anggaran, risiko, kontrak, serta komunikasi yang terdampak sebelum mengimplementasikan perubahan. Pilihan A menghasilkan ketidaksesuaian antara pekerjaan dan acuan resmi. Pilihan C merusak audit trail, sedangkan pilihan D berlebihan karena tidak semua perubahan memerlukan persetujuan ulang charter. Pengendalian perubahan menjaga agar keputusan, sumber daya, dan ekspektasi stakeholder tetap konsisten.","whyOthersWrong":"A melewati integrasi dokumen; C menghilangkan audit trail; D tidak proporsional.","tip":"Disetujui → perbarui acuan → komunikasikan → implementasikan → verifikasi.","reference":"TM 4 — Perform Integrated Change Control; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"approved change; baseline; komunikasi"},{"number":15,"topic":"Manajemen Biaya Proyek","subtopic":"Cost baseline dan project budget","learningOutcome":"Menghitung baseline dan project budget.","difficulty":"Sedang","type":"Penerapan","question":"Estimasi biaya proyek Rp5,4 miliar, contingency reserve 10% dari estimasi, dan management reserve Rp360 juta. Nilai cost baseline dan project budget adalah ...","options":["Rp5,40 miliar dan Rp5,76 miliar","Rp5,76 miliar dan Rp5,94 miliar","Rp5,94 miliar dan Rp6,30 miliar","Rp6,30 miliar dan Rp6,84 miliar"],"correct":"C","concept":"Cost baseline = estimasi + contingency; project budget = baseline + management reserve.","explanation":"Jawaban C benar. Contingency reserve = 10% × Rp5,4 miliar = Rp0,54 miliar. Cost baseline = Rp5,4 + Rp0,54 = Rp5,94 miliar. Project budget = cost baseline + management reserve = Rp5,94 + Rp0,36 = Rp6,30 miliar. Contingency reserve mencakup risiko yang telah diidentifikasi dan menjadi bagian baseline. Management reserve berada di luar baseline, tetapi termasuk project budget. Kinerja EVM diukur terhadap baseline, bukan terhadap seluruh project budget.","whyOthersWrong":"A mengabaikan contingency; B salah mengagregasikan cadangan; D menambahkan cadangan secara berlebihan.","tip":"Estimasi + contingency = baseline; baseline + management reserve = budget.","reference":"TM 7 — Determine Budget dan Reserve; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"contingency; baseline; management reserve"},{"number":16,"topic":"System View, Organisasi, dan Daur Hidup","subtopic":"Struktur organisasi","learningOutcome":"Menganalisis kewenangan project manager.","difficulty":"Sulit","type":"Mini Kasus","question":"Project manager harus meminjam anggota tim dari beberapa unit. Functional manager tetap menentukan prioritas, penilaian kinerja, dan alokasi orang. Struktur yang PALING mungkin adalah ...","options":["Projectized","Matriks kuat","Matriks seimbang","Fungsional"],"correct":"D","concept":"Dalam struktur fungsional, kewenangan PM sangat rendah.","explanation":"Jawaban D benar. Pada organisasi fungsional, anggota tim tetap berada di unit fungsi dan functional manager mengendalikan sumber daya serta keputusan utama. Project manager lebih menyerupai koordinator yang harus bernegosiasi untuk memperoleh orang dan prioritas. Dalam matriks seimbang, kewenangan dibagi; matriks kuat memberi PM kewenangan lebih besar; projectized menempatkan tim terutama di bawah PM. Kasus ini menekankan bahwa struktur organisasi memengaruhi kecepatan keputusan dan kemampuan PM mengendalikan sumber daya.","whyOthersWrong":"A dan B memberi PM kewenangan tinggi; C menunjukkan pembagian kewenangan yang lebih seimbang.","tip":"Semakin dominan functional manager, semakin dekat ke struktur fungsional.","reference":"TM 2 — Struktur Organisasi dan Kewenangan PM; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"functional manager; kewenangan rendah"},{"number":17,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Keberhasilan proyek","learningOutcome":"Mengevaluasi keberhasilan berdasarkan manfaat dan adopsi.","difficulty":"Sulit","type":"Mini Kasus","question":"SIA selesai sesuai jadwal, scope, dan anggaran. Namun pengguna kembali memakai spreadsheet karena alurnya rumit. Penilaian yang PALING tepat adalah ...","options":["Keberhasilan proyek lemah karena penerimaan, adopsi, dan manfaat bisnis tidak tercapai.","Proyek sepenuhnya berhasil karena triple constraint telah dipenuhi.","Proyek termasuk operasi karena sistem telah digunakan setelah go-live.","Keberhasilan tidak dapat dinilai sebelum semua fitur tambahan dikembangkan."],"correct":"A","concept":"Keberhasilan proyek lebih luas daripada scope, waktu, dan biaya.","explanation":"Jawaban A benar. Triple constraint tetap penting, tetapi tidak cukup untuk menyatakan proyek berhasil. Hasil harus memenuhi kebutuhan, diterima dan digunakan, memberikan manfaat, memiliki kualitas layak, serta dapat dioperasikan secara berkelanjutan. Dalam kasus ini, pengguna menolak alur baru sehingga manfaat yang menjadi alasan investasi tidak terealisasi. Pilihan B hanya melihat keberhasilan administratif, pilihan C salah mengklasifikasikan proyek, dan pilihan D menganggap penambahan fitur sebagai syarat penilaian tanpa dasar.","whyOthersWrong":"B terlalu sempit; C mencampur proyek dengan operasi; D menggeser kriteria keberhasilan.","tip":"Tanyakan bukan hanya 'selesai?', tetapi 'dipakai dan memberi manfaat?'.","reference":"TM 1 — Keberhasilan Proyek; Schwalbe 9th Ed.; RPS MPSIA ASP4130.","keywords":"adopsi; manfaat; triple constraint"},{"number":18,"topic":"Process Groups dan Metodologi","subtopic":"Metodologi dan tailoring","learningOutcome":"Mengevaluasi tingkat kontrol sesuai karakter proyek.","difficulty":"Sulit","type":"Mini Kasus","question":"Proyek nasional berisiko tinggi memerlukan audit trail, baseline formal, dan CCB. Proyek perbaikan satu laporan internal memakai backlog sederhana dan persetujuan sponsor. Prinsip yang diterapkan adalah ...","options":["Gold plating","Tailoring","Scope creep","Fast tracking"],"correct":"B","concept":"Tailoring menyesuaikan proses dan kontrol dengan konteks.","explanation":"Jawaban B benar. Tailoring berarti menyesuaikan pendekatan, proses, dokumen, kontrol, dan alat dengan ukuran, kompleksitas, risiko, regulasi, budaya, dan kebutuhan stakeholder. Proyek nasional memerlukan kontrol lebih formal, sedangkan proyek kecil dapat memakai mekanisme yang lebih ringan tanpa kehilangan disiplin. Gold plating adalah penambahan fitur yang tidak diminta, scope creep adalah perluasan scope tanpa kontrol, dan fast tracking adalah kompresi jadwal melalui overlap. Tailoring bukan alasan menghapus pengendalian, melainkan memastikan pengelolaan proporsional.","whyOthersWrong":"A dan C berkaitan dengan scope; D adalah teknik kompresi jadwal.","tip":"Berbeda proyek, berbeda kadar proses—tetapi tetap terkontrol.","reference":"TM 3 — Metodologi dan Tailoring; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"tailoring; risiko; proporsional"},{"number":19,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Requirements Traceability Matrix","learningOutcome":"Menganalisis dampak perubahan kebutuhan.","difficulty":"Sulit","type":"Mini Kasus","question":"Pengguna mengubah aturan audit trail. Tim perlu mengetahui desain, kode, test case, dokumentasi, jadwal, dan biaya yang terdampak. Tindakan PERTAMA yang PALING tepat adalah ...","options":["Meminta pengembang langsung mengubah kode karena kebutuhannya penting.","Menelusuri kebutuhan melalui RTM lalu memproses dampaknya melalui change control.","Menghapus kebutuhan lama dan membuat nomor kebutuhan baru tanpa riwayat.","Menunda seluruh proyek sampai pengguna menyetujui kembali seluruh scope."],"correct":"B","concept":"RTM menghubungkan kebutuhan dengan artefak dan pengujian.","explanation":"Jawaban B benar. Requirements Traceability Matrix menghubungkan kebutuhan dengan alasan bisnis, sumber, desain, deliverable, test case, status, dan penerimaan. Ketika aturan audit trail berubah, RTM membantu memetakan artefak yang terdampak sebelum keputusan perubahan dibuat. Setelah dampak scope, jadwal, biaya, kualitas, dan risiko dianalisis, perubahan diproses melalui change control. Pilihan A memicu perubahan tidak terkendali, pilihan C menghilangkan audit trail, dan pilihan D tidak proporsional.","whyOthersWrong":"A melewati analisis; C menghilangkan keterlacakan; D menghentikan proyek secara berlebihan.","tip":"Perubahan kebutuhan: telusuri dulu, analisis, baru putuskan.","reference":"TM 5 — Requirements Documentation dan RTM; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"RTM; traceability; change impact"},{"number":20,"topic":"Manajemen Jadwal Proyek","subtopic":"Schedule compression","learningOutcome":"Memilih teknik kompresi jadwal.","difficulty":"Sulit","type":"Mini Kasus","question":"Tanggal go-live harus maju. Aktivitas pada critical path dapat dibuat tumpang tindih, tetapi risiko rework meningkat jika hasil predecessor berubah. Teknik yang digunakan adalah ...","options":["Resource smoothing","Crashing","Fast tracking","Rolling wave planning"],"correct":"C","concept":"Fast tracking menumpangtindihkan aktivitas yang semula berurutan.","explanation":"Jawaban C benar. Fast tracking mempercepat jadwal dengan menjalankan aktivitas yang semula berurutan secara tumpang tindih. Teknik ini dapat mengurangi durasi, tetapi meningkatkan risiko rework karena successor dimulai sebelum predecessor selesai sepenuhnya. Crashing menambah sumber daya atau biaya untuk mengurangi durasi. Resource smoothing menyesuaikan penggunaan sumber daya dalam batas float, sedangkan rolling wave planning merinci pekerjaan dekat dan mempertahankan pekerjaan jauh pada tingkat tinggi. Kompresi harus difokuskan pada jalur kritis dan dihitung ulang.","whyOthersWrong":"A adalah penyesuaian sumber daya; B menambah sumber daya/biaya; D adalah perencanaan bertahap.","tip":"Overlap = fast tracking; tambah sumber daya/biaya = crashing.","reference":"TM 6 — Crashing dan Fast Tracking; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"overlap; rework; critical path"},{"number":21,"topic":"Manajemen Integrasi Proyek","subtopic":"Risk dan issue","learningOutcome":"Membedakan risiko dan masalah aktual.","difficulty":"Mudah","type":"Perbandingan","question":"Perbedaan risk dan issue yang benar adalah ...","options":["Risk belum pasti terjadi, sedangkan issue sudah terjadi atau sedang terjadi.","Risk selalu negatif, sedangkan issue selalu memiliki dampak positif.","Risk dicatat setelah kejadian, sedangkan issue hanya dicatat sebelum kejadian.","Risk dikelola vendor, sedangkan issue hanya boleh dikelola sponsor."],"correct":"A","concept":"Risk adalah ketidakpastian; issue adalah masalah aktual.","explanation":"Jawaban A benar. Risk merupakan peristiwa atau kondisi yang belum pasti terjadi dan dapat berdampak positif atau negatif. Issue adalah masalah yang telah terjadi atau sedang berlangsung serta membutuhkan tindakan. Contoh: 'vendor mungkin terlambat' adalah risiko; 'vendor telah melewati tanggal pengiriman' adalah issue. Pilihan B salah karena risiko tidak selalu negatif. Pilihan C membalik waktu pencatatan, sedangkan pilihan D membatasi tanggung jawab tanpa dasar. Pemisahan ini penting agar respons risiko dan penanganan issue tidak tertukar.","whyOthersWrong":"B salah mengenai dampak; C membalik urutan; D membuat pembagian tanggung jawab yang tidak berlaku umum.","tip":"Mungkin terjadi = risk; sudah terjadi = issue.","reference":"TM 4 — Direct and Manage Project Work; PMBOK Guide 6th Ed.","keywords":"uncertainty; event occurred"},{"number":22,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Control Quality dan Validate Scope","learningOutcome":"Membedakan verifikasi teknis dan penerimaan formal.","difficulty":"Mudah","type":"Perbandingan","question":"Hubungan Control Quality dan Validate Scope yang PALING tepat adalah ...","options":["Validate Scope memeriksa kode, sedangkan Control Quality menandatangani penerimaan sponsor.","Keduanya hanya dilakukan pada akhir proyek setelah seluruh modul selesai.","Control Quality memverifikasi spesifikasi; Validate Scope memperoleh penerimaan formal dari pihak berwenang.","Control Quality mengendalikan perubahan scope; Validate Scope menyusun requirements."],"correct":"C","concept":"Kualitas memverifikasi; scope memvalidasi penerimaan.","explanation":"Jawaban C benar. Control Quality memeriksa apakah deliverable memenuhi spesifikasi dan standar teknis sehingga menjadi verified deliverable. Validate Scope kemudian meminta customer atau sponsor yang berwenang menerima hasil tersebut secara formal sehingga menjadi accepted deliverable. Pilihan A membalik fungsi, pilihan B salah karena validasi dapat dilakukan per deliverable atau fase, dan pilihan D mencampur proses dengan Control Scope serta Collect Requirements. Cara cepat membedakan: benar secara teknis belum otomatis berarti diterima pemilik kebutuhan.","whyOthersWrong":"A membalik fungsi; B membatasi waktu secara keliru; D mencampur proses scope lainnya.","tip":"Quality bertanya 'sesuai spesifikasi?'; Validate Scope bertanya 'diterima?'.","reference":"TM 5 — Validate Scope, Control Scope, dan Control Quality; PMBOK Guide 6th Ed.","keywords":"verified deliverable; accepted deliverable"},{"number":23,"topic":"Manajemen Biaya Proyek","subtopic":"Contingency dan management reserve","learningOutcome":"Membedakan dua jenis cadangan.","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan contingency reserve dan management reserve yang benar adalah ...","options":["Keduanya berada di luar project budget dan tidak boleh digunakan.","Contingency untuk risiko teridentifikasi dan masuk baseline; management reserve di luar baseline tetapi masuk project budget.","Contingency hanya untuk biaya tetap; management reserve hanya untuk biaya variabel.","Contingency ditambahkan setelah proyek selesai; management reserve dihapus saat perencanaan."],"correct":"B","concept":"Posisi cadangan berbeda terhadap cost baseline.","explanation":"Jawaban B benar. Contingency reserve disediakan untuk risiko yang telah diidentifikasi atau known-unknowns dan menjadi bagian cost baseline. Management reserve disediakan untuk ketidakpastian yang belum dapat dirinci atau unknown-unknowns, berada di luar cost baseline, tetapi termasuk project budget. Pilihan A salah karena kedua cadangan merupakan bagian pendanaan proyek dengan aturan penggunaan. Pilihan C tidak berkaitan dengan klasifikasi fixed-variable, dan pilihan D membalik waktu serta fungsi cadangan.","whyOthersWrong":"A meniadakan fungsi cadangan; C memakai klasifikasi biaya yang berbeda; D salah urutan.","tip":"Known risk masuk baseline; unknown uncertainty di luar baseline.","reference":"TM 7 — Contingency Reserve dan Management Reserve; PMBOK Guide 6th Ed.","keywords":"known-unknowns; unknown-unknowns; baseline"},{"number":24,"topic":"Manajemen Jadwal Proyek","subtopic":"Critical path dan keputusan kompresi","learningOutcome":"Mengevaluasi aktivitas yang layak dipercepat.","difficulty":"Sulit","type":"Analisis","question":"Network memiliki jalur A-B-D-E-F = 18 hari dan A-C-E-F = 13 hari. Usulan mengurangi durasi C dua hari tidak mengubah dependensi lain. Kesimpulan yang PALING tepat adalah ...","options":["Durasi proyek turun dua hari karena setiap aktivitas yang dipercepat mengurangi tanggal akhir.","Jalur A-C-E-F menjadi critical path baru dengan durasi 11 hari.","Critical path tidak relevan selama sponsor menyetujui biaya kompresi.","Tanggal akhir belum berubah; kompresi harus difokuskan pada aktivitas jalur 18 hari dan network dihitung ulang."],"correct":"D","concept":"Mempercepat aktivitas nonkritis belum tentu mempercepat proyek.","explanation":"Jawaban D benar. Jalur terpanjang adalah A-B-D-E-F dengan 18 hari sehingga menentukan tanggal selesai proyek. Jalur A-C-E-F berdurasi 13 hari dan memiliki kelonggaran lima hari relatif terhadap jalur kritis. Mengurangi C dua hari hanya memperbesar kelonggaran jalur nonkritis; tanggal proyek tetap 18 hari. Untuk mempercepat proyek, tim harus menilai aktivitas pada jalur kritis, memilih crashing atau fast tracking yang layak, lalu menghitung ulang network karena critical path dapat berubah.","whyOthersWrong":"A menganggap semua kompresi efektif; B salah karena jalur makin pendek; C mengabaikan logika jadwal.","tip":"Sebelum mempercepat, tandai jalur terpanjang dan float.","reference":"TM 6 — Critical Path Method dan Schedule Compression; PMBOK Guide 6th Ed.","keywords":"critical path; float; compression"},{"number":25,"topic":"Manajemen Biaya Proyek","subtopic":"Earned Value Management","learningOutcome":"Menganalisis kinerja dan forecast biaya.","difficulty":"Sulit","type":"Analisis","question":"BAC Rp6 miliar, PV Rp3 miliar, EV Rp2,4 miliar, dan AC Rp3 miliar. Jika efisiensi biaya saat ini berlanjut, interpretasi yang benar adalah ...","options":["CPI = 0,80; SPI = 0,80; proyek over budget dan tertinggal; EAC = Rp7,5 miliar.","CPI = 1,25; SPI = 1,25; proyek under budget dan lebih maju; EAC = Rp4,8 miliar.","CPI = 0,80; SPI = 1,25; proyek over budget tetapi lebih maju; EAC = Rp6 miliar.","CPI = 1,00; SPI = 0,80; biaya sesuai anggaran; EAC tidak dapat dihitung."],"correct":"A","concept":"CPI = EV/AC; SPI = EV/PV; EAC = BAC/CPI.","explanation":"Jawaban A benar. CPI = EV/AC = 2,4/3,0 = 0,80, sehingga setiap Rp1 yang dibelanjakan hanya menghasilkan Rp0,80 nilai pekerjaan; proyek tidak efisien atau over budget. SPI = EV/PV = 2,4/3,0 = 0,80, sehingga progres nilai pekerjaan hanya 80% dari rencana dan proyek tertinggal. Jika pola efisiensi biaya berlanjut, EAC = BAC/CPI = 6/0,80 = Rp7,5 miliar. EVM menunjukkan gejala kinerja, tetapi tim tetap harus menganalisis penyebab.","whyOthersWrong":"B membalik pembagian; C salah menghitung SPI; D mengabaikan varians biaya dan forecast.","tip":"Indeks di bawah 1 = tidak baik; EAC umum = BAC ÷ CPI.","reference":"TM 7 — Earned Value Management; PMBOK Guide 6th Ed.; Schwalbe 9th Ed.","keywords":"CPI; SPI; EAC; EVM"}],"flashcards":[{"number":1,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Proyek","difficulty":"Mudah","type":"Definisi","question":"Apa definisi proyek?","shortAnswer":"Upaya sementara untuk menghasilkan produk, layanan, kemampuan, atau hasil yang unik.","explanation":"Sementara berarti proyek memiliki awal dan kondisi akhir yang jelas, bukan berarti harus berlangsung singkat. Unik berarti terdapat kombinasi kebutuhan, pengguna, teknologi, lokasi, regulasi, atau cara penerapan yang membedakannya dari pekerjaan rutin.","example":"Implementasi SIA terintegrasi selama 18 bulan merupakan proyek; pemrosesan transaksi harian setelah go-live merupakan operasi.","keywords":"temporary; unique; tujuan","comparison":"Operasi — kegiatan rutin dan berulang tanpa garis akhir proyek.","mnemonic":"Proyek = Punya tujuan, Perubahan, dan Penutupan."},{"number":2,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Stakeholder","difficulty":"Mudah","type":"Definisi","question":"Siapa yang disebut stakeholder proyek?","shortAnswer":"Pihak yang dapat memengaruhi, dipengaruhi, atau merasa terdampak oleh proyek.","explanation":"Stakeholder tidak terbatas pada anggota tim. Sponsor, pengguna, pemilik proses, auditor, regulator, vendor, unit keamanan, pimpinan, dan pihak yang menolak proyek dapat menjadi stakeholder apabila memiliki kepentingan, pengaruh, atau dampak yang perlu dikelola.","example":"Auditor internal dapat menjadi stakeholder karena memerlukan audit trail, walaupun tidak mengembangkan sistem.","keywords":"pengaruh; kepentingan; dampak","comparison":"Tim proyek — hanya salah satu kelompok stakeholder yang mengerjakan deliverable.","mnemonic":"3P: Pengaruh, Penting, atau Punya dampak."},{"number":3,"topic":"System View, Organisasi, dan Daur Hidup","subtopic":"Systems approach","difficulty":"Mudah","type":"Definisi","question":"Apa inti systems approach pada proyek TI?","shortAnswer":"Melihat bisnis, organisasi, proses, data, manusia, dan teknologi sebagai unsur yang saling memengaruhi.","explanation":"Solusi teknis yang bagus dapat gagal apabila tidak cocok dengan proses bisnis, struktur kewenangan, budaya, kemampuan pengguna, regulasi, atau kesiapan data. Karena itu, keputusan proyek harus menilai dampak perubahan pada keseluruhan sistem organisasi.","example":"Dashboard selesai secara teknis, tetapi gagal dipakai karena SOP tidak diperbarui dan pengguna tidak dilatih.","keywords":"business; organization; technology","comparison":"Technology-only view — hanya menilai aplikasi, infrastruktur, dan kode.","mnemonic":"BOT: Business–Organization–Technology."},{"number":4,"topic":"Process Groups dan Metodologi","subtopic":"Process groups","difficulty":"Mudah","type":"Definisi","question":"Apa fungsi lima process groups?","shortAnswer":"Memberi alur berpikir untuk memulai, merencanakan, mengerjakan, mengendalikan, dan menutup proyek.","explanation":"Lima kelompoknya adalah Initiating, Planning, Executing, Monitoring and Controlling, serta Closing. Process groups bukan nama fase yang wajib; proses dari kelompok tersebut dapat muncul berulang pada berbagai fase proyek.","example":"Pada fase migrasi data tetap ada perencanaan, eksekusi, pengendalian, dan penutupan pekerjaan fase.","keywords":"initiate; plan; execute; control; close","comparison":"Project life cycle — rangkaian fase dari awal sampai proyek selesai.","mnemonic":"I-P-E-M-C: Izin, Peta, Eksekusi, Monitor, Close."},{"number":5,"topic":"Manajemen Integrasi Proyek","subtopic":"Project charter","difficulty":"Mudah","type":"Definisi","question":"Apa fungsi project charter?","shortAnswer":"Memberi otorisasi formal kepada proyek dan project manager serta menetapkan arah tingkat tinggi.","explanation":"Charter menghubungkan proyek dengan tujuan organisasi dan umumnya memuat tujuan, high-level scope, milestone, anggaran awal, risiko utama, sponsor, stakeholder kunci, dan kewenangan project manager. Charter bukan rencana proyek lengkap.","example":"Charter proyek SIA menetapkan target konsolidasi tiga hari, anggaran awal, sponsor, target go-live, dan otoritas PM.","keywords":"otorisasi; sponsor; high-level","comparison":"Project management plan — menjelaskan cara proyek dilaksanakan, dipantau, dikendalikan, dan ditutup.","mnemonic":"Charter = cap resmi untuk mulai."},{"number":6,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"WBS","difficulty":"Mudah","type":"Definisi","question":"Apa itu Work Breakdown Structure (WBS)?","shortAnswer":"Penguraian hierarkis seluruh ruang lingkup pekerjaan proyek yang berorientasi pada deliverable.","explanation":"WBS mencakup 100% pekerjaan dalam scope. Decomposition dihentikan ketika komponen cukup jelas untuk diestimasi, dijadwalkan, diberi tanggung jawab, dipantau, dan dikendalikan. Tingkat terendah yang dikelola disebut work package.","example":"SIA → Analisis Kebutuhan → Workshop → Dokumen Kebutuhan → Review dan Persetujuan.","keywords":"decomposition; deliverable; work package","comparison":"Activity list — daftar kegiatan dan urutan pelaksanaan, bukan struktur deliverable.","mnemonic":"WBS = Work Broken into Smaller deliverables."},{"number":7,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Progressive elaboration","difficulty":"Mudah","type":"Istilah","question":"Apa arti progressive elaboration?","shortAnswer":"Rencana dan informasi proyek diperinci secara bertahap ketika pemahaman bertambah.","explanation":"Rencana awal dibuat menggunakan informasi terbaik yang tersedia, lalu diperbarui secara terkendali. Konsep ini bukan izin untuk bekerja tanpa rencana dan bukan berarti baseline dapat diubah sesuka hati.","example":"Estimasi migrasi awal berupa rentang, kemudian diperinci setelah profil kualitas data diketahui.","keywords":"bertahap; informasi; kontrol","comparison":"Scope creep — penambahan scope tanpa persetujuan dan penyesuaian resmi.","mnemonic":"Makin tahu, makin rinci—tetap melalui kontrol."},{"number":8,"topic":"Manajemen Jadwal Proyek","subtopic":"Milestone","difficulty":"Mudah","type":"Istilah","question":"Apa itu milestone dalam jadwal proyek?","shortAnswer":"Titik pencapaian atau keputusan penting yang memiliki durasi nol.","explanation":"Milestone menandai peristiwa seperti charter disetujui, desain dibekukan, UAT selesai, atau go-live. Milestone membantu komunikasi dan pemantauan, tetapi tidak menggantikan aktivitas yang menghasilkan pencapaian tersebut.","example":"UAT selesai adalah milestone; pelaksanaan UAT selama sepuluh hari adalah aktivitas.","keywords":"titik; durasi nol; pencapaian","comparison":"Aktivitas — pekerjaan yang memerlukan durasi dan sumber daya.","mnemonic":"Milestone = penanda kilometer, bukan perjalanan."},{"number":9,"topic":"Manajemen Integrasi Proyek","subtopic":"Project management plan","difficulty":"Sedang","type":"Istilah","question":"Apa yang dijelaskan oleh project management plan?","shortAnswer":"Bagaimana proyek dilaksanakan, dipantau, dikendalikan, dan ditutup.","explanation":"PMP mengintegrasikan subsidiary plans dan baseline, misalnya scope, schedule, cost, quality, resource, communication, risk, procurement, stakeholder, change management, dan configuration management. Tingkat detailnya disesuaikan dengan kebutuhan proyek.","example":"PMP menetapkan aturan baseline, toleransi varians, mekanisme CCB, format laporan, dan tata kelola risiko.","keywords":"aturan main; baseline; subsidiary plans","comparison":"Project charter — memberi izin dan arah awal, bukan prosedur pengelolaan rinci.","mnemonic":"Charter = izin; PMP = aturan main."},{"number":10,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Requirements Traceability Matrix","difficulty":"Sedang","type":"Istilah","question":"Untuk apa Requirements Traceability Matrix (RTM) digunakan?","shortAnswer":"Menelusuri setiap kebutuhan ke alasan bisnis, sumber, desain, deliverable, test case, status, dan penerimaan.","explanation":"RTM membantu memastikan kebutuhan tidak hilang, telah diwujudkan, dan telah diuji. Ketika kebutuhan berubah, tim dapat melihat artefak, jadwal, biaya, dokumentasi, dan pengujian yang ikut terdampak.","example":"R-02 audit trail dihubungkan dengan desain database, modul jurnal, test case TC-083, dan persetujuan auditor.","keywords":"traceability; requirement; test","comparison":"Requirements documentation — mencatat isi kebutuhan; RTM menelusuri hubungan kebutuhan.","mnemonic":"RTM = Requirement punya Track Map."},{"number":11,"topic":"Manajemen Biaya Proyek","subtopic":"Cost baseline","difficulty":"Sedang","type":"Istilah","question":"Apa yang termasuk dalam cost baseline?","shortAnswer":"Estimasi biaya yang disetujui dan contingency reserve, disusun bertahap waktu.","explanation":"Cost baseline menjadi acuan resmi untuk mengukur kinerja biaya. Management reserve tidak termasuk baseline, tetapi menjadi bagian project budget. Karena itu, EVM membandingkan kinerja terhadap baseline, bukan seluruh anggaran yang mencakup management reserve.","example":"Estimasi Rp5,4 miliar + contingency Rp0,54 miliar menghasilkan baseline Rp5,94 miliar.","keywords":"time-phased; contingency; performance","comparison":"Project budget — cost baseline ditambah management reserve.","mnemonic":"Baseline = biaya kerja + cadangan risiko yang dikenali."},{"number":12,"topic":"Process Groups dan Metodologi","subtopic":"Urutan process groups","difficulty":"Sedang","type":"Tahapan","question":"Sebutkan urutan logis lima process groups.","shortAnswer":"Initiating → Planning → Executing → Monitoring and Controlling → Closing.","explanation":"Urutan tersebut merupakan alur berpikir, bukan rangkaian kaku satu arah. Monitoring and Controlling memberi umpan balik ke planning dan executing. Setiap fase dapat memiliki proses untuk memulai, merencanakan, mengerjakan, mengendalikan, dan menutup pekerjaan fase.","example":"Proyek SIA: charter → rencana → pembangunan → pengukuran varians → serah terima.","keywords":"I; P; E; M&C; C","comparison":"Fase proyek — dapat bernama analisis, desain, pembangunan, dan implementasi.","mnemonic":"Izin–Peta–Eksekusi–Monitor–Close."},{"number":13,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"Proses scope management","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan enam proses scope management?","shortAnswer":"Plan Scope Management → Collect Requirements → Define Scope → Create WBS → Validate Scope → Control Scope.","explanation":"Alur dimulai dengan menetapkan cara scope dikelola, menggali kebutuhan, memperjelas batas, memecah pekerjaan, memperoleh penerimaan formal, lalu memantau scope dan perubahan baseline. Validate dan Control tidak boleh tertukar.","example":"Kebutuhan laporan digali, dimasukkan scope, dipecah dalam WBS, diuji, diterima, dan perubahannya dikendalikan.","keywords":"plan; collect; define; WBS; validate; control","comparison":"Control Quality — memverifikasi spesifikasi teknis, bukan penerimaan formal.","mnemonic":"Rencana–Kumpulkan–Definisikan–Pecah–Terima–Kendalikan."},{"number":14,"topic":"Manajemen Integrasi Proyek","subtopic":"Integrated Change Control","difficulty":"Sulit","type":"Tahapan","question":"Apa urutan pengendalian perubahan terintegrasi?","shortAnswer":"Catat → analisis dampak → keputusan berwenang → perbarui acuan → implementasi → verifikasi.","explanation":"Permintaan perubahan harus dinilai terhadap scope, jadwal, biaya, kualitas, sumber daya, risiko, kontrak, manfaat, dan stakeholder. Jika disetujui, baseline dan dokumen diperbarui serta dikomunikasikan sebelum perubahan dijalankan.","example":"Fitur baru dicatat, dianalisis, diputuskan CCB, baseline diperbarui, dikembangkan, lalu hasilnya diuji.","keywords":"change request; CCB; baseline","comparison":"Scope creep — perubahan dikerjakan tanpa analisis dan persetujuan resmi.","mnemonic":"C-A-P-U-I-V: Catat, Analisis, Putuskan, Update, Implementasi, Verifikasi."},{"number":15,"topic":"Manajemen Jadwal Proyek","subtopic":"Forward dan backward pass","difficulty":"Sulit","type":"Tahapan","question":"Bagaimana urutan perhitungan CPM?","shortAnswer":"Forward pass untuk ES/EF → tentukan durasi proyek → backward pass untuk LF/LS → hitung float.","explanation":"Forward pass bergerak dari awal dan memakai EF terbesar bila predecessor lebih dari satu. Backward pass bergerak dari akhir dan memakai LS terkecil bila successor lebih dari satu. Total float = LS − ES = LF − EF.","example":"Jika ES=3, durasi=5, maka EF=8. Jika LS=8, total float=5.","keywords":"ES; EF; LS; LF; float","comparison":"PERT — mengestimasi durasi dengan O, M, dan P; bukan menghitung network pass.","mnemonic":"Maju cari awal; mundur cari batas; selisihnya float."},{"number":16,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Proyek versus operasi","difficulty":"Sedang","type":"Perbandingan","question":"Apa pembeda utama proyek dan operasi?","shortAnswer":"Proyek menciptakan perubahan unik dan berakhir; operasi menjaga layanan rutin agar terus berjalan.","explanation":"Keduanya sama-sama memerlukan orang, biaya, perencanaan, dan kontrol. Pembeda terletak pada arah dan keberlanjutan pekerjaan. Hasil proyek biasanya diserahkan kepada unit operasi untuk digunakan dan dipelihara.","example":"Membangun modul payroll adalah proyek; menjalankan payroll tiap bulan adalah operasi.","keywords":"perubahan; rutin; serah terima","comparison":"Pekerjaan berulang dapat muncul di dalam proyek, tetapi keseluruhan proyek tetap memiliki tujuan unik dan akhir.","mnemonic":"Proyek membangun rumah; operasi menempati dan merawatnya."},{"number":17,"topic":"System View, Organisasi, dan Daur Hidup","subtopic":"Life cycle dan process groups","difficulty":"Sulit","type":"Perbandingan","question":"Bedakan project life cycle, product life cycle, dan process groups.","shortAnswer":"Project life cycle = perjalanan satu proyek; product life cycle = umur produk; process groups = tujuan proses manajemen.","explanation":"Satu produk dapat melalui banyak proyek pengembangan dan upgrade. Dalam tiap fase proyek dapat terjadi initiating, planning, executing, monitoring and controlling, serta closing. Karena itu, process groups tidak otomatis sama dengan fase.","example":"Proyek membangun SIA berakhir saat serah terima; produk SIA dipelihara dan di-upgrade bertahun-tahun.","keywords":"project; product; process","comparison":"Fase — bagian perjalanan proyek dengan deliverable dan keputusan tertentu.","mnemonic":"Proyek = satu perjalanan; produk = umur panjang; process = cara mengelola."},{"number":18,"topic":"Manajemen Integrasi Proyek","subtopic":"Risk versus issue","difficulty":"Sedang","type":"Perbandingan","question":"Bagaimana membedakan risk dan issue?","shortAnswer":"Risk belum pasti terjadi; issue sudah terjadi atau sedang berlangsung.","explanation":"Risk dikelola melalui identifikasi, analisis, pemilik, dan respons sebelum kejadian. Issue membutuhkan penyelesaian aktual, eskalasi, dan tindak lanjut. Risk dapat memberi dampak positif atau negatif.","example":"Vendor mungkin terlambat = risk; vendor melewati tanggal pengiriman = issue.","keywords":"uncertainty; actual problem","comparison":"Change request — usulan perubahan terhadap deliverable, baseline, atau dokumen.","mnemonic":"R = Risiko masih Ramalan; I = Issue sudah In terjadi."},{"number":19,"topic":"Manajemen Biaya Proyek","subtopic":"Jenis cadangan","difficulty":"Sulit","type":"Perbandingan","question":"Bedakan contingency reserve dan management reserve.","shortAnswer":"Contingency untuk risiko teridentifikasi dan masuk baseline; management reserve untuk ketidakpastian belum terinci dan di luar baseline.","explanation":"Keduanya bukan uang bebas. Penggunaannya harus mengikuti kewenangan dan dokumentasi. Cost baseline ditambah management reserve membentuk project budget, sedangkan pengukuran kinerja biaya dilakukan terhadap baseline.","example":"Risiko variasi kualitas data memakai contingency; gangguan tak terduga tingkat organisasi dapat memerlukan management reserve.","keywords":"known-unknown; unknown-unknown; reserve","comparison":"Sunk cost — biaya masa lalu yang tidak dapat dipulihkan dan tidak seharusnya menentukan keputusan masa depan.","mnemonic":"C = Confirmed risk; M = Mystery uncertainty."},{"number":20,"topic":"Manajemen Jadwal Proyek","subtopic":"PERT","difficulty":"Sedang","type":"Penerapan","question":"Bagaimana menghitung expected duration PERT?","shortAnswer":"TE = (O + 4M + P) / 6.","explanation":"O adalah optimistic, M most likely, dan P pessimistic. Bobot empat diberikan kepada M. Standar deviasi dapat dihitung dengan SD = (P − O) / 6 untuk membaca ketidakpastian estimasi.","example":"O=4, M=7, P=16 → TE=(4+28+16)/6=8 hari; SD=(16−4)/6=2 hari.","keywords":"O; M; P; 1-4-1","comparison":"Analogous estimating — memakai durasi pekerjaan serupa tanpa tiga skenario.","mnemonic":"PERT memakai sandwich 1–4–1."},{"number":21,"topic":"Manajemen Jadwal Proyek","subtopic":"Critical path dan float","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menentukan critical path dan total float?","shortAnswer":"Critical path adalah jalur berdurasi total terpanjang; TF = LS − ES = LF − EF.","explanation":"Jalur kritis menentukan tanggal selesai tercepat berdasarkan network saat ini. Aktivitas kritis umumnya memiliki total float nol atau sangat kecil. Critical path dapat berubah setelah durasi, logika, progres, atau sumber daya diperbarui.","example":"Jika jalur A-B-D-E-F =18 hari dan A-C-E-F=13 hari, jalur pertama kritis; jalur kedua memiliki kelonggaran lima hari.","keywords":"longest path; total float","comparison":"Jalur dengan aktivitas terbanyak atau biaya terbesar belum tentu critical path.","mnemonic":"Kritis = paling panjang waktunya, bukan paling ramai aktivitasnya."},{"number":22,"topic":"Manajemen Biaya Proyek","subtopic":"EVM","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana membaca CPI, SPI, dan EAC?","shortAnswer":"CPI=EV/AC; SPI=EV/PV; EAC umum=BAC/CPI bila efisiensi biaya berlanjut.","explanation":"Indeks di atas satu menunjukkan kondisi lebih baik, sama dengan satu sesuai rencana, dan di bawah satu menunjukkan masalah. CPI membaca efisiensi biaya, sedangkan SPI membaca kemajuan nilai pekerjaan terhadap rencana.","example":"EV=2,4; AC=3; PV=3; BAC=6 → CPI=0,8; SPI=0,8; EAC=7,5 miliar.","keywords":"PV; EV; AC; CPI; SPI","comparison":"CV dan SV adalah selisih uang: CV=EV−AC; SV=EV−PV.","mnemonic":"Indeks = Earned dibagi pembanding; <1 berarti tertinggal."},{"number":23,"topic":"Dasar Proyek dan Manajemen Proyek","subtopic":"Keberhasilan proyek","difficulty":"Sedang","type":"Mini Kasus","question":"Kasus: proyek tepat waktu dan anggaran, tetapi sistem tidak dipakai. Berhasilkah?","shortAnswer":"Keberhasilannya lemah karena adopsi dan manfaat bisnis tidak tercapai.","explanation":"Keberhasilan harus menilai kualitas, penerimaan, penggunaan, manfaat, dukungan strategi, risiko, dan keberlanjutan operasi—bukan hanya scope, waktu, dan biaya. Triple constraint adalah indikator penting, tetapi bukan satu-satunya ukuran.","example":"Pegawai kembali ke spreadsheet karena alur sistem terlalu rumit.","keywords":"adopsi; benefit realization; success","comparison":"Keberhasilan administratif — hanya melihat kesesuaian scope, jadwal, dan anggaran.","mnemonic":"Selesai belum tentu berhasil; manfaat harus terasa."},{"number":24,"topic":"Manajemen Ruang Lingkup Proyek","subtopic":"RTM dan perubahan kebutuhan","difficulty":"Sulit","type":"Mini Kasus","question":"Kasus: aturan audit trail berubah. Apa langkah awal yang tepat?","shortAnswer":"Gunakan RTM untuk menelusuri dampak, lalu proses perubahan melalui change control.","explanation":"Tim harus mengetahui desain, kode, test case, dokumentasi, jadwal, biaya, dan risiko yang terdampak. Langsung mengubah kode akan menciptakan perubahan tidak terkendali dan berpotensi meninggalkan artefak yang tidak konsisten.","example":"R-02 ditelusuri ke database, modul jurnal, TC-083, manual pengguna, dan acceptance criteria.","keywords":"traceability; impact; change control","comparison":"Scope creep — perubahan dikerjakan tanpa analisis, persetujuan, pendanaan, dan pembaruan baseline.","mnemonic":"Telusuri sebelum mengubah."},{"number":25,"topic":"Process Groups dan Metodologi","subtopic":"Tailoring","difficulty":"Sedang","type":"Mini Kasus","question":"Kasus: proyek nasional memakai CCB formal, proyek kecil memakai persetujuan sponsor. Konsep apa?","shortAnswer":"Tailoring—menyesuaikan proses dan kontrol dengan ukuran, risiko, kompleksitas, serta regulasi proyek.","explanation":"Tailoring menjaga keseimbangan antara kontrol yang cukup dan birokrasi yang tidak perlu. Proyek kecil tetap membutuhkan disiplin, tetapi tidak harus menyalin seluruh dokumen dan mekanisme proyek besar.","example":"Proyek nasional memakai baseline rinci dan audit trail; perbaikan laporan memakai backlog dan change log sederhana.","keywords":"proporsional; konteks; metodologi","comparison":"Menghapus kontrol — bukan tailoring karena membuat proyek kehilangan disiplin dan keterlacakan.","mnemonic":"Ukuran baju proses harus pas dengan proyek."}]},"metopen":{"id":"metopen","title":"Metodologi Penelitian","short":"Metodologi Penelitian","konsen":["gabungan"],"quiz":[{"number":1,"topic":"Fondasi Penelitian","subtopic":"Ciri penelitian ilmiah","learningOutcome":"Mengidentifikasi karakteristik utama penelitian ilmiah","difficulty":"Mudah","type":"Definisi","question":"Karakteristik yang PALING membedakan penelitian ilmiah dari pencarian informasi biasa adalah ...","options":["mengumpulkan sebanyak mungkin informasi dari berbagai media","menggunakan proses sistematis, berbasis data, dan diarahkan oleh tujuan yang jelas","memilih jawaban yang paling sesuai dengan pengalaman peneliti","menghasilkan kesimpulan yang selalu dapat diterapkan pada semua situasi"],"correct":"B","concept":"Penelitian ilmiah","explanation":"Jawaban B benar karena penelitian ilmiah tidak cukup hanya mengumpulkan informasi. Penelitian harus memiliki tujuan yang dinyatakan jelas, langkah yang terencana, data yang dikumpulkan dan dianalisis secara sistematis, serta kesimpulan yang dapat ditelusuri ke bukti. Pengalaman peneliti dapat membantu membentuk pertanyaan, tetapi tidak boleh menggantikan prosedur dan data. Kesimpulan ilmiah juga tidak otomatis berlaku universal; tingkat generalisasi bergantung pada desain, sampel, konteks, dan kualitas bukti.","whyOthersWrong":"A hanya menggambarkan pencarian informasi. C menempatkan pengalaman sebagai dasar keputusan. D mengabaikan batas konteks dan generalisasi.","tip":"Cari kata yang menekankan proses, bukti, dan tujuan; bukan sekadar banyaknya informasi.","reference":"TM 1; RPS Sub-CPMK 1; Saunders et al. (2019), Bab 1","keywords":"sistematis; berbasis data; tujuan"},{"number":2,"topic":"Paradigma Penelitian","subtopic":"Ontologi","learningOutcome":"Menjelaskan asumsi ontologis dalam penelitian","difficulty":"Mudah","type":"Definisi","question":"Dalam filsafat penelitian, ontologi terutama membahas ...","options":["asumsi mengenai hakikat realitas dan apa yang dianggap ada","teknik statistik yang digunakan untuk menguji hipotesis","cara menyusun daftar pustaka dan sitasi ilmiah","nilai moral yang harus dipatuhi peneliti"],"correct":"A","concept":"Ontologi","explanation":"Jawaban A benar. Ontologi menanyakan seperti apa realitas yang diteliti: apakah dianggap tunggal dan berada di luar peneliti, atau jamak serta dibentuk melalui pengalaman dan interaksi sosial. Jawaban atas pertanyaan ontologis memengaruhi apa yang dipandang sebagai fenomena yang sah untuk diteliti. Teknik statistik berada pada tingkat metode, sitasi berkaitan dengan penulisan akademik, sedangkan nilai dan etika lebih dekat dengan aksiologi. Ontologi tidak menentukan metode secara kaku, tetapi membantu menjelaskan konsistensi pilihan penelitian.","whyOthersWrong":"B adalah teknik analisis. C adalah praktik akademik. D lebih dekat dengan aksiologi dan etika penelitian.","tip":"Ingat: ontologi = “apa yang nyata atau ada?”","reference":"TM 1; Saunders et al. (2019), Bab 4","keywords":"ontologi; realitas; asumsi"},{"number":3,"topic":"Fondasi Penelitian","subtopic":"Basic dan applied research","learningOutcome":"Membedakan penelitian dasar dan terapan","difficulty":"Mudah","type":"Definisi","question":"Penelitian yang dirancang untuk membantu sebuah instansi meningkatkan ketepatan waktu pembayaran pajak dalam tahun berjalan terutama termasuk ...","options":["penelitian dasar karena menggunakan konsep ilmiah","penelitian eksploratif karena selalu dilakukan sebelum survei","penelitian terapan karena berorientasi pada penyelesaian masalah praktis yang aktual","penelitian etnografi karena dilakukan dalam organisasi"],"correct":"C","concept":"Penelitian terapan","explanation":"Jawaban C benar karena penelitian terapan berfokus pada masalah aktual dan hasilnya diharapkan membantu pengambilan keputusan atau perbaikan praktik dalam waktu yang relevan. Penggunaan teori atau prosedur ilmiah tidak otomatis menjadikan penelitian sebagai penelitian dasar. Penelitian dasar lebih diarahkan pada pengembangan pemahaman atau teori yang lebih luas. Penelitian juga tidak otomatis eksploratif atau etnografis hanya karena dilakukan di organisasi. Klasifikasi dasar-terapan terutama dilihat dari tujuan dan orientasi manfaat penelitian.","whyOthersWrong":"A keliru karena semua penelitian dapat menggunakan konsep ilmiah. B tidak sesuai karena eksploratif adalah tujuan desain. D tidak sesuai karena etnografi mempelajari budaya/praktik secara mendalam.","tip":"Tanyakan: hasil penelitian terutama untuk memperluas pengetahuan atau menyelesaikan masalah sekarang?","reference":"TM 1; Merged PPT Pertemuan 1; Saunders et al. (2019), Bab 1","keywords":"applied research; masalah praktis"},{"number":4,"topic":"Strategi Penelitian","subtopic":"Strategi, metode, dan teknik","learningOutcome":"Menjelaskan pengertian strategi penelitian","difficulty":"Mudah","type":"Definisi","question":"Strategi penelitian PALING tepat dipahami sebagai ...","options":["rumus statistik yang dipakai untuk menganalisis data","instrumen khusus yang dipakai untuk memperoleh jawaban responden","format baku penulisan laporan hasil penelitian","rencana umum yang menghubungkan pertanyaan penelitian dengan cara memperoleh dan menganalisis bukti"],"correct":"D","concept":"Strategi penelitian","explanation":"Jawaban D benar karena strategi penelitian merupakan pendekatan menyeluruh untuk menjawab pertanyaan penelitian, misalnya eksperimen, survei, studi kasus, etnografi, atau action research. Strategi menjembatani tujuan, jenis bukti, konteks, waktu, dan cara analisis. Rumus statistik adalah teknik analisis, instrumen adalah alat pengumpulan data, dan format laporan merupakan aspek penyajian. Kesalahan umum adalah menyebut kuesioner sebagai strategi; kuesioner sebenarnya instrumen yang dapat digunakan dalam strategi survei atau strategi lain.","whyOthersWrong":"A adalah teknik analisis. B adalah instrumen. C adalah struktur pelaporan, bukan strategi.","tip":"Strategi berada di tingkat “rencana besar”; teknik dan instrumen berada di tingkat pelaksanaan.","reference":"TM 2; Saunders et al. (2019), Bab 5","keywords":"strategi; pertanyaan; bukti"},{"number":5,"topic":"Latar Belakang","subtopic":"Research gap","learningOutcome":"Menjelaskan makna research gap","difficulty":"Mudah","type":"Definisi","question":"Research gap yang kuat adalah ...","options":["kesenjangan pengetahuan yang ditunjukkan melalui sintesis literatur dan dijelaskan pentingnya untuk diteliti","pernyataan bahwa belum ada penelitian pada satu kantor tertentu","perbedaan pendapat pribadi antara peneliti dan pembimbing","daftar topik yang belum sempat dibahas dalam perkuliahan"],"correct":"A","concept":"Research gap","explanation":"Jawaban A benar. Research gap harus menunjukkan apa yang belum diketahui, belum konsisten, belum memadai secara teori atau metode, atau belum dipahami dalam konteks tertentu. Gap dibangun dari perbandingan beberapa sumber, bukan diumumkan tanpa bukti. Kalimat “belum pernah diteliti di Kantor X” baru bermakna jika konteks X memang dapat mengubah teori, mekanisme, metode, atau implikasi praktis. Gap juga harus dikaitkan dengan urgensi dan kontribusi penelitian agar tidak menjadi sekadar celah administratif.","whyOthersWrong":"B belum cukup tanpa alasan teoretis atau praktis. C bukan kesenjangan ilmiah. D tidak berkaitan dengan bukti literatur.","tip":"Gap = bukti kekurangan pengetahuan + alasan mengapa kekurangan itu penting.","reference":"TM 3; RPS Sub-CPMK 3; Saunders et al. (2019), Bab 2 dan 3","keywords":"research gap; sintesis; signifikansi"},{"number":6,"topic":"Strategi Penelitian","subtopic":"Deduksi dan induksi","learningOutcome":"Memahami hubungan teori dan data dalam pendekatan deduktif","difficulty":"Mudah","type":"Konseptual","question":"Urutan yang paling mencerminkan pendekatan deduktif adalah ...","options":["data → pola → konsep → teori","fenomena → wawancara → tema → proposisi sementara","teori → hipotesis → pengukuran → pengujian dengan data","masalah → tindakan → refleksi → siklus tindakan berikutnya"],"correct":"C","concept":"Pendekatan deduktif","explanation":"Jawaban C benar karena deduksi bergerak dari teori yang ada menuju prediksi atau hipotesis yang kemudian diuji dengan data. Data digunakan untuk menilai apakah pola yang diprediksi didukung. Pilihan A dan B lebih dekat dengan induksi, yaitu membangun konsep atau teori dari pola data. Pilihan D menggambarkan siklus action research. Deduksi tidak berarti peneliti harus menutup diri terhadap temuan tak terduga; hasil yang tidak sesuai dapat mendorong revisi teori atau penelitian lanjutan.","whyOthersWrong":"A dan B menggambarkan gerak induktif. D menggambarkan action research.","tip":"Deduksi: dari umum ke khusus—teori dulu, pengujian kemudian.","reference":"TM 2; Saunders et al. (2019), Bab 4","keywords":"deduksi; teori; hipotesis"},{"number":7,"topic":"Paradigma Penelitian","subtopic":"Paradigma dan metode","learningOutcome":"Menganalisis hubungan paradigma dengan pilihan metode","difficulty":"Sedang","type":"Konseptual","question":"Pernyataan yang PALING tepat mengenai hubungan paradigma dan metode adalah ...","options":["positivisme selalu mewajibkan eksperimen laboratorium","paradigma memandu asumsi dan konsistensi desain, tetapi tidak mengunci satu metode secara mutlak","interpretivisme tidak dapat menggunakan data numerik sama sekali","pragmatisme mengabaikan teori dan etika demi memperoleh hasil cepat"],"correct":"B","concept":"Keselarasan paradigma-metode","explanation":"Jawaban B benar. Paradigma menyediakan asumsi tentang realitas, pengetahuan, dan peran nilai, sehingga membantu peneliti memilih desain yang koheren. Namun, hubungan tersebut bukan aturan mekanis satu paradigma-satu metode. Positivisme sering terkait dengan pengukuran kuantitatif, tetapi tidak selalu menuntut eksperimen laboratorium. Interpretivisme dapat memakai angka sebagai data pendukung bila konsisten dengan tujuan pemaknaan. Pragmatisme memilih metode berdasarkan pertanyaan dan konsekuensi praktis, tetapi tetap memerlukan teori, kualitas bukti, dan etika.","whyOthersWrong":"A dan C terlalu absolut. D salah karena pragmatisme bukan pembenaran untuk mengabaikan teori atau etika.","tip":"Waspadai kata “selalu”, “hanya”, dan “tidak dapat”; paradigma memberi arah, bukan borgol metodologis.","reference":"TM 1–2; Saunders et al. (2019), Bab 4–5","keywords":"paradigma; metode; konsistensi"},{"number":8,"topic":"Strategi Penelitian","subtopic":"Case study","learningOutcome":"Memahami ciri studi kasus yang kuat","difficulty":"Sedang","type":"Konseptual","question":"Sebuah penelitian pada satu pemerintah daerah layak disebut case study yang kuat apabila ...","options":["menggunakan kuesioner kepada seluruh pegawai","hanya menampilkan profil organisasi secara rinci","memakai jumlah variabel yang lebih banyak daripada penelitian lain","menetapkan batas kasus, menganalisis konteks, dan menggunakan berbagai sumber bukti"],"correct":"D","concept":"Studi kasus","explanation":"Jawaban D benar. Studi kasus tidak ditentukan hanya oleh lokasi tunggal, melainkan oleh adanya kasus yang dibatasi secara jelas—misalnya program, organisasi, proses, atau peristiwa—serta analisis mendalam terhadap konteks. Penggunaan berbagai sumber bukti seperti wawancara, dokumen, observasi, dan data arsip memperkuat pemahaman dan triangulasi. Kuesioner dapat dipakai, tetapi tidak otomatis menjadikan penelitian sebagai case study. Profil organisasi dan banyaknya variabel juga tidak menggantikan logika desain kasus.","whyOthersWrong":"A hanya menyebut instrumen. B hanya deskripsi lokasi. C tidak berkaitan dengan logika studi kasus.","tip":"Cari tiga unsur: batas kasus, konteks, dan banyak sumber bukti.","reference":"TM 2; Saunders et al. (2019), Bab 5","keywords":"case boundary; konteks; triangulasi"},{"number":9,"topic":"Literatur","subtopic":"Sintesis literatur","learningOutcome":"Membedakan ringkasan artikel dan sintesis kritis","difficulty":"Sedang","type":"Konseptual","question":"Tinjauan literatur disebut sintesis ketika peneliti ...","options":["membandingkan pola, perbedaan, konteks, metode, dan makna temuan antarstudi untuk membangun argumen","menuliskan satu paragraf untuk setiap artikel berdasarkan urutan tahun","mengutip sebanyak mungkin definisi dari buku teks","memilih hanya penelitian yang mendukung hipotesis"],"correct":"A","concept":"Sintesis literatur","explanation":"Jawaban A benar karena sintesis mengintegrasikan temuan lintas sumber untuk menjawab pertanyaan yang lebih besar: di mana hasil konsisten, mengapa berbeda, konteks apa yang memengaruhi, dan apa yang belum diketahui. Menulis artikel satu per satu menghasilkan ringkasan, bukan sintesis. Banyak kutipan definisi juga tidak otomatis menghasilkan argumen. Memilih hanya studi yang mendukung posisi peneliti menimbulkan confirmation bias. Tinjauan kritis harus transparan terhadap bukti yang mendukung maupun yang menantang.","whyOthersWrong":"B bersifat deskriptif artikel-per-artikel. C menumpuk definisi. D menciptakan bias seleksi.","tip":"Sintesis menjawab hubungan antarstudi, bukan sekadar isi masing-masing studi.","reference":"TM 4; Saunders et al. (2019), Bab 3","keywords":"sintesis; pola; perbandingan"},{"number":10,"topic":"Teori dan Hipotesis","subtopic":"Mediasi","learningOutcome":"Memahami fungsi variabel mediator","difficulty":"Sedang","type":"Konseptual","question":"Dalam model kualitas layanan digital → kepuasan → kepercayaan, kepuasan berperan sebagai ...","options":["variabel kontrol karena nilainya dibuat tetap","moderator karena mengubah kekuatan hubungan","mediator karena menjelaskan mekanisme pengaruh kualitas layanan terhadap kepercayaan","variabel bebas kedua yang tidak terkait dengan jalur utama"],"correct":"C","concept":"Variabel mediator","explanation":"Jawaban C benar. Mediator menjelaskan bagaimana atau mengapa variabel independen memengaruhi variabel dependen. Dalam contoh ini, kualitas layanan yang lebih baik meningkatkan kepuasan, lalu kepuasan membentuk kepercayaan. Moderator berbeda karena menjelaskan kapan atau bagi siapa hubungan menjadi lebih kuat atau lemah. Variabel kontrol digunakan untuk menahan pengaruh alternatif secara statistik atau desain. Pemahaman mekanisme diperlukan agar model tidak sekadar kumpulan panah tanpa argumen teoretis.","whyOthersWrong":"A mendeskripsikan kontrol. B mendeskripsikan moderasi. D mengabaikan posisi kepuasan pada jalur X–M–Y.","tip":"Mediator = “bagaimana/mengapa”; moderator = “kapan/untuk siapa”.","reference":"TM 5; Saunders et al. (2019), Bab 4","keywords":"mediasi; mekanisme; jalur tidak langsung"},{"number":11,"topic":"Strategi Penelitian","subtopic":"Pemilihan strategi","learningOutcome":"Menerapkan kriteria pemilihan strategi penelitian","difficulty":"Sedang","type":"Penerapan","question":"Peneliti ingin mengetahui apakah pesan pengingat tertentu menyebabkan peningkatan pembayaran pajak tepat waktu. Strategi yang PALING tepat adalah ...","options":["ethnography untuk memahami budaya wajib pajak","experiment dengan kelompok perlakuan dan pembanding yang memadai","narrative research terhadap satu wajib pajak","documentary research atas regulasi perpajakan"],"correct":"B","concept":"Eksperimen","explanation":"Jawaban B benar karena pertanyaan menggunakan logika sebab-akibat: apakah pesan tertentu menyebabkan perubahan perilaku. Eksperimen memungkinkan manipulasi perlakuan, penggunaan kelompok pembanding, dan—bila memungkinkan—randomisasi untuk mengurangi penjelasan alternatif. Ethnography cocok untuk memahami budaya dan praktik, narrative research untuk pengalaman yang diceritakan, dan documentary research untuk menganalisis dokumen. Eksperimen lapangan tetap perlu memperhatikan etika, kesetaraan perlakuan, dan potensi kontaminasi antarkelompok.","whyOthersWrong":"A, C, dan D dapat memberi pemahaman lain, tetapi tidak sekuat eksperimen untuk menguji efek kausal perlakuan.","tip":"Kata “menyebabkan” mengarah ke desain dengan manipulasi dan pembanding.","reference":"TM 2; Saunders et al. (2019), Bab 5","keywords":"eksperimen; kausalitas; kelompok pembanding"},{"number":12,"topic":"Latar Belakang","subtopic":"Pertanyaan dan tujuan","learningOutcome":"Menyusun tujuan yang selaras dengan pertanyaan penelitian","difficulty":"Sedang","type":"Penerapan","question":"Pertanyaan penelitian berbunyi “Bagaimana pegawai memaknai perubahan sistem pelaporan?” Tujuan penelitian yang PALING selaras adalah ...","options":["menghitung persentase pegawai yang menggunakan sistem","menguji pengaruh perubahan sistem terhadap produktivitas","membandingkan rata-rata kinerja sebelum dan setelah perubahan","memahami makna dan pengalaman pegawai dalam menghadapi perubahan sistem"],"correct":"D","concept":"Keselarasan pertanyaan–tujuan","explanation":"Jawaban D benar karena kata “bagaimana memaknai” menunjukkan tujuan interpretatif untuk memahami pengalaman dan konstruksi makna pegawai. Tujuan harus mempertahankan fokus yang sama dengan pertanyaan penelitian. Pilihan A bersifat deskriptif kuantitatif, sedangkan B dan C mengarah pada pengujian hubungan atau perbedaan. Ketidaksesuaian antara pertanyaan dan tujuan akan merusak desain berikutnya karena data dan analisis menjadi tidak menjawab masalah yang dirumuskan.","whyOthersWrong":"A mengukur frekuensi, B menguji pengaruh, dan C membandingkan rata-rata; ketiganya tidak langsung menjawab makna pengalaman.","tip":"Cocokkan kata kerja: “memaknai/mengalami” → memahami atau mengeksplorasi.","reference":"TM 3; RPS Sub-CPMK 3; Saunders et al. (2019), Bab 2","keywords":"alignment; makna; pengalaman"},{"number":13,"topic":"Desain dan Sampling","subtopic":"Sampling frame","learningOutcome":"Menentukan sampling frame yang sesuai","difficulty":"Sedang","type":"Penerapan","question":"Populasi target adalah seluruh bendahara pengeluaran pemerintah daerah pada tahun berjalan. Sampling frame yang PALING tepat adalah ...","options":["daftar resmi bendahara aktif yang mutakhir dan mencakup unit dalam populasi target","daftar peserta satu pelatihan yang kebetulan mudah dihubungi","jumlah total pemerintah daerah di Indonesia","daftar seluruh pegawai tanpa informasi jabatan"],"correct":"A","concept":"Sampling frame","explanation":"Jawaban A benar. Sampling frame adalah daftar operasional elemen atau unit yang digunakan untuk menarik sampel. Frame harus sedekat mungkin dengan populasi target, mutakhir, dan meminimalkan unit yang terlewat atau tidak memenuhi syarat. Daftar peserta pelatihan berpotensi menimbulkan coverage bias karena hanya mencakup individu tertentu. Jumlah pemerintah daerah bukan daftar elemen, sedangkan daftar seluruh pegawai terlalu luas dan tidak mengidentifikasi bendahara.","whyOthersWrong":"B adalah convenience frame yang bias. C hanya agregat. D tidak mampu mengidentifikasi elemen populasi target.","tip":"Sampling frame harus berupa daftar yang benar-benar bisa dipakai memilih anggota sampel.","reference":"TM 6; Saunders et al. (2019), Bab 7","keywords":"sampling frame; populasi target; cakupan"},{"number":14,"topic":"Desain dan Sampling","subtopic":"Validitas instrumen","learningOutcome":"Menerapkan konsep validitas isi","difficulty":"Sedang","type":"Penerapan","question":"Sebelum menyebarkan kuesioner akuntabilitas dana desa, peneliti meminta pakar menilai apakah seluruh dimensi penting telah terwakili. Langkah ini terutama mendukung ...","options":["test-retest reliability","validitas kriteria","content validity","random sampling"],"correct":"C","concept":"Validitas isi","explanation":"Jawaban C benar. Content validity menilai apakah butir instrumen mencakup domain atau dimensi konstruk secara memadai. Penilaian pakar, pemetaan indikator ke definisi konseptual, dan telaah item merupakan cara umum mendukung validitas isi. Test-retest reliability menilai kestabilan skor dari waktu ke waktu. Validitas kriteria membandingkan ukuran dengan kriteria eksternal. Random sampling berkaitan dengan pemilihan sampel, bukan kualitas isi instrumen.","whyOthersWrong":"A menguji konsistensi waktu. B memerlukan pembanding eksternal. D tidak menilai apakah item mewakili konstruk.","tip":"Jika fokusnya “apakah seluruh isi konstruk tercakup?”, jawabannya validitas isi.","reference":"TM 6; Merged PPT Pengukuran; Saunders et al. (2019), Bab 11","keywords":"content validity; dimensi; pakar"},{"number":15,"topic":"Proposal Penelitian","subtopic":"Alignment matrix","learningOutcome":"Menerapkan alignment matrix dalam proposal","difficulty":"Sedang","type":"Penerapan","question":"Fungsi UTAMA alignment matrix dalam proposal penelitian adalah ...","options":["memperbanyak jumlah tabel agar proposal terlihat sistematis","memastikan masalah, pertanyaan, tujuan, teori, data, metode, analisis, dan luaran saling konsisten","menggantikan tinjauan literatur dan pengembangan teori","menentukan hasil penelitian sebelum data dikumpulkan"],"correct":"B","concept":"Alignment matrix","explanation":"Jawaban B benar. Alignment matrix membantu memeriksa koherensi horizontal antarkomponen proposal: setiap pertanyaan harus memiliki tujuan, data, metode pengumpulan, dan teknik analisis yang sesuai. Matriks tidak menggantikan tinjauan literatur atau teori; justru merangkum hubungan komponen yang telah dijelaskan. Matriks juga tidak boleh digunakan untuk menetapkan hasil terlebih dahulu. Penggunaan yang baik akan mengungkap pertanyaan yang tidak memiliki data, tujuan yang terlalu luas, atau analisis yang tidak sesuai.","whyOthersWrong":"A hanya fungsi kosmetik. C menghilangkan substansi penting. D bertentangan dengan integritas penelitian.","tip":"Baca setiap baris matriks sebagai rantai: pertanyaan → data → analisis → jawaban.","reference":"TM 7; RPS Sub-CPMK 7; Saunders et al. (2019), Bab 2 dan 5","keywords":"alignment; konsistensi; proposal"},{"number":16,"topic":"Etika Penelitian","subtopic":"Kerahasiaan dan relasi kuasa","learningOutcome":"Mengevaluasi risiko etika pada pengumpulan data","difficulty":"Sulit","type":"Mini Kasus","question":"Kepala unit meminta peneliti mengumpulkan NIP dalam survei kepuasan pegawai agar dapat mengetahui siapa yang memberi nilai rendah. Tindakan peneliti yang PALING tepat adalah ...","options":["mengikuti permintaan karena kepala unit adalah pemberi izin penelitian","mengumpulkan NIP tetapi menyembunyikannya dari responden","menghapus pertanyaan kepuasan agar tidak menimbulkan konflik","menolak penggunaan identitas untuk pemantauan individu, menjelaskan risiko, dan merancang pengumpulan data yang menjaga kerahasiaan"],"correct":"D","concept":"Etika dan kerahasiaan","explanation":"Jawaban D benar karena izin organisasi tidak menghapus kewajiban melindungi partisipan. Penggunaan NIP untuk mengidentifikasi pemberi nilai rendah menciptakan risiko pembalasan, tekanan, dan pelanggaran tujuan persetujuan. Peneliti perlu menegosiasikan desain yang meminimalkan identitas, membatasi akses data, menjelaskan penggunaan data, dan memastikan partisipasi sukarela. Mengikuti permintaan atau menyembunyikan tujuan pengumpulan identitas melanggar integritas. Menghapus seluruh pertanyaan juga tidak perlu jika risiko dapat dikelola melalui desain yang etis.","whyOthersWrong":"A menyamakan izin gatekeeper dengan persetujuan partisipan. B bersifat menipu. C menghindari masalah tanpa mencoba mitigasi yang proporsional.","tip":"Izin institusi ≠ izin menggunakan data pribadi untuk tujuan lain.","reference":"TM 1 dan 7; Saunders et al. (2019), Bab 6","keywords":"kerahasiaan; relasi kuasa; informed consent"},{"number":17,"topic":"Desain dan Sampling","subtopic":"Nonresponse bias","learningOutcome":"Menganalisis kualitas hasil survei","difficulty":"Sulit","type":"Mini Kasus","question":"Survei layanan digital dikirim kepada 2.000 pengguna, tetapi hanya 180 orang merespons. Mayoritas responden adalah pengguna sangat aktif. Langkah analitis yang PALING tepat adalah ...","options":["menilai potensi nonresponse bias dan membandingkan karakteristik responden dengan populasi yang tersedia","menganggap hasil representatif karena jumlah 180 sudah lebih dari 100","menghapus responden aktif agar distribusi terlihat seimbang","menyimpulkan seluruh pengguna puas jika rata-ratanya tinggi"],"correct":"A","concept":"Nonresponse bias","explanation":"Jawaban A benar. Masalah utama bukan hanya jumlah responden, tetapi apakah responden berbeda secara sistematis dari nonresponden. Jika pengguna aktif lebih mungkin menjawab, estimasi kepuasan dapat terlalu tinggi. Peneliti perlu membandingkan karakteristik yang tersedia, melaporkan tingkat respons, mempertimbangkan pembobotan atau tindak lanjut, dan membatasi klaim. Ambang angka tertentu tidak otomatis menjamin representativitas. Menghapus data tanpa dasar justru menambah bias, sedangkan generalisasi langsung tidak dapat dipertanggungjawabkan.","whyOthersWrong":"B mengabaikan komposisi sampel. C memanipulasi data. D melompat dari sampel bias ke populasi.","tip":"Tanyakan bukan hanya “berapa banyak?”, tetapi “siapa yang menjawab dan siapa yang tidak?”.","reference":"TM 6; Saunders et al. (2019), Bab 7 dan 11","keywords":"nonresponse bias; representativitas"},{"number":18,"topic":"Strategi Penelitian","subtopic":"Grounded theory","learningOutcome":"Mengevaluasi kesesuaian label dan prosedur grounded theory","difficulty":"Sulit","type":"Mini Kasus","question":"Peneliti menyatakan memakai grounded theory, tetapi sejak awal menetapkan teori utama, merekrut sampel tetap, dan hanya melakukan coding sekali setelah seluruh wawancara selesai. Masalah UTAMANYA adalah ...","options":["grounded theory wajib menggunakan kuesioner tertutup","grounded theory tidak boleh membahas organisasi","prosedur tersebut tidak menunjukkan constant comparison, theoretical sampling, dan pengembangan teori dari data","grounded theory selalu harus dilakukan lebih dari lima tahun"],"correct":"C","concept":"Grounded theory","explanation":"Jawaban C benar. Grounded theory menuntut proses iteratif antara pengumpulan dan analisis data, perbandingan konstan, pengembangan kategori, dan penyesuaian sampling berdasarkan kebutuhan teori yang sedang tumbuh. Menetapkan seluruh sampel dan menunda analisis sampai akhir lebih menyerupai studi kualitatif tematik biasa. Teori awal dapat berfungsi sebagai sensitizing concept, tetapi tidak boleh menutup kemungkinan teori dibangun dari data. Grounded theory tidak mewajibkan kuesioner, tidak terbatas pada konteks tertentu, dan tidak ditentukan oleh durasi baku.","whyOthersWrong":"A, B, dan D adalah aturan fiktif. Inti masalah terletak pada ketidaksesuaian prosedur dengan logika grounded theory.","tip":"Grounded theory = analisis berjalan bersama pengumpulan data, bukan setelah semuanya selesai.","reference":"TM 2; Saunders et al. (2019), Bab 5 dan 13","keywords":"grounded theory; constant comparison; theoretical sampling"},{"number":19,"topic":"Literatur","subtopic":"Korelasi dan rival causes","learningOutcome":"Mengevaluasi klaim dari data observasional","difficulty":"Sulit","type":"Mini Kasus","question":"Setelah aplikasi layanan publik diluncurkan, kepuasan meningkat. Pada saat yang sama, waktu tunggu berkurang dan jumlah petugas bertambah. Kesimpulan PALING tepat adalah ...","options":["aplikasi pasti menyebabkan seluruh kenaikan kepuasan","kenaikan kepuasan dapat terkait aplikasi, tetapi perubahan waktu tunggu dan jumlah petugas merupakan rival causes yang harus dinilai","aplikasi tidak mungkin berpengaruh karena ada perubahan lain","cukup melihat koefisien korelasi tanpa memeriksa desain"],"correct":"B","concept":"Rival causes","explanation":"Jawaban B benar. Kenaikan setelah peluncuran menunjukkan hubungan temporal, tetapi belum memisahkan pengaruh aplikasi dari perubahan lain yang terjadi bersamaan. Waktu tunggu dan jumlah petugas adalah penjelasan alternatif yang masuk akal. Peneliti dapat menggunakan kelompok pembanding, data sebelum-sesudah yang lebih panjang, kontrol statistik, atau desain quasi-experimental. Menyatakan pasti berpengaruh terlalu kuat, sedangkan menyatakan tidak mungkin berpengaruh juga tidak berdasar. Korelasi saja tidak menghilangkan rival causes.","whyOthersWrong":"A melakukan post hoc fallacy. C menolak kemungkinan tanpa analisis. D mengabaikan ancaman terhadap inferensi kausal.","tip":"Setiap klaim “X menyebabkan Y” harus diuji terhadap penjelasan alternatif.","reference":"TM 4 dan 6; Browne & Keeley; Saunders et al. (2019), Bab 5","keywords":"rival causes; kausalitas; desain"},{"number":20,"topic":"Teori dan Hipotesis","subtopic":"Moderasi","learningOutcome":"Menganalisis peran variabel dalam model","difficulty":"Sulit","type":"Mini Kasus","question":"Pengaruh kualitas sistem terhadap penggunaan layanan lebih kuat pada pengguna dengan literasi digital tinggi dibanding pengguna dengan literasi rendah. Literasi digital berperan sebagai ...","options":["mediator karena selalu berada di antara X dan Y","variabel dependen karena dipengaruhi kualitas sistem","variabel kontrol karena harus dihilangkan pengaruhnya","moderator karena mengubah kekuatan hubungan kualitas sistem dan penggunaan"],"correct":"D","concept":"Variabel moderator","explanation":"Jawaban D benar. Moderator menunjukkan kondisi ketika hubungan X–Y berubah kekuatan atau arahnya. Dalam kasus ini, efek kualitas sistem terhadap penggunaan berbeda menurut tingkat literasi digital, sehingga terdapat logika interaksi. Mediator menjelaskan mekanisme perantara, bukan perbedaan kekuatan hubungan. Variabel kontrol dimasukkan untuk mengurangi penjelasan alternatif, bukan untuk menjelaskan kapan hubungan berubah. Analisis moderasi harus didukung teori dan biasanya memerlukan pengujian interaksi.","whyOthersWrong":"A salah karena moderator tidak berada pada jalur mekanisme. B tidak sesuai dengan peran yang dijelaskan. C menghilangkan fungsi substantif literasi digital.","tip":"Jika kalimatnya “hubungan lebih kuat/lemah ketika ...”, pikirkan moderator.","reference":"TM 5; Saunders et al. (2019), Bab 4 dan 12","keywords":"moderasi; interaksi; kekuatan hubungan"},{"number":21,"topic":"Etika Penelitian","subtopic":"Confidentiality dan anonymity","learningOutcome":"Membedakan kerahasiaan dan anonimitas","difficulty":"Mudah","type":"Perbandingan","question":"Perbedaan yang tepat antara confidentiality dan anonymity adalah ...","options":["confidentiality membatasi akses identitas, sedangkan anonymity berarti identitas tidak dikumpulkan atau tidak dapat dihubungkan dengan data","confidentiality hanya berlaku pada penelitian kuantitatif, sedangkan anonymity pada kualitatif","confidentiality berarti data dibuka kepada organisasi, sedangkan anonymity kepada publik","keduanya identik dan dapat digunakan bergantian"],"correct":"A","concept":"Kerahasiaan vs anonimitas","explanation":"Jawaban A benar. Dalam confidentiality, peneliti mungkin mengetahui identitas partisipan tetapi mengendalikan akses, penyimpanan, dan pengungkapan data. Dalam anonymity, identitas tidak dikumpulkan atau tidak dapat ditautkan kembali secara wajar ke respons. Wawancara mendalam sering sulit benar-benar anonim karena peneliti bertemu partisipan, tetapi tetap dapat dirahasiakan. Kedua konsep berlaku pada berbagai pendekatan penelitian dan tidak berarti data boleh dibuka sembarangan.","whyOthersWrong":"B membatasi konsep secara salah. C membalik makna perlindungan data. D mengabaikan perbedaan penting.","tip":"Confidential = diketahui tetapi dijaga; anonymous = tidak diketahui/tidak tertaut.","reference":"TM 1; Saunders et al. (2019), Bab 6","keywords":"confidentiality; anonymity; identitas"},{"number":22,"topic":"Desain dan Sampling","subtopic":"Stratified dan cluster sampling","learningOutcome":"Membedakan dua teknik probability sampling","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan UTAMA stratified sampling dan cluster sampling adalah ...","options":["stratified selalu nonprobability, sedangkan cluster selalu probability","stratified memilih kelompok utuh, sedangkan cluster memilih individu dari setiap kelompok","stratified mengambil sampel dari setiap strata, sedangkan cluster memilih sebagian kelompok lalu meneliti unit di dalam kelompok terpilih","keduanya hanya dapat digunakan jika populasi homogen"],"correct":"C","concept":"Stratified vs cluster sampling","explanation":"Jawaban C benar. Stratified sampling membagi populasi ke strata yang relevan dan mengambil sampel dari setiap strata agar kelompok penting terwakili. Cluster sampling membagi populasi menjadi kelompok alami, memilih sebagian cluster, lalu meneliti semua atau sebagian unit di cluster terpilih. Keduanya dapat menjadi probability sampling. Stratifikasi sering meningkatkan presisi ketika anggota dalam strata relatif serupa, sedangkan cluster digunakan untuk efisiensi geografis atau operasional.","whyOthersWrong":"A salah karena keduanya dapat bersifat probability. B membalik mekanisme. D salah karena kebutuhan homogenitas berbeda.","tip":"Strata: ambil dari semua lapisan. Cluster: pilih beberapa kelompok.","reference":"TM 6; Saunders et al. (2019), Bab 7","keywords":"strata; cluster; sampling"},{"number":23,"topic":"Literatur","subtopic":"Scoping dan systematic review","learningOutcome":"Membedakan tujuan scoping review dan systematic review","difficulty":"Sedang","type":"Perbandingan","question":"Pernyataan yang PALING tepat mengenai scoping review dan systematic review adalah ...","options":["scoping review selalu menguji efektivitas intervensi, systematic review hanya memetakan istilah","scoping review memetakan keluasan bukti, sedangkan systematic review biasanya menjawab pertanyaan lebih spesifik dengan appraisal yang lebih ketat","keduanya tidak memerlukan kriteria inklusi dan eksklusi","systematic review cukup menggunakan satu basis data jika artikelnya banyak"],"correct":"B","concept":"Scoping vs systematic review","explanation":"Jawaban B benar. Scoping review cocok untuk memetakan jenis bukti, konsep, dan celah pada topik luas atau baru. Systematic review umumnya memiliki pertanyaan lebih terfokus, strategi pencarian terstruktur, kriteria seleksi jelas, dan appraisal kualitas yang lebih ketat untuk mensintesis bukti. Keduanya tetap memerlukan transparansi pencarian dan seleksi. Penggunaan satu basis data saja dapat menyebabkan bukti penting terlewat, kecuali ada justifikasi khusus.","whyOthersWrong":"A membalik tujuan. C menghapus prinsip transparansi. D menilai kecukupan hanya dari jumlah artikel.","tip":"Scoping = peta luas; systematic = jawaban fokus dan penilaian ketat.","reference":"TM 4; Saunders et al. (2019), Bab 3","keywords":"scoping review; systematic review; appraisal"},{"number":24,"topic":"Desain dan Sampling","subtopic":"Inferensi kausal","learningOutcome":"Mengevaluasi batas kesimpulan desain cross-sectional","difficulty":"Sulit","type":"Analisis","question":"Survei cross-sectional menemukan korelasi positif antara transparansi laporan dan kepercayaan publik. Kesimpulan yang PALING dapat dipertanggungjawabkan adalah ...","options":["transparansi terbukti menyebabkan kepercayaan karena koefisiennya positif","kepercayaan pasti menyebabkan transparansi karena responden menilai keduanya sekaligus","hubungan tidak bermakna sebelum dilakukan eksperimen laboratorium","terdapat asosiasi pada data yang diamati, tetapi arah sebab-akibat dan rival causes belum dapat dipastikan"],"correct":"D","concept":"Batas inferensi kausal","explanation":"Jawaban D benar. Data cross-sectional mengukur variabel pada satu titik waktu sehingga dapat menunjukkan asosiasi, tetapi lemah untuk menetapkan urutan waktu dan menyingkirkan reverse causality atau confounding. Kesimpulan kausal memerlukan argumen teori, temporal precedence, kontrol penjelasan alternatif, dan desain yang lebih kuat. Eksperimen bukan satu-satunya jalan, tetapi desain longitudinal, natural experiment, atau quasi-experiment dapat memperkuat inferensi. Koefisien positif tidak cukup untuk menyatakan sebab-akibat.","whyOthersWrong":"A dan B menyimpulkan arah tanpa bukti. C terlalu ekstrem karena studi observasional tetap dapat informatif.","tip":"Cross-sectional kuat untuk “berhubungan”, bukan otomatis untuk “menyebabkan”.","reference":"TM 6; Saunders et al. (2019), Bab 5 dan 12","keywords":"cross-sectional; korelasi; kausalitas"},{"number":25,"topic":"Proposal Penelitian","subtopic":"Koherensi proposal","learningOutcome":"Mengevaluasi konsistensi pertanyaan, data, dan analisis","difficulty":"Sulit","type":"Analisis","question":"Proposal bertanya “mengapa pegawai menolak sistem baru”, tetapi hanya merencanakan menghitung frekuensi penggunaan dari log sistem. Perbaikan PALING tepat adalah ...","options":["menambahkan data yang dapat menjelaskan alasan, seperti wawancara atau pertanyaan terbuka, dan menyesuaikan analisis dengan tujuan eksplanatif","mengganti judul tanpa mengubah pertanyaan dan metode","mempertahankan metode karena semua data numerik pasti objektif","menyimpulkan alasan penolakan dari pegawai yang tidak pernah login"],"correct":"A","concept":"Koherensi proposal","explanation":"Jawaban A benar. Pertanyaan “mengapa” membutuhkan bukti tentang alasan, mekanisme, persepsi, atau konteks. Log penggunaan hanya menunjukkan perilaku yang tercatat, bukan alasan di baliknya. Peneliti dapat menambahkan wawancara, survei dengan konstruk yang relevan, atau desain mixed methods, lalu memilih analisis yang sesuai. Mengganti judul tidak memperbaiki ketidakselarasan. Menganggap data numerik selalu lebih objektif mengabaikan keterbatasan pengukuran, sedangkan menyimpulkan motif dari ketidakaktifan merupakan inferensi tanpa bukti.","whyOthersWrong":"B bersifat kosmetik. C menyamakan format data dengan kecukupan bukti. D menebak motif tanpa mengumpulkan data alasan.","tip":"Uji setiap komponen: apakah data yang direncanakan benar-benar dapat menjawab kata tanya dalam pertanyaan penelitian?","reference":"TM 7; RPS Sub-CPMK 7; Saunders et al. (2019), Bab 2 dan 5","keywords":"koherensi; data; pertanyaan mengapa"}],"flashcards":[{"number":1,"topic":"Fondasi Penelitian","subtopic":"Penelitian ilmiah","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud dengan penelitian ilmiah?","shortAnswer":"Proses terorganisasi, sistematis, berbasis data, kritis, dan bertujuan untuk menjawab masalah atau menghasilkan pemahaman yang dapat dipertanggungjawabkan.","explanation":"Penelitian ilmiah tidak hanya mengumpulkan informasi. Peneliti harus merumuskan tujuan, memilih desain, mengumpulkan data secara terencana, menganalisisnya dengan prosedur yang sesuai, dan menarik kesimpulan berdasarkan bukti. Keterbatasan juga harus diungkapkan agar pembaca dapat menilai kekuatan temuan.","example":"Menilai faktor yang memengaruhi kepatuhan pajak dengan survei terstruktur dan analisis yang sesuai.","keywords":"sistematis; data; tujuan; bukti","comparison":"Pencarian informasi biasa: dapat berhenti pada menemukan fakta tanpa desain dan analisis ilmiah.","mnemonic":"T-S-D-A-K: Tujuan–Sistematis–Data–Analisis–Kesimpulan"},{"number":2,"topic":"Fondasi Penelitian","subtopic":"Metode dan metodologi","difficulty":"Mudah","type":"Definisi","question":"Apa perbedaan metode penelitian dan metodologi penelitian?","shortAnswer":"Metode adalah teknik/prosedur untuk mengumpulkan atau menganalisis data; metodologi adalah alasan dan logika yang menjelaskan mengapa pilihan metode tersebut tepat.","explanation":"Metode menjawab “bagaimana data diperoleh atau dianalisis”, misalnya wawancara, kuesioner, regresi, atau thematic analysis. Metodologi membahas dasar filosofis, desain, strategi, kualitas bukti, dan koherensi keseluruhan pilihan. Menyebut daftar teknik saja belum menjelaskan metodologi.","example":"Kuesioner adalah metode; alasan memilih survei kuantitatif untuk menguji hubungan adalah bagian metodologi.","keywords":"metode; metodologi; alasan; teknik","comparison":"Strategi penelitian berada di antara metodologi dan teknik, misalnya survey atau case study.","mnemonic":"Metode = cara; metodologi = alasan di balik cara."},{"number":3,"topic":"Paradigma Penelitian","subtopic":"Ontologi","difficulty":"Mudah","type":"Definisi","question":"Apa fokus utama ontologi dalam penelitian?","shortAnswer":"Hakikat realitas: apa yang dianggap ada dan apakah realitas dipandang tunggal, objektif, atau jamak serta dibentuk sosial.","explanation":"Asumsi ontologis memengaruhi cara peneliti memahami fenomena. Realitas kinerja dapat dipandang sebagai angka yang dapat diukur, atau sebagai pengalaman yang maknanya berbeda bagi tiap pihak. Ontologi tidak otomatis menentukan satu metode, tetapi membantu menjaga konsistensi desain.","example":"Kepuasan publik dapat dipandang sebagai skor terukur atau pengalaman bermakna yang perlu dipahami.","keywords":"realitas; keberadaan; objektif; jamak","comparison":"Epistemologi menanyakan bagaimana pengetahuan yang sah tentang realitas diperoleh.","mnemonic":"ONTO = “apa yang ON/ada?”"},{"number":4,"topic":"Paradigma Penelitian","subtopic":"Epistemologi","difficulty":"Mudah","type":"Definisi","question":"Apa yang ditanyakan oleh epistemologi?","shortAnswer":"Apa yang dianggap sebagai pengetahuan yang valid dan bagaimana pengetahuan tersebut dapat diperoleh serta dikomunikasikan.","explanation":"Epistemologi memengaruhi apakah peneliti menekankan pengukuran yang dapat direplikasi, pemahaman makna partisipan, atau gabungan bukti yang paling berguna. Pertanyaan ini menyangkut hubungan peneliti dengan objek dan standar bukti yang diterima.","example":"Apakah kepercayaan publik lebih tepat diketahui melalui skala survei, wawancara, atau kombinasi keduanya?","keywords":"pengetahuan; valid; bukti; cara mengetahui","comparison":"Ontologi = hakikat realitas; epistemologi = cara mengetahui realitas.","mnemonic":"EPI = Evidence Produces Insight."},{"number":5,"topic":"Desain dan Sampling","subtopic":"Research design","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud dengan research design?","shortAnswer":"Blueprint yang menyelaraskan pertanyaan, tujuan, strategi, data, pengukuran, sampling, analisis, waktu, dan kualitas penelitian.","explanation":"Research design memastikan bahwa bukti yang dikumpulkan benar-benar dapat menjawab pertanyaan penelitian. Tidak ada satu desain terbaik untuk semua situasi; desain dinilai dari koherensi, kelayakan, etika, dan kemampuannya mengurangi penjelasan alternatif.","example":"Pertanyaan kausal memerlukan desain yang lebih kuat daripada sekadar survei satu waktu.","keywords":"blueprint; koherensi; data; analisis","comparison":"Metode adalah bagian dari desain, bukan keseluruhan desain.","mnemonic":"Q-D-A: Question–Data–Analysis harus tersambung."},{"number":6,"topic":"Latar Belakang","subtopic":"Research gap","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud dengan research gap?","shortAnswer":"Kekurangan, ketidakjelasan, inkonsistensi, atau keterbatasan pengetahuan yang ditunjukkan melalui sintesis literatur dan layak diteliti.","explanation":"Gap dapat bersifat teoretis, empiris, metodologis, kontekstual, populasi, atau inkonsistensi hasil. Gap yang baik bukan hanya pernyataan bahwa lokasi tertentu belum pernah diteliti, tetapi menjelaskan mengapa konteks tersebut penting bagi teori atau praktik.","example":"Hasil studi digitalisasi pajak berbeda antarkelompok pengguna dan mekanismenya belum dijelaskan.","keywords":"gap; literatur; inkonsistensi; kontribusi","comparison":"Masalah praktis adalah kesenjangan kondisi aktual–ideal; research gap adalah kesenjangan pengetahuan.","mnemonic":"Gap = Belum jelas + Bukti + Penting."},{"number":7,"topic":"Fondasi Penelitian","subtopic":"Purposiveness","difficulty":"Mudah","type":"Istilah","question":"Apa arti purposiveness sebagai hallmark penelitian ilmiah?","shortAnswer":"Penelitian memiliki tujuan yang jelas, spesifik, dan relevan dengan masalah yang ingin dijawab.","explanation":"Tujuan yang jelas mengarahkan pemilihan data, metode, dan analisis. Tanpa purposiveness, penelitian mudah melebar dan menghasilkan informasi yang tidak menjawab masalah. Tujuan juga menjadi dasar menilai apakah kesimpulan sesuai dengan pertanyaan awal.","example":"Tujuan “menguji pengaruh kualitas layanan terhadap kepuasan” lebih terarah daripada “meneliti layanan publik”.","keywords":"tujuan; fokus; relevansi","comparison":"Rigor membahas ketelitian prosedur, bukan kejelasan tujuan.","mnemonic":"PURPOSE = penunjuk arah penelitian."},{"number":8,"topic":"Fondasi Penelitian","subtopic":"Rigor","difficulty":"Mudah","type":"Istilah","question":"Apa arti rigor dalam penelitian?","shortAnswer":"Ketelitian dan kecermatan dalam teori, desain, pengukuran, pengumpulan data, analisis, dan pelaporan.","explanation":"Rigor tidak sama dengan banyaknya data. Penelitian kecil dapat rigor jika konsep jelas, prosedur transparan, bukti memadai, dan analisis sesuai. Sebaliknya, data besar tetap lemah bila sampling bias, instrumen tidak valid, atau kesimpulan melampaui bukti.","example":"Melakukan pilot test dan melaporkan proses coding meningkatkan rigor.","keywords":"ketelitian; prosedur; kualitas","comparison":"Precision berkaitan dengan ketepatan estimasi; rigor mencakup kualitas proses yang lebih luas.","mnemonic":"RIGOR = Rinci, Integritas, Grounded, Objektif, Reproducible."},{"number":9,"topic":"Strategi Penelitian","subtopic":"Abduksi","difficulty":"Sedang","type":"Istilah","question":"Apa yang dimaksud dengan pendekatan abduktif?","shortAnswer":"Gerak bolak-balik antara data dan teori untuk menemukan penjelasan yang paling masuk akal terhadap temuan yang mengejutkan.","explanation":"Abduksi dimulai dari observasi yang tidak sepenuhnya dijelaskan teori. Peneliti membandingkan temuan dengan teori, menyusun penjelasan sementara, lalu kembali ke data atau teori untuk memperbaikinya. Pendekatan ini berbeda dari deduksi murni maupun induksi murni.","example":"Penggunaan aplikasi naik tetapi kepuasan turun; peneliti menelusuri teori beban digital dan data wawancara.","keywords":"bolak-balik; teori; data; penjelasan","comparison":"Deduksi menguji teori; induksi membangun pola dari data.","mnemonic":"ABDUKSI = Aneh → Bandingkan → Dugaan → Uji kembali."},{"number":10,"topic":"Strategi Penelitian","subtopic":"Saturation","difficulty":"Sedang","type":"Istilah","question":"Apa arti saturation dalam penelitian kualitatif?","shortAnswer":"Kondisi ketika pengumpulan data tambahan tidak lagi menghasilkan wawasan atau kategori substantif yang baru.","explanation":"Saturation bukan angka peserta yang berlaku universal. Penilaiannya bergantung pada fokus studi, keragaman partisipan, kedalaman data, dan teknik analisis. Peneliti harus menjelaskan indikator kejenuhan dan proses yang digunakan, bukan sekadar menyatakan “data sudah jenuh”.","example":"Wawancara tambahan hanya mengulang pola alasan penolakan sistem yang sudah teridentifikasi.","keywords":"kejenuhan; kategori; data baru","comparison":"Sample size kuantitatif didasarkan pada presisi/power; saturation bersifat analitis.","mnemonic":"Saturasi = “sudah tidak ada tema baru”."},{"number":11,"topic":"Desain dan Sampling","subtopic":"Sampling frame","difficulty":"Sedang","type":"Istilah","question":"Apa yang dimaksud dengan sampling frame?","shortAnswer":"Daftar operasional elemen atau unit populasi yang digunakan sebagai dasar untuk menarik sampel.","explanation":"Sampling frame yang baik harus mutakhir, mencakup populasi target, dan meminimalkan duplikasi atau unit yang tidak memenuhi syarat. Ketidaksesuaian frame dengan populasi menyebabkan coverage error dan membatasi generalisasi.","example":"Daftar bendahara pengeluaran aktif, bukan daftar seluruh pegawai.","keywords":"daftar; populasi; pemilihan sampel","comparison":"Populasi adalah keseluruhan sasaran; frame adalah daftar yang tersedia untuk memilih sampel.","mnemonic":"FRAME = daftar bingkai populasi."},{"number":12,"topic":"Strategi Penelitian","subtopic":"Research onion","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan logis lapisan research onion dari luar ke dalam?","shortAnswer":"Filosofi → pendekatan teori → pilihan metodologis → strategi → horizon waktu → teknik/prosedur pengumpulan dan analisis data.","explanation":"Research onion membantu peneliti menjaga koherensi. Lapisan luar memberi dasar asumsi, sedangkan lapisan dalam menjelaskan pelaksanaan teknis. Urutan ini bukan resep kaku, tetapi alat untuk memeriksa apakah setiap pilihan saling mendukung.","example":"Pragmatisme → abduksi → mixed methods → case study → longitudinal → wawancara dan data arsip.","keywords":"filosofi; pendekatan; strategi; teknik","comparison":"Metode pengumpulan data berada pada lapisan paling dalam, bukan filosofi.","mnemonic":"Fi-Pe-Me-St-Ho-Te."},{"number":13,"topic":"Literatur","subtopic":"Proses penelusuran literatur","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan inti penelusuran dan sintesis literatur?","shortAnswer":"Tentukan topik → susun kata kunci → cari → screening → ekstraksi → mapping → evaluasi kritis → sintesis → rumuskan gap.","explanation":"Proses yang transparan mencegah peneliti memilih sumber secara sembarangan. Kriteria inklusi dan eksklusi sebaiknya ditetapkan lebih awal, metadata diperiksa, dan alasan seleksi dicatat. Sintesis dilakukan setelah studi dipetakan dan dinilai.","example":"Mencari studi digitalisasi pajak dengan kombinasi kata kunci dan Boolean operators.","keywords":"search; screening; mapping; sintesis","comparison":"Mapping mengorganisasi informasi; review menyusun argumen.","mnemonic":"Cari–Saring–Petakan–Nilai–Sintesis–Gap."},{"number":14,"topic":"Desain dan Sampling","subtopic":"Operasionalisasi variabel","difficulty":"Sedang","type":"Tahapan","question":"Apa tahapan operasionalisasi konstruk?","shortAnswer":"Definisi konseptual → dimensi → indikator → item → skala → pilot test dan evaluasi kualitas.","explanation":"Operasionalisasi mengubah konstruk abstrak menjadi sesuatu yang dapat diamati secara konsisten. Setiap indikator harus memiliki dasar teori, item harus jelas, dan skala harus sesuai. Pilot test membantu mendeteksi masalah sebelum pengumpulan data utama.","example":"Akuntabilitas → transparansi, pertanggungjawaban, kepatuhan → indikator dan item Likert.","keywords":"konstruk; indikator; item; skala","comparison":"Definisi konseptual menjelaskan makna; definisi operasional menjelaskan cara mengukur.","mnemonic":"De-Di-In-It-Sk-Pi."},{"number":15,"topic":"Proposal Penelitian","subtopic":"Alignment proposal","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana memeriksa alignment proposal secara berurutan?","shortAnswer":"Masalah → pertanyaan → tujuan → teori → data → metode → analisis → luaran.","explanation":"Setiap pertanyaan harus memiliki tujuan yang sesuai, data yang dapat diperoleh, dan analisis yang mampu menghasilkan jawaban. Pemeriksaan alignment mengungkap komponen yang hilang atau tidak cocok sebelum penelitian dimulai.","example":"Pertanyaan “mengapa” memerlukan data alasan dan analisis eksplanatif, bukan hanya frekuensi.","keywords":"alignment; koherensi; proposal","comparison":"Feasibility menilai kelayakan sumber daya; alignment menilai konsistensi logis.","mnemonic":"Ma-Pe-Tu-Te-Da-Me-An-Lu."},{"number":16,"topic":"Fondasi Penelitian","subtopic":"Basic vs applied research","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan penelitian dasar dan penelitian terapan?","shortAnswer":"Dasar memperluas pemahaman atau teori; terapan memecahkan masalah praktis aktual.","explanation":"Keduanya tetap menggunakan metode ilmiah dan dapat saling mendukung. Pembeda utama adalah orientasi tujuan dan pengguna awal hasil. Penelitian terapan tidak berarti kurang ilmiah, sedangkan penelitian dasar tidak berarti tanpa manfaat praktis.","example":"Teori motivasi pegawai = dasar; intervensi untuk mengurangi absensi unit = terapan.","keywords":"basic; applied; tujuan","comparison":"Eksploratif/deskriptif/eksplanatori adalah tujuan desain, bukan klasifikasi dasar-terapan.","mnemonic":"Basic = bangun pengetahuan; applied = pakai untuk masalah."},{"number":17,"topic":"Strategi Penelitian","subtopic":"Survey vs questionnaire","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan survey dan questionnaire?","shortAnswer":"Survey adalah strategi penelitian; questionnaire adalah salah satu instrumen pengumpulan data.","explanation":"Survei mencakup perencanaan populasi, sampling, pengukuran, pengumpulan data, dan analisis untuk menjawab pertanyaan. Kuesioner hanya alat berisi pertanyaan. Kuesioner dapat digunakan di luar survei, dan survei dapat menggabungkan sumber data lain.","example":"Survei kepuasan menggunakan kuesioner daring sebagai instrumen.","keywords":"strategi; instrumen; survei","comparison":"Interview juga instrumen, bukan otomatis strategi.","mnemonic":"Survey = sistem; questionnaire = alat tanya."},{"number":18,"topic":"Teori dan Hipotesis","subtopic":"Mediasi vs moderasi","difficulty":"Sedang","type":"Perbandingan","question":"Apa perbedaan mediator dan moderator?","shortAnswer":"Mediator menjelaskan bagaimana/mengapa X memengaruhi Y; moderator menjelaskan kapan/untuk siapa hubungan X–Y berubah.","explanation":"Mediator berada pada jalur mekanisme X→M→Y. Moderator berinteraksi dengan X sehingga kekuatan atau arah hubungan berbeda pada kondisi tertentu. Keduanya harus didukung teori, bukan hanya ditemukan melalui coba-coba statistik.","example":"Kepuasan memediasi kualitas layanan–kepercayaan; literasi memoderasi kualitas sistem–penggunaan.","keywords":"mediasi; moderasi; mekanisme; interaksi","comparison":"Variabel kontrol mengurangi penjelasan alternatif, bukan menjelaskan mekanisme atau kondisi.","mnemonic":"MEdiator = MEkanisme; MODerator = MODifikasi hubungan."},{"number":19,"topic":"Desain dan Sampling","subtopic":"Validitas vs reliabilitas","difficulty":"Sulit","type":"Perbandingan","question":"Apa perbedaan validitas dan reliabilitas?","shortAnswer":"Validitas menilai apakah instrumen mengukur konsep yang seharusnya; reliabilitas menilai konsistensi hasil pengukuran.","explanation":"Instrumen dapat konsisten tetapi salah sasaran, sehingga reliabel namun tidak valid. Validitas mencakup isi, konstruk, konvergen, diskriminan, dan lainnya. Reliabilitas dapat dinilai melalui kestabilan atau konsistensi internal. Keduanya diperlukan tetapi tidak saling menggantikan.","example":"Timbangan yang selalu lebih 3 kg reliabel tetapi tidak valid.","keywords":"validitas; reliabilitas; ketepatan; konsistensi","comparison":"Precision adalah ketepatan estimasi, bukan validitas konstruk.","mnemonic":"Valid = benar sasaran; reliable = tetap hasilnya."},{"number":20,"topic":"Strategi Penelitian","subtopic":"Pemilihan case study","difficulty":"Sulit","type":"Penerapan","question":"Kapan case study paling tepat digunakan?","shortAnswer":"Ketika peneliti ingin memahami kasus yang dibatasi secara mendalam dalam konteks nyata dengan berbagai sumber bukti.","explanation":"Case study cocok untuk pertanyaan “bagaimana” dan “mengapa” yang membutuhkan konteks. Peneliti harus menetapkan batas kasus, unit analisis, periode, dan sumber bukti. Satu lokasi tidak otomatis berarti case study.","example":"Implementasi sistem keuangan pada satu pemerintah daerah selama dua tahun.","keywords":"kasus; konteks; batas; bukti","comparison":"Ethnography fokus pada budaya dan praktik sosial melalui keterlibatan panjang.","mnemonic":"Case = Context + Boundary + Evidence."},{"number":21,"topic":"Desain dan Sampling","subtopic":"Stratified sampling","difficulty":"Sulit","type":"Penerapan","question":"Kapan stratified sampling tepat digunakan?","shortAnswer":"Ketika populasi memiliki subkelompok penting dan peneliti ingin memastikan setiap strata terwakili.","explanation":"Populasi dibagi menjadi strata yang saling eksklusif, lalu sampel diambil dari setiap strata secara proporsional atau tidak proporsional. Teknik ini dapat meningkatkan presisi dan representasi kelompok kecil jika frame tersedia.","example":"Mengambil sampel bendahara dari setiap jenis pemerintah daerah.","keywords":"strata; representasi; probability","comparison":"Cluster sampling memilih sebagian kelompok, bukan mengambil dari semua lapisan.","mnemonic":"Strata = Semua lapisan ikut."},{"number":22,"topic":"Desain dan Sampling","subtopic":"Interpretasi p-value","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana menafsirkan p-value dengan benar?","shortAnswer":"p-value menunjukkan kompatibilitas data dengan hipotesis nol dalam asumsi model; bukan probabilitas hipotesis nol benar.","explanation":"p-value kecil dapat menjadi bukti menentang H0, tetapi tidak menunjukkan besar efek, pentingnya temuan, kualitas desain, atau kebenaran teori. Interpretasi harus bersama effect size, interval kepercayaan, asumsi, dan konteks substantif.","example":"p=0,01 dengan efek sangat kecil mungkin signifikan secara statistik tetapi kurang penting secara praktis.","keywords":"p-value; H0; effect size","comparison":"Confidence interval memberi rentang estimasi yang masuk akal, bukan keputusan biner semata.","mnemonic":"P kecil ≠ pengaruh besar."},{"number":23,"topic":"Etika Penelitian","subtopic":"Identitas responden","difficulty":"Sulit","type":"Mini Kasus","question":"Survei pegawai meminta NIP untuk melacak pemberi nilai rendah. Apa masalah utama dan tindakannya?","shortAnswer":"Risiko relasi kuasa dan pelanggaran kerahasiaan; minimalkan identitas, jelaskan penggunaan data, batasi akses, dan pastikan partisipasi sukarela.","explanation":"Izin pimpinan tidak menggantikan informed consent partisipan. Identitas yang dapat digunakan untuk pembalasan menimbulkan risiko nyata. Peneliti harus menegosiasikan desain yang aman dan tidak menggunakan data di luar tujuan yang disetujui.","example":"Gunakan kode acak dan laporan agregat, bukan daftar individu.","keywords":"kerahasiaan; consent; relasi kuasa","comparison":"Anonymity berarti identitas tidak dapat ditautkan; confidentiality berarti identitas dijaga.","mnemonic":"Izin gatekeeper bukan izin membuka identitas."},{"number":24,"topic":"Literatur","subtopic":"Korelasi dan kausalitas","difficulty":"Sulit","type":"Mini Kasus","question":"Kepuasan naik setelah aplikasi diluncurkan, tetapi petugas juga bertambah. Apa kesimpulan yang aman?","shortAnswer":"Ada perubahan yang berasosiasi dengan peluncuran, tetapi efek aplikasi belum terpisah dari rival causes.","explanation":"Urutan waktu saja tidak cukup. Peneliti perlu kelompok pembanding, data longitudinal, kontrol statistik, atau desain quasi-experimental untuk menilai penjelasan alternatif. Klaim kausal harus proporsional dengan desain.","example":"Bandingkan unit yang menerapkan aplikasi dengan unit serupa yang belum menerapkan.","keywords":"rival causes; kausalitas; kontrol","comparison":"Korelasi menunjukkan hubungan; kausalitas memerlukan urutan waktu dan eliminasi alternatif.","mnemonic":"Sesudah tidak selalu karena."},{"number":25,"topic":"Proposal Penelitian","subtopic":"Diagnosis ketidakselarasan","difficulty":"Sulit","type":"Mini Kasus","question":"Pertanyaan proposal menanyakan “mengapa”, tetapi data hanya berupa frekuensi log. Apa yang harus diperbaiki?","shortAnswer":"Tambahkan data tentang alasan atau mekanisme dan sesuaikan analisis; atau ubah pertanyaan agar sesuai dengan data deskriptif.","explanation":"Log sistem menunjukkan perilaku, bukan motif. Peneliti dapat menggunakan wawancara, pertanyaan terbuka, atau konstruk penjelas dalam survei. Alternatifnya, pertanyaan diubah menjadi deskriptif. Perbaikan harus menjaga alignment antara pertanyaan, data, dan analisis.","example":"Dari “mengapa pegawai menolak?” menjadi wawancara alasan, atau ubah menjadi “berapa tingkat penggunaan?”.","keywords":"alignment; pertanyaan; data; analisis","comparison":"Feasibility tidak sama dengan alignment; data mudah diperoleh belum tentu menjawab pertanyaan.","mnemonic":"Kata tanya menentukan jenis bukti."}]},"praktikum-audit":{"id":"praktikum-audit","title":"Praktikum Audit","short":"Praktikum Audit","konsen":["audit","pppn"],"quiz":[{"number":1,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Surat perikatan audit","learningOutcome":"Menjelaskan fungsi surat perikatan audit","difficulty":"Mudah","type":"Definisi","question":"Dokumen yang menetapkan tujuan, ruang lingkup, tanggung jawab auditor dan manajemen, serta bentuk komunikasi hasil audit adalah ...","options":["memorandum prosedur analitis","surat perikatan audit","surat representasi manajemen","management letter"],"correct":"B","concept":"Fungsi surat perikatan audit","explanation":"Surat perikatan audit merupakan kesepakatan tertulis yang memperjelas tujuan dan ruang lingkup audit, tanggung jawab auditor, tanggung jawab manajemen atas laporan keuangan serta pengendalian internal, kerangka pelaporan yang digunakan, dan bentuk laporan yang diharapkan. Dokumen ini dibuat pada awal penugasan agar tidak terjadi kesalahpahaman mengenai batas pekerjaan. Surat representasi diperoleh menjelang penyelesaian audit, management letter berisi rekomendasi pengendalian, sedangkan memorandum prosedur analitis mendokumentasikan hasil analisis awal. Karena itu, jawaban yang paling tepat adalah surat perikatan audit.","whyOthersWrong":"A mendokumentasikan analisis, bukan kesepakatan penugasan. C merupakan pernyataan manajemen pada tahap akhir. D berisi rekomendasi atas kelemahan pengendalian.","tip":"Cari kata “tujuan, ruang lingkup, tanggung jawab, dan bentuk laporan”. Keempat unsur tersebut menunjuk pada engagement letter.","reference":"TM 1; RPS Praktikum Audit ASP4126; Agoes & Trisnawati (2019), Bagian Instruksi Umum dan Persiapan.","keywords":"surat perikatan; ruang lingkup"},{"number":2,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Permanent file dan current file","learningOutcome":"Mengidentifikasi isi permanent file","difficulty":"Mudah","type":"Definisi","question":"Dokumen yang PALING TEPAT disimpan dalam permanent file adalah ...","options":["akta pendirian dan perubahan struktur organisasi","konfirmasi piutang tahun berjalan","hasil kas opname akhir tahun","daftar jurnal penyesuaian tahun berjalan"],"correct":"A","concept":"Berkas permanen","explanation":"Permanent file berisi informasi klien yang relatif tetap dan dapat digunakan kembali pada audit periode berikutnya, seperti akta pendirian, struktur organisasi, kebijakan akuntansi, kode akun, kontrak jangka panjang, dan dokumen hukum penting. Konfirmasi piutang, kas opname, serta jurnal penyesuaian berkaitan langsung dengan audit periode berjalan sehingga ditempatkan dalam current file. Pembeda utamanya adalah horizon manfaat informasi: permanent file mendukung pemahaman berkelanjutan atas entitas, sedangkan current file membuktikan prosedur dan hasil audit tahun tertentu.","whyOthersWrong":"B, C, dan D merupakan bukti serta dokumentasi yang hanya relevan untuk periode audit berjalan sehingga termasuk current file.","tip":"Gunakan pertanyaan sederhana: apakah dokumen ini masih relevan pada audit beberapa tahun berikutnya? Jika ya, kemungkinan besar permanent file.","reference":"TM 1; Buddy Brief Praktikum Audit 2026; Agoes & Trisnawati (2019), Berkas Permanen.","keywords":"permanent file; dokumen jangka panjang"},{"number":3,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Materialitas laporan keuangan","learningOutcome":"Menjelaskan makna materialitas","difficulty":"Mudah","type":"Definisi","question":"Materialitas dalam audit paling tepat dipahami sebagai ...","options":["jumlah transaksi yang harus diuji seluruhnya","tingkat risiko bawaan yang selalu tinggi","besaran atau sifat salah saji yang dapat memengaruhi keputusan pengguna","persentase tetap yang wajib dipakai semua auditor"],"correct":"C","concept":"Materialitas audit","explanation":"Materialitas berkaitan dengan apakah besaran atau sifat suatu salah saji, secara individual maupun agregat, dapat memengaruhi keputusan ekonomi pengguna laporan keuangan. Materialitas bukan angka baku yang sama bagi semua entitas karena auditor mempertimbangkan benchmark, kondisi entitas, serta faktor kualitatif seperti fraud atau pelanggaran perjanjian. Materialitas juga tidak sama dengan ukuran sampel atau risiko bawaan. Dalam praktik, auditor menetapkan materialitas laporan keuangan keseluruhan dan materialitas pelaksanaan untuk merancang sifat, waktu, dan luas prosedur audit.","whyOthersWrong":"A mencampur materialitas dengan cakupan pengujian. B membahas risiko bawaan. D salah karena standar menuntut pertimbangan profesional, bukan persentase tunggal.","tip":"Kata kunci utama adalah “memengaruhi keputusan pengguna”, bukan sekadar besar nominal atau jumlah sampel.","reference":"TM 2; SA 320 Materialitas dalam Perencanaan dan Pelaksanaan Audit; RPS Praktikum Audit ASP4126.","keywords":"materialitas; keputusan pengguna"},{"number":4,"topic":"Risiko Fraud dan Pengendalian Internal","subtopic":"Model risiko audit","learningOutcome":"Menjelaskan komponen risiko audit","difficulty":"Mudah","type":"Definisi","question":"Dalam model AR = IR × CR × DR, detection risk adalah risiko bahwa ...","options":["saldo akun rentan salah saji sebelum mempertimbangkan pengendalian","pengendalian klien gagal mencegah atau mendeteksi salah saji","manajemen sengaja melakukan override atas pengendalian","prosedur auditor gagal mendeteksi salah saji material yang ada"],"correct":"D","concept":"Risiko deteksi","explanation":"Detection risk adalah risiko bahwa prosedur audit yang dirancang dan dilaksanakan auditor tidak mendeteksi salah saji yang ada dan dapat material. Risiko ini berbeda dari inherent risk, yaitu kerentanan akun sebelum mempertimbangkan pengendalian, dan control risk, yaitu risiko pengendalian internal gagal mencegah atau mendeteksi salah saji secara tepat waktu. Auditor mengelola detection risk melalui perubahan sifat, waktu, dan luas prosedur. Ketika inherent risk dan control risk tinggi, detection risk yang dapat diterima harus diturunkan dengan memperoleh bukti yang lebih andal atau lebih luas.","whyOthersWrong":"A merupakan inherent risk. B merupakan control risk. C adalah salah satu sumber risiko fraud, tetapi bukan definisi detection risk.","tip":"Lihat pelakunya: jika kegagalan berada pada prosedur auditor, konsepnya adalah detection risk.","reference":"TM 3; Agoes & Trisnawati (2019), Menetapkan Risiko Audit.","keywords":"detection risk; prosedur auditor"},{"number":5,"topic":"Audit Piutang Usaha","subtopic":"Konfirmasi positif","learningOutcome":"Menjelaskan karakter konfirmasi positif","difficulty":"Mudah","type":"Definisi","question":"Konfirmasi positif atas piutang usaha meminta pelanggan untuk ...","options":["menjawab hanya jika tidak setuju dengan saldo","memberikan jawaban baik setuju maupun tidak setuju","mengirim pembayaran langsung kepada auditor","menilai efektivitas pengendalian penjualan"],"correct":"B","concept":"Konfirmasi positif","explanation":"Konfirmasi positif meminta pihak pelanggan memberikan respons langsung kepada auditor, baik ketika setuju maupun tidak setuju dengan saldo atau informasi yang dikonfirmasi. Metode ini umumnya digunakan ketika saldo material, risiko salah saji lebih tinggi, atau auditor membutuhkan bukti eksternal yang lebih kuat. Konfirmasi negatif hanya meminta balasan jika pelanggan tidak setuju dan biasanya cocok ketika risiko rendah, jumlah saldo kecil tetapi banyak, serta auditor memperkirakan penerima akan memperhatikan permintaan. Pembayaran bukan tujuan konfirmasi, dan pelanggan tidak menilai desain pengendalian klien.","whyOthersWrong":"A menjelaskan konfirmasi negatif. C mengubah konfirmasi menjadi proses penagihan. D merupakan tanggung jawab auditor, bukan pelanggan.","tip":"Ingat: positif berarti auditor mengharapkan respons dalam dua kondisi—setuju maupun tidak setuju.","reference":"TM 6; Buddy Brief Praktikum Audit 2026; Agoes & Trisnawati (2019), Modul Piutang Usaha.","keywords":"konfirmasi positif; jawaban pelanggan"},{"number":6,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Arah pengujian audit","learningOutcome":"Menghubungkan arah pengujian dengan asersi","difficulty":"Mudah","type":"Konseptual","question":"Menelusuri surat jalan bernomor urut ke jurnal penjualan terutama membantu auditor menguji asersi ...","options":["hak dan kewajiban","penilaian dan alokasi","kelengkapan","keberadaan kas"],"correct":"C","concept":"Tracing untuk kelengkapan","explanation":"Tracing bergerak dari dokumen sumber menuju catatan akuntansi. Ketika auditor memilih surat jalan dan menelusurinya ke jurnal penjualan, auditor mencari transaksi pengiriman yang seharusnya dicatat tetapi mungkin belum masuk pembukuan. Karena itu, tujuan utama prosedur tersebut adalah menguji completeness atau kelengkapan. Sebaliknya, vouching bergerak dari catatan menuju bukti sumber dan lebih kuat untuk occurrence. Hak dan kewajiban, penilaian, serta keberadaan kas memerlukan prosedur lain yang lebih langsung dan tidak terutama dijawab oleh urutan surat jalan.","whyOthersWrong":"A dan B tidak menjadi fokus utama arah dokumen ke catatan. D tidak relevan karena sumber yang diuji adalah dokumen pengiriman dan jurnal penjualan.","tip":"Dokumen sumber → catatan = tracing = mencari yang belum dicatat = completeness.","reference":"TM 5 dan TM 7; Agoes & Trisnawati (2019), Istilah Audit: trace dan vouching.","keywords":"tracing; completeness"},{"number":7,"topic":"Pengendalian Penjualan Kredit","subtopic":"Reliance pada pengendalian","learningOutcome":"Menganalisis hubungan test of control dan pengujian substantif","difficulty":"Sedang","type":"Konseptual","question":"Apabila test of control menunjukkan persetujuan kredit tidak dijalankan secara konsisten, respons auditor yang PALING TEPAT adalah ...","options":["menilai kembali control risk lebih tinggi dan memperluas pengujian substantif","menaikkan materialitas agar penyimpangan tidak signifikan","menghapus seluruh prosedur konfirmasi piutang","menyimpulkan laporan keuangan salah tanpa pengujian tambahan"],"correct":"A","concept":"Dampak kegagalan pengendalian","explanation":"Ketika pengendalian kunci tidak berjalan konsisten, auditor tidak dapat mempertahankan tingkat reliance yang direncanakan. Control risk perlu dinilai kembali lebih tinggi, sehingga detection risk yang dapat diterima turun. Respons praktisnya adalah mengubah sifat, waktu, atau luas pengujian substantif, misalnya memperbesar sampel, menggunakan bukti eksternal, atau melakukan prosedur lebih dekat dengan tanggal laporan. Materialitas tidak dinaikkan hanya untuk menutupi kelemahan kontrol. Auditor juga tidak boleh langsung menyimpulkan salah saji sebelum memperoleh bukti substantif yang cukup dan tepat.","whyOthersWrong":"B merupakan manipulasi pertimbangan materialitas. C justru mengurangi bukti ketika risiko naik. D terlalu dini karena kelemahan kontrol tidak otomatis membuktikan salah saji.","tip":"Kegagalan kontrol → reliance turun → control risk naik → substantive testing diperluas.","reference":"TM 5; RPS Praktikum Audit ASP4126; Agoes & Trisnawati (2019), Test of Controls and Transaction.","keywords":"test of control; control risk; substantive"},{"number":8,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Analisis perubahan dan rasio","learningOutcome":"Menafsirkan hasil prosedur analitis awal","difficulty":"Sedang","type":"Konseptual","question":"Penjualan dan piutang meningkat tajam, tetapi penerimaan kas tidak meningkat sebanding. Implikasi audit UTAMA adalah ...","options":["profitabilitas pasti membaik tanpa risiko tambahan","saldo kas harus dianggap salah saji material","auditor cukup memeriksa anggaran penjualan","terdapat risiko cut-off, eksistensi, dan kolektibilitas piutang yang perlu ditindaklanjuti"],"correct":"D","concept":"Interpretasi hubungan lintas akun","explanation":"Prosedur analitis tidak berhenti pada perhitungan perubahan, tetapi menilai apakah hubungan antarakun masuk akal. Penjualan dan piutang yang tumbuh tanpa dukungan penerimaan kas dapat menunjukkan pencatatan pendapatan terlalu dini, penjualan fiktif, keterlambatan penagihan, atau memburuknya kolektibilitas. Auditor perlu menghubungkan indikator tersebut dengan asersi occurrence, cut-off, dan valuation, lalu merancang konfirmasi, pengujian dokumen pengiriman, subsequent receipt, dan evaluasi penyisihan. Kondisi ini tidak otomatis membuktikan kas salah, tetapi merupakan red flag yang memerlukan bukti tambahan.","whyOthersWrong":"A mengabaikan risiko kualitas pendapatan. B menyimpulkan salah saji tanpa bukti. C terlalu sempit karena anggaran bukan bukti utama atas keberadaan piutang.","tip":"Perhatikan hubungan penjualan–piutang–kas. Jika salah satu tidak bergerak konsisten, cari risiko pendapatan dan kolektibilitas.","reference":"TM 2 dan TM 7; UTS Praktikum Audit 2023/2024; Memorandum Prosedur Analitis.","keywords":"analitis; penjualan; piutang; kas"},{"number":9,"topic":"Risiko Fraud dan Pengendalian Internal","subtopic":"Management override","learningOutcome":"Mengidentifikasi risiko fraud pada level manajemen","difficulty":"Sedang","type":"Konseptual","question":"Mengapa management override tetap menjadi perhatian walaupun desain pengendalian tampak baik?","options":["karena setiap pengendalian otomatis tidak dapat diuji","karena manajemen dapat mengabaikan atau memanipulasi pengendalian yang telah ditetapkan","karena auditor wajib menganggap semua transaksi sebagai fraud","karena override hanya terjadi pada perusahaan kecil"],"correct":"B","concept":"Risiko management override","explanation":"Manajemen memiliki posisi dan otoritas yang memungkinkan mereka melewati persetujuan normal, membuat jurnal tidak biasa, mengubah estimasi, atau memengaruhi staf agar pengendalian tidak dijalankan. Karena itu, desain kontrol yang baik tidak sepenuhnya menghilangkan risiko fraud pada level manajemen. Auditor perlu mempertahankan skeptisisme profesional, menelaah jurnal penyesuaian, estimasi, transaksi tidak biasa, dan bias manajemen. Auditor tidak menganggap semua transaksi fraud, tetapi menilai risiko secara terarah. Override juga dapat terjadi pada entitas besar maupun kecil.","whyOthersWrong":"A salah karena kontrol otomatis tetap dapat diuji. C bertentangan dengan pendekatan berbasis risiko. D salah karena override tidak bergantung pada ukuran entitas.","tip":"Kata kunci “otoritas manajemen untuk melewati kontrol” selalu mengarah pada management override.","reference":"TM 3; Buddy Brief Praktikum Audit 2026; Materi risiko fraud dan memorandum perencanaan.","keywords":"management override; fraud"},{"number":10,"topic":"Audit Kas dan Setara Kas","subtopic":"Konfirmasi bank dan rekonsiliasi bank","learningOutcome":"Membedakan tujuan bukti eksternal dan rekonsiliasi","difficulty":"Mudah","type":"Konseptual","question":"Perbedaan utama konfirmasi bank dan rekonsiliasi bank adalah ...","options":["konfirmasi bank dibuat klien, sedangkan rekonsiliasi dibuat bank","keduanya hanya menguji kas kecil","konfirmasi memperoleh bukti eksternal tentang hubungan bank, sedangkan rekonsiliasi menjelaskan perbedaan saldo buku dan bank","rekonsiliasi tidak memerlukan pengujian auditor"],"correct":"C","concept":"Perbedaan konfirmasi dan rekonsiliasi bank","explanation":"Konfirmasi bank dikirim dan dikendalikan oleh auditor untuk memperoleh bukti langsung dari bank mengenai saldo, pinjaman, jaminan, atau hubungan perbankan. Rekonsiliasi bank biasanya disiapkan klien untuk menjelaskan perbedaan antara saldo menurut buku dan rekening koran, misalnya cek beredar atau setoran dalam perjalanan. Auditor tetap harus menguji ketepatan aritmetika dan validitas pos rekonsiliasi melalui cutoff bank statement atau dokumen pendukung. Kedua prosedur saling melengkapi dan tidak terbatas pada kas kecil.","whyOthersWrong":"A membalik sumber dokumen. B salah karena fokusnya saldo bank. D salah karena rekonsiliasi buatan klien harus diuji.","tip":"Konfirmasi = bukti dari bank. Rekonsiliasi = jembatan buku ke bank.","reference":"TM 4; Agoes & Trisnawati (2019), Modul Kas dan Setara Kas.","keywords":"konfirmasi bank; rekonsiliasi bank"},{"number":11,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Perhitungan materialitas","learningOutcome":"Menghitung materialitas pelaksanaan","difficulty":"Sedang","type":"Penerapan","question":"Laba bersih setelah pajak sebesar Rp3.455.152.644. Materialitas laporan keuangan ditetapkan 4% dan materialitas pelaksanaan 80% dari materialitas tersebut. Nilai materialitas pelaksanaan yang PALING TEPAT adalah ...","options":["Rp138.206.106","Rp86.378.816","Rp110.564.885","Rp276.412.212"],"correct":"C","concept":"Perhitungan materialitas pelaksanaan","explanation":"Pertama, hitung materialitas laporan keuangan keseluruhan: 4% × Rp3.455.152.644 = Rp138.206.105,76, dibulatkan menjadi Rp138.206.106. Selanjutnya, materialitas pelaksanaan adalah 80% × Rp138.206.105,76 = Rp110.564.884,608 atau sekitar Rp110.564.885. Urutan perhitungan penting karena persentase 80% diterapkan terhadap overall materiality, bukan langsung terhadap laba bersih. Materialitas pelaksanaan yang lebih rendah digunakan untuk mengurangi kemungkinan bahwa agregat salah saji yang tidak dikoreksi dan tidak terdeteksi melampaui materialitas keseluruhan.","whyOthersWrong":"A adalah overall materiality, bukan performance materiality. B menggunakan persentase yang tidak sesuai. D menggandakan materialitas.","tip":"Hitung dua tahap: benchmark × 4%, lalu hasilnya × 80%. Jangan menukar basis perhitungan.","reference":"TM 2; UTS Praktikum Audit 2023/2024; SA 320.","keywords":"performance materiality; 4%; 80%"},{"number":12,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Analisis common-size laba rugi","learningOutcome":"Menganalisis perubahan margin laba bruto","difficulty":"Sedang","type":"Penerapan","question":"Laba bruto tahun 2023 Rp9.370.636.041 dan penjualan Rp42.586.834.000, sedangkan margin laba bruto 2022 sekitar 18,74%. Interpretasi yang PALING TEPAT adalah ...","options":["margin 2023 sekitar 22,00%, sehingga kenaikan perlu dijelaskan melalui harga jual, volume, atau biaya pokok","margin 2023 sekitar 4,55%, sehingga penjualan pasti salah","margin 2023 sekitar 39,07%, sama dengan pertumbuhan penjualan","margin tidak dapat dihitung karena laba bruto bukan akun neraca"],"correct":"A","concept":"Analisis margin laba bruto","explanation":"Margin laba bruto 2023 dihitung Rp9.370.636.041 ÷ Rp42.586.834.000 × 100% = sekitar 22,00%. Dibandingkan margin 2022 sekitar 18,74%, terdapat peningkatan sekitar 3,26 poin persentase. Perubahan ini belum otomatis menunjukkan salah saji, tetapi auditor harus memperoleh penjelasan yang masuk akal, misalnya perubahan harga jual, bauran produk, diskon, biaya pembelian, atau pencatatan persediaan. Jika penjelasan tidak konsisten dengan data operasional, auditor memperluas prosedur pada penjualan, persediaan, dan beban pokok penjualan.","whyOthersWrong":"B salah menghitung rasio. C mencampur margin dengan pertumbuhan penjualan. D salah karena rasio laba rugi dapat dianalisis.","tip":"Margin laba bruto = laba bruto ÷ penjualan, bukan perubahan penjualan atau laba bruto ÷ laba bersih.","reference":"TM 2; UTS Praktikum Audit 2023/2024; Prosedur Analitis Awal.","keywords":"gross margin; common-size"},{"number":13,"topic":"Audit Piutang Usaha","subtopic":"Pemilihan jenis konfirmasi","learningOutcome":"Menerapkan pemilihan prosedur konfirmasi","difficulty":"Sedang","type":"Penerapan","question":"Saldo piutang pelanggan sangat material, telah lama menunggak, dan terdapat perselisihan. Prosedur konfirmasi yang PALING TEPAT adalah ...","options":["konfirmasi negatif tanpa tindak lanjut","konfirmasi positif yang dikendalikan auditor dan diikuti prosedur alternatif jika tidak dijawab","konfirmasi lisan melalui staf penjualan klien","tidak perlu konfirmasi karena saldo sudah ada di buku besar"],"correct":"B","concept":"Pemilihan konfirmasi pada risiko tinggi","explanation":"Konfirmasi positif paling sesuai ketika saldo material, menunggak, atau diperselisihkan karena auditor membutuhkan respons langsung baik setuju maupun tidak setuju. Auditor harus mengendalikan pemilihan alamat, pengiriman, dan penerimaan jawaban untuk menjaga keandalan bukti. Jika tidak ada respons, auditor melakukan prosedur alternatif seperti memeriksa penerimaan kas setelah tanggal neraca, dokumen pengiriman, faktur, dan korespondensi pelanggan. Konfirmasi negatif tidak cukup kuat dalam kondisi risiko tinggi, sedangkan konfirmasi melalui staf klien mengurangi independensi sumber bukti.","whyOthersWrong":"A cocok untuk risiko rendah dan banyak saldo kecil. C tidak independen. D mengandalkan catatan klien tanpa bukti eksternal.","tip":"Material + lama menunggak + sengketa = risiko tinggi = pilih konfirmasi positif dan siapkan prosedur alternatif.","reference":"TM 6; Agoes & Trisnawati (2019), Prosedur Audit Piutang Usaha.","keywords":"konfirmasi positif; saldo material"},{"number":14,"topic":"Pengendalian Penjualan Kredit","subtopic":"Attributes sampling","learningOutcome":"Menentukan respons atas hasil sampling pengendalian","difficulty":"Sedang","type":"Penerapan","question":"Dalam attributes sampling, actual deviation rate melebihi tolerable deviation rate. Auditor seharusnya ...","options":["menganggap pengendalian tetap efektif karena sampel sudah selesai","menurunkan control risk tanpa bukti tambahan","mengurangi ukuran sampel substantif menjadi nol","menilai pengendalian tidak dapat diandalkan sesuai rencana dan menyesuaikan prosedur substantif"],"correct":"D","concept":"Evaluasi hasil attributes sampling","explanation":"Tolerable deviation rate adalah batas penyimpangan pengendalian yang masih dapat diterima auditor untuk mempertahankan reliance yang direncanakan. Jika tingkat penyimpangan aktual atau estimasian melebihi batas tersebut, hasil sampling tidak mendukung kesimpulan bahwa kontrol berjalan efektif pada tingkat yang diharapkan. Auditor perlu menilai penyebab penyimpangan, mempertimbangkan perluasan pengujian kontrol, menilai kembali control risk, dan menambah atau memperkuat prosedur substantif. Hasil sampling tidak membenarkan penurunan control risk maupun penghapusan pengujian substantif.","whyOthersWrong":"A mengabaikan evaluasi hasil. B berlawanan dengan bukti. C justru mengurangi respons saat risiko meningkat.","tip":"Actual > tolerable berarti batas reliance terlampaui. Responsnya bukan mengubah batas, tetapi mengubah penilaian risiko dan audit response.","reference":"TM 5; Materi Test of Control dan Attributes Sampling.","keywords":"actual deviation; tolerable deviation"},{"number":15,"topic":"Audit Kas dan Setara Kas","subtopic":"Proof of cash","learningOutcome":"Menentukan prosedur audit kas yang sesuai","difficulty":"Sedang","type":"Penerapan","question":"Auditor ingin menguji hubungan saldo awal, penerimaan, pengeluaran, dan saldo akhir kas bank selama satu periode. Prosedur yang paling sesuai adalah ...","options":["cash count","konfirmasi piutang","proof of cash","inspeksi aset tetap"],"correct":"C","concept":"Penggunaan proof of cash","explanation":"Proof of cash merekonsiliasi saldo kas awal, total penerimaan, total pengeluaran, dan saldo kas akhir antara catatan bank dan buku klien. Prosedur ini dapat mengungkap perbedaan transaksi maupun saldo, termasuk penerimaan atau pengeluaran yang belum dicatat, salah periode, atau manipulasi tertentu. Cash count hanya menguji uang fisik pada suatu waktu, sehingga tidak menjelaskan aliran transaksi bank selama periode. Konfirmasi piutang dan inspeksi aset tetap tidak relevan dengan tujuan yang dinyatakan dalam soal.","whyOthersWrong":"A fokus pada kas fisik, bukan rekonsiliasi aliran bank. B dan D menguji akun lain.","tip":"Empat unsur “saldo awal–penerimaan–pengeluaran–saldo akhir” adalah pola khas proof of cash.","reference":"TM 4; Buddy Brief Praktikum Audit 2026; Modul Kas dan Setara Kas.","keywords":"proof of cash; aliran kas"},{"number":16,"topic":"Audit Kas dan Setara Kas","subtopic":"Kas kecil imprest","learningOutcome":"Menganalisis selisih kas kecil","difficulty":"Sulit","type":"Mini Kasus","question":"Dana kas kecil imprest ditetapkan Rp5.000.000. Saat cash count, kas fisik Rp700.000 dan voucher sah Rp3.800.000. Tindakan auditor yang PALING TEPAT adalah ...","options":["mencatat selisih Rp500.000, menelusuri pertanggungjawaban, otorisasi, dan kemungkinan penyalahgunaan","menyimpulkan saldo benar karena voucher lebih besar daripada kas fisik","mengabaikan selisih karena kas kecil tidak pernah material","mengganti seluruh voucher dengan konfirmasi bank"],"correct":"A","concept":"Evaluasi kas kecil imprest","explanation":"Dalam sistem imprest, kas fisik ditambah voucher sah seharusnya sama dengan dana tetap. Rp700.000 + Rp3.800.000 = Rp4.500.000, sehingga terdapat kekurangan Rp500.000. Auditor perlu mendokumentasikan selisih, memeriksa tanggal dan otorisasi voucher, bukti pengisian kembali, pihak yang memegang kas, serta meminta penjelasan tertulis. Selisih dapat menunjukkan kesalahan, voucher tidak lengkap, atau penyalahgunaan. Materialitas nominal tetap dipertimbangkan bersama faktor kualitatif, terutama jika kelemahan kontrol atau indikasi fraud muncul.","whyOthersWrong":"B salah karena total hanya Rp4,5 juta. C mengabaikan faktor kualitatif. D tidak relevan karena konfirmasi bank tidak membuktikan isi kas kecil.","tip":"Imprest harus memenuhi rumus: kas fisik + voucher sah = dana tetap.","reference":"TM 4; Contoh Kas Kecil Imprest pada Cheatsheet Praktikum Audit TM 1–7.","keywords":"imprest; cash shortage; vouching"},{"number":17,"topic":"Audit Piutang Usaha","subtopic":"NSF check dan subsequent receipt","learningOutcome":"Mengevaluasi bukti pelunasan piutang","difficulty":"Sulit","type":"Mini Kasus","question":"Pelanggan menyatakan telah membayar Rp325.000.000 sebelum tahun-end, tetapi rekening koran menunjukkan cek tersebut NSF. Perlakuan audit yang PALING TEPAT adalah ...","options":["menghapus piutang karena pelanggan mengaku telah membayar","mengakui kas dan mengurangi piutang karena cek telah diterima","mereklasifikasi seluruh saldo menjadi pendapatan lain-lain","mempertahankan piutang dan menilai kolektibilitas karena cek gagal dicairkan"],"correct":"D","concept":"Dampak NSF check","explanation":"NSF check adalah cek yang tidak dapat dicairkan karena dana tidak mencukupi. Penerimaan cek tersebut belum menghasilkan kas yang dapat digunakan dan tidak menyelesaikan kewajiban pelanggan. Karena itu, piutang tetap ada sampai pembayaran valid diterima. Auditor perlu memeriksa rekening koran, korespondensi, penerimaan berikutnya, serta menilai apakah kondisi pelanggan memerlukan penyisihan kerugian kredit. Mengurangi piutang atau mengakui kas akan melebihsajikan kas dan merendahsajikan piutang jika cek gagal dicairkan.","whyOthersWrong":"A dan B menganggap cek gagal sebagai pembayaran sah. C tidak memiliki dasar akuntansi dan tidak menyelesaikan isu eksistensi atau penilaian.","tip":"Cek diterima belum tentu kas. Jika NSF, perlakukan seolah pembayaran belum terjadi.","reference":"TM 6; Kasus Audit Piutang PT Centris pada Buddy Drill Praktikum Audit.","keywords":"NSF check; piutang; kolektibilitas"},{"number":18,"topic":"Pengendalian Penjualan Kredit","subtopic":"Retur penjualan dan cut-off","learningOutcome":"Menentukan koreksi atas transaksi periode berjalan","difficulty":"Sulit","type":"Mini Kasus","question":"Pelanggan mengonfirmasi saldo Rp75.000.000 lebih rendah karena retur barang tanggal 8 Desember belum dicatat klien. Credit memo mendukung retur tersebut. Koreksi PALING TEPAT adalah ...","options":["menambah penjualan dan piutang Rp75.000.000","hanya memindahkan piutang ke pelanggan lain","mengurangi penjualan atau retur penjualan dan mengurangi piutang Rp75.000.000","menunda koreksi sampai pelanggan membayar"],"correct":"C","concept":"Koreksi retur sebelum tanggal laporan","explanation":"Retur yang terjadi sebelum tanggal laporan dan didukung credit memo harus tercermin dalam saldo penjualan neto dan piutang pada periode tersebut. Jika belum dicatat, penjualan dan piutang terlalu tinggi sebesar Rp75.000.000. Koreksi yang tepat adalah mendebit retur penjualan atau mengurangi penjualan serta mengkredit piutang usaha. Bukti konfirmasi dan credit memo saling menguatkan. Menunda koreksi sampai pembayaran tidak tepat karena isu utamanya adalah pengakuan retur pada periode yang benar, bukan waktu kas diterima.","whyOthersWrong":"A memperbesar salah saji. B hanya memindahkan saldo tanpa mengakui retur. D melanggar cut-off karena transaksi sudah terjadi sebelum tahun-end.","tip":"Retur sebelum tahun-end + credit memo = turunkan penjualan neto dan piutang pada periode berjalan.","reference":"TM 5 dan TM 6; Kasus Audit Piutang PT Berdikari.","keywords":"retur penjualan; credit memo; cut-off"},{"number":19,"topic":"Audit Piutang Usaha","subtopic":"Prosedur alternatif konfirmasi","learningOutcome":"Menentukan prosedur ketika konfirmasi tidak dijawab","difficulty":"Sulit","type":"Mini Kasus","question":"Konfirmasi positif kepada pelanggan tidak dijawab. Dua minggu setelah tahun-end, pelanggan membayar seluruh saldo melalui bank. Kesimpulan dan prosedur yang PALING TEPAT adalah ...","options":["menganggap konfirmasi gagal dan menghapus saldo","memeriksa subsequent receipt beserta rekening koran dan dokumen penjualan sebagai prosedur alternatif","mengganti jawaban pelanggan dengan pernyataan staf penjualan","langsung menyatakan pengendalian penjualan efektif"],"correct":"B","concept":"Prosedur alternatif atas nonresponse","explanation":"Ketika konfirmasi positif tidak dijawab, auditor tidak boleh menganggap saldo salah atau benar tanpa bukti tambahan. Subsequent receipt merupakan prosedur alternatif yang kuat apabila auditor memeriksa kredit pada rekening koran, pencatatan penerimaan kas, identitas pelanggan, serta dokumen penjualan dan pengiriman yang mendasari saldo. Pembayaran setelah tanggal laporan mendukung eksistensi dan sering membantu penilaian kolektibilitas, tetapi auditor tetap memastikan pembayaran benar-benar berkaitan dengan saldo yang diuji. Pernyataan staf klien tidak menggantikan bukti eksternal.","whyOthersWrong":"A tidak didukung bukti. C kurang independen. D membahas efektivitas kontrol, bukan validitas saldo individu.","tip":"Nonresponse bukan akhir prosedur. Cari subsequent cash receipt dan bukti transaksi asal.","reference":"TM 6; Agoes & Trisnawati (2019), Prosedur Alternatif Konfirmasi Piutang.","keywords":"nonresponse; subsequent receipt"},{"number":20,"topic":"Pengendalian Penjualan Kredit","subtopic":"Penjualan ganda","learningOutcome":"Menganalisis bukti transaksi ganda","difficulty":"Sulit","type":"Mini Kasus","question":"Dua entri penjualan masing-masing Rp11.000.000 menggunakan nomor surat jalan yang sama dan hanya ada satu pengiriman. Tindakan auditor yang PALING TEPAT adalah ...","options":["membalik satu pencatatan penjualan dan piutang serta menilai kelemahan kontrol duplikasi","mempertahankan keduanya karena faktur telah bernomor","menghapus seluruh saldo pelanggan","mengakui selisih sebagai pendapatan bunga"],"correct":"A","concept":"Koreksi penjualan ganda","explanation":"Satu bukti pengiriman hanya mendukung satu transaksi penjualan. Dua entri dengan surat jalan yang sama menunjukkan pencatatan ganda sehingga penjualan dan piutang terlalu tinggi sebesar Rp11.000.000. Auditor perlu mengusulkan pembalikan satu entri, menelusuri faktur dan jurnal, serta menilai mengapa sistem tidak mencegah nomor dokumen dipakai dua kali. Asersi yang terdampak terutama occurrence dan accuracy. Nomor faktur saja tidak cukup jika tidak ada pengiriman kedua, dan penghapusan seluruh saldo akan berlebihan.","whyOthersWrong":"B mengabaikan bukti pengiriman. C menghapus transaksi yang sah. D tidak terkait dengan sifat salah saji.","tip":"Satu pengiriman tidak boleh mendukung dua penjualan. Fokus pada occurrence dan kontrol nomor dokumen.","reference":"TM 5 dan TM 6; Kasus PT Krakatau pada Buddy Drill Praktikum Audit.","keywords":"duplicate sale; occurrence; accuracy"},{"number":21,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Vouching dan tracing","learningOutcome":"Membedakan arah dan tujuan pengujian","difficulty":"Sedang","type":"Perbandingan","question":"Pernyataan yang PALING TEPAT mengenai vouching dan tracing adalah ...","options":["keduanya selalu dimulai dari laporan keuangan dan menguji valuation","vouching menguji kelengkapan, sedangkan tracing menguji occurrence","vouching hanya untuk kas, sedangkan tracing hanya untuk persediaan","vouching bergerak dari catatan ke bukti untuk occurrence, sedangkan tracing dari bukti ke catatan untuk completeness"],"correct":"D","concept":"Perbedaan vouching dan tracing","explanation":"Vouching memilih transaksi yang telah dicatat lalu memeriksa dokumen sumber untuk memastikan transaksi benar-benar terjadi dan didukung bukti, sehingga terutama relevan untuk occurrence. Tracing memilih dokumen sumber lalu menelusurinya ke catatan akuntansi untuk menemukan transaksi yang mungkin belum dicatat, sehingga terutama relevan untuk completeness. Kedua prosedur dapat digunakan pada berbagai siklus, bukan hanya kas atau persediaan. Arah pengujian menjadi jembatan penting untuk memilih asersi yang diuji.","whyOthersWrong":"A salah karena arah dan asersinya berbeda. B membalik fungsi keduanya. C membatasi prosedur tanpa dasar.","tip":"Vouching: book to proof. Tracing: proof to book.","reference":"TM 5 dan TM 7; Agoes & Trisnawati (2019), Istilah Audit.","keywords":"vouching; tracing; arah pengujian"},{"number":22,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Overall dan performance materiality","learningOutcome":"Membedakan dua tingkat materialitas","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan yang PALING TEPAT antara overall materiality dan performance materiality adalah ...","options":["overall hanya untuk akun kas, performance hanya untuk piutang","overall selalu lebih kecil daripada performance","overall menjadi batas pada laporan keuangan keseluruhan, sedangkan performance ditetapkan lebih rendah untuk merancang prosedur dan mengurangi risiko agregasi salah saji","keduanya wajib bernilai sama"],"correct":"C","concept":"Dua tingkat materialitas","explanation":"Overall materiality berhubungan dengan salah saji yang dapat memengaruhi keputusan pengguna pada laporan keuangan secara keseluruhan. Performance materiality ditetapkan pada jumlah yang lebih rendah untuk mengurangi kemungkinan agregat salah saji tidak dikoreksi dan tidak terdeteksi melebihi overall materiality. Nilai yang lebih rendah tersebut membantu auditor merancang prosedur untuk golongan transaksi, saldo akun, dan pengungkapan. Keduanya tidak dibatasi pada akun tertentu dan tidak harus sama; hubungan umumnya adalah performance materiality lebih rendah daripada overall materiality.","whyOthersWrong":"A membatasi secara keliru. B membalik hubungan. D menghilangkan fungsi pengaman performance materiality.","tip":"Overall = batas keseluruhan. Performance = bantalan kerja yang lebih rendah.","reference":"TM 2; SA 320; RPS Praktikum Audit ASP4126.","keywords":"overall materiality; performance materiality"},{"number":23,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Jurnal penyesuaian dan reklasifikasi","learningOutcome":"Membedakan dampak dua jenis jurnal audit","difficulty":"Sedang","type":"Perbandingan","question":"Perbedaan utama jurnal penyesuaian dan jurnal reklasifikasi dalam kertas kerja audit adalah ...","options":["penyesuaian mengoreksi salah saji yang memengaruhi jumlah, sedangkan reklasifikasi memperbaiki penyajian antarpos tanpa mengubah laba bersih secara total","penyesuaian hanya dibuat auditor internal, reklasifikasi hanya auditor eksternal","reklasifikasi selalu menambah laba bersih","keduanya tidak perlu dikaitkan dengan temuan audit"],"correct":"A","concept":"AJE dan reclassification entry","explanation":"Jurnal penyesuaian audit mengoreksi salah saji pengakuan, pengukuran, atau periode yang memengaruhi saldo akun dan dapat memengaruhi laba atau ekuitas. Jurnal reklasifikasi memindahkan jumlah antarpos agar penyajian dan klasifikasi laporan keuangan tepat, tetapi secara total biasanya tidak mengubah laba bersih. Keduanya harus didukung temuan, bukti, dan referensi silang pada kertas kerja. Pembeda ini penting agar auditor dan klien memahami apakah isu menyangkut jumlah yang salah atau hanya lokasi penyajian.","whyOthersWrong":"B tidak berdasar. C salah karena reklasifikasi umumnya tidak mengubah total laba. D bertentangan dengan prinsip dokumentasi audit.","tip":"Adjustment mengubah angka yang salah; reclassification mengubah tempat penyajian.","reference":"TM 1 dan TM 7; Agoes & Trisnawati (2019), Daftar Jurnal Koreksi dan Reklasifikasi.","keywords":"adjusting entry; reclassification"},{"number":24,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Respons audit terintegrasi","learningOutcome":"Mengevaluasi risiko dan merancang kombinasi prosedur","difficulty":"Sulit","type":"Analisis","question":"Penjualan naik 39%, piutang naik 41%, penerimaan kas tertinggal, dan test of control atas persetujuan kredit gagal. Paket respons audit yang PALING KUAT adalah ...","options":["mengandalkan rasio saja karena perubahan masih searah","menilai control risk lebih tinggi, menguji cut-off dan dokumen pengiriman, memperluas konfirmasi serta subsequent receipt, dan mengevaluasi penyisihan","menaikkan materialitas lalu mengurangi sampel","hanya melakukan inquiry kepada manajer pemasaran"],"correct":"B","concept":"Rancangan respons audit berbasis risiko","explanation":"Fakta analitis dan kegagalan kontrol saling memperkuat risiko pada occurrence, cut-off, serta valuation piutang. Auditor perlu menaikkan penilaian control risk dan menurunkan detection risk yang dapat diterima melalui prosedur substantif yang lebih kuat. Kombinasi yang tepat meliputi vouching dokumen pengiriman, pengujian cut-off, konfirmasi piutang, subsequent receipt, serta evaluasi umur piutang dan penyisihan. Mengandalkan rasio atau inquiry saja tidak cukup, sedangkan menaikkan materialitas untuk mengurangi pekerjaan tidak sesuai dengan tujuan materialitas.","whyOthersWrong":"A dan D tidak menghasilkan bukti cukup. C menyesuaikan ambang agar pekerjaan berkurang, bukan merespons risiko.","tip":"Gabungkan fakta analitis + kontrol gagal → respons harus mencakup occurrence, cut-off, dan valuation dengan bukti eksternal serta dokumen sumber.","reference":"TM 2, TM 5, TM 6, dan TM 7; RPS Praktikum Audit ASP4126.","keywords":"integrated response; NTE; piutang"},{"number":25,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Kecukupan bukti dan simpulan kertas kerja","learningOutcome":"Mengevaluasi kesiapan auditor menarik simpulan","difficulty":"Sulit","type":"Analisis","question":"Auditor belum memperoleh jawaban konfirmasi atas saldo piutang material, subsequent receipt tidak tersedia, dan dokumen pengiriman tidak lengkap. Tindakan PERTAMA yang PALING TEPAT adalah ...","options":["menyimpulkan saldo benar karena ada di buku besar","langsung menerbitkan management letter","menghapus piutang tanpa persetujuan klien","memperluas prosedur alternatif dan mendokumentasikan isu sebagai unresolved item sebelum menarik simpulan"],"correct":"D","concept":"Kecukupan bukti sebelum simpulan","explanation":"Auditor belum memiliki bukti cukup dan tepat untuk mendukung eksistensi, cut-off, atau nilai saldo material. Karena itu, langkah pertama adalah mencari prosedur alternatif lain, misalnya korespondensi pelanggan, bukti pesanan, dokumen pengiriman pihak ketiga, penerimaan periode berikutnya yang lebih panjang, atau pemeriksaan kontrak. Isu harus dicatat sebagai unresolved item dan dikomunikasikan untuk review. Auditor tidak boleh menyimpulkan saldo benar hanya dari buku besar, menghapus saldo secara sepihak, atau beralih ke pelaporan sebelum dampak keterbatasan bukti dievaluasi.","whyOthersWrong":"A mengandalkan bukti internal yang tidak cukup. B terlalu dini. C bukan kewenangan auditor dan belum didukung bukti.","tip":"Jika bukti belum cukup, jangan lompat ke simpulan. Perluas prosedur, dokumentasikan isu, lalu evaluasi dampaknya.","reference":"TM 6 dan TM 7; Kecukupan Bukti dan Self-Review Kertas Kerja.","keywords":"sufficiency; unresolved item; alternative procedure"}],"flashcards":[{"number":1,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Audit laporan keuangan","difficulty":"Mudah","type":"Definisi","question":"Apa tujuan utama audit laporan keuangan?","shortAnswer":"Memberikan opini apakah laporan keuangan disajikan secara wajar sesuai kerangka pelaporan yang berlaku.","explanation":"Audit bukan jaminan bahwa seluruh transaksi bebas kesalahan. Auditor memperoleh keyakinan memadai melalui pendekatan berbasis risiko dan bukti audit yang cukup serta tepat. Fokusnya adalah salah saji material, baik akibat kekeliruan maupun kecurangan, lalu mengomunikasikan kesimpulan melalui laporan auditor. Opini tersebut didasarkan pada pengujian sampel, prosedur analitis, pemahaman pengendalian, dan evaluasi bukti secara keseluruhan.","example":"Auditor memusatkan pengujian pada penjualan kredit dan piutang ketika pertumbuhannya tidak sejalan dengan penerimaan kas.","keywords":"opini; kewajaran; salah saji material","comparison":"Audit laporan keuangan ≠ pemeriksaan 100% seluruh transaksi.","mnemonic":"Ingat O-W-M: Opini atas Wajar tidaknya salah saji Material."},{"number":2,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Perencanaan audit","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud dengan perencanaan audit?","shortAnswer":"Proses menyusun strategi dan rencana kerja agar audit efektif, efisien, dan berfokus pada risiko salah saji material.","explanation":"Perencanaan mencakup pemahaman bisnis, penentuan materialitas, prosedur analitis awal, identifikasi risiko, penilaian pengendalian, penetapan tim, jadwal, dan program audit. Rencana bukan dokumen statis; auditor memperbaruinya ketika memperoleh informasi baru selama pelaksanaan audit. Hasil perencanaan juga menjadi dasar pembagian tugas serta dokumentasi alasan auditor memilih prosedur tertentu.","example":"Kelemahan pengendalian kas membuat auditor merencanakan cash count, konfirmasi bank, dan pengujian rekonsiliasi lebih luas.","keywords":"strategi; risiko; materialitas; program audit","comparison":"Strategi audit bersifat menyeluruh, sedangkan program audit merinci prosedur per area.","mnemonic":"Pahami–Nilai–Rancang: pahami bisnis, nilai risiko, rancang prosedur."},{"number":3,"topic":"Risiko Fraud dan Pengendalian Internal","subtopic":"Pengendalian internal","difficulty":"Mudah","type":"Definisi","question":"Apa itu pengendalian internal?","shortAnswer":"Kebijakan dan prosedur untuk menjaga aset, mendukung pelaporan andal, meningkatkan kepatuhan, dan membantu operasi berjalan efektif.","explanation":"Pengendalian dapat bersifat preventif, detektif, atau korektif. Auditor memahami desain dan implementasinya untuk menilai risiko salah saji serta menentukan apakah pengendalian dapat diandalkan. Pengendalian yang baik mengurangi risiko, tetapi tidak menghilangkannya karena ada keterbatasan bawaan dan kemungkinan management override. Efektivitasnya dinilai melalui walkthrough, inquiry, inspeksi dokumen, observasi, dan test of control yang relevan.","example":"Persetujuan kredit sebelum pengiriman mencegah penjualan kepada pelanggan berisiko tinggi.","keywords":"aset; pelaporan; kepatuhan; operasi","comparison":"Pengendalian internal ≠ prosedur audit; pengendalian milik klien, prosedur audit dilakukan auditor.","mnemonic":"A-P-K-O: Aset, Pelaporan, Kepatuhan, Operasi."},{"number":4,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Materialitas","difficulty":"Mudah","type":"Definisi","question":"Apa arti materialitas dalam audit?","shortAnswer":"Besaran atau sifat salah saji yang secara wajar dapat memengaruhi keputusan pengguna laporan keuangan.","explanation":"Materialitas bersifat relatif dan memerlukan pertimbangan profesional. Auditor memilih benchmark yang relevan, mempertimbangkan faktor kuantitatif dan kualitatif, lalu menetapkan overall materiality dan performance materiality. Salah saji kecil dapat tetap material jika berkaitan dengan fraud, perjanjian utang, atau perubahan tren laba.","example":"Kesalahan Rp10 juta mungkin tidak material bagi perusahaan besar, tetapi dapat material bagi organisasi kecil atau jika menutupi fraud.","keywords":"benchmark; pengguna; kuantitatif; kualitatif","comparison":"Materialitas ≠ tolerable deviation rate; yang satu untuk salah saji laporan, yang lain untuk penyimpangan kontrol.","mnemonic":"BESAR atau SIFAT yang mengubah keputusan."},{"number":5,"topic":"Risiko Fraud dan Pengendalian Internal","subtopic":"Risiko audit","difficulty":"Mudah","type":"Definisi","question":"Apa tiga komponen model risiko audit?","shortAnswer":"Inherent risk, control risk, dan detection risk; dirumuskan AR = IR × CR × DR.","explanation":"Inherent risk adalah kerentanan salah saji sebelum mempertimbangkan kontrol. Control risk adalah risiko kontrol klien gagal mencegah atau mendeteksi salah saji. Detection risk adalah risiko prosedur auditor gagal menemukan salah saji material. Auditor mengelola detection risk melalui sifat, waktu, dan luas prosedur.","example":"Jika IR dan CR tinggi pada piutang, auditor menurunkan DR dengan memperluas konfirmasi dan subsequent receipt.","keywords":"IR; CR; DR; audit risk","comparison":"IR dan CR berasal dari entitas; DR dipengaruhi rancangan dan pelaksanaan audit.","mnemonic":"Entitas memberi I-C, Auditor mengelola D."},{"number":6,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Permanent file","difficulty":"Mudah","type":"Definisi","question":"Apa fungsi permanent file?","shortAnswer":"Menyimpan informasi klien yang relatif tetap dan dapat digunakan kembali pada audit periode berikutnya.","explanation":"Isi umum permanent file meliputi akta pendirian, struktur organisasi, kebijakan akuntansi, kode akun, kontrak jangka panjang, serta dokumen hukum penting. Auditor menelaah dan memperbaruinya jika terjadi perubahan. Dokumen yang khusus untuk tahun berjalan disimpan dalam current file. Pemisahan ini menjaga arsip tetap ringkas, mudah diperbarui, dan dapat direviu tanpa mencampur bukti antarperiode.","example":"Perubahan susunan direksi diperbarui pada struktur organisasi dalam permanent file.","keywords":"jangka panjang; akta; struktur; kebijakan","comparison":"Permanent file bersifat lintas periode; current file khusus audit tahun berjalan.","mnemonic":"Permanen = Panjang umur informasinya."},{"number":7,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Surat perikatan","difficulty":"Mudah","type":"Istilah","question":"Apa isi kunci engagement letter?","shortAnswer":"Tujuan dan ruang lingkup audit, tanggung jawab auditor dan manajemen, kerangka pelaporan, serta bentuk komunikasi hasil.","explanation":"Engagement letter mencegah kesalahpahaman sebelum audit dimulai. Dokumen ini juga dapat memuat jadwal, akses informasi, penggunaan pakar, dan honorarium jika relevan. Surat ini berbeda dari surat representasi yang diperoleh menjelang penyelesaian audit. Auditor memastikan ketentuan tersebut dipahami dan disepakati sebelum pekerjaan lapangan serta permintaan data dimulai.","example":"Klien menandatangani surat perikatan sebelum auditor meminta dokumen perencanaan.","keywords":"engagement; scope; responsibility","comparison":"Engagement letter dibuat di awal; representation letter diperoleh di akhir.","mnemonic":"E-S-R-L: Engagement = Scope, Responsibility, Letter/report."},{"number":8,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Tickmark dan cross-reference","difficulty":"Mudah","type":"Istilah","question":"Mengapa tickmark dan cross-reference penting?","shortAnswer":"Untuk menunjukkan prosedur yang telah dilakukan dan menghubungkan bukti antar-kertas kerja secara dapat ditelusuri.","explanation":"Tickmark harus memiliki legenda yang jelas, sedangkan cross-reference menghubungkan lead schedule, supporting schedule, jurnal penyesuaian, dan dokumen sumber. Keduanya membantu reviewer memahami pekerjaan tanpa penjelasan lisan tambahan dan memastikan audit trail keputusan terjaga. Dokumentasi yang konsisten juga memudahkan pemeriksa mutu menelusuri asal angka dan alasan kesimpulan audit.","example":"Simbol TB menunjukkan saldo telah dicocokkan ke trial balance; indeks E mengarah ke lead schedule piutang.","keywords":"tickmark; indeks; referensi silang","comparison":"Tickmark menjelaskan tindakan; cross-reference menunjukkan lokasi bukti terkait.","mnemonic":"Tanda = tindakan, referensi = rute."},{"number":9,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Benchmark materialitas","difficulty":"Sedang","type":"Istilah","question":"Apa yang dimaksud benchmark materialitas?","shortAnswer":"Tolok ukur finansial yang digunakan sebagai dasar awal menghitung materialitas.","explanation":"Benchmark dipilih berdasarkan karakter dan stabilitas entitas, misalnya laba sebelum pajak, penjualan, total aset, atau ekuitas. Auditor tidak memilih benchmark secara mekanis; faktor pengguna laporan dan volatilitas kinerja perlu dipertimbangkan. Persentase kemudian diterapkan sebagai titik awal, bukan aturan mutlak. Perubahan benchmark harus didokumentasikan agar pertimbangan materialitas dapat dipahami dan direviu.","example":"Entitas nirlaba mungkin lebih relevan menggunakan total beban atau aset daripada laba.","keywords":"benchmark; laba; penjualan; aset","comparison":"Benchmark adalah dasar angka; faktor kualitatif dapat mengubah kesimpulan materialitas.","mnemonic":"Pilih angka yang paling dilihat pengguna."},{"number":10,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Days Sales Outstanding","difficulty":"Sedang","type":"Istilah","question":"Apa makna kenaikan DSO dalam prosedur analitis?","shortAnswer":"Rata-rata waktu penagihan meningkat, sehingga risiko keterlambatan, kolektibilitas, atau kualitas pendapatan perlu ditelaah.","explanation":"DSO menghubungkan saldo piutang dengan penjualan kredit. Kenaikan yang tidak dijelaskan dapat menunjukkan penagihan memburuk, piutang lama, penjualan mendekati akhir periode, atau pencatatan pendapatan yang agresif. Auditor menggabungkan analisis ini dengan aging schedule, subsequent receipt, dan konfirmasi. Rasio ini tidak berdiri sendiri; auditor perlu membandingkannya dengan kebijakan kredit, tren industri, dan data periode sebelumnya.","example":"DSO naik dari 45 menjadi 78 hari sementara kebijakan kredit tidak berubah.","keywords":"DSO; penagihan; aging; kolektibilitas","comparison":"Pertumbuhan piutang menunjukkan perubahan nominal; DSO menilai kecepatan penagihan relatif terhadap penjualan.","mnemonic":"DSO naik = Dana Semakin Ompong/terlambat masuk."},{"number":11,"topic":"Audit Piutang Usaha","subtopic":"Konfirmasi positif","difficulty":"Sedang","type":"Istilah","question":"Kapan konfirmasi positif lebih tepat digunakan?","shortAnswer":"Saat saldo material, risiko tinggi, terdapat sengketa, atau auditor membutuhkan respons langsung dari pelanggan.","explanation":"Konfirmasi positif meminta respons baik setuju maupun tidak setuju. Auditor mengendalikan alamat, pengiriman, dan penerimaan jawaban. Nonresponse harus ditindaklanjuti dengan pengiriman ulang atau prosedur alternatif. Bukti ini terutama mendukung eksistensi dan dapat membantu hak serta akurasi. Selisih jawaban harus direkonsiliasi, bukan langsung dianggap sebagai salah saji tanpa memahami penyebab waktunya.","example":"Saldo pelanggan terbesar yang menunggak 180 hari dikonfirmasi secara positif.","keywords":"positive confirmation; response; material","comparison":"Konfirmasi negatif hanya meminta respons jika tidak setuju dan cocok untuk risiko lebih rendah.","mnemonic":"Positif = pasti minta jawaban."},{"number":12,"topic":"Perencanaan Audit dan Kertas Kerja","subtopic":"Tahapan audit","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan umum proses audit dari awal sampai pelaporan?","shortAnswer":"Penerimaan klien → perencanaan → pemahaman kontrol → pengujian → evaluasi temuan → pelaporan.","explanation":"Urutan tersebut membantu auditor bergerak dari keputusan menerima penugasan menuju opini. Dalam praktik, beberapa aktivitas dapat berlangsung paralel dan rencana diperbarui berdasarkan bukti baru. Setiap tahap harus terdokumentasi dan terhubung dengan risiko serta tujuan audit. Evaluasi akhir juga memastikan seluruh temuan, jurnal koreksi, dan isu belum terselesaikan telah ditangani sebelum laporan diterbitkan.","example":"Setelah perencanaan dan penilaian kontrol, auditor melaksanakan test of control serta pengujian substantif.","keywords":"acceptance; planning; testing; reporting","comparison":"Tahapan audit adalah alur besar; program audit adalah daftar prosedur rinci per area.","mnemonic":"Terima–Rancang–Pahami–Uji–Nilai–Lapor."},{"number":13,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Prosedur analitis awal","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan prosedur analitis awal yang efektif?","shortAnswer":"Susun ekspektasi → hitung perubahan/rasio → identifikasi deviasi → cari penjelasan → hubungkan ke risiko dan prosedur.","explanation":"Auditor harus menetapkan ekspektasi yang masuk akal sebelum menilai selisih. Angka yang tidak biasa tidak otomatis salah, tetapi harus ditindaklanjuti dengan informasi bisnis, data nonkeuangan, dan bukti audit. Hasil akhirnya didokumentasikan dalam memorandum perencanaan. Penjelasan manajemen harus dikorroborasi dengan bukti, bukan diterima hanya berdasarkan inquiry.","example":"Margin laba bruto naik tajam; auditor menilai perubahan harga, biaya pembelian, dan kemungkinan salah saji persediaan.","keywords":"ekspektasi; deviasi; risiko; memorandum","comparison":"Perhitungan rasio adalah alat; interpretasi dan tindak lanjut adalah tujuan analitis.","mnemonic":"E-H-I-J-R: Ekspektasi, Hitung, Identifikasi, Jelaskan, Respons."},{"number":14,"topic":"Audit Kas dan Setara Kas","subtopic":"Audit rekonsiliasi bank","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan ringkas mengaudit rekonsiliasi bank?","shortAnswer":"Cocokkan saldo buku dan bank → uji aritmetika → periksa setoran dalam perjalanan dan cek beredar → telusuri clearing setelah tahun-end → simpulkan.","explanation":"Auditor juga membandingkan saldo dengan konfirmasi bank dan buku besar. Setiap pos rekonsiliasi harus memiliki bukti dan periode yang tepat. Cutoff bank statement membantu memastikan pos tersebut benar-benar clearing setelah tanggal laporan dan bukan rekayasa. Auditor juga memeriksa transaksi transfer antarbank agar tidak terjadi window dressing atau pencatatan ganda.","example":"Cek beredar ditelusuri ke rekening koran Januari untuk memastikan pencairan setelah 31 Desember.","keywords":"rekonsiliasi; clearing; cutoff statement","comparison":"Rekonsiliasi menjelaskan perbedaan; konfirmasi membuktikan informasi langsung dari bank.","mnemonic":"B-A-P-C-S: Buku/Bank, Aritmetika, Pos, Clearing, Simpulan."},{"number":15,"topic":"Audit Piutang Usaha","subtopic":"Tindak lanjut konfirmasi","difficulty":"Sedang","type":"Tahapan","question":"Apa langkah ketika konfirmasi positif tidak dijawab?","shortAnswer":"Kirim ulang bila perlu → lakukan prosedur alternatif → evaluasi bukti → dokumentasikan kesimpulan.","explanation":"Prosedur alternatif umumnya mencakup subsequent receipt, rekening koran, faktur, surat jalan, pesanan pelanggan, dan korespondensi. Auditor memastikan bukti terkait dengan saldo yang sama dan periode yang benar. Nonresponse tidak otomatis berarti salah saji, tetapi tidak boleh diabaikan. Jika bukti pengganti tetap tidak memadai, auditor mengevaluasi dampaknya terhadap kesimpulan dan kemungkinan keterbatasan lingkup.","example":"Pembayaran Januari ditelusuri ke rekening koran dan akun pelanggan yang dikonfirmasi.","keywords":"nonresponse; alternative procedure; subsequent receipt","comparison":"Konfirmasi memberi bukti eksternal langsung; prosedur alternatif menggabungkan beberapa bukti pengganti.","mnemonic":"Ulang–Alternatif–Evaluasi–Dokumentasi."},{"number":16,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Vouching vs tracing","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda vouching dan tracing?","shortAnswer":"Vouching: catatan ke bukti untuk occurrence. Tracing: bukti ke catatan untuk completeness.","explanation":"Arah prosedur menentukan salah saji yang dicari. Vouching mendeteksi transaksi tercatat tanpa dasar atau fiktif. Tracing mendeteksi transaksi sumber yang tidak masuk pembukuan. Keduanya dapat diterapkan pada penjualan, pembelian, kas, dan siklus lain. Pemilihan sampel harus mengikuti arah yang sesuai agar prosedur tidak menguji asersi yang keliru.","example":"Jurnal penjualan ke surat jalan = vouching; surat jalan ke jurnal penjualan = tracing.","keywords":"book-to-proof; proof-to-book","comparison":"Occurrence menjawab “terjadi?”, completeness menjawab “semuanya tercatat?”.","mnemonic":"Vouch = Verify yang tercatat; Trace = Track yang belum masuk."},{"number":17,"topic":"Pengendalian Penjualan Kredit","subtopic":"Test of control vs substantive test","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda test of control dan substantive test?","shortAnswer":"Test of control menilai efektivitas kontrol; substantive test mencari salah saji pada transaksi, saldo, atau pengungkapan.","explanation":"Pengujian kontrol berfokus pada apakah persetujuan, rekonsiliasi, atau review dijalankan sebagaimana dirancang. Pengujian substantif mencakup test of details dan prosedur analitis substantif. Hasil kontrol memengaruhi seberapa jauh auditor dapat mengandalkan sistem dan luas pengujian substantif. Keduanya dapat digunakan bersama karena kontrol yang kuat tidak menghapus kebutuhan memperoleh bukti substantif.","example":"Memeriksa bukti approval kredit adalah test of control; konfirmasi saldo pelanggan adalah substantive test.","keywords":"control effectiveness; misstatement","comparison":"Kontrol menjawab “proses berjalan?”, substantif menjawab “angka salah?”.","mnemonic":"Control = cara kerja; Substantive = isi angka."},{"number":18,"topic":"Audit Piutang Usaha","subtopic":"Konfirmasi positif vs negatif","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda konfirmasi positif dan negatif?","shortAnswer":"Positif meminta semua penerima menjawab; negatif hanya meminta jawaban jika tidak setuju.","explanation":"Konfirmasi positif menghasilkan bukti lebih kuat tetapi memerlukan tindak lanjut atas nonresponse. Konfirmasi negatif lebih efisien, namun cocok hanya bila risiko rendah, banyak saldo kecil, kontrol efektif, dan auditor yakin penerima memperhatikan permintaan. Pemilihan harus didasarkan pada risiko, bukan kenyamanan.","example":"Saldo besar bermasalah memakai positif; ribuan saldo kecil berisiko rendah dapat mempertimbangkan negatif.","keywords":"positive; negative; response","comparison":"Tidak adanya jawaban pada konfirmasi negatif dianggap tidak keberatan, tetapi bukti lebih lemah.","mnemonic":"Positif = respon pasti; negatif = respon bila beda."},{"number":19,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Overall vs performance materiality","difficulty":"Sulit","type":"Perbandingan","question":"Apa beda overall materiality dan performance materiality?","shortAnswer":"Overall berlaku untuk laporan keuangan keseluruhan; performance ditetapkan lebih rendah untuk merancang pengujian dan mengendalikan risiko agregasi.","explanation":"Performance materiality bukan materialitas baru yang berdiri sendiri, melainkan bantalan kerja agar kumpulan salah saji kecil tidak melampaui batas keseluruhan. Auditor dapat menetapkan tingkat yang berbeda untuk area tertentu berdasarkan risiko. Hubungan keduanya penting saat menentukan ukuran sampel dan evaluasi salah saji.","example":"Overall Rp138 juta dan performance 80% menjadi sekitar Rp111 juta.","keywords":"overall; performance; aggregation","comparison":"Overall menilai dampak keseluruhan; performance memandu pelaksanaan prosedur.","mnemonic":"Overall = plafon; Performance = pagar pengaman di bawah plafon."},{"number":20,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Perhitungan materialitas","difficulty":"Sulit","type":"Penerapan","question":"Jika laba bersih Rp3.455.152.644, overall materiality 4%, dan performance 80%, berapa performance materiality?","shortAnswer":"Sekitar Rp110.564.885.","explanation":"Hitung overall materiality: 4% × Rp3.455.152.644 = Rp138.206.105,76. Lalu hitung performance materiality: 80% × Rp138.206.105,76 = Rp110.564.884,608. Pembulatan dapat dilakukan sesuai kebijakan audit, tetapi urutan basis perhitungan harus benar. Nilai akhir digunakan sebagai ambang kerja dalam merancang pengujian akun, bukan sebagai batas otomatis setiap salah saji individual.","example":"Kesalahan umum adalah langsung mengambil 80% dari laba bersih.","keywords":"4%; 80%; performance materiality","comparison":"Rp138.206.106 adalah overall, bukan performance materiality.","mnemonic":"4 dulu, baru 80."},{"number":21,"topic":"Integrasi Bukti dan Dokumentasi Audit","subtopic":"Risk–assertion–procedure","difficulty":"Sulit","type":"Penerapan","question":"Bagaimana memetakan risiko ke prosedur audit?","shortAnswer":"Nyatakan fakta dan risiko → pilih asersi terdampak → tentukan prosedur serta bukti → simpulkan hasil.","explanation":"Prosedur yang kuat selalu menjawab risiko tertentu. Misalnya risiko penjualan fiktif diarahkan ke occurrence, lalu diuji dengan vouching faktur ke surat jalan dan konfirmasi piutang. Dokumentasi harus memperlihatkan hubungan logis agar reviewer dapat menilai kecukupan bukti. Setiap perubahan respons audit harus diperbarui pada program audit dan direferensikan ke kertas kerja pendukung.","example":"Risiko utang belum tercatat → completeness → tracing dokumen penerimaan setelah tahun-end ke jurnal utang.","keywords":"risiko; asersi; prosedur; bukti","comparison":"Prosedur tanpa asersi mudah menjadi daftar aktivitas yang tidak fokus.","mnemonic":"RAP-BS: Risiko–Asersi–Prosedur–Bukti–Simpulan."},{"number":22,"topic":"Materialitas dan Prosedur Analitis","subtopic":"Analisis penjualan–piutang–kas","difficulty":"Sulit","type":"Penerapan","question":"Apa respons saat penjualan dan piutang naik, tetapi kas tertinggal?","shortAnswer":"Uji DSO, cut-off, occurrence, subsequent receipt, dan kecukupan penyisihan piutang.","explanation":"Pola tersebut dapat mencerminkan pertumbuhan normal, tetapi juga pendapatan terlalu dini, penjualan fiktif, atau kolektibilitas memburuk. Auditor perlu memperoleh penjelasan manajemen, membandingkan data operasional, dan menguji bukti eksternal serta dokumen pengiriman. Analisis menjadi dasar untuk mengubah nature, timing, dan extent.","example":"Perluasan konfirmasi pada pelanggan besar dan pengujian transaksi akhir Desember.","keywords":"sales; receivable; cash; DSO","comparison":"Perubahan nominal saja tidak cukup; hubungan antarakun memberi konteks risiko.","mnemonic":"Naik penjualan, naik piutang, kas diam = alarm kualitas pendapatan."},{"number":23,"topic":"Audit Kas dan Setara Kas","subtopic":"Kas kecil imprest","difficulty":"Sulit","type":"Mini Kasus","question":"Dana imprest Rp5 juta, kas fisik Rp700 ribu, voucher sah Rp3,8 juta. Apa kesimpulannya?","shortAnswer":"Terdapat kekurangan kas Rp500 ribu yang harus ditelusuri dan didokumentasikan.","explanation":"Dalam imprest, kas fisik ditambah voucher sah harus sama dengan dana tetap. Auditor memeriksa tanggal, otorisasi, bukti pengisian kembali, dan penjelasan pemegang kas. Selisih kecil sekalipun dapat signifikan secara kualitatif jika menunjukkan kelemahan kontrol atau penyalahgunaan. Auditor juga menilai apakah selisih merupakan kejadian terisolasi atau indikasi masalah yang lebih luas.","example":"Usulkan jurnal kekurangan kas atau pertanggungjawaban setelah penyebab dipastikan.","keywords":"imprest; cash count; shortage","comparison":"Cash count membuktikan kas fisik; konfirmasi bank tidak menyelesaikan selisih kas kecil.","mnemonic":"Fisik + voucher = dana tetap."},{"number":24,"topic":"Audit Piutang Usaha","subtopic":"NSF check","difficulty":"Sulit","type":"Mini Kasus","question":"Pelanggan mengaku membayar, tetapi cek NSF. Apa perlakuan auditnya?","shortAnswer":"Piutang tetap diakui; evaluasi kolektibilitas dan jangan mengakui kas.","explanation":"Cek NSF gagal dicairkan sehingga pembayaran belum efektif. Auditor memeriksa rekening koran, korespondensi, dan pembayaran berikutnya. Jika kondisi pelanggan memburuk, penyisihan kerugian kredit mungkin diperlukan. Menghapus piutang atau mengakui kas akan menghasilkan salah saji. Kesimpulan harus mempertimbangkan apakah diperlukan penyisihan, penghapusbukuan, atau pengungkapan sesuai bukti.","example":"Saldo Rp325 juta tetap menjadi piutang sampai dana benar-benar diterima.","keywords":"NSF; receivable; collectability","comparison":"Cek diterima ≠ kas tersedia jika belum berhasil clearing.","mnemonic":"NSF = Not Sufficient Funds = Not Settled Finance."},{"number":25,"topic":"Pengendalian Penjualan Kredit","subtopic":"Penjualan ganda","difficulty":"Sulit","type":"Mini Kasus","question":"Dua penjualan memakai satu surat jalan dan hanya ada satu pengiriman. Apa tindakan auditor?","shortAnswer":"Balik satu penjualan dan piutang, lalu evaluasi kelemahan kontrol nomor dokumen.","explanation":"Satu pengiriman hanya mendukung satu transaksi. Pencatatan kedua tidak memenuhi occurrence dan membuat penjualan serta piutang terlalu tinggi. Auditor melakukan vouching, menelusuri faktur, mengusulkan AJE, dan menilai apakah sistem mencegah penggunaan nomor dokumen yang sama. Temuan tersebut dapat mendorong perluasan sampel untuk mencari duplikasi lain dalam populasi penjualan.","example":"Duplikasi Rp11 juta dikoreksi dengan mengurangi penjualan dan piutang Rp11 juta.","keywords":"duplicate; occurrence; AJE","comparison":"Kesalahan jumlah berbeda dari duplikasi; duplikasi berarti transaksi tercatat lebih dari sekali.","mnemonic":"Satu kirim = satu jual."}]},"sim":{"id":"sim","title":"Sistem Informasi Manajemen","short":"SIM","konsen":["gabungan"],"quiz":[{"number":1,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Data, informasi, dan knowledge","learningOutcome":"Membedakan data, informasi, dan knowledge","difficulty":"Mudah","type":"Definisi","question":"Urutan transformasi yang PALING TEPAT dari fakta mentah hingga dasar tindakan manajerial adalah ...","options":["Data → informasi → knowledge","Informasi → data → knowledge","Knowledge → data → informasi","Data → knowledge → informasi"],"correct":"A","concept":"Hierarki data–informasi–knowledge","explanation":"Jawaban A benar karena data merupakan fakta mentah yang belum diberi konteks. Setelah data diorganisasi, dibersihkan, dihitung, atau dibandingkan, data berubah menjadi informasi yang bermakna bagi penerima. Informasi menjadi knowledge ketika dipadukan dengan pengalaman, pemahaman, aturan, dan pembelajaran sehingga dapat digunakan untuk memecahkan masalah atau memilih tindakan. Dalam SIM, kualitas keputusan tidak cukup ditentukan oleh banyaknya data, tetapi oleh proses pemberian konteks dan interpretasi yang tepat.","whyOthersWrong":"Pilihan B dan C membalik urutan logis karena informasi serta knowledge tidak muncul sebelum data tersedia. Pilihan D kurang tepat karena knowledge bukan tahap perantara sebelum informasi; knowledge justru terbentuk setelah informasi dipahami dan dikaitkan dengan pengalaman.","tip":"Cari kata 'fakta mentah', 'konteks', dan 'tindakan'. Urutannya selalu dari bahan mentah menuju pemaknaan.","reference":"SI ARUN – SIM, TM 1, bagian Data, Information, Knowledge; RPS Sub-CPMK 1.","keywords":"data; informasi; knowledge"},{"number":2,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Komponen CBIS","learningOutcome":"Menjelaskan fungsi prosedur dalam CBIS","difficulty":"Mudah","type":"Definisi","question":"Dalam Computer-Based Information System, komponen procedures terutama berfungsi untuk ...","options":["Menyediakan perangkat fisik pemrosesan data","Menyimpan tabel dan record organisasi","Menetapkan aturan dan instruksi penggunaan sistem","Menghubungkan komputer melalui media transmisi"],"correct":"C","concept":"Enam komponen CBIS","explanation":"Jawaban C benar. Procedures adalah aturan, instruksi, kebijakan, dan langkah kerja yang mengarahkan manusia menggunakan hardware, software, database, dan network secara konsisten. Prosedur menjelaskan siapa melakukan apa, kapan aktivitas dilakukan, data apa yang dibutuhkan, serta bagaimana kesalahan ditangani. Tanpa prosedur, teknologi yang baik tetap dapat menghasilkan data tidak akurat atau proses tidak seragam. Karena itu, SIM merupakan sistem sosio-teknis, bukan sekadar kumpulan perangkat komputer.","whyOthersWrong":"Pilihan A menjelaskan hardware, pilihan B menjelaskan database, dan pilihan D menjelaskan network. Ketiganya merupakan komponen CBIS, tetapi bukan fungsi procedures. Jebakannya adalah menganggap prosedur sebagai program, padahal program termasuk software.","tip":"Ingat enam komponen: hardware, software, database, network, procedures, people. Kata 'aturan' menunjuk procedures.","reference":"SI ARUN – SIM, TM 1, bagian IT Infrastructure dan komponen CBIS.","keywords":"CBIS; procedures; aturan"},{"number":3,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Input–resources–output","learningOutcome":"Mengidentifikasi unsur proses bisnis","difficulty":"Mudah","type":"Definisi","question":"Pegawai, mesin, waktu, modal, dan prosedur yang digunakan untuk mengolah input disebut ...","options":["Output proses","Resources proses","Umpan balik proses","Tujuan strategis"],"correct":"B","concept":"Unsur proses bisnis","explanation":"Jawaban B benar karena resources adalah seluruh sumber daya yang dipakai untuk mengubah input menjadi output. Sumber daya dapat berupa pegawai, teknologi, mesin, waktu, modal, material, dan prosedur kerja. Contohnya, pada proses perbaikan kapal, laporan kerusakan menjadi input, teknisi dan suku cadang menjadi resources, sedangkan kapal yang telah diperbaiki menjadi output. Identifikasi unsur ini membantu organisasi mengukur efisiensi dan menemukan titik pemborosan.","whyOthersWrong":"Pilihan A adalah hasil akhir proses, bukan alat pengolah. Umpan balik pada pilihan C digunakan untuk mengevaluasi dan memperbaiki proses. Tujuan strategis pada pilihan D merupakan sasaran organisasi yang lebih luas dan tidak identik dengan sumber daya proses.","tip":"Tanyakan: 'Apa yang masuk, apa yang dipakai, dan apa yang keluar?' Yang dipakai untuk mengolah adalah resources.","reference":"SI ARUN – SIM, TM 2, bagian Unsur Business Processes.","keywords":"input; resources; output"},{"number":4,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Business Process Improvement","learningOutcome":"Menjelaskan karakteristik BPI","difficulty":"Mudah","type":"Definisi","question":"Karakteristik UTAMA Business Process Improvement (BPI) adalah ...","options":["Menghapus seluruh proses lama dengan pendekatan clean slate","Mengganti struktur organisasi dan teknologi secara menyeluruh","Melakukan perubahan radikal dengan risiko dan biaya tinggi","Memperbaiki proses secara bertahap dengan risiko relatif rendah"],"correct":"D","concept":"Business Process Improvement","explanation":"Jawaban D benar. BPI memperbaiki proses secara inkremental dengan fokus pada akar penyebab masalah, hasil yang terukur, dan gangguan operasional yang lebih kecil. Organisasi dapat menyederhanakan formulir, mengurangi tahap persetujuan, atau memperbaiki integrasi data tanpa mengganti keseluruhan proses. Pendekatan ini sering melibatkan pegawai operasional karena mereka memahami masalah sehari-hari. Six Sigma dengan siklus DMAIC merupakan salah satu metode yang lazim digunakan dalam BPI.","whyOthersWrong":"Pilihan A, B, dan C lebih menggambarkan Business Process Reengineering (BPR), yaitu desain ulang radikal yang dapat mengubah teknologi, struktur, dan pola kerja secara menyeluruh. Jebakan umum adalah menyamakan semua program perbaikan proses sebagai BPR.","tip":"BPI = improvement bertahap. BPR = reengineering radikal. Perhatikan kata risiko, biaya, dan clean slate.","reference":"SI ARUN – SIM, TM 2, bagian Business Process Improvement.","keywords":"BPI; bertahap; risiko"},{"number":5,"topic":"TM 3 – Data Management","subtopic":"Karakteristik Big Data","learningOutcome":"Mengidentifikasi karakteristik Big Data","difficulty":"Mudah","type":"Definisi","question":"Kombinasi karakteristik Big Data yang PALING LENGKAP adalah ...","options":["Volume, velocity, variety, veracity, dan value","Volume, validity, visualization, version, dan value","Velocity, visibility, variety, validation, dan value","Variety, vulnerability, volume, validity, dan visualization"],"correct":"A","concept":"Lima karakteristik Big Data","explanation":"Jawaban A benar. Big Data lazim dijelaskan melalui 5V: volume menunjukkan jumlah data yang besar; velocity menunjukkan kecepatan data dibuat dan diproses; variety menunjukkan keragaman format; veracity berkaitan dengan keandalan serta kualitas data; dan value menekankan manfaat yang dapat diperoleh organisasi. Lima unsur tersebut membantu manajemen menilai apakah masalah data memerlukan arsitektur dan teknik analitik di luar pengolahan konvensional.","whyOthersWrong":"Pilihan B, C, dan D mencampurkan istilah yang terdengar teknis tetapi bukan rangkaian standar karakteristik Big Data. Validity dan visualization dapat penting dalam analitik, tetapi tidak menggantikan velocity, variety, veracity, atau value dalam kerangka 5V.","tip":"Mnemonik: 'Besar–Cepat–Beragam–Benar–Bernilai' = volume, velocity, variety, veracity, value.","reference":"SI ARUN – SIM, TM 3–4, bagian Big Data.","keywords":"Big Data; 5V"},{"number":6,"topic":"TM 1 – Introduction to Information Systems","subtopic":"FAIS dan ERP","learningOutcome":"Menjelaskan hubungan sistem fungsional dan ERP","difficulty":"Mudah","type":"Konseptual","question":"Hubungan antara Functional Area Information Systems (FAIS) dan Enterprise Resource Planning (ERP) yang PALING TEPAT adalah ...","options":["FAIS hanya digunakan pihak luar, sedangkan ERP hanya untuk pelanggan","ERP mengintegrasikan aliran data dari berbagai area fungsional","FAIS menggantikan seluruh sistem organisasi secara otomatis","ERP hanya memproses satu jenis transaksi pada satu departemen"],"correct":"B","concept":"Breadth of support","explanation":"Jawaban B benar. FAIS mendukung fungsi tertentu seperti akuntansi, keuangan, pemasaran, operasi, atau SDM. ERP menghubungkan dan mengintegrasikan berbagai fungsi tersebut melalui basis data serta proses bersama sehingga informasi tidak terpecah dalam silo departemen. Integrasi memungkinkan transaksi yang dimasukkan pada satu fungsi digunakan oleh fungsi lain secara konsisten, misalnya data penerimaan barang memperbarui persediaan, utang, dan laporan manajerial.","whyOthersWrong":"Pilihan A keliru karena FAIS dan ERP terutama digunakan untuk mendukung operasi internal, meskipun dapat terhubung dengan pihak luar. Pilihan C berlebihan karena FAIS tidak otomatis menggantikan seluruh sistem. Pilihan D justru menggambarkan sistem yang sempit, bukan ERP.","tip":"FAIS = fokus fungsi. ERP = integrasi enterprise. Kata 'antarbagian' atau 'satu data bersama' mengarah ke ERP.","reference":"SI ARUN – SIM, TM 1, Types of Computer-Based Information Systems.","keywords":"FAIS; ERP; integrasi"},{"number":7,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Strategi diferensiasi","learningOutcome":"Menjelaskan dukungan SI terhadap diferensiasi","difficulty":"Mudah","type":"Konseptual","question":"Sistem informasi paling langsung mendukung strategi diferensiasi ketika organisasi ...","options":["Menekan biaya dengan mengurangi seluruh variasi layanan","Menyalin fitur digital pesaing tanpa memahami pelanggan","Menggunakan data pelanggan untuk personalisasi layanan bernilai","Memusatkan keputusan hanya pada harga pembelian terendah"],"correct":"C","concept":"Strategi keunggulan kompetitif","explanation":"Jawaban C benar. Diferensiasi dicapai dengan menawarkan keunikan yang dipersepsikan bernilai oleh pelanggan, misalnya pengalaman layanan yang lebih personal, fitur digital khusus, respons lebih cepat, atau kualitas informasi yang lebih baik. Sistem informasi menyediakan data pelanggan, analitik, kanal digital, dan mekanisme umpan balik untuk memahami kebutuhan yang berbeda. Keunggulan bukan sekadar memiliki teknologi, tetapi menggunakan teknologi bersama proses dan kompetensi yang sulit ditiru.","whyOthersWrong":"Pilihan A dan D lebih dekat dengan kepemimpinan biaya atau efisiensi operasional. Pilihan B tidak menjamin diferensiasi karena fitur yang ditiru mudah kehilangan nilai dan belum tentu sesuai kebutuhan pengguna. Diferensiasi memerlukan keunikan yang relevan, bukan sekadar tampilan berbeda.","tip":"Diferensiasi = unik dan bernilai. Cost leadership = biaya lebih rendah. Jangan hanya mencari kata 'teknologi'.","reference":"SI ARUN – SIM, TM 2, Competitive Advantage and Strategic Information Systems.","keywords":"diferensiasi; personalisasi; nilai"},{"number":8,"topic":"TM 4 – Database & KMS Practice","subtopic":"Normalisasi database","learningOutcome":"Menjelaskan dampak normalisasi","difficulty":"Sedang","type":"Konseptual","question":"Normalisasi pada database relasional terutama dilakukan untuk ...","options":["Menyimpan semua atribut dalam satu tabel besar","Menghilangkan kebutuhan primary key dan foreign key","Menyembunyikan informasi sensitif dari seluruh pengguna","Mengurangi redundansi dan meningkatkan integritas data"],"correct":"D","concept":"Normalization","explanation":"Jawaban D benar. Normalisasi menganalisis ketergantungan antaratribut dan memecah struktur data ke bentuk yang lebih teratur agar pengulangan tidak perlu, anomali perubahan berkurang, dan hubungan antartabel terjaga. Dengan struktur yang tepat, satu fakta disimpan pada tempat yang semestinya sehingga pembaruan tidak menghasilkan nilai yang berbeda di beberapa baris. Primary key dan foreign key tetap diperlukan untuk menjaga identitas serta referential integrity.","whyOthersWrong":"Pilihan A justru meningkatkan redundansi dan anomali. Pilihan B salah karena kunci merupakan bagian penting dalam database relasional. Pilihan C berkaitan dengan kontrol akses atau masking, bukan tujuan utama normalisasi. Normalisasi juga bukan pengganti backup maupun enkripsi.","tip":"Kata kunci normalisasi: redundansi, anomali insert/update/delete, dependency, dan integritas.","reference":"SI ARUN – SIM, TM 3–4, Appendix Fundamentals of Relational Database Operations.","keywords":"normalisasi; redundansi; integritas"},{"number":9,"topic":"TM 4 – Database & KMS Practice","subtopic":"Tacit dan explicit knowledge","learningOutcome":"Menganalisis peran KMS terhadap knowledge","difficulty":"Sedang","type":"Konseptual","question":"Mengapa tacit knowledge lebih sulit dikelola dibandingkan explicit knowledge?","options":["Tacit knowledge melekat pada pengalaman dan sulit sepenuhnya didokumentasikan","Tacit knowledge selalu tersimpan sebagai dokumen terstruktur","Explicit knowledge hanya dapat dipahami oleh pembuatnya","Explicit knowledge tidak dapat disebarkan melalui teknologi"],"correct":"A","concept":"Jenis knowledge","explanation":"Jawaban A benar. Tacit knowledge berada dalam pengalaman, intuisi, keterampilan, dan cara berpikir individu, sehingga sering sulit diungkapkan secara lengkap dalam dokumen. KMS perlu menggunakan wawancara, komunitas praktik, mentoring, lesson learned, atau kolaborasi untuk menangkapnya. Explicit knowledge lebih mudah dikodifikasi dalam pedoman, prosedur, laporan, video, atau basis pengetahuan. Organisasi perlu mengelola keduanya agar pengetahuan tidak hilang ketika pegawai pindah atau pensiun.","whyOthersWrong":"Pilihan B justru merupakan ciri explicit knowledge. Pilihan C salah karena explicit knowledge dirancang agar dapat dipahami dan digunakan kembali. Pilihan D juga salah karena teknologi sangat membantu penyimpanan serta distribusi explicit knowledge, meskipun teknologi saja belum cukup menangkap pengalaman manusia.","tip":"Tacit = tersimpan di kepala dan praktik. Explicit = tertulis/terekam. Ingat: 'tacit = terasa, sulit ditulis'.","reference":"SI ARUN – SIM, TM 3–4, Knowledge Management System.","keywords":"tacit; explicit; KMS"},{"number":10,"topic":"TM 5 – Telecommunications & Networking","subtopic":"Intranet dan internet","learningOutcome":"Membedakan model akses jaringan","difficulty":"Sedang","type":"Konseptual","question":"Pernyataan yang PALING TEPAT mengenai intranet adalah ...","options":["Jaringan global yang terbuka bagi seluruh masyarakat","Layanan berbasis teknologi internet dengan akses internal terbatas","Jaringan antarnegera yang selalu dimiliki satu operator","Koneksi personal jarak sangat dekat antarperangkat"],"correct":"B","concept":"Model akses jaringan","explanation":"Jawaban B benar. Intranet menggunakan teknologi dan protokol yang serupa dengan internet, tetapi aksesnya dibatasi untuk anggota organisasi atau pengguna berwenang. Intranet dapat digunakan untuk portal pegawai, dokumen internal, sistem kepegawaian, dashboard, dan kolaborasi. Istilah intranet menekankan pola akses dan penggunaan layanan, sedangkan LAN atau WAN lebih menekankan cakupan infrastruktur. Intranet tetap memerlukan autentikasi, otorisasi, segmentasi, dan pengelolaan keamanan.","whyOthersWrong":"Pilihan A menjelaskan internet. Pilihan C lebih dekat pada WAN tetapi tidak selalu dimiliki satu operator. Pilihan D menjelaskan Personal Area Network atau teknologi jarak dekat seperti Bluetooth. Jebakannya adalah menyamakan intranet dengan LAN; intranet dapat berjalan pada LAN maupun WAN.","tip":"LAN/WAN = cakupan. Intranet/internet = akses dan penggunaan. Internal tidak otomatis berarti aman.","reference":"SI ARUN – SIM, TM 5; pembahasan LAN, WAN, intranet, dan internet.","keywords":"intranet; internet; akses"},{"number":11,"topic":"TM 2 – Strategy & Business Processes","subtopic":"DMAIC","learningOutcome":"Menerapkan urutan DMAIC","difficulty":"Sedang","type":"Penerapan","question":"Tim telah mengukur waktu pengadaan dan menganalisis akar keterlambatan. Tahap DMAIC yang dilakukan SETELAH itu adalah ...","options":["Define","Measure","Improve","Control"],"correct":"C","concept":"Siklus Six Sigma DMAIC","explanation":"Jawaban C benar. Setelah Define menetapkan masalah, Measure mengumpulkan data, dan Analyze menemukan akar penyebab, organisasi memasuki tahap Improve untuk merancang serta menerapkan solusi. Contohnya adalah membuat formulir digital, menyederhanakan persetujuan, memperbaiki data persediaan, atau mengevaluasi pemasok. Setelah solusi terbukti, tahap Control memastikan perbaikan tetap berjalan melalui indikator, dashboard, prosedur, audit, dan evaluasi berkala.","whyOthersWrong":"Pilihan A dan B merupakan tahap yang sudah dilewati. Pilihan D baru dilakukan setelah solusi pada tahap Improve diterapkan dan perlu distabilkan. Jebakan soal urutan adalah memilih Control karena terdengar penting, padahal kontrol tidak mendahului implementasi solusi.","tip":"DMAIC: Define–Measure–Analyze–Improve–Control. Setelah Analyze selalu Improve.","reference":"SI ARUN – SIM, TM 2, Business Process Improvement dan DMAIC.","keywords":"DMAIC; improve; urutan"},{"number":12,"topic":"TM 3 – Data Management","subtopic":"Data warehouse","learningOutcome":"Menentukan solusi penyimpanan data analitis","difficulty":"Sedang","type":"Penerapan","question":"Organisasi ingin menggabungkan data historis keuangan, pegawai, aset, dan kinerja untuk laporan manajemen. Solusi PALING SESUAI adalah ...","options":["Data warehouse terintegrasi","Folder dokumen per unit","Personal database setiap manajer","Media sosial internal"],"correct":"A","concept":"Data warehouse","explanation":"Jawaban A benar. Data warehouse mengintegrasikan data dari berbagai sumber, menyimpan data historis yang telah dibersihkan dan distandardisasi, serta menyediakan dasar konsisten untuk pelaporan dan analisis manajerial. Data dari sistem operasional biasanya diekstrak, ditransformasi, dan dimuat melalui proses ETL. Dengan data warehouse, organisasi dapat membandingkan tren lintas periode dan fungsi tanpa mengganggu pemrosesan transaksi harian.","whyOthersWrong":"Folder dokumen dan personal database menghasilkan silo, definisi tidak seragam, dan risiko duplikasi. Media sosial internal mendukung komunikasi, bukan integrasi data analitis. Jebakan utamanya adalah memilih solusi penyimpanan sederhana yang tidak menjamin kualitas, sejarah, dan konsistensi data.","tip":"Kata 'berbagai sumber', 'historis', dan 'laporan manajemen' biasanya menunjuk data warehouse.","reference":"SI ARUN – SIM, TM 3–4, Data Warehouse and Data Marts.","keywords":"data warehouse; historis; integrasi"},{"number":13,"topic":"TM 5 – Telecommunications & Networking","subtopic":"WAN dan VPN","learningOutcome":"Menentukan arsitektur jaringan organisasi","difficulty":"Sedang","type":"Penerapan","question":"Instansi memiliki kantor di banyak provinsi dan perlu mengakses aplikasi pusat secara aman. Desain yang PALING TEPAT adalah ...","options":["PAN tanpa autentikasi untuk seluruh kantor","Satu LAN tunggal tanpa koneksi antarwilayah","Internet publik tanpa enkripsi dan tanpa cadangan jalur","WAN dengan VPN, kontrol akses, dan redundansi koneksi"],"correct":"D","concept":"Arsitektur jaringan luas","explanation":"Jawaban D benar. WAN menghubungkan lokasi geografis luas, sedangkan VPN membentuk kanal terlindungi melalui jaringan publik atau penyedia komunikasi. Kontrol akses membatasi pengguna berwenang dan redundansi menjaga ketersediaan ketika satu jalur gagal. Desain jaringan harus mempertimbangkan kapasitas, latency, keamanan, monitoring, failover, dan SLA. Cakupan luas saja tidak cukup apabila tidak disertai pengendalian dan kesinambungan layanan.","whyOthersWrong":"PAN hanya cocok untuk perangkat personal jarak dekat. LAN tunggal tidak menghubungkan kantor lintas provinsi. Internet publik tanpa enkripsi serta cadangan jalur menimbulkan risiko kerahasiaan dan ketersediaan. Pilihan yang baik harus memenuhi kebutuhan konektivitas sekaligus keamanan.","tip":"Banyak lokasi = WAN. Akses aman di atas jaringan lain = VPN. Layanan kritis = redundansi dan SLA.","reference":"SI ARUN – SIM, TM 5; Cheatsheet SIM TM 5, WAN, VPN, failover, dan SLA.","keywords":"WAN; VPN; redundansi"},{"number":14,"topic":"TM 6 – Wireless, Mobile & IoT","subtopic":"RFID dan GPS","learningOutcome":"Menerapkan teknologi identifikasi dan lokasi","difficulty":"Sedang","type":"Penerapan","question":"Pasangan fungsi teknologi yang PALING TEPAT adalah ...","options":["RFID menentukan koordinat satelit; GPS membaca tag barang","RFID mengidentifikasi tag; GPS memperkirakan posisi","NFC menghubungkan kantor antarkota; GPS menyimpan database","Wi-Fi membaca barcode; RFID mengenkripsi seluruh transaksi"],"correct":"B","concept":"Teknologi wireless","explanation":"Jawaban B benar. RFID menggunakan tag dan reader untuk mengidentifikasi atau melacak objek yang memiliki tag, misalnya aset atau persediaan. GPS menggunakan sinyal satelit untuk memperkirakan posisi geografis perangkat. Keduanya dapat digabungkan, tetapi fungsi dasarnya berbeda: RFID menjawab 'objek apa' dan GPS membantu menjawab 'berada di mana'. Pemilihan teknologi harus memperhatikan jangkauan, akurasi, biaya, privasi, dan kebutuhan proses.","whyOthersWrong":"Pilihan A menukar fungsi RFID dan GPS. NFC digunakan untuk komunikasi proximity sangat dekat, bukan jaringan antarkota. Wi-Fi menyediakan konektivitas jaringan dan tidak secara khusus membaca barcode. Enkripsi juga bukan fungsi otomatis RFID pada seluruh transaksi.","tip":"RFID = identity/tag. GPS = position/location. NFC = sangat dekat. Wi-Fi = jaringan lokal nirkabel.","reference":"SI ARUN – SIM, TM 6, Wireless Technologies dan Internet of Things.","keywords":"RFID; GPS; identifikasi"},{"number":15,"topic":"TM 7 – Information Security","subtopic":"Kontrol akses","learningOutcome":"Menentukan kontrol preventif","difficulty":"Sedang","type":"Penerapan","question":"Kontrol teknis PREVENTIF yang paling langsung mengurangi risiko penggunaan kredensial curian adalah ...","options":["Laporan insiden tahunan","Audit manual setelah transaksi","Multi-factor authentication dan pembatasan hak akses","Penyimpanan password pada catatan bersama"],"correct":"C","concept":"Access controls","explanation":"Jawaban C benar. Multi-factor authentication menambah bukti identitas selain password sehingga kredensial yang dicuri tidak selalu cukup untuk masuk. Pembatasan hak akses berdasarkan kebutuhan kerja mengurangi dampak apabila akun berhasil disalahgunakan. Keduanya merupakan kontrol preventif teknis. Kontrol yang baik tetap perlu didukung monitoring, edukasi pengguna, peninjauan hak akses, dan respons insiden agar pertahanan bersifat berlapis.","whyOthersWrong":"Laporan tahunan dan audit setelah transaksi lebih bersifat detektif atau evaluatif. Menyimpan password pada catatan bersama justru menghilangkan akuntabilitas dan memperbesar risiko. Jebakan umum adalah menganggap semua kontrol keamanan memiliki fungsi yang sama; preventive menghambat, detective menemukan, corrective memulihkan.","tip":"Kredensial curian: cari faktor tambahan (MFA) dan least privilege. Perhatikan label PREVENTIF.","reference":"SI ARUN – SIM, TM 7, Access Controls dan Information Security Controls.","keywords":"MFA; otorisasi; preventif"},{"number":16,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Implementasi SIM terintegrasi","learningOutcome":"Menganalisis kebutuhan awal implementasi SIM","difficulty":"Sedang","type":"Mini Kasus","question":"Kampus memiliki data mahasiswa, nilai, absensi, dan pembayaran yang berbeda antarunit. Tindakan PERTAMA yang paling tepat adalah ...","options":["Membeli aplikasi termahal tanpa memetakan proses","Memindahkan semua file ke satu folder bersama","Memberi seluruh pegawai akses penuh ke setiap data","Memetakan kebutuhan informasi, proses, pemilik data, dan hak akses"],"correct":"D","concept":"Tahap awal implementasi SIM","explanation":"Jawaban D benar. Implementasi SIM harus dimulai dengan memahami kebutuhan informasi, proses yang berjalan, sumber data, pemilik data, definisi, dan hak akses. Pemetaan ini menjadi dasar pemilihan aplikasi, desain integrasi, pembersihan data, pelatihan, dan evaluasi. Tanpa analisis kebutuhan, organisasi berisiko mengotomatisasi proses yang buruk atau memindahkan ketidakkonsistenan lama ke sistem baru. Teknologi harus mengikuti tujuan dan proses, bukan sebaliknya.","whyOthersWrong":"Harga aplikasi tidak menjamin kesesuaian. Folder bersama tidak menyelesaikan definisi data dan kontrol. Akses penuh melanggar prinsip least privilege serta meningkatkan risiko kebocoran. Soal meminta tindakan pertama, sehingga fondasi kebutuhan dan tata kelola harus didahulukan.","tip":"Kata PERTAMA biasanya menuntut analisis kebutuhan dan proses sebelum pengadaan atau konfigurasi.","reference":"Sistem Informasi Manajemen.pdf, pembahasan implementasi SIM pada kampus; RPS CPMK 1 dan CPMK 4.","keywords":"kebutuhan informasi; integrasi; tata kelola"},{"number":17,"topic":"TM 2 – Strategy & Business Processes","subtopic":"TI sebagai enabler strategis","learningOutcome":"Mengevaluasi nilai strategis e-procurement","difficulty":"Sedang","type":"Mini Kasus","question":"Pemerintah menerapkan e-procurement dengan tender digital, jejak audit, dan analitik risiko. Nilai strategis UTAMANYA adalah ...","options":["Meningkatkan transparansi, kompetisi, efisiensi, dan pengawasan","Menghapus kebutuhan pengendalian internal","Memastikan semua pemasok selalu menawarkan harga identik","Mengubah setiap keputusan pengadaan menjadi keputusan otomatis"],"correct":"A","concept":"Strategic information system","explanation":"Jawaban A benar. E-procurement bukan hanya mengganti formulir kertas dengan layar digital, tetapi dapat mengubah akses pemasok, jejak keputusan, kecepatan proses, keterbukaan informasi, dan kemampuan analisis risiko. Dengan demikian TI berperan sebagai enabler perubahan proses dan nilai publik. Namun manfaat harus diukur melalui outcome seperti waktu proses, persaingan sehat, kualitas pengadaan, dan pengurangan penyimpangan, bukan sekadar jumlah fitur.","whyOthersWrong":"Pilihan B salah karena digitalisasi tetap membutuhkan pengendalian. Harga pemasok tidak harus identik, sehingga C tidak tepat. Pilihan D berlebihan karena keputusan tetap memerlukan kewenangan, pertimbangan, dan akuntabilitas manusia. Teknologi mendukung keputusan, bukan selalu menggantikannya.","tip":"Cari perubahan proses dan outcome publik, bukan sekadar otomatisasi atau penghapusan peran manusia.","reference":"SI ARUN – SIM, TM 2; Cheatsheet SIM TM 2, contoh e-procurement.","keywords":"e-procurement; enabler; nilai publik"},{"number":18,"topic":"TM 3 – Data Management","subtopic":"ETL dan kualitas data","learningOutcome":"Menentukan perbaikan data sebelum analisis","difficulty":"Sedang","type":"Mini Kasus","question":"Laporan pendapatan dari tiga unit berbeda karena definisi periode dan kode akun tidak sama. Tindakan PALING TEPAT adalah ...","options":["Menjumlahkan seluruh angka tanpa rekonsiliasi","Menstandarkan definisi dan melakukan transformasi serta rekonsiliasi","Menghapus unit dengan nilai paling berbeda","Mengganti tampilan dashboard tanpa memperbaiki sumber data"],"correct":"B","concept":"Kualitas data dan transformasi","explanation":"Jawaban B benar. Perbedaan definisi periode, kode akun, dan aturan agregasi harus diselesaikan sebelum data digabungkan. Tahap transform dalam ETL dapat memetakan kode, menyelaraskan format, membersihkan nilai, dan menerapkan aturan bisnis. Rekonsiliasi memastikan total sesuai dengan sumber resmi. Dashboard yang menarik tidak dapat memperbaiki data yang tidak konsisten; kualitas informasi bergantung pada definisi, lineage, kontrol, dan penanggung jawab data.","whyOthersWrong":"Menjumlahkan angka tanpa rekonsiliasi menghasilkan informasi menyesatkan. Menghapus unit karena berbeda dapat menutupi masalah dan merusak kelengkapan. Mengubah tampilan hanya menyelesaikan aspek presentasi, bukan kualitas data. Jebakannya adalah menganggap integrasi sama dengan sekadar mengumpulkan file.","tip":"Masalah definisi dan kode = standardisasi/transformasi. Masalah total = rekonsiliasi.","reference":"SI ARUN – SIM, TM 3–4, Data Warehouse; Cheatsheet SIM TM 3–4, ETL dan data governance.","keywords":"ETL; standardisasi; rekonsiliasi"},{"number":19,"topic":"TM 5 – Telecommunications & Networking","subtopic":"Latency dan jitter","learningOutcome":"Menganalisis metrik kinerja jaringan","difficulty":"Sulit","type":"Mini Kasus","question":"Bandwidth kantor cukup besar, tetapi rapat video sering patah-patah dan waktu respons berubah-ubah. Metrik yang PALING relevan dianalisis adalah ...","options":["Kapasitas penyimpanan dan ukuran database","Jumlah pengguna dan warna antarmuka","Latency, jitter, dan packet loss","Jumlah printer dan format dokumen"],"correct":"C","concept":"Kinerja jaringan","explanation":"Jawaban C benar. Bandwidth menunjukkan kapasitas, tetapi kualitas komunikasi real-time juga sangat dipengaruhi latency, jitter, dan packet loss. Latency adalah waktu tempuh paket, jitter adalah variasi waktu kedatangan paket, dan packet loss adalah paket yang tidak sampai. Video atau suara dapat terganggu walaupun kapasitas nominal besar jika ketiga metrik tersebut buruk. Analisis harus dilakukan end-to-end, termasuk perangkat, rute, Wi-Fi, kemacetan, dan kualitas penyedia.","whyOthersWrong":"Pilihan A, B, dan D tidak menjelaskan gejala komunikasi real-time. Jumlah pengguna dapat menjadi penyebab tidak langsung, tetapi metrik yang perlu diuji tetap latency, jitter, packet loss, dan throughput. Jebakannya adalah menyamakan bandwidth tinggi dengan pengalaman layanan yang pasti baik.","tip":"Video patah-patah + respons tidak stabil = jitter/latency/loss, bukan hanya bandwidth.","reference":"Cheatsheet SIM TM 5, bandwidth, latency, throughput, jitter, dan packet loss.","keywords":"latency; jitter; packet loss"},{"number":20,"topic":"TM 6 – Wireless, Mobile & IoT","subtopic":"Aplikasi offline-first","learningOutcome":"Menentukan desain sinkronisasi mobile","difficulty":"Sulit","type":"Mini Kasus","question":"Aplikasi inspeksi lapangan sering kehilangan koneksi dan menghasilkan transaksi ganda saat sinkronisasi. Desain PALING TEPAT adalah ...","options":["Menolak seluruh input ketika jaringan tidak stabil","Mengirim transaksi berulang tanpa identitas unik","Menyimpan semua data permanen dalam plaintext","Store-and-forward dengan ID unik dan sinkronisasi idempotent"],"correct":"D","concept":"Mobile computing","explanation":"Jawaban D benar. Pola store-and-forward memungkinkan pengguna tetap bekerja secara offline, menyimpan transaksi lokal, lalu mengirimkannya ketika koneksi tersedia. ID unik dan operasi idempotent memastikan pengiriman ulang tidak menciptakan transaksi ganda. Desain juga perlu mencakup enkripsi lokal, penanganan konflik, status sinkronisasi, validasi waktu, dan audit trail. Solusi mobile harus mengakui kondisi jaringan sebagai bagian dari desain proses, bukan menganggap koneksi selalu tersedia.","whyOthersWrong":"Menolak seluruh input menghambat operasi lapangan. Transaksi tanpa ID unik memperbesar duplikasi. Penyimpanan plaintext memperbesar dampak kehilangan perangkat. Jebakan utama adalah memecahkan masalah konektivitas dengan mengorbankan keamanan atau integritas data.","tip":"Offline bukan berarti tanpa kontrol. Cari ID unik, antrean lokal, retry aman, dan idempotency.","reference":"Cheatsheet SIM TM 6, mobile computing dan pola store-and-forward.","keywords":"offline-first; idempotent; sinkronisasi"},{"number":21,"topic":"TM 2 – Strategy & Business Processes","subtopic":"BPI versus BPR","learningOutcome":"Membedakan BPI dan BPR","difficulty":"Sulit","type":"Perbandingan","question":"Perbedaan BPI dan BPR yang PALING TEPAT adalah ...","options":["BPI bertahap dan berisiko lebih rendah; BPR radikal dengan clean slate","BPI selalu top-down; BPR hanya dilakukan pegawai operasional","BPI menghapus proses; BPR mempertahankan seluruh proses lama","BPI hanya untuk teknologi; BPR tidak melibatkan teknologi"],"correct":"A","concept":"Pendekatan perbaikan proses","explanation":"Jawaban A benar. BPI memperbaiki bagian proses secara inkremental, umumnya dengan biaya dan risiko lebih rendah serta hasil yang dapat dibandingkan sebelum dan sesudah. BPR mempertanyakan asumsi dasar proses, menggunakan pendekatan clean slate, dan dapat mengganti alur, peran, struktur, atau teknologi untuk memperoleh lompatan kinerja. Pilihan pendekatan harus disesuaikan dengan besarnya masalah, urgensi, kesiapan organisasi, dan toleransi risiko.","whyOthersWrong":"Pilihan B, C, dan D membalik karakteristik kedua konsep. BPI dapat melibatkan pegawai operasional, sedangkan BPR biasanya memerlukan dukungan manajemen puncak. Keduanya dapat menggunakan teknologi dan keduanya berfokus pada proses, bukan sekadar perangkat.","tip":"Improvement = incremental. Reengineering = radical redesign. Clean slate selalu mengarah ke BPR.","reference":"SI ARUN – SIM, TM 2, BPI dan BPR.","keywords":"BPI; BPR; clean slate"},{"number":22,"topic":"TM 3 – Data Management","subtopic":"Big Data, data warehouse, data mart","learningOutcome":"Membedakan tiga arsitektur data","difficulty":"Sulit","type":"Perbandingan","question":"Pernyataan yang PALING TEPAT mengenai Big Data, data warehouse, dan data mart adalah ...","options":["Ketiganya selalu memiliki cakupan, format, dan tujuan yang sama","Data mart lebih luas daripada data warehouse dan mencakup seluruh organisasi","Big Data menekankan skala/keragaman; warehouse mengintegrasikan data; mart berfokus pada unit","Data warehouse hanya menyimpan data tidak terstruktur dan tidak historis"],"correct":"C","concept":"Perbandingan arsitektur data","explanation":"Jawaban C benar. Big Data berkaitan dengan data sangat besar, cepat, dan beragam yang memerlukan pendekatan khusus untuk penyimpanan serta analisis. Data warehouse mengintegrasikan data terstruktur dan historis dari berbagai sistem agar konsisten untuk pelaporan. Data mart memiliki ruang lingkup lebih sempit untuk fungsi tertentu, misalnya keuangan atau SDM. Ketiganya dapat saling melengkapi, tetapi tidak boleh diperlakukan sebagai istilah yang sama.","whyOthersWrong":"Pilihan A mengabaikan perbedaan tujuan dan cakupan. Pilihan B membalik hubungan mart dan warehouse. Pilihan D salah karena warehouse biasanya menyimpan data terstruktur dan historis. Jebakannya adalah menganggap semua tempat penyimpanan data sebagai database yang identik.","tip":"Big Data = sifat data. Warehouse = integrasi organisasi. Mart = potongan untuk unit.","reference":"SI ARUN – SIM, TM 3–4; Sistem Informasi Manajemen.pdf, Big Data, Data Warehouse, Data Mart.","keywords":"Big Data; warehouse; mart"},{"number":23,"topic":"TM 7 – Information Security","subtopic":"Authentication dan authorization","learningOutcome":"Membedakan kontrol identitas dan hak akses","difficulty":"Sulit","type":"Perbandingan","question":"Perbedaan authentication dan authorization yang PALING TEPAT adalah ...","options":["Authentication menentukan hak; authorization membuktikan identitas","Authentication membuktikan identitas; authorization menentukan hak akses","Keduanya hanya berfungsi mengenkripsi data","Keduanya dapat diabaikan jika jaringan menggunakan intranet"],"correct":"B","concept":"Access control","explanation":"Jawaban B benar. Authentication menjawab 'siapa Anda' dengan memverifikasi bukti seperti password, token, biometrik, atau kombinasi faktor. Authorization menjawab 'apa yang boleh Anda lakukan' berdasarkan peran, kebijakan, dan kebutuhan kerja. Pengguna dapat berhasil login tetapi tetap tidak berhak menyetujui pembayaran atau membaca data tertentu. Akuntabilitas juga memerlukan identitas individual dan log, sehingga akun bersama harus dihindari.","whyOthersWrong":"Pilihan A menukar fungsi kedua konsep. Pilihan C salah karena enkripsi memiliki tujuan berbeda, yaitu melindungi kerahasiaan data. Pilihan D salah karena intranet tetap dapat disalahgunakan oleh pihak internal atau akun yang dikompromikan. Internal tidak sama dengan terpercaya.","tip":"Authentication = identity. Authorization = permission. Ingat: 'AuthN siapa, AuthZ boleh apa'.","reference":"SI ARUN – SIM, TM 7, Access Controls; Cheatsheet SIM TM 7.","keywords":"authentication; authorization; akses"},{"number":24,"topic":"TM 7 – Information Security","subtopic":"Risk analysis dan mitigasi","learningOutcome":"Mengevaluasi urutan manajemen risiko keamanan","difficulty":"Sulit","type":"Analisis","question":"Organisasi menemukan akun admin terpapar, phishing vendor, dan backup belum pernah diuji. Urutan tindakan PALING TEPAT adalah ...","options":["Membeli alat keamanan baru lalu mengabaikan proses bisnis","Menghapus seluruh akun dan menghentikan layanan tanpa analisis","Menyusun laporan tahunan sebelum mengendalikan risiko kritis","Menilai aset, ancaman, kerentanan, dampak; memprioritaskan kontrol dan menguji pemulihan"],"correct":"D","concept":"Manajemen risiko keamanan","explanation":"Jawaban D benar. Organisasi perlu mengidentifikasi aset dan proses kritis, menghubungkan ancaman dengan kerentanan, menilai kemungkinan serta dampak, lalu menentukan prioritas mitigasi. Kontrol dapat mencakup pengamanan akun admin, MFA, verifikasi perubahan rekening vendor, monitoring, patching, serta pengujian restore backup. Pengujian pemulihan penting karena keberadaan file backup belum membuktikan data dapat dipulihkan tepat waktu. Pendekatan berbasis risiko menghindari pembelian kontrol yang tidak sesuai prioritas.","whyOthersWrong":"Pilihan A berorientasi alat tanpa skenario risiko. Pilihan B dapat menghentikan operasi secara tidak proporsional. Pilihan C menunda pengendalian risiko kritis. Jebakannya adalah memilih tindakan yang terlihat tegas tetapi tidak mempertimbangkan likelihood, impact, residual risk, dan kesinambungan layanan.","tip":"Urutan logis: asset → threat/vulnerability → likelihood/impact → control → test/evaluate.","reference":"SI ARUN – SIM, TM 7, Risk, Risk Analysis, Risk Mitigation, dan Business Continuity.","keywords":"risk analysis; mitigasi; recovery"},{"number":25,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Strategic alignment dan outcome","learningOutcome":"Mengevaluasi keselarasan investasi TI","difficulty":"Sulit","type":"Analisis","question":"Instansi menambah banyak modul aplikasi, tetapi waktu layanan dan kesalahan tidak membaik. Respons manajerial PALING TEPAT adalah ...","options":["Menilai keselarasan tujuan, proses, data, pengguna, kontrol, dan outcome sebelum menambah fitur","Menambah fitur sebanyak mungkin agar investasi terlihat besar","Mengukur keberhasilan hanya dari selesainya pengembangan aplikasi","Memisahkan strategi TI dari tujuan organisasi agar lebih fleksibel"],"correct":"A","concept":"Keselarasan bisnis–TI","explanation":"Jawaban A benar. Investasi TI bernilai ketika mendukung tujuan organisasi, memperbaiki proses, menghasilkan informasi berkualitas, digunakan secara benar, dan memberikan outcome terukur. Banyak modul tidak otomatis mempercepat layanan apabila proses tetap rumit, data tidak konsisten, pengguna belum siap, atau pengendalian tidak tepat. Manajemen perlu mengukur waktu proses, kualitas, kepuasan, biaya, risiko, dan akuntabilitas, kemudian memperbaiki akar masalah sebelum menambah fitur.","whyOthersWrong":"Pilihan B dan C menggunakan ukuran output teknis, bukan manfaat organisasi. Pilihan D bertentangan dengan strategic alignment karena strategi TI seharusnya mendukung prioritas organisasi. Jebakan analisis adalah menganggap proyek selesai sama dengan manfaat telah terealisasi.","tip":"Bedakan output proyek (fitur selesai) dari outcome organisasi (layanan, biaya, kualitas, risiko).","reference":"SI ARUN – SIM, TM 2, Strategic Information Systems; RPS CPMK 4.","keywords":"strategic alignment; outcome; nilai"}],"flashcards":[{"number":1,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Informed user","difficulty":"Mudah","type":"Definisi","question":"Apa yang dimaksud informed user?","shortAnswer":"Pengguna yang memahami manfaat, cara kerja dasar, keterbatasan, risiko, dan kebutuhan pengendalian SI.","explanation":"Informed user tidak harus menjadi programmer. Ia mampu memberi masukan kebutuhan, mengevaluasi aplikasi, memahami dampak teknologi terhadap pekerjaan, dan berkomunikasi dengan personel TI. Pemahaman ini membantu organisasi menghindari keputusan yang hanya didasarkan pada tren teknologi.","example":"Bendahara memahami alur data dan kontrol aplikasi sebelum menyetujui perubahan fitur pembayaran.","keywords":"informed user; kebutuhan; risiko","comparison":"Ahli TI — ahli TI merancang atau mengelola teknologi secara mendalam; informed user memahami teknologi untuk pekerjaannya.","mnemonic":"Paham 4K: Kegunaan, Kerja dasar, Keterbatasan, Kontrol."},{"number":2,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Data–informasi–knowledge","difficulty":"Mudah","type":"Definisi","question":"Bedakan data, informasi, dan knowledge.","shortAnswer":"Data = fakta mentah; informasi = data berkonteks; knowledge = informasi + pengalaman untuk bertindak.","explanation":"Data baru menjadi informasi setelah diorganisasi, dihitung, dibandingkan, atau diberi konteks. Knowledge muncul ketika informasi dipahami melalui pengalaman, aturan, dan pembelajaran sehingga dapat digunakan untuk memecahkan masalah atau mengambil keputusan.","example":"78 adalah data; rata-rata kelas 78 adalah informasi; keputusan remediasi topik tertentu adalah knowledge.","keywords":"data; informasi; knowledge","comparison":"Informasi vs knowledge — informasi menjelaskan keadaan, knowledge membantu memilih tindakan.","mnemonic":"Mentah → Makna → Melangkah."},{"number":3,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Komponen CBIS","difficulty":"Mudah","type":"Definisi","question":"Apa enam komponen dasar CBIS?","shortAnswer":"Hardware, software, database, network, procedures, dan people.","explanation":"CBIS merupakan kombinasi teknologi dan unsur organisasi. Hardware dan software memproses data; database menyimpan; network menghubungkan; procedures mengatur cara kerja; people mengoperasikan serta menggunakan hasil. Kegagalan satu komponen dapat menurunkan kualitas seluruh sistem.","example":"Aplikasi nilai membutuhkan server, program, data mahasiswa, jaringan, SOP pengisian, dan dosen pengguna.","keywords":"hardware; software; data; network; prosedur; people","comparison":"Software vs procedures — software adalah instruksi mesin, procedures adalah aturan kerja manusia dan organisasi.","mnemonic":"Har–So–Da–Ja–Pro–O: Hardware, Software, Data, Jaringan, Prosedur, Orang."},{"number":4,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Business process","difficulty":"Mudah","type":"Definisi","question":"Apa definisi business process?","shortAnswer":"Rangkaian aktivitas terkait yang mengolah input dengan resources menjadi output bernilai.","explanation":"Proses bisnis melintasi aktivitas, sumber daya, pelaksana, aturan, dan hasil. Proses dapat berada dalam satu fungsi atau melibatkan banyak fungsi. Pengukuran proses menilai biaya, waktu, kualitas, produktivitas, dan kepuasan pengguna.","example":"Pengadaan: kebutuhan diajukan, stok dicek, pemasok dipilih, barang diterima, dan pembayaran dilakukan.","keywords":"input; resources; output; nilai","comparison":"Tugas individual — tugas adalah satu aktivitas; proses menghubungkan beberapa aktivitas menuju hasil.","mnemonic":"I–R–O: Input, Resources, Output."},{"number":5,"topic":"TM 3 – Data Management","subtopic":"Data warehouse","difficulty":"Sedang","type":"Definisi","question":"Apa itu data warehouse?","shortAnswer":"Penyimpanan terpusat data terintegrasi, historis, dan siap analisis untuk keputusan manajerial.","explanation":"Data warehouse menggabungkan data dari berbagai sistem melalui proses ekstraksi, transformasi, dan pemuatan. Data dibersihkan serta distandardisasi agar laporan lintas unit dan periode menggunakan definisi yang konsisten. Fokusnya berbeda dari sistem transaksi harian.","example":"Instansi menggabungkan data anggaran, aset, pegawai, dan kinerja untuk dashboard pimpinan.","keywords":"warehouse; historis; integrasi; ETL","comparison":"Database operasional — database operasional mendukung transaksi harian; warehouse mendukung analisis historis.","mnemonic":"Gudang = Gabung, Uji, Data historis, Analisis, Nilai, Governance."},{"number":6,"topic":"TM 7 – Information Security","subtopic":"CIA triad","difficulty":"Sedang","type":"Definisi","question":"Apa tiga tujuan utama CIA triad?","shortAnswer":"Confidentiality, Integrity, dan Availability.","explanation":"Confidentiality memastikan data hanya diakses pihak berwenang. Integrity menjaga data akurat, lengkap, dan tidak diubah tanpa izin. Availability memastikan sistem dan informasi tersedia ketika dibutuhkan. Kontrol keamanan harus menyeimbangkan ketiganya sesuai risiko proses.","example":"Enkripsi menjaga kerahasiaan, hash/log membantu integritas, dan redundansi mendukung ketersediaan.","keywords":"confidentiality; integrity; availability","comparison":"Privacy — privacy berfokus pada penggunaan data pribadi; confidentiality mencakup perlindungan akses informasi secara umum.","mnemonic":"KIK: Kerahasiaan, Integritas, Ketersediaan."},{"number":7,"topic":"TM 1 – Introduction to Information Systems","subtopic":"FAIS","difficulty":"Mudah","type":"Istilah","question":"Apa fungsi Functional Area Information Systems (FAIS)?","shortAnswer":"Mendukung aktivitas dan informasi pada area fungsional tertentu.","explanation":"FAIS dikembangkan untuk fungsi seperti akuntansi, keuangan, pemasaran, operasi, atau SDM. Sistem ini dapat sangat efektif dalam satu fungsi, tetapi tanpa integrasi dapat membentuk silo data. ERP menghubungkan berbagai FAIS agar aliran data lebih konsisten.","example":"Sistem payroll mendukung fungsi SDM dan terhubung ke akuntansi untuk pencatatan beban.","keywords":"FAIS; fungsi; departemen","comparison":"ERP — ERP mengintegrasikan banyak fungsi; FAIS berfokus pada satu fungsi.","mnemonic":"FAIS = Fokus Area Internal Spesifik."},{"number":8,"topic":"TM 1 – Introduction to Information Systems","subtopic":"TPS","difficulty":"Mudah","type":"Istilah","question":"Apa peran Transaction Processing System (TPS)?","shortAnswer":"Mencatat, menyimpan, dan memproses transaksi operasional rutin secara andal.","explanation":"TPS menangani transaksi volume tinggi seperti penjualan, pembayaran, penerimaan barang, absensi, atau pencairan. Output TPS menjadi sumber bagi laporan dan analitik. Karena berada di dasar operasi, akurasi, kelengkapan, ketersediaan, dan kontrol transaksi sangat penting.","example":"Sistem kasir mencatat barang, jumlah, harga, waktu, dan metode pembayaran.","keywords":"TPS; transaksi; operasional","comparison":"BI system — TPS merekam transaksi; BI menganalisis data untuk keputusan.","mnemonic":"TPS = Transaksi Pasti Tercatat."},{"number":9,"topic":"TM 4 – Database & KMS Practice","subtopic":"Tacit knowledge","difficulty":"Mudah","type":"Istilah","question":"Apa ciri utama tacit knowledge?","shortAnswer":"Melekat pada pengalaman, intuisi, dan keterampilan individu sehingga sulit dikodifikasi.","explanation":"Tacit knowledge sering terlihat dalam cara seorang pakar menyelesaikan masalah, bukan hanya dalam dokumen. Organisasi dapat menangkapnya melalui mentoring, wawancara, komunitas praktik, demonstrasi, dan lesson learned. KMS harus mendukung interaksi manusia, bukan hanya penyimpanan file.","example":"Auditor berpengalaman mengenali pola risiko dari kombinasi indikator yang belum tertulis dalam SOP.","keywords":"tacit; pengalaman; intuisi","comparison":"Explicit knowledge — explicit dapat ditulis, direkam, dan dibagikan lebih mudah.","mnemonic":"Tacit = Tersimpan pada Ahli, Cenderung sulit Itu Tertulis."},{"number":10,"topic":"TM 5 – Telecommunications & Networking","subtopic":"Latency","difficulty":"Mudah","type":"Istilah","question":"Apa arti latency pada jaringan?","shortAnswer":"Waktu yang dibutuhkan data untuk bergerak dari sumber ke tujuan.","explanation":"Latency memengaruhi kecepatan respons aplikasi, terutama layanan interaktif dan real-time. Nilai bandwidth tinggi tidak menjamin latency rendah. Rute yang panjang, kemacetan, media, perangkat, dan pemrosesan dapat menambah delay.","example":"Rapat video terasa terlambat walaupun paket internet memiliki kapasitas besar.","keywords":"latency; delay; respons","comparison":"Bandwidth — bandwidth adalah kapasitas; latency adalah waktu tempuh.","mnemonic":"Latency = Lama Tiba."},{"number":11,"topic":"TM 6 – Wireless, Mobile & IoT","subtopic":"Internet of Things","difficulty":"Sedang","type":"Istilah","question":"Apa yang membuat suatu solusi disebut IoT?","shortAnswer":"Objek fisik terhubung yang mengindra, mengirim, memproses data, lalu mendukung tindakan.","explanation":"IoT bukan hanya sensor atau koneksi internet. Nilai muncul dari keseluruhan loop sense–connect–process–analyze–act. Desain IoT juga harus mempertimbangkan identitas perangkat, kualitas sensor, keamanan, privasi, konektivitas, pemeliharaan, dan keputusan yang dihasilkan.","example":"Sensor suhu gudang mengirim data, sistem mendeteksi anomali, lalu memberi peringatan atau mengaktifkan pendingin.","keywords":"IoT; sensor; connect; act","comparison":"Mobile app — aplikasi mobile dapat menjadi antarmuka IoT, tetapi IoT mencakup objek dan loop data-tindakan.","mnemonic":"SCPAA: Sense, Connect, Process, Analyze, Act."},{"number":12,"topic":"TM 2 – Strategy & Business Processes","subtopic":"DMAIC","difficulty":"Sedang","type":"Tahapan","question":"Sebutkan urutan DMAIC.","shortAnswer":"Define → Measure → Analyze → Improve → Control.","explanation":"DMAIC digunakan dalam BPI/Six Sigma. Define menetapkan masalah; Measure mengukur kondisi; Analyze menemukan akar penyebab; Improve menerapkan solusi; Control menjaga hasil agar berkelanjutan. Urutan penting karena solusi seharusnya berdasarkan data dan analisis, bukan dugaan.","example":"Waktu pengadaan diukur, penyebab keterlambatan dianalisis, alur disederhanakan, lalu dipantau dengan dashboard.","keywords":"DMAIC; Six Sigma; BPI","comparison":"PDCA — sama-sama siklus perbaikan, tetapi DMAIC memiliki tahap Measure dan Analyze yang eksplisit.","mnemonic":"Definisikan, Mengukur, Analisis, Improve, Control."},{"number":13,"topic":"TM 4 – Database & KMS Practice","subtopic":"Siklus KMS","difficulty":"Sedang","type":"Tahapan","question":"Apa urutan siklus Knowledge Management System?","shortAnswer":"Create → Capture → Refine → Store → Manage → Disseminate.","explanation":"Pengetahuan diciptakan, ditangkap dari individu atau proses, disaring agar akurat dan relevan, disimpan, dikelola, lalu disebarkan kepada pihak yang membutuhkan. Siklus harus menghasilkan penggunaan kembali dan pembelajaran, bukan sekadar penumpukan dokumen.","example":"Lesson learned proyek diwawancarai, divalidasi, dimasukkan ke basis pengetahuan, lalu dipakai tim berikutnya.","keywords":"create; capture; refine; disseminate","comparison":"Document management — KMS menekankan pembelajaran dan pemanfaatan pengetahuan, bukan hanya arsip.","mnemonic":"CiTa SaSi MaSe: Cipta, Tangkap, Saring, Simpan, Manage, Sebar."},{"number":14,"topic":"TM 7 – Information Security","subtopic":"Manajemen risiko","difficulty":"Sedang","type":"Tahapan","question":"Bagaimana urutan sederhana analisis risiko keamanan?","shortAnswer":"Identifikasi aset → ancaman/kerentanan → likelihood/impact → kontrol → residual risk.","explanation":"Aset memiliki nilai; ancaman dapat memanfaatkan kerentanan; likelihood dan impact menentukan tingkat risiko. Kontrol dipilih untuk mengurangi risiko, lalu residual risk dinilai kembali. Pendekatan ini memastikan prioritas keamanan mengikuti kebutuhan organisasi.","example":"Database pembayaran adalah aset, phishing ancaman, password lemah kerentanan, MFA kontrol.","keywords":"asset; threat; vulnerability; risk; control","comparison":"Threat vs vulnerability — threat adalah bahaya, vulnerability adalah kelemahan yang dapat dimanfaatkan.","mnemonic":"A–A/K–L/I–K–R: Aset, Ancaman/Kerentanan, Likelihood/Impact, Kontrol, Residual."},{"number":15,"topic":"TM 7 – Information Security","subtopic":"Audit sistem informasi","difficulty":"Sulit","type":"Tahapan","question":"Apa tahapan inti audit sistem informasi?","shortAnswer":"Pahami kebijakan → kumpulkan bukti → uji konfigurasi/kontrol → identifikasi kelemahan → laporkan rekomendasi.","explanation":"Audit sistem informasi menilai keamanan, hak akses, pengelolaan data, operasi, dan kepatuhan. Auditor perlu menghubungkan tujuan kontrol dengan bukti pelaksanaan, tidak hanya membaca kebijakan. Pengujian dapat mencakup konfigurasi, log, sampel transaksi, dan efektivitas kontrol.","example":"Auditor memeriksa daftar pengguna, log perubahan hak akses, bukti review, dan sampel akun keluar.","keywords":"audit; bukti; pengujian; rekomendasi","comparison":"Monitoring — monitoring dilakukan terus-menerus oleh manajemen; audit memberi penilaian independen atau periodik.","mnemonic":"PBUIL: Pahami, Bukti, Uji, Identifikasi, Lapor."},{"number":16,"topic":"TM 2 – Strategy & Business Processes","subtopic":"Efisiensi dan efektivitas","difficulty":"Sedang","type":"Perbandingan","question":"Apa beda efisiensi dan efektivitas?","shortAnswer":"Efisiensi = hemat sumber daya; efektivitas = mencapai tujuan yang tepat.","explanation":"Proses dapat efisien tetapi tidak efektif, misalnya layanan selesai cepat namun hasilnya tidak memenuhi kebutuhan. Sebaliknya, proses efektif dapat terlalu mahal atau lambat. SIM membantu mengukur keduanya melalui biaya, waktu, kualitas, output, dan outcome.","example":"Menghasilkan laporan tepat waktu tetapi salah adalah efisien semu dan tidak efektif.","keywords":"efisiensi; efektivitas; outcome","comparison":"Produktivitas — produktivitas membandingkan output dengan input, tetapi belum selalu menilai ketepatan tujuan.","mnemonic":"Efisien = irit; efektif = tepat."},{"number":17,"topic":"TM 2 – Strategy & Business Processes","subtopic":"BPI dan BPR","difficulty":"Sedang","type":"Perbandingan","question":"Bandingkan BPI dan BPR.","shortAnswer":"BPI bertahap dan berisiko lebih rendah; BPR radikal dengan pendekatan clean slate.","explanation":"BPI memperbaiki bagian bermasalah dan cocok ketika proses masih layak. BPR mendesain ulang asumsi dasar, peran, alur, dan teknologi untuk lompatan kinerja. BPR memerlukan kesiapan perubahan serta dukungan pimpinan yang lebih besar.","example":"BPI mengurangi satu tahap persetujuan; BPR mengganti seluruh alur kertas menjadi proses digital terintegrasi.","keywords":"BPI; BPR; incremental; radical","comparison":"BPM — BPM adalah pengelolaan proses berkelanjutan, bukan hanya satu proyek perubahan.","mnemonic":"I = Incremental, R = Radical."},{"number":18,"topic":"TM 5 – Telecommunications & Networking","subtopic":"Cakupan dan akses jaringan","difficulty":"Sedang","type":"Perbandingan","question":"Bedakan LAN/WAN dengan intranet/internet.","shortAnswer":"LAN/WAN menjelaskan cakupan infrastruktur; intranet/internet menjelaskan model akses dan penggunaan.","explanation":"LAN mencakup area lokal, WAN menghubungkan wilayah luas. Intranet menggunakan teknologi internet untuk akses internal, sedangkan internet bersifat global dan publik. Sebuah intranet dapat berjalan pada LAN atau WAN, sehingga istilah tersebut tidak saling menggantikan.","example":"Portal pegawai adalah intranet yang dapat diakses kantor pusat dan wilayah melalui WAN.","keywords":"LAN; WAN; intranet; internet","comparison":"Intranet vs LAN — intranet adalah layanan internal; LAN adalah cakupan jaringan lokal.","mnemonic":"L/W = Luas wilayah; In/Internet = Izin akses."},{"number":19,"topic":"TM 7 – Information Security","subtopic":"Authentication dan authorization","difficulty":"Sulit","type":"Perbandingan","question":"Bedakan authentication dan authorization.","shortAnswer":"Authentication membuktikan identitas; authorization menentukan tindakan yang diizinkan.","explanation":"Login yang berhasil tidak berarti pengguna berhak melakukan semua fungsi. Hak akses harus diberikan berdasarkan peran, kebutuhan kerja, dan prinsip least privilege. Log individual diperlukan agar aktivitas dapat ditelusuri dan dipertanggungjawabkan.","example":"Pegawai boleh login, tetapi hanya pejabat tertentu boleh menyetujui pembayaran.","keywords":"identity; permission; least privilege","comparison":"Encryption — enkripsi melindungi isi data, bukan menentukan identitas dan hak pengguna.","mnemonic":"AuthN = Name; AuthZ = Zone izin."},{"number":20,"topic":"TM 1 – Introduction to Information Systems","subtopic":"Integrasi ERP","difficulty":"Sedang","type":"Penerapan","question":"Kapan organisasi memerlukan ERP?","shortAnswer":"Ketika proses lintas fungsi membutuhkan data bersama dan sistem terpisah menimbulkan silo.","explanation":"ERP relevan ketika transaksi satu fungsi memengaruhi fungsi lain dan organisasi memerlukan definisi serta proses terintegrasi. Implementasi harus disertai perbaikan proses, tata kelola data, pelatihan, kontrol akses, dan manajemen perubahan.","example":"Penerimaan barang otomatis memperbarui persediaan, utang, dan laporan anggaran.","keywords":"ERP; integrasi; silo","comparison":"FAIS — FAIS cukup jika kebutuhan benar-benar terbatas pada satu fungsi dan integrasi minimal.","mnemonic":"ERP = Enterprise Rukun Pakai data."},{"number":21,"topic":"TM 3 – Data Management","subtopic":"Pemilihan data mart","difficulty":"Sulit","type":"Penerapan","question":"Kapan data mart lebih tepat daripada data warehouse penuh?","shortAnswer":"Ketika satu fungsi membutuhkan analisis terfokus dengan cakupan data yang lebih sempit.","explanation":"Data mart dapat mempercepat kebutuhan analisis unit, misalnya keuangan atau SDM, karena struktur dan indikator disesuaikan dengan pengguna tertentu. Namun definisi dan sumber sebaiknya tetap konsisten dengan tata kelola data organisasi agar tidak membentuk silo baru.","example":"Data mart keuangan berisi anggaran, realisasi, pendapatan, dan indikator serapan.","keywords":"data mart; unit; analisis","comparison":"Data warehouse — warehouse memiliki cakupan organisasi lebih luas dan menjadi sumber terintegrasi.","mnemonic":"Mart = Mini area reporting team."},{"number":22,"topic":"TM 6 – Wireless, Mobile & IoT","subtopic":"Keamanan perangkat mobile","difficulty":"Sulit","type":"Penerapan","question":"Kontrol apa yang penting saat perangkat kerja hilang?","shortAnswer":"Enkripsi, screen lock, MDM, remote wipe, MFA, dan pelaporan insiden.","explanation":"Perangkat hilang dapat membuka data lokal, sesi aktif, dan kredensial. Enkripsi melindungi isi, MDM membantu mengelola konfigurasi, remote wipe menghapus data, dan MFA mengurangi penyalahgunaan akun. Prosedur pelaporan cepat memungkinkan pencabutan token serta investigasi.","example":"Ponsel dinas hilang, akun dinonaktifkan, token dicabut, lokasi diperiksa, dan perangkat dihapus jarak jauh.","keywords":"MDM; remote wipe; enkripsi; MFA","comparison":"Backup — backup membantu pemulihan data, tetapi tidak mencegah akses ke perangkat yang hilang.","mnemonic":"Kunci–Kelola–Hapus–Verifikasi–Lapor."},{"number":23,"topic":"TM 2 – Strategy & Business Processes","subtopic":"E-procurement","difficulty":"Sulit","type":"Mini Kasus","question":"Tender digital selesai lebih cepat, tetapi persaingan pemasok tidak meningkat. Apa yang perlu dievaluasi?","shortAnswer":"Outcome, desain proses, akses pemasok, kualitas data, aturan, dan pengendalian.","explanation":"Keberhasilan tidak cukup diukur dari aplikasi selesai atau waktu proses. Organisasi perlu menilai apakah lebih banyak pemasok dapat berpartisipasi, informasi mudah diakses, kriteria jelas, jejak audit memadai, dan hasil pengadaan meningkat. TI harus selaras dengan tujuan nilai publik.","example":"Analisis menunjukkan persyaratan portal sulit dan registrasi pemasok terlalu panjang.","keywords":"outcome; e-procurement; alignment","comparison":"Output vs outcome — output adalah sistem/tender selesai; outcome adalah perubahan kualitas dan manfaat.","mnemonic":"Selesai belum tentu berhasil: ukur Akses, Proses, Hasil."},{"number":24,"topic":"TM 3 – Data Management","subtopic":"Konflik laporan","difficulty":"Sulit","type":"Mini Kasus","question":"Tiga dashboard menunjukkan total berbeda untuk periode yang sama. Langkah awal terbaik?","shortAnswer":"Telusuri definisi, lineage, periode, transformasi, dan rekonsiliasi sumber.","explanation":"Perbedaan angka sering berasal dari definisi indikator, cutoff waktu, pemetaan kode, filter, duplikasi, atau aturan agregasi. Tim harus menyepakati data dictionary, memeriksa lineage dan ETL, lalu merekonsiliasi ke sumber resmi sebelum mengubah visualisasi.","example":"Satu dashboard memakai tanggal transaksi, lainnya tanggal posting sehingga total bulanan berbeda.","keywords":"lineage; definisi; rekonsiliasi","comparison":"Masalah visual — warna atau grafik tidak menyebabkan perbedaan total jika logika datanya sama.","mnemonic":"DeLiPeTaRe: Definisi, Lineage, Periode, Transformasi, Rekonsiliasi."},{"number":25,"topic":"TM 7 – Information Security","subtopic":"Phishing perubahan rekening","difficulty":"Sulit","type":"Mini Kasus","question":"Email vendor meminta perubahan rekening secara mendesak. Tindakan paling aman?","shortAnswer":"Jangan gunakan kontak email tersebut; verifikasi independen, pisahkan persetujuan, dan catat bukti.","explanation":"Spear phishing memanfaatkan urgensi dan penyamaran. Verifikasi harus dilakukan melalui nomor atau kontak resmi yang telah tersimpan, bukan informasi baru dalam email. Perubahan rekening perlu maker-checker, notifikasi, dan monitoring transaksi agar satu pengguna tidak dapat mengubah serta membayar tanpa pengawasan.","example":"Petugas menelepon PIC vendor melalui nomor kontrak, lalu perubahan disetujui pejabat berbeda.","keywords":"phishing; callback; segregation of duties","comparison":"Autentikasi email — alamat pengirim yang tampak benar belum membuktikan permintaan sah.","mnemonic":"STOP: Stop, Telepon kontak resmi, Otorisasi terpisah, Proof/log."}]}};
